INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('386e5a13-061f-4993-98df-9f51909668d7', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 1, 'ผู้ป่วยชายอายุ 55 ปี มีโรค Dyslipidemia รับประทาน Simvastatin 40 mg ตรวจพบการติดเชื้อราที่เล็บเท้าและซอกนิ้วเท้า เชื้อที่พบน่าจะเป็น Trichophyton ซึ่งทำให้เกิดโรคชนิดใดต่อไปนี้', NULL, '[{"label":"A","text":"Tinea capitis"},{"label":"B","text":"Tinea manuum"},{"label":"C","text":"Tinea cruris"},{"label":"D","text":"Tinea pedis"},{"label":"E","text":"Tinea corporis"}]'::jsonb, 'D', 'Trichophyton rubrum = สาเหตุหลักของ Tinea pedis (athlete''s foot) ซึ่งพบที่ซอกนิ้วเท้าและฝ่าเท้า', '{"summary":"Tinea pedis — การจำแนก Tinea ตาม body site","reason":"Trichophyton rubrum เป็นเชื้อหลักของ Tinea pedis ซึ่งเกิดที่เท้า/ซอกนิ้วเท้า","choices":[{"label":"A","text":"Tinea capitis","explanation":"✗ ผิด — Tinea capitis = เชื้อราที่หนังศีรษะ/เส้นผม ไม่ใช่เท้า"},{"label":"B","text":"Tinea manuum","explanation":"✗ ผิด — Tinea manuum = เชื้อราที่ฝ่ามือ"},{"label":"C","text":"Tinea cruris","explanation":"✗ ผิด — Tinea cruris = เชื้อราที่ขาหนีบ (jock itch)"},{"label":"D","text":"Tinea pedis","explanation":"✓ ถูก — Trichophyton rubrum/mentagrophytes = สาเหตุหลัก Tinea pedis (athlete''s foot) พบที่ซอกนิ้วเท้าและฝ่าเท้า"},{"label":"E","text":"Tinea corporis","explanation":"✗ ผิด — Tinea corporis = ringworm บนผิวหนังลำตัว ไม่ใช่เท้า"}],"key_takeaway":"จำ: pedis=เท้า, cruris=ขาหนีบ, capitis=ศีรษะ, manuum=มือ, corporis=ลำตัว, unguium=เล็บ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:01') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('870ac66a-9f25-481b-be4f-30bbd9a2e383', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 2, 'จากกรณีผู้ป่วยข้างต้น ยาใดต่อไปนี้เหมาะสมที่สุดในการรักษา Tinea pedis แบบผิวหนัง (ไม่ใช่เล็บ)', NULL, '[{"label":"A","text":"Ketoconazole cream"},{"label":"B","text":"Itraconazole capsule"},{"label":"C","text":"Mupirocin cream"},{"label":"D","text":"Dexamethasone cream"},{"label":"E","text":"Miconazole tablets"}]'::jsonb, 'A', 'Tinea pedis ที่ผิวหนัง → Topical antifungal เป็น first-line: Ketoconazole 2% cream ทา 2-4 สัปดาห์ หากเป็น onychomycosis จึงใช้ oral Itraconazole', '{"summary":"การรักษา Tinea pedis ที่ผิวหนัง (ไม่ใช่เล็บ)","reason":"Tinea pedis ที่ผิวหนัง → Topical antifungal เป็น first-line ไม่ต้องใช้ oral","choices":[{"label":"A","text":"Ketoconazole cream","explanation":"✓ ถูก — Topical azole (Ketoconazole 2% cream) = first-line สำหรับ Tinea pedis ที่ผิวหนัง ทา 2-4 สัปดาห์"},{"label":"B","text":"Itraconazole capsule","explanation":"✗ ผิด — Oral itraconazole ใช้สำหรับ onychomycosis (Tinea unguium) ไม่จำเป็นสำหรับ skin infection"},{"label":"C","text":"Mupirocin cream","explanation":"✗ ผิด — Mupirocin = antibacterial ใช้กับ MRSA/impetigo ไม่มีฤทธิ์ antifungal"},{"label":"D","text":"Dexamethasone cream","explanation":"✗ ผิด — Corticosteroid ห้ามใช้ใน fungal infection เพราะจะกดภูมิทำให้เชื้อรุนแรงขึ้น"},{"label":"E","text":"Miconazole tablets","explanation":"✗ ผิด — Miconazole oral tablet ใช้สำหรับ oral/esophageal candidiasis ไม่ใช่ Tinea pedis ที่ผิวหนัง"}],"key_takeaway":"Skin Tinea → topical antifungal; Nail Tinea → oral antifungal (Itraconazole/Terbinafine)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:01') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('139f1c71-baf0-4feb-a5b5-ef7b69b8aa68', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 3, 'ผลข้างเคียงสำคัญที่ต้องระวังเป็นพิเศษเมื่อใช้ Azole antifungal (Ketoconazole, Itraconazole) คือข้อใด', NULL, '[{"label":"A","text":"Agranulocytosis"},{"label":"B","text":"Kidney Injury"},{"label":"C","text":"Hepatotoxicity"},{"label":"D","text":"Nephrotoxicity"},{"label":"E","text":"Cardiotoxicity"}]'::jsonb, 'C', 'Azole antifungals ทำให้เกิด Hepatotoxicity — Ketoconazole ถูกถอนออกจากตลาดหลายประเทศเพราะ liver toxicity รุนแรง ต้อง monitor LFT', '{"summary":"ADR ของ Azole antifungals","reason":"Azole antifungals ยับยั้ง CYP enzymes โดยเฉพาะ CYP3A4 → สะสมใน liver → Hepatotoxicity","choices":[{"label":"A","text":"Agranulocytosis","explanation":"✗ ผิด — Agranulocytosis พบกับ Clozapine, Carbimazole, Carbamazepine ไม่ใช่ azoles"},{"label":"B","text":"Kidney Injury","explanation":"✗ ผิด — Nephrotoxicity เป็น ADR ของ Amphotericin B ไม่ใช่ azoles"},{"label":"C","text":"Hepatotoxicity","explanation":"✓ ถูก — Azoles (โดยเฉพาะ Ketoconazole) → Hepatotoxicity ต้อง monitor LFT; Ketoconazole ถูกถอนออกจากตลาดหลายประเทศ"},{"label":"D","text":"Nephrotoxicity","explanation":"✗ ผิด — Nephrotoxicity ไม่ใช่ ADR หลักของ azoles แต่เป็นของ Amphotericin B"},{"label":"E","text":"Cardiotoxicity","explanation":"✗ ผิด — Itraconazole อาจทำให้ QT prolongation ได้บ้าง แต่ไม่ใช่ ADR หลักของ azoles ทุกตัว"}],"key_takeaway":"Azole = Hepatotoxicity; Amphotericin B = Nephrotoxicity + Infusion reactions"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:01') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('37a61e3e-828b-48ab-b7cc-c6c7458b82a4', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 4, 'จากสูตรตำรับ Ketoconazole nail lacquer: Ketoconazole 100mg, Eudragit RL100 400mg, PG 1ml, Glyceryl triacetate 2.5ml, Isopropyl alcohol qs 10ml สารใดทำหน้าที่เป็น Film-former', NULL, '[{"label":"A","text":"PEG 400"},{"label":"B","text":"PG (Propylene glycol)"},{"label":"C","text":"Eudragit RL 100"},{"label":"D","text":"Glyceryl triacetate"},{"label":"E","text":"Isopropyl alcohol"}]'::jsonb, 'C', 'Eudragit RL 100 (polymethacrylic acid copolymer) = Film-forming polymer ทำให้ยาเกาะติดผิวเล็บ; Glyceryl triacetate = Plasticizer; IPA = Solvent', '{"summary":"หน้าที่ของ excipient ใน Ketoconazole nail lacquer","reason":"Eudragit RL 100 = film-forming polymer ทำให้ยาเกาะติดเล็บเป็นฟิล์ม","choices":[{"label":"A","text":"PEG 400","explanation":"✗ ผิด — PEG 400 ไม่มีในสูตรตำรับนี้; PEG เป็น solvent/plasticizer ไม่ใช่ film-former"},{"label":"B","text":"PG (Propylene glycol)","explanation":"✗ ผิด — PG = co-solvent/humectant ช่วยละลายยา ไม่ใช่ film-former"},{"label":"C","text":"Eudragit RL 100","explanation":"✓ ถูก — Eudragit RL 100 (polymethacrylic acid copolymer) = film-forming polymer ทำให้ยาเกาะเล็บเป็น film ค้างอยู่นาน"},{"label":"D","text":"Glyceryl triacetate","explanation":"✗ ผิด — Glyceryl triacetate (Triacetin) = Plasticizer เพิ่มความยืดหยุ่นของ film ไม่แตกหรือลอก"},{"label":"E","text":"Isopropyl alcohol","explanation":"✗ ผิด — IPA = solvent ทำหน้าที่ละลาย drug และ polymer ระเหยออกหลังทา"}],"key_takeaway":"Nail lacquer: Film-former=Eudragit, Plasticizer=Triacetin, Solvent=IPA, Co-solvent=PG"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:01') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b026b6bc-6ffb-43de-a949-b8cbc29fde93', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 5, 'ใน Ketoconazole nail lacquer สูตรเดิม Glyceryl triacetate (Triacetin) ทำหน้าที่อะไร', NULL, '[{"label":"A","text":"Antioxidant"},{"label":"B","text":"Buffer"},{"label":"C","text":"Preservative"},{"label":"D","text":"Opacifier"},{"label":"E","text":"Plasticizer"}]'::jsonb, 'E', 'Glyceryl triacetate (Triacetin) = Plasticizer เพิ่มความยืดหยุ่นของ Eudragit film ไม่ให้แตกหรือลอก', '{"summary":"หน้าที่ของ Glyceryl triacetate (Triacetin) ใน nail lacquer","reason":"Triacetin = plasticizer ป้องกัน film แตกหรือลอก เพิ่ม flexibility","choices":[{"label":"A","text":"Antioxidant","explanation":"✗ ผิด — Antioxidant เช่น Vitamin E, BHA, BHT ไม่ใช่ Triacetin"},{"label":"B","text":"Buffer","explanation":"✗ ผิด — Buffer ปรับ pH เช่น phosphate, citrate buffer ไม่ใช่ Triacetin"},{"label":"C","text":"Preservative","explanation":"✗ ผิด — Preservative เช่น BAK, chlorhexidine ไม่ใช่ Triacetin"},{"label":"D","text":"Opacifier","explanation":"✗ ผิด — Opacifier เช่น TiO₂ ทำให้ขุ่นขาว ไม่ใช่ Triacetin"},{"label":"E","text":"Plasticizer","explanation":"✓ ถูก — Glyceryl triacetate/Triacetin = plasticizer เพิ่ม flexibility ของ Eudragit film ป้องกันฟิล์มแตกร้าวขณะงอนิ้ว"}],"key_takeaway":"Plasticizers ใน nail lacquer: Triacetin, Dibutyl sebacate, PEG — ต้องเพิ่มเพื่อให้ film ยืดหยุ่น"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:01') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ddf9ff58-c25f-41c5-b626-4f4c37c889ae', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', 'Pharmacyguru', 1, 6, 'สารใดต่อไปนี้ทำหน้าที่เป็น Preservative ในสูตรตำรับ ophthalmic solution', NULL, '[{"label":"A","text":"Antioxidant"},{"label":"B","text":"Benzalkonium chloride"},{"label":"C","text":"Eudragit RL 100"},{"label":"D","text":"PEG 400"},{"label":"E","text":"Isopropyl alcohol"}]'::jsonb, 'B', 'Benzalkonium chloride (BAK) = Preservative ที่ใช้บ่อยที่สุดใน ophthalmic solutions (0.01-0.02%)', '{"summary":"Preservative ใน ophthalmic solution","reason":"Benzalkonium chloride (BAK) = most common preservative ใน eye drops","choices":[{"label":"A","text":"Antioxidant","explanation":"✗ ผิด — Antioxidant เช่น Na2EDTA, sodium metabisulfite ป้องกัน oxidation ไม่ใช่ microbial preservative"},{"label":"B","text":"Benzalkonium chloride","explanation":"✓ ถูก — BAK 0.01-0.02% = most widely used preservative ใน ophthalmic solution; ออกฤทธิ์ disrupt bacterial cell membrane"},{"label":"C","text":"Eudragit RL 100","explanation":"✗ ผิด — Eudragit = film-former ใน nail lacquer ไม่ใช่ ophthalmic preservative"},{"label":"D","text":"PEG 400","explanation":"✗ ผิด — PEG 400 = solvent/vehicle ไม่ใช่ preservative"},{"label":"E","text":"Isopropyl alcohol","explanation":"✗ ผิด — IPA ระคายเคืองตาอย่างรุนแรง ไม่ใช้ใน ophthalmic ยกเว้นในกระบวนการผลิต"}],"key_takeaway":"BAK = most common ophthalmic preservative แต่ toxic ต่อ corneal epithelium ใน long-term → preservative-free ดีกว่าในผู้ป่วย glaucoma"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('58dc3fe1-cc18-42ca-8496-2a9ede46d39c', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 7, 'ข้อใดต่อไปนี้กล่าว "ไม่ถูกต้อง" เกี่ยวกับการจัดการโรคปอดอักเสบตามคะแนน CURB-65', NULL, '[{"label":"A","text":"CURB-65 = 0 → รักษาที่บ้านได้"},{"label":"B","text":"CURB-65 = 1 → ผู้ป่วยนอก (OPD)"},{"label":"C","text":"CURB-65 ≥ 2 → รับไว้รักษาในโรงพยาบาล (non-ICU)"},{"label":"D","text":"CURB-65 ≥ 2 → รับไว้รักษาใน ICU ทันที"},{"label":"E","text":"CURB-65 ≥ 3 → พิจารณา ICU"}]'::jsonb, 'D', 'CURB-65: 0-1=home/OPD, 2=hospital non-ICU, ≥3=consider ICU — CURB-65 ≥2 ไม่ได้แปลว่าต้อง ICU ทันที', '{"summary":"CURB-65 score และการจัดการ CAP","reason":"CURB-65 ≥ 2 = admit ward ไม่ใช่ ICU ทันที; ≥ 3 จึงพิจารณา ICU","choices":[{"label":"A","text":"CURB-65 = 0 → รักษาที่บ้านได้","explanation":"✓ ถูก — Score 0 = low risk → OPD/home treatment"},{"label":"B","text":"CURB-65 = 1 → ผู้ป่วยนอก (OPD)","explanation":"✓ ถูก — Score 1 = short admission หรือ OPD ขึ้นกับ clinical judgement"},{"label":"C","text":"CURB-65 ≥ 2 → รับไว้รักษาในโรงพยาบาล (non-ICU)","explanation":"✓ ถูก — Score 2 = admit ward"},{"label":"D","text":"CURB-65 ≥ 2 → รับไว้รักษาใน ICU ทันที","explanation":"✗ ผิด — Score 2 = admit ward ไม่ใช่ ICU; ต้องได้ score ≥ 3 จึงพิจารณา ICU"},{"label":"E","text":"CURB-65 ≥ 3 → พิจารณา ICU","explanation":"✓ ถูก — Score ≥ 3 = high risk → consider ICU admission"}],"key_takeaway":"CURB-65: 0-1=home, 2=ward, ≥3=ICU; C=Confusion, U=Urea>7, R=RR≥30, B=SBP<90, 65=age≥65"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6e519cbe-4edd-4198-87cd-6d1c69bf584b', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 8, 'ผู้ป่วย CAP (Community-Acquired Pneumonia) ที่ต้องรับไว้รักษาในโรงพยาบาล ควรได้รับ empirical therapy ใด', NULL, '[{"label":"A","text":"Ceftriaxone + Azithromycin"},{"label":"B","text":"Ceftriaxone + Doxycycline"},{"label":"C","text":"Piperacillin/tazobactam + Azithromycin"},{"label":"D","text":"Amoxicillin/Clavulanic acid"},{"label":"E","text":"Ampicillin + Sulbactam"}]'::jsonb, 'A', 'CAP ที่ต้องนอนโรงพยาบาล (non-ICU): Beta-lactam (Ceftriaxone) + Macrolide (Azithromycin) — IDSA/ATS guidelines', '{"summary":"Empirical therapy สำหรับ CAP ที่ต้อง admit (non-ICU)","reason":"IDSA/ATS: Beta-lactam + Macrolide = standard สำหรับ inpatient non-ICU CAP","choices":[{"label":"A","text":"Ceftriaxone + Azithromycin","explanation":"✓ ถูก — Beta-lactam (Ceftriaxone) + Macrolide (Azithromycin) = recommended combination สำหรับ inpatient non-ICU CAP ตาม IDSA/ATS"},{"label":"B","text":"Ceftriaxone + Doxycycline","explanation":"✗ ผิด — Doxycycline เป็น alternative ได้ แต่ Azithromycin เป็น preferred มากกว่าเพราะ dosing และ efficacy"},{"label":"C","text":"Piperacillin/tazobactam + Azithromycin","explanation":"✗ ผิด — Pip/tazo ใช้สำหรับ Hospital-acquired/Pseudomonal pneumonia ไม่ใช่ typical CAP"},{"label":"D","text":"Amoxicillin/Clavulanic acid","explanation":"✗ ผิด — Augmentin ใช้ outpatient CAP ไม่เหมาะสำหรับ inpatient ที่ต้อง IV"},{"label":"E","text":"Ampicillin + Sulbactam","explanation":"✗ ผิด — Ampicillin/sulbactam ไม่ครอบคลุม atypical organisms (Mycoplasma, Chlamydia, Legionella)"}],"key_takeaway":"Inpatient CAP non-ICU: Ceftriaxone + Azithromycin (IV); ICU CAP: เพิ่ม respiratory FQ หรือ beta-lactam+macrolide"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4114f41b-0f58-4a8e-abaa-95ba8767771d', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 9, 'ข้อใดต่อไปนี้เป็น antipseudomonal antibiotic ที่เหมาะสำหรับ Pseudomonas aeruginosa', NULL, '[{"label":"A","text":"Ampicillin"},{"label":"B","text":"Amoxicillin/Clavulanic"},{"label":"C","text":"Ceftazidime"},{"label":"D","text":"Doxycycline"},{"label":"E","text":"Azithromycin"}]'::jsonb, 'C', 'Ceftazidime = 3rd gen cephalosporin ที่มีฤทธิ์ต้าน Pseudomonas — ทางเลือกอื่น: Cefepime, Pip/tazo, Meropenem, Ciprofloxacin', '{"summary":"Antipseudomonal antibiotics","reason":"Ceftazidime = 3rd gen cephalosporin ที่มีฤทธิ์ต้าน Pseudomonas aeruginosa","choices":[{"label":"A","text":"Ampicillin","explanation":"✗ ผิด — Ampicillin ไม่มีฤทธิ์ต้าน Pseudomonas (narrow spectrum gram-positive)"},{"label":"B","text":"Amoxicillin/Clavulanic","explanation":"✗ ผิด — Augmentin ครอบคลุม gram-negative แต่ไม่ครอบคลุม Pseudomonas"},{"label":"C","text":"Ceftazidime","explanation":"✓ ถูก — Ceftazidime = 3rd gen cephalosporin ที่มี anti-Pseudomonal activity; ใช้ใน Pseudomonal infections"},{"label":"D","text":"Doxycycline","explanation":"✗ ผิด — Doxycycline = tetracycline ครอบคลุม atypicals, MRSA community แต่ไม่ใช่ Pseudomonas"},{"label":"E","text":"Azithromycin","explanation":"✗ ผิด — Azithromycin = macrolide ครอบคลุม atypicals/gram-positive ไม่มีฤทธิ์ต้าน Pseudomonas"}],"key_takeaway":"Anti-Pseudomonal: Ceftazidime, Cefepime, Pip/tazo, Meropenem, Imipenem, Ciprofloxacin, Aminoglycosides"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('88b9e664-a313-441f-9e14-1a6100e6709b', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 10, 'Ceftriaxone sodium ไม่ควรผสมกับสารละลายใดต่อไปนี้', NULL, '[{"label":"A","text":"D5W"},{"label":"B","text":"0.9% NaCl"},{"label":"C","text":"0.45% NaCl"},{"label":"D","text":"สารละลายที่มี Calcium (Ringer''s Lactate)"},{"label":"E","text":"D10W"}]'::jsonb, 'D', 'Ceftriaxone + Calcium → ตกตะกอน Ceftriaxone-calcium precipitate — ห้ามใช้ร่วมกับ Ringer''s Lactate, Hartmann''s (fatal ใน newborn)', '{"summary":"Incompatibility ของ Ceftriaxone","reason":"Ceftriaxone + Calcium → ตกตะกอน ceftriaxone-calcium salt อันตรายถึงชีวิต","choices":[{"label":"A","text":"D5W","explanation":"✗ ผิด — Ceftriaxone ผสม D5W ได้ปกติ (compatible)"},{"label":"B","text":"0.9% NaCl","explanation":"✗ ผิด — Ceftriaxone ผสม NSS ได้ปกติ"},{"label":"C","text":"0.45% NaCl","explanation":"✗ ผิด — Half-normal saline compatible กับ Ceftriaxone"},{"label":"D","text":"สารละลายที่มี Calcium (Ringer''s Lactate)","explanation":"✓ ถูก — Ceftriaxone + Ca²⁺ → ตกตะกอน Ceftriaxone-calcium salt ในปอด/ไต → เสียชีวิต (Black box warning โดยเฉพาะใน newborn)"},{"label":"E","text":"D10W","explanation":"✗ ผิด — D10W compatible กับ Ceftriaxone"}],"key_takeaway":"Ceftriaxone + Calcium (LR, Hartmann''s) = ห้ามเด็ดขาด → Fatal precipitate; ใน neonates ห้ามให้ IV calcium ภายใน 48 ชม."}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('59b5e91a-c268-49da-b137-4bed5607d42e', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 11, 'RCT เปรียบเทียบ Amoxicillin/Clavulanate กับ Cefixime ใน CAP พบ RR = 1.7 และ 95% CI: 1.3-2.45 ข้อใดแปลผลได้ถูกต้อง', NULL, '[{"label":"A","text":"Amoxicillin/Clavulanate ดีกว่า Cefixime อย่างมีนัยสำคัญ"},{"label":"B","text":"Amoxicillin/Clavulanate ดีกว่าแต่ไม่มีนัยสำคัญ"},{"label":"C","text":"ไม่แตกต่างกัน"},{"label":"D","text":"Cefixime ดีกว่าอย่างมีนัยสำคัญ"},{"label":"E","text":"ยังสรุปไม่ได้"}]'::jsonb, 'A', 'RR = 1.7 และ 95% CI ไม่ครอบ 1.0 (1.3-2.45) → แตกต่างอย่างมีนัยสำคัญ (p < 0.05)', '{"summary":"การแปลผล Relative Risk และ 95% CI","reason":"RR = 1.7, 95% CI 1.3-2.45 — CI ไม่ครอบค่า 1.0 → significant difference","choices":[{"label":"A","text":"Amoxicillin/Clavulanate ดีกว่า Cefixime อย่างมีนัยสำคัญ","explanation":"✓ ถูก — RR > 1.0 และ 95% CI (1.3-2.45) ไม่ครอบ 1.0 → แตกต่างอย่างมีนัยสำคัญ (p < 0.05); RR > 1 หมาย Amoxiclav ให้ผลดีกว่า"},{"label":"B","text":"Amoxicillin/Clavulanate ดีกว่าแต่ไม่มีนัยสำคัญ","explanation":"✗ ผิด — ถ้าไม่มีนัยสำคัญ CI ต้องครอบ 1.0"},{"label":"C","text":"ไม่แตกต่างกัน","explanation":"✗ ผิด — ถ้าไม่แตกต่าง RR จะ = 1 และ CI ครอบ 1.0"},{"label":"D","text":"Cefixime ดีกว่าอย่างมีนัยสำคัญ","explanation":"✗ ผิด — RR > 1 แสดงว่า Amoxiclav ดีกว่า ไม่ใช่ Cefixime; Cefixime ดีกว่าถ้า RR < 1 และ CI ต่ำกว่า 1.0"},{"label":"E","text":"ยังสรุปไม่ได้","explanation":"✗ ผิด — สรุปได้ชัดเจนเพราะ CI ไม่ครอบ 1.0"}],"key_takeaway":"95% CI ไม่ครอบ 1.0 → p < 0.05 → significant; ครอบ 1.0 → p > 0.05 → not significant"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('834f7d43-dd44-4c7c-a5fc-f159b416dd44', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 12, 'จากการทดลอง: Placebo เกิด 40 เหตุการณ์จาก 200 คน, Dapagliflozin เกิด 20 เหตุการณ์จาก 200 คน ค่า NNT คือเท่าใด', NULL, '[{"label":"A","text":"5"},{"label":"B","text":"10"},{"label":"C","text":"13"},{"label":"D","text":"20"},{"label":"E","text":"25"}]'::jsonb, 'B', 'ARR = 40/200 − 20/200 = 0.20 − 0.10 = 0.10 (10%)
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4804259d-6f19-44a9-b776-c6f9f93d6015', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 13, 'ผู้ป่วย COPD ที่ได้รับ Amoxicillin/Clavulanic acid 500 mg ทุก 8 ชั่วโมง นาน 3,000 mg/วัน ซึ่งสูงกว่าขนาดปกติ เหตุผลที่ถูกต้องคือ', NULL, '[{"label":"A","text":"เพื่อเพิ่ม absorption"},{"label":"B","text":"เพื่อเอาชนะ MIC สูงของเชื้อดื้อยา"},{"label":"C","text":"เพื่อลด side effects"},{"label":"D","text":"เป็นขนาดปกติสำหรับ COPD exacerbation"},{"label":"E","text":"ลด protein binding"}]'::jsonb, 'B', 'Beta-lactam ออกฤทธิ์แบบ time-dependent — การเพิ่มขนาดยาเพื่อเอาชนะ MIC ที่สูงของเชื้อดื้อยา เช่น H. influenzae, M. catarrhalis ใน COPD', '{"summary":"เหตุผลที่ใช้ Amoxicillin/Clavulanate ขนาดสูงใน COPD exacerbation","reason":"Beta-lactam เป็น time-dependent — การเพิ่มขนาดเพื่อ overcome MIC ที่สูงของเชื้อดื้อยา","choices":[{"label":"A","text":"เพื่อเพิ่ม absorption","explanation":"✗ ผิด — การเพิ่มขนาดไม่ได้เพิ่ม oral bioavailability อย่างมีนัยสำคัญ"},{"label":"B","text":"เพื่อเอาชนะ MIC สูงของเชื้อดื้อยา","explanation":"✓ ถูก — Beta-lactam = time-dependent (T>MIC); การเพิ่มขนาดเพื่อ achieve และรักษา T>MIC ต่อเชื้อดื้อยา เช่น H. influenzae, M. catarrhalis"},{"label":"C","text":"เพื่อลด side effects","explanation":"✗ ผิด — ขนาดสูงกว่าปกติ เพิ่ม GI side effects ไม่ใช่ลด"},{"label":"D","text":"เป็นขนาดปกติสำหรับ COPD exacerbation","explanation":"✗ ผิด — 3000 mg/day สูงกว่าขนาดปกติ (750-2000 mg/day)"},{"label":"E","text":"ลด protein binding","explanation":"✗ ผิด — ขนาดยาไม่ได้มีผลต่อ protein binding อย่างมีนัยสำคัญ"}],"key_takeaway":"Beta-lactam = time-dependent (ต้องรักษา T>MIC ≥40-50%); Aminoglycosides/Fluoroquinolones = concentration-dependent"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b3f82a4f-6577-46ac-af49-2b030c98c3b0', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 14, 'ผู้ป่วย SLE ที่ต้องการเริ่มใช้ Hydroxychloroquine (HCQ) ควรตรวจอะไรเป็น baseline ก่อนเริ่มยา', NULL, '[{"label":"A","text":"Serum creatinine"},{"label":"B","text":"eGFR"},{"label":"C","text":"CBC"},{"label":"D","text":"Vision (Ophthalmologic exam)"},{"label":"E","text":"การทดสอบการได้ยิน"}]'::jsonb, 'D', 'HCQ สะสมในจอตา (retina) ทำให้เกิด retinopathy ถาวร — ต้อง ophthalmologic exam baseline และทุกปีหลังใช้ 5 ปี (ACR 2016 guidelines)', '{"summary":"Baseline monitoring ก่อนเริ่ม Hydroxychloroquine ใน SLE","reason":"HCQ สะสมใน melanin-containing tissues รวมถึง retina → ต้อง baseline eye exam","choices":[{"label":"A","text":"Serum creatinine","explanation":"✗ ผิด — Renal function ไม่ใช่ main concern ของ HCQ; อาจ adjust dose ใน severe renal impairment แต่ไม่ใช่ baseline หลัก"},{"label":"B","text":"eGFR","explanation":"✗ ผิด — eGFR ไม่ใช่ baseline monitoring หลักสำหรับ HCQ"},{"label":"C","text":"CBC","explanation":"✗ ผิด — HCQ ไม่ก่อ myelosuppression ที่ต้อง baseline CBC"},{"label":"D","text":"Vision (Ophthalmologic exam)","explanation":"✓ ถูก — HCQ → retinal toxicity → ต้อง baseline ophthalmologic exam (visual field + spectral-domain OCT) ตาม ACR 2016 guidelines"},{"label":"E","text":"การทดสอบการได้ยิน","explanation":"✗ ผิด — Hearing loss เป็น ADR ของ Quinine/Aminoglycosides ไม่ใช่ HCQ"}],"key_takeaway":"HCQ monitoring: baseline eye exam + ทุกปีหลัง 5 ปี; HCQ dose ≤5 mg/kg/day ลด retinopathy risk"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('09f6a4bb-2306-469f-8694-4cddb764788e', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 15, 'ข้อใดเป็น absolute contraindication ของ Hydroxychloroquine', NULL, '[{"label":"A","text":"ตั้งครรภ์"},{"label":"B","text":"ไตวาย"},{"label":"C","text":"เบาหวาน"},{"label":"D","text":"Retinal/Macular disease ที่มีอยู่เดิม"},{"label":"E","text":"ความดันโลหิตสูง"}]'::jsonb, 'D', 'HCQ มี retinal toxicity — absolute contraindicated ใน pre-existing retinal/macular disease; HCQ ปลอดภัยในการตั้งครรภ์ (ไม่ใช่ CI)', '{"summary":"Absolute contraindication ของ Hydroxychloroquine","reason":"HCQ สะสม retina → pre-existing retinal disease = absolute CI","choices":[{"label":"A","text":"ตั้งครรภ์","explanation":"✗ ผิด — HCQ ปลอดภัยในการตั้งครรภ์ (Category C, แต่ benefit > risk ใน SLE); ไม่ใช่ CI"},{"label":"B","text":"ไตวาย","explanation":"✗ ผิด — ไตวายต้องปรับขนาดยา แต่ไม่ใช่ absolute CI"},{"label":"C","text":"เบาหวาน","explanation":"✗ ผิด — HCQ อาจ reduce blood glucose ได้เล็กน้อย ไม่ใช่ CI"},{"label":"D","text":"Retinal/Macular disease ที่มีอยู่เดิม","explanation":"✓ ถูก — Pre-existing retinal/macular disease = absolute contraindication เพราะ HCQ จะทำให้แย่ลงอย่างถาวร"},{"label":"E","text":"ความดันโลหิตสูง","explanation":"✗ ผิด — Hypertension ไม่ใช่ CI ของ HCQ"}],"key_takeaway":"HCQ: ปลอดภัยในการตั้งครรภ์และ breastfeeding; CI หลัก = pre-existing retinopathy"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2ff78ef0-c483-4f13-a014-76fb32c81d4b', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 16, 'Hydroxychloroquine ในผู้ป่วย SLE ใช้เป็นอะไร', NULL, '[{"label":"A","text":"Rescue therapy เฉพาะตอน flare"},{"label":"B","text":"Background/maintenance therapy ใน SLE ทุก severity"},{"label":"C","text":"ใช้เฉพาะใน severe SLE"},{"label":"D","text":"ใช้แทน corticosteroid"},{"label":"E","text":"ใช้เฉพาะใน lupus nephritis"}]'::jsonb, 'B', 'HCQ = cornerstone therapy ใน SLE — ใช้ต่อเนื่องในทุก severity เพื่อลด disease activity, ป้องกัน flare และลด mortality', '{"summary":"บทบาทของ Hydroxychloroquine ใน SLE","reason":"HCQ = cornerstone/background therapy ใน SLE ทุก severity ไม่ใช่แค่ rescue therapy","choices":[{"label":"A","text":"Rescue therapy เฉพาะตอน flare","explanation":"✗ ผิด — HCQ ใช้ต่อเนื่อง ไม่ใช่แค่ตอน flare; หยุดยาเพิ่มความเสี่ยง flare"},{"label":"B","text":"Background/maintenance therapy ใน SLE ทุก severity","explanation":"✓ ถูก — ACR แนะนำ HCQ ในผู้ป่วย SLE ทุกราย (ยกเว้น CI) เพื่อลด disease activity, flare, organ damage, mortality"},{"label":"C","text":"ใช้เฉพาะใน severe SLE","explanation":"✗ ผิด — ใช้ได้ทุก severity รวมถึง mild SLE"},{"label":"D","text":"ใช้แทน corticosteroid","explanation":"✗ ผิด — HCQ ไม่ใช่ corticosteroid; ใช้ร่วมกันได้และช่วยลดขนาด steroid"},{"label":"E","text":"ใช้เฉพาะใน lupus nephritis","explanation":"✗ ผิด — ใช้ได้ทุก manifestation ไม่จำกัดแค่ nephritis"}],"key_takeaway":"HCQ benefits ใน SLE: ลด flare, ลด organ damage, ลด thrombosis (APS), ลด mortality, ปลอดภัยในตั้งครรภ์"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c6e17a69-e3ad-482b-a4e0-6531c36ce131', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 17, 'ข้อใดถูกต้องเกี่ยวกับการ monitoring ระหว่างใช้ Hydroxychloroquine', NULL, '[{"label":"A","text":"ตรวจ Serum creatinine ทุก 3 เดือน"},{"label":"B","text":"ตรวจ eGFR ทุก 6 เดือน"},{"label":"C","text":"CBC ทุกเดือน"},{"label":"D","text":"Vision field test ทุกปีหลังใช้ยา 5 ปี"},{"label":"E","text":"ไม่ต้อง monitor ใดๆ"}]'::jsonb, 'D', 'ACR 2016: ophthalmologic monitoring ปีละ 1 ครั้งหลังใช้ยา 5 ปี (หรือก่อนหน้าถ้า renal/hepatic disease, high cumulative dose, อายุ ≥ 60 ปี)', '{"summary":"Monitoring ระหว่างใช้ Hydroxychloroquine","reason":"ACR 2016: ophthalmologic monitoring ปีละ 1 ครั้งหลังใช้ยา 5 ปี","choices":[{"label":"A","text":"ตรวจ Serum creatinine ทุก 3 เดือน","explanation":"✗ ผิด — Renal monitoring ไม่ใช่ routine สำหรับ HCQ โดยเฉพาะ"},{"label":"B","text":"ตรวจ eGFR ทุก 6 เดือน","explanation":"✗ ผิด — eGFR ไม่ใช่ primary monitoring parameter ของ HCQ"},{"label":"C","text":"CBC ทุกเดือน","explanation":"✗ ผิด — HCQ ไม่มีผล myelosuppression ที่ต้อง monthly CBC"},{"label":"D","text":"Vision field test ทุกปีหลังใช้ยา 5 ปี","explanation":"✓ ถูก — ACR 2016: annual ophthalmologic exam หลัง 5 ปีแรก (หรือเร็วกว่าถ้า high-risk: renal/liver disease, high dose, อายุ ≥60)"},{"label":"E","text":"ไม่ต้อง monitor ใดๆ","explanation":"✗ ผิด — ต้อง monitor eyes เสมอ"}],"key_takeaway":"HCQ safe dose ≤5 mg/kg/day; ophthalmologic screening ปีแรก (baseline) แล้ว annual ตั้งแต่ปีที่ 5"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('bbbc2b06-4265-469b-aaf6-f00e7966e360', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 18, 'ข้อใดกล่าว "ไม่ถูกต้อง" เกี่ยวกับการใช้ Hydroxychloroquine ใน SLE', NULL, '[{"label":"A","text":"ใช้ร่วมกับ Methotrexate ได้"},{"label":"B","text":"ใช้ HCQ แทน Immunosuppressant ทุกชนิดได้"},{"label":"C","text":"ใช้ได้อย่างปลอดภัยในหญิงตั้งครรภ์ที่เป็น SLE"},{"label":"D","text":"ใช้ร่วมกับ Mycophenolate mofetil ได้"},{"label":"E","text":"ลดความเสี่ยง thrombosis ใน APS"}]'::jsonb, 'B', 'HCQ ไม่สามารถแทน immunosuppressant (MMF, Azathioprine, Cyclophosphamide) ได้ใน lupus nephritis class III/IV ที่ต้องใช้ immunosuppressant', '{"summary":"ข้อที่ไม่ถูกต้องเกี่ยวกับ HCQ ใน SLE","reason":"HCQ ไม่สามารถทดแทน immunosuppressant ได้ใน severe disease","choices":[{"label":"A","text":"ใช้ร่วมกับ Methotrexate ได้","explanation":"✗ คำตอบนี้ถูกต้อง — HCQ + MTX ใช้ร่วมกันได้ใน RA และ SLE"},{"label":"B","text":"ใช้ HCQ แทน Immunosuppressant ทุกชนิดได้","explanation":"✓ นี่คือข้อที่ผิด — HCQ ไม่สามารถแทน MMF/Azathioprine/Cyclophosphamide ใน severe manifestations เช่น lupus nephritis class III/IV"},{"label":"C","text":"ใช้ได้อย่างปลอดภัยในหญิงตั้งครรภ์ที่เป็น SLE","explanation":"✗ คำตอบนี้ถูกต้อง — HCQ ปลอดภัยในการตั้งครรภ์; การหยุดยาเพิ่มความเสี่ยง flare"},{"label":"D","text":"ใช้ร่วมกับ Mycophenolate mofetil ได้","explanation":"✗ คำตอบนี้ถูกต้อง — HCQ + MMF ใช้ร่วมกันเป็น standard of care ใน lupus nephritis"},{"label":"E","text":"ลดความเสี่ยง thrombosis ใน APS","explanation":"✗ คำตอบนี้ถูกต้อง — HCQ มีคุณสมบัติ antithrombotic ลด risk ใน antiphospholipid syndrome"}],"key_takeaway":"HCQ = adjunct therapy ไม่สามารถแทน immunosuppressants ได้; ใน severe SLE ต้องใช้ร่วมกัน"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c4cdd364-ea32-46de-a14a-9cea5e23bfde', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 19, 'ยาใดต่อไปนี้เป็น classic cause ของ Drug-induced lupus (DIL)', NULL, '[{"label":"A","text":"Enalapril"},{"label":"B","text":"Hydralazine"},{"label":"C","text":"Simvastatin"},{"label":"D","text":"Amlodipine"},{"label":"E","text":"Metformin"}]'::jsonb, 'B', 'Drug-induced lupus: Hydralazine, Procainamide, Isoniazid = H-P-I classic triad; ยาอื่น: Minocycline, Anti-TNF agents', '{"summary":"Drug-induced lupus (DIL) — classic causative drugs","reason":"H-P-I triad = Hydralazine, Procainamide, Isoniazid — classic DIL","choices":[{"label":"A","text":"Enalapril","explanation":"✗ ผิด — ACE inhibitors ไม่ใช่ classic DIL drugs; อาจทำให้ SLE flare ได้แต่ไม่ใช่ classic"},{"label":"B","text":"Hydralazine","explanation":"✓ ถูก — Hydralazine = classic DIL; มักเป็น slow acetylators; ANA+ (anti-histone Ab); หายหลังหยุดยา"},{"label":"C","text":"Simvastatin","explanation":"✗ ผิด — Statins อาจทำ lupus-like ได้บ้างแต่ไม่ใช่ classic"},{"label":"D","text":"Amlodipine","explanation":"✗ ผิด — Calcium channel blockers ไม่ใช่ classic DIL drugs"},{"label":"E","text":"Metformin","explanation":"✗ ผิด — Metformin ไม่ก่อ DIL"}],"key_takeaway":"Classic DIL: H=Hydralazine, P=Procainamide, I=Isoniazid; Others: Minocycline, Anti-TNF, Methyldopa; DIL = anti-histone Ab+"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9e44f799-9874-49d8-863d-96e0be683639', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', 'Pharmacyguru', 1, 20, 'ผู้ป่วย SLE ที่มี antiphospholipid antibody positive ควรใช้การคุมกำเนิดแบบใด', NULL, '[{"label":"A","text":"Combined oral contraceptive (COC)"},{"label":"B","text":"Progestin-only pill"},{"label":"C","text":"ไม่ต้องคุมกำเนิด"},{"label":"D","text":"ฉีด DMPA"},{"label":"E","text":"ใส่ห่วงอนามัยชนิดฮอร์โมน"}]'::jsonb, 'B', 'SLE + APS → thrombosis risk สูง → ห้ามใช้ COC (estrogen เพิ่ม clot risk) — ใช้ Progestin-only, Copper IUD หรือ barrier method แทน', '{"summary":"การคุมกำเนิดใน SLE ที่มี antiphospholipid antibody","reason":"APS + estrogen = เพิ่ม thrombosis risk → ห้าม COC; ใช้ progestin-only แทน","choices":[{"label":"A","text":"Combined oral contraceptive (COC)","explanation":"✗ ผิด — Estrogen ใน COC เพิ่ม thrombosis risk อย่างมากใน APS → ห้ามใช้"},{"label":"B","text":"Progestin-only pill","explanation":"✓ ถูก — Progestin-only (norethindrone) ไม่เพิ่ม thrombosis risk → เลือกใช้ใน SLE/APS"},{"label":"C","text":"ไม่ต้องคุมกำเนิด","explanation":"✗ ผิด — การตั้งครรภ์ใน APS เสี่ยง recurrent miscarriage, thrombosis; ต้องวางแผน"},{"label":"D","text":"ฉีด DMPA","explanation":"✗ ผิด — DMPA (progestin) ใช้ได้แต่มี concern เรื่อง bone density loss ในระยะยาว; อาจพิจารณาได้"},{"label":"E","text":"ใส่ห่วงอนามัยชนิดฮอร์โมน","explanation":"✗ ผิด — Levonorgestrel IUD (progestin) พิจารณาได้ แต่ copper IUD ดีกว่าถ้าต้องการ hormone-free"}],"key_takeaway":"SLE+APS: ห้าม COC → Progestin-only pill, copper IUD, or barrier method; Hydroxychloroquine ลด thrombosis risk"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('dbab7cff-2f87-4f06-a12b-48950f0d96fe', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 21, 'ผู้ป่วย HF ที่มี LVEF 30% จัดอยู่ใน category ใด', NULL, '[{"label":"A","text":"Acute heart failure"},{"label":"B","text":"Acute decompensated heart failure"},{"label":"C","text":"HFrEF (LVEF < 40%)"},{"label":"D","text":"HFmrEF (LVEF 40-49%)"},{"label":"E","text":"HFpEF (LVEF ≥ 50%)"}]'::jsonb, 'C', 'HFrEF: LVEF < 40%; HFmrEF: LVEF 40-49%; HFpEF: LVEF ≥ 50% — LVEF 30% = HFrEF', '{"summary":"การจัดประเภท Heart Failure ตาม LVEF","reason":"LVEF 30% < 40% จัดเป็น HFrEF","choices":[{"label":"A","text":"Acute heart failure","explanation":"✗ ผิด — Acute HF อธิบาย timeline ไม่ใช่ category ตาม LVEF"},{"label":"B","text":"Acute decompensated heart failure","explanation":"✗ ผิด — ADHF = acute deterioration ของ chronic HF ไม่ใช่ category ตาม LVEF"},{"label":"C","text":"HFrEF (LVEF < 40%)","explanation":"✓ ถูก — LVEF 30% < 40% = HFrEF (Heart Failure with reduced EF); มี evidence-based treatment ที่ลด mortality"},{"label":"D","text":"HFmrEF (LVEF 40-49%)","explanation":"✗ ผิด — HFmrEF = 40-49%; LVEF 30% ต่ำกว่า"},{"label":"E","text":"HFpEF (LVEF ≥ 50%)","explanation":"✗ ผิด — HFpEF = preserved EF ≥50%; LVEF 30% ไม่ใช่ category นี้"}],"key_takeaway":"HF categories: HFrEF <40%, HFmrEF 40-49%, HFpEF ≥50%; ยา mortality benefit มีเฉพาะ HFrEF"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cd9b2cfa-177e-49cb-91ef-1ef8e1375d93', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 22, 'Sacubitril/Valsartan (ARNI) ยับยั้ง Receptor ใดเป็นหลัก', NULL, '[{"label":"A","text":"Block Angiotensin II receptor"},{"label":"B","text":"Block Neprilysin (NEP)"},{"label":"C","text":"Block Angiotensin converting enzyme"},{"label":"D","text":"Block Beta-adrenergic receptor"},{"label":"E","text":"Block Aldosterone receptor"}]'::jsonb, 'B', 'Sacubitril = Neprilysin inhibitor → เพิ่ม natriuretic peptides → vasodilation + natriuresis; Valsartan = ARB — PARADIGM-HF trial', '{"summary":"กลไกของ Sacubitril/Valsartan (ARNI)","reason":"Sacubitril = Neprilysin inhibitor → เพิ่ม natriuretic peptides; Valsartan = ARB","choices":[{"label":"A","text":"Block Angiotensin II receptor","explanation":"✗ ผิด — นี่คือกลไกของ Valsartan (ARB component) เพียงส่วนเดียว ไม่ใช่กลไกหลักที่ทำให้ ARNI แตกต่าง"},{"label":"B","text":"Block Neprilysin (NEP)","explanation":"✓ ถูก — Sacubitril → Sacubitrilat → inhibit Neprilysin → เพิ่ม BNP, ANP → vasodilation + natriuresis + anti-fibrosis; PARADIGM-HF พิสูจน์ลด mortality"},{"label":"C","text":"Block Angiotensin converting enzyme","explanation":"✗ ผิด — นี่คือกลไกของ ACE inhibitors; ห้ามใช้ ARNI ร่วมกับ ACEi"},{"label":"D","text":"Block Beta-adrenergic receptor","explanation":"✗ ผิด — นี่คือกลไกของ Beta-blockers"},{"label":"E","text":"Block Aldosterone receptor","explanation":"✗ ผิด — นี่คือกลไกของ Spironolactone/Eplerenone (MRA)"}],"key_takeaway":"ARNI = Neprilysin inhibitor (Sacubitril) + ARB (Valsartan); ห้ามใช้ร่วมกับ ACEi (angioedema risk)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a39eafdd-d0f3-4057-8b50-71e5c786801a', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 23, 'ผู้ป่วย HFrEF รับประทาน Enalapril อยู่ การเปลี่ยนเป็น Sacubitril/Valsartan ต้องทำอย่างไร', NULL, '[{"label":"A","text":"เปลี่ยนทันทีได้เลย"},{"label":"B","text":"หยุด ACE inhibitor อย่างน้อย 36 ชั่วโมงก่อนเริ่ม ARNI"},{"label":"C","text":"ให้ร่วมกันได้"},{"label":"D","text":"เปลี่ยนเป็น Losartan ก่อน"},{"label":"E","text":"ไม่ต้องหยุด"}]'::jsonb, 'B', 'ต้องหยุด ACE inhibitor ≥ 36 ชั่วโมงก่อนเริ่ม ARNI เพื่อป้องกัน angioedema (ทั้งคู่เพิ่ม bradykinin)', '{"summary":"การเปลี่ยนจาก ACE inhibitor เป็น ARNI","reason":"ต้อง washout ACEi ≥ 36 ชั่วโมงก่อนเริ่ม ARNI เพื่อป้องกัน angioedema","choices":[{"label":"A","text":"เปลี่ยนทันทีได้เลย","explanation":"✗ ผิด — ห้ามเปลี่ยนทันที; ต้อง washout เพื่อป้องกัน angioedema จาก bradykinin excess"},{"label":"B","text":"หยุด ACE inhibitor อย่างน้อย 36 ชั่วโมงก่อนเริ่ม ARNI","explanation":"✓ ถูก — ACEi ยับยั้ง bradykinin degradation; Sacubitril ก็ยับยั้ง Neprilysin (ซึ่ง degrade bradykinin) → ถ้าให้พร้อมกัน bradykinin สูงมาก → angioedema"},{"label":"C","text":"ให้ร่วมกันได้","explanation":"✗ ผิด — ห้ามใช้ ARNI + ACEi ร่วมกัน เป็น absolute contraindication"},{"label":"D","text":"เปลี่ยนเป็น Losartan ก่อน","explanation":"✗ ผิด — ไม่จำเป็นต้องเปลี่ยนผ่าน ARB ก่อน; แค่ washout 36 ชั่วโมงแล้วเริ่ม ARNI"},{"label":"E","text":"ไม่ต้องหยุด","explanation":"✗ ผิด — ต้อง washout เสมอ"}],"key_takeaway":"ACEi → ARNI: หยุด ACEi ≥36h → เริ่ม ARNI; ARB → ARNI: ไม่ต้อง washout"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4a1c3557-9505-461f-8a0b-b85adbaa2d08', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 24, 'Beta-blocker ใดได้รับการรับรองสำหรับใช้ใน HFrEF', NULL, '[{"label":"A","text":"Atenolol"},{"label":"B","text":"Bisoprolol"},{"label":"C","text":"Nebivolol"},{"label":"D","text":"Propranolol"},{"label":"E","text":"Nadolol"}]'::jsonb, 'B', 'Beta-blockers ที่ approved ใน HFrEF (mortality benefit): Carvedilol, Bisoprolol, Metoprolol succinate — ต้องเริ่มขนาดต่ำแล้วค่อย titrate', '{"summary":"Beta-blockers ที่ได้รับการรับรองใน HFrEF","reason":"มีเพียง 3 BB ที่ approved ใน HFrEF: Carvedilol, Bisoprolol, Metoprolol succinate","choices":[{"label":"A","text":"Atenolol","explanation":"✗ ผิด — Atenolol ไม่ได้ approved สำหรับ HFrEF; เป็น cardioselective BB แต่ไม่มี evidence ลด mortality ใน HF"},{"label":"B","text":"Bisoprolol","explanation":"✓ ถูก — Bisoprolol ได้ approved สำหรับ HFrEF (CIBIS-II trial); ลด all-cause mortality 34%"},{"label":"C","text":"Nebivolol","explanation":"✗ ผิด — Nebivolol ใช้ใน elderly HFrEF (SENIORS trial) แต่ไม่ใช่ standard first-line ที่ approved เช่น Bisoprolol"},{"label":"D","text":"Propranolol","explanation":"✗ ผิด — Propranolol non-selective BB ไม่ approved ใน HFrEF"},{"label":"E","text":"Nadolol","explanation":"✗ ผิด — Nadolol ไม่ approved ใน HFrEF"}],"key_takeaway":"HFrEF BB: Carvedilol (CAPRICORN/COPERNICUS), Bisoprolol (CIBIS-II), Metoprolol succinate (MERIT-HF); เริ่มขนาดต่ำ titrate ขึ้น"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ea55fffa-3e97-4344-90ca-208e4da7c312', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 25, 'Placebo เกิด 40/200 คน, Dapagliflozin เกิด 20/200 คน ค่า ARR และ NNT คือเท่าใด', NULL, '[{"label":"A","text":"ARR 5%, NNT 5"},{"label":"B","text":"ARR 10%, NNT 10"},{"label":"C","text":"ARR 13%, NNT 13"},{"label":"D","text":"ARR 20%, NNT 20"},{"label":"E","text":"ARR 25%, NNT 25"}]'::jsonb, 'B', 'ARR = 40/200 − 20/200 = 0.10 = 10%
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('071bd1cf-39ae-4ff7-8a9d-e9e359798db0', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 26, 'การผลิต Digoxin tablet 0.25 mg ควรใช้กระบวนการใด เนื่องจากขนาดยาน้อยและไวต่อความร้อน/ชื้น', NULL, '[{"label":"A","text":"Wet granulation"},{"label":"B","text":"Dry granulation (Slugging)"},{"label":"C","text":"Direct compression"},{"label":"D","text":"Hot melt extrusion"},{"label":"E","text":"Spray drying"}]'::jsonb, 'B', 'Digoxin ขนาดน้อย (0.25 mg) ไวต่อความร้อนชื้น — Dry granulation (slugging) หลีกเลี่ยงได้', '{"summary":"การเลือกกระบวนการผลิต Digoxin tablet ขนาดน้อยที่ไวต่อความร้อน/ชื้น","reason":"Dry granulation หลีกเลี่ยงทั้งความร้อน (oven drying) และน้ำ","choices":[{"label":"A","text":"Wet granulation","explanation":"✗ ผิด — Wet granulation ใช้น้ำ/solvent + ความร้อนตากแห้ง → ทำลาย Digoxin ที่ heat/moisture labile"},{"label":"B","text":"Dry granulation (Slugging)","explanation":"✓ ถูก — Dry granulation ไม่ใช้น้ำและไม่ใช้ความร้อน เหมาะกับ drug ที่ heat/moisture labile เช่น Digoxin ขนาดน้อย"},{"label":"C","text":"Direct compression","explanation":"✗ ผิด — Direct compression ใช้ได้แต่ Digoxin มีปัญหา flowability และ content uniformity เพราะ dose เล็กมาก; dry granulation ดีกว่า"},{"label":"D","text":"Hot melt extrusion","explanation":"✗ ผิด — Hot melt extrusion ใช้ความร้อนสูง → ทำลาย Digoxin"},{"label":"E","text":"Spray drying","explanation":"✗ ผิด — Spray drying ใช้ความร้อน + moisture labile"}],"key_takeaway":"Dry granulation (Roller compaction/Slugging): ไม่ใช้น้ำ ไม่ใช้ความร้อน → เหมาะกับ heat/moisture-sensitive drugs"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4e124658-6c14-441e-995d-a34f2b7872e4', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 27, 'ผู้ป่วย HFrEF มี fluid overload ควรเพิ่มยาใดก่อน', NULL, '[{"label":"A","text":"เพิ่ม Furosemide (loop diuretic)"},{"label":"B","text":"เพิ่ม Spironolactone"},{"label":"C","text":"เพิ่ม Thiazide"},{"label":"D","text":"เพิ่ม Digoxin"},{"label":"E","text":"เพิ่ม Amlodipine"}]'::jsonb, 'A', 'Loop diuretic (Furosemide) = first-line สำหรับ fluid overload ใน HF — ลด preload, บรรเทา dyspnea และ edema', '{"summary":"การจัดการ Fluid overload ใน HFrEF","reason":"Loop diuretic = first-line สำหรับ fluid overload ใน HF ลด preload บรรเทา congestion","choices":[{"label":"A","text":"เพิ่ม Furosemide (loop diuretic)","explanation":"✓ ถูก — Loop diuretic (Furosemide) = first-line สำหรับ acute fluid overload; ลด preload, บรรเทา dyspnea, ลด edema"},{"label":"B","text":"เพิ่ม Spironolactone","explanation":"✗ ผิด — Spironolactone (MRA) ใช้ลด mortality ใน HFrEF แต่ effect diuretic อ่อนกว่า loop diuretic; ไม่ใช่ first-line สำหรับ acute fluid overload"},{"label":"C","text":"เพิ่ม Thiazide","explanation":"✗ ผิด — Thiazide ออกฤทธิ์อ่อนกว่า loop diuretic; ใช้เป็น add-on ใน diuretic resistance ไม่ใช่ first-line"},{"label":"D","text":"เพิ่ม Digoxin","explanation":"✗ ผิด — Digoxin ใช้ลด heart rate ใน HF+AF และลด hospitalization แต่ไม่ช่วย fluid overload โดยตรง"},{"label":"E","text":"เพิ่ม Amlodipine","explanation":"✗ ผิด — CCB (Amlodipine) ไม่ใช่ยา HF; อาจ worsen HF ได้ในบางกรณี"}],"key_takeaway":"Fluid overload ใน HF → Furosemide IV/PO; ถ้าดื้อยา: เพิ่มขนาด + Thiazide combination (sequential nephron blockade)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e05fa4e2-8c4c-4bdb-b963-664d2e131245', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', 'Pharmacyguru', 1, 28, 'T-score เท่าใดที่วินิจฉัย Osteoporosis ตาม WHO criteria', NULL, '[{"label":"A","text":"T-score ≤ −1.0"},{"label":"B","text":"T-score ≤ −2.5"},{"label":"C","text":"T-score ≤ −3.0"},{"label":"D","text":"T-score ≤ −1.5"},{"label":"E","text":"T-score ≤ −2.0"}]'::jsonb, 'B', 'WHO: T-score ≥ −1.0 = Normal; −1.0 ถึง −2.5 = Osteopenia; ≤ −2.5 = Osteoporosis', '{"summary":"Criteria วินิจฉัย Osteoporosis ตาม WHO","reason":"WHO BMD criteria: T-score ≤ −2.5 = Osteoporosis","choices":[{"label":"A","text":"T-score ≤ −1.0","explanation":"✗ ผิด — T-score ≤ −1.0 = เริ่มออกจาก Normal ลงไปหา Osteopenia; ≤ −1.0 ถึง −2.5 = Osteopenia"},{"label":"B","text":"T-score ≤ −2.5","explanation":"✓ ถูก — WHO: T-score ≤ −2.5 = Osteoporosis; ถ้ามี fragility fracture ด้วย = Severe osteoporosis"},{"label":"C","text":"T-score ≤ −3.0","explanation":"✗ ผิด — ≤ −3.0 ยังคงเป็น Osteoporosis แต่ไม่ใช่ threshold diagnosis"},{"label":"D","text":"T-score ≤ −1.5","explanation":"✗ ผิด — ≤ −1.5 อยู่ใน Osteopenia range (−1.0 ถึง −2.5)"},{"label":"E","text":"T-score ≤ −2.0","explanation":"✗ ผิด — ≤ −2.0 ยังเป็น Osteopenia"}],"key_takeaway":"T-score: ≥−1.0=Normal; −1.0 to −2.5=Osteopenia; ≤−2.5=Osteoporosis; ≤−2.5+fragility fracture=Severe OP"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('bf223239-c6d5-4279-9502-d28b3e275607', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', 'Pharmacyguru', 1, 29, 'คำแนะนำที่ถูกต้องสำหรับการรับประทาน Alendronate คือข้อใด', NULL, '[{"label":"A","text":"รับประทานตอนเช้ากับน้ำเปล่า 200 mL ก่อนอาหาร 30 นาที นั่งตัวตรง ≥ 30 นาที"},{"label":"B","text":"รับประทานพร้อมอาหารเพื่อลด GI irritation"},{"label":"C","text":"ดื่มนมพร้อมยา"},{"label":"D","text":"รับประทานก่อนนอน"},{"label":"E","text":"รับประทานได้ตลอดเวลา"}]'::jsonb, 'A', 'Bisphosphonate: น้ำเปล่า 200 mL, ก่อนอาหาร 30 นาที, อย่านอนราบ ≥ 30 นาทีหลังกิน — ป้องกัน esophageal ulcer', '{"summary":"คำแนะนำการรับประทาน Alendronate (Bisphosphonate)","reason":"ต้องดื่มน้ำเปล่า 200 mL นั่งตัวตรง ≥30 นาที เพื่อป้องกัน esophageal ulcer","choices":[{"label":"A","text":"รับประทานตอนเช้ากับน้ำเปล่า 200 mL ก่อนอาหาร 30 นาที นั่งตัวตรง ≥ 30 นาที","explanation":"✓ ถูก — ปฏิบัติถูกต้อง: น้ำเปล่า (ไม่ใช่น้ำอื่น), ก่อนอาหาร 30 นาที, upright position ≥30 นาที — ป้องกัน esophageal ulcer"},{"label":"B","text":"รับประทานพร้อมอาหารเพื่อลด GI irritation","explanation":"✗ ผิด — อาหารลด bioavailability ของ bisphosphonate อย่างมาก ต้องกินตอนท้องว่าง"},{"label":"C","text":"ดื่มนมพร้อมยา","explanation":"✗ ผิด — Ca²⁺ ในนม chelate bisphosphonate → ลด absorption อย่างมาก"},{"label":"D","text":"รับประทานก่อนนอน","explanation":"✗ ผิด — นอนราบหลังกินยา → gastroesophageal reflux → esophageal ulcer/stricture"},{"label":"E","text":"รับประทานได้ตลอดเวลา","explanation":"✗ ผิด — ต้องกินตอนเช้าพร้อมน้ำเปล่า ก่อนอาหาร และนั่งตัวตรง"}],"key_takeaway":"Bisphosphonate counseling: น้ำเปล่า 200 mL + ก่อนอาหาร 30 นาที + upright ≥30 นาที + ไม่ Ca/Fe/Mg ร่วม"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3fd4e212-de83-49a2-985a-d86a77621e27', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', 'Pharmacyguru', 1, 30, 'ผู้ป่วยหญิงอายุ 70 ปี T-score −2.9 ที่ lumbar spine ควรได้รับยา first-line ใด', NULL, '[{"label":"A","text":"Calcium + Vitamin D เท่านั้น"},{"label":"B","text":"Calcitonin"},{"label":"C","text":"Alendronate"},{"label":"D","text":"Estrogen"},{"label":"E","text":"Teriparatide"}]'::jsonb, 'C', 'Alendronate (bisphosphonate) = first-line pharmacotherapy สำหรับ osteoporosis ลด vertebral, hip fracture risk ได้ดีที่สุด', '{"summary":"First-line pharmacotherapy สำหรับ Osteoporosis","reason":"Bisphosphonate (Alendronate) = first-line ลด fracture risk ได้ดีที่สุด และ cost-effective","choices":[{"label":"A","text":"Calcium + Vitamin D เท่านั้น","explanation":"✗ ผิด — Ca+VitD เป็น adjunct therapy ไม่เพียงพอสำหรับ T-score −2.9 ที่ต้องการ pharmacotherapy"},{"label":"B","text":"Calcitonin","explanation":"✗ ผิด — Calcitonin เป็น 2nd/3rd line; ไม่ได้แสดง fracture reduction ที่ดีเท่า bisphosphonate"},{"label":"C","text":"Alendronate","explanation":"✓ ถูก — Alendronate (bisphosphonate) = first-line pharmacotherapy สำหรับ postmenopausal osteoporosis; ลด vertebral fracture 50%, hip fracture 51%"},{"label":"D","text":"Estrogen","explanation":"✗ ผิด — Estrogen/HRT ลด fracture ได้แต่ เพิ่มความเสี่ยง cardiovascular disease, breast cancer → ไม่ใช่ first-line"},{"label":"E","text":"Teriparatide","explanation":"✗ ผิด — Teriparatide (PTH analogue) = anabolic therapy สำหรับ very high risk/severe OP หรือ bisphosphonate failure"}],"key_takeaway":"First-line OP: Bisphosphonate (Alendronate/Risedronate/Zoledronate); 2nd line: Denosumab; Severe/very high risk: Teriparatide/Romosozumab"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6f7040d2-44ba-4f5b-a7fb-b46855fe8290', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', 'Pharmacyguru', 1, 31, 'ผลข้างเคียงใดต่อไปนี้ "ไม่ใช่" ADR ของ Alendronate', NULL, '[{"label":"A","text":"Esophageal ulcer"},{"label":"B","text":"Bradykinesia"},{"label":"C","text":"Osteonecrosis of the jaw (ONJ)"},{"label":"D","text":"Atrial fibrillation"},{"label":"E","text":"Atypical femur fracture"}]'::jsonb, 'B', 'Bradykinesia = อาการ Parkinson''s disease ไม่ใช่ ADR ของ Bisphosphonate — ADR จริง: GI, ONJ, AFib, atypical fracture, hypocalcemia', '{"summary":"ADR ที่ไม่ใช่ของ Alendronate","reason":"Bradykinesia เป็นอาการ Parkinson''s disease ไม่ใช่ ADR ของ bisphosphonate","choices":[{"label":"A","text":"Esophageal ulcer","explanation":"✗ คำตอบนี้ถูก (เป็น ADR จริง) — Esophageal ulcer/stricture ถ้าไม่ปฏิบัติตามคำแนะนำ"},{"label":"B","text":"Bradykinesia","explanation":"✓ นี่คือข้อที่ไม่ใช่ ADR — Bradykinesia = อาการ Parkinson''s ไม่มีความสัมพันธ์กับ bisphosphonate"},{"label":"C","text":"Osteonecrosis of the jaw (ONJ)","explanation":"✗ คำตอบนี้ถูก (เป็น ADR จริง) — ONJ พบใน bisphosphonate ที่ใช้ขนาดสูง (IV zoledronate ใน cancer) หรือระยะยาว"},{"label":"D","text":"Atrial fibrillation","explanation":"✗ คำตอบนี้ถูก (เป็น ADR จริง) — Bisphosphonate เพิ่มความเสี่ยง AFib เล็กน้อย"},{"label":"E","text":"Atypical femur fracture","explanation":"✗ คำตอบนี้ถูก (เป็น ADR จริง) — Long-term bisphosphonate (>5 ปี) → atypical subtrochanteric fracture"}],"key_takeaway":"Bisphosphonate ADR: GI (esophageal ulcer), ONJ, Atypical fracture, AFib, Hypocalcemia, Flu-like (IV route)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('968e3c4c-198c-45e5-84f2-66c87f4c320e', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 32, 'ข้อใดต่อไปนี้เป็น excipient ที่เหมาะที่สุดสำหรับ Direct compression', NULL, '[{"label":"A","text":"Starch"},{"label":"B","text":"PVP (Povidone)"},{"label":"C","text":"HPMC"},{"label":"D","text":"Lactose monohydrate ทั่วไป"},{"label":"E","text":"Microcrystalline cellulose (MCC)"}]'::jsonb, 'E', 'MCC (Avicel) = ideal สำหรับ direct compression เพราะ compressibility + flowability ดี เป็นทั้ง diluent และ binder', '{"summary":"Excipient ที่เหมาะสมสำหรับ Direct Compression","reason":"MCC (Avicel) = ideal สำหรับ direct compression เพราะ compressibility + flowability ดีเยี่ยม","choices":[{"label":"A","text":"Starch","explanation":"✗ ผิด — Regular starch มี poor flowability ไม่เหมาะสำหรับ direct compression"},{"label":"B","text":"PVP (Povidone)","explanation":"✗ ผิด — PVP = binder ใน wet granulation ไม่ใช่ diluent/filler สำหรับ direct compression"},{"label":"C","text":"HPMC","explanation":"✗ ผิด — HPMC ใช้เป็น binder หรือ controlled-release matrix ไม่ใช่ primary diluent สำหรับ DC"},{"label":"D","text":"Lactose monohydrate ทั่วไป","explanation":"✗ ผิด — Regular lactose monohydrate มี poor flowability ต้องทำ granulation ก่อน; Spray-dried lactose ถึงจะใช้ DC ได้"},{"label":"E","text":"Microcrystalline cellulose (MCC)","explanation":"✓ ถูก — MCC (Avicel PH-101, PH-102) = gold standard สำหรับ direct compression; ทำหน้าที่ diluent + binder ในเม็ดเดียว compressibility ดี"}],"key_takeaway":"DC excipients: MCC (Avicel), Spray-dried lactose, DiCal phosphate, Mannitol DC grade — ต้องมี good flowability + compressibility"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3aee1ed3-0c52-4ae6-8309-e76186bb6266', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 33, 'Direct compression ต้องใช้ diluent ชนิดใด', NULL, '[{"label":"A","text":"Starch"},{"label":"B","text":"Colloidal silicon dioxide"},{"label":"C","text":"Spray dried lactose"},{"label":"D","text":"Talc"},{"label":"E","text":"Regular lactose monohydrate"}]'::jsonb, 'C', 'Spray dried lactose มี flowability + compressibility ดีเหมาะสำหรับ direct compression ต่างจาก regular lactose ที่ต้องทำ granulation', '{"summary":"Diluent ที่เหมาะสำหรับ Direct Compression","reason":"Spray dried lactose มี flowability + compressibility ดี เหมาะสำหรับ DC","choices":[{"label":"A","text":"Starch","explanation":"✗ ผิด — Regular starch มี poor flowability ต้องทำ granulation ก่อน"},{"label":"B","text":"Colloidal silicon dioxide","explanation":"✗ ผิด — Colloidal SiO₂ (Aerosil) = glidant ช่วย flowability แต่ไม่ใช่ diluent หลัก"},{"label":"C","text":"Spray dried lactose","explanation":"✓ ถูก — Spray dried lactose ผลิตโดย spray drying → รูปทรงกลม, compressibility + flowability ดี เหมาะสำหรับ DC; ต่างจาก regular lactose monohydrate"},{"label":"D","text":"Talc","explanation":"✗ ผิด — Talc = glidant/lubricant ไม่ใช่ diluent หลัก"},{"label":"E","text":"Regular lactose monohydrate","explanation":"✗ ผิด — Regular lactose = poor flowability; ต้องทำ granulation ก่อนจะใช้ได้"}],"key_takeaway":"DC diluent: Spray dried lactose > MCC > DiCal phosphate; Regular lactose ต้อง granulate ก่อน"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c78fb8c1-9e42-453d-a0c9-d27562d70b5f', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 34, 'Superdisintegrant ในสูตรตำรับ tablet คือสารใด', NULL, '[{"label":"A","text":"PVP"},{"label":"B","text":"Lactose"},{"label":"C","text":"Colloidal silicon dioxide"},{"label":"D","text":"Sodium starch glycolate"},{"label":"E","text":"Magnesium stearate"}]'::jsonb, 'D', 'Sodium starch glycolate (Explotab) = superdisintegrant พองตัวเร็ว — ชนิดอื่น: Croscarmellose sodium, Crospovidone (XL)', '{"summary":"Superdisintegrant ในสูตรตำรับ tablet","reason":"Sodium starch glycolate = superdisintegrant พองตัวเร็ว ช่วย tablet แตกตัวเร็ว","choices":[{"label":"A","text":"PVP","explanation":"✗ ผิด — PVP = binder ยึดอนุภาค ไม่ใช่ disintegrant"},{"label":"B","text":"Lactose","explanation":"✗ ผิด — Lactose = diluent/filler ไม่ใช่ disintegrant"},{"label":"C","text":"Colloidal silicon dioxide","explanation":"✗ ผิด — Colloidal SiO₂ = glidant ช่วย flowability ไม่ใช่ disintegrant"},{"label":"D","text":"Sodium starch glycolate","explanation":"✓ ถูก — Sodium starch glycolate (Explotab/Primojel) = superdisintegrant พองตัวเร็ว 300× ช่วย tablet disintegrate ใน < 5 นาที"},{"label":"E","text":"Magnesium stearate","explanation":"✗ ผิด — Mg stearate = lubricant ลดการเสียดสี ไม่ใช่ disintegrant"}],"key_takeaway":"Superdisintegrants: Sodium starch glycolate, Croscarmellose sodium (Ac-Di-Sol), Crospovidone (XL) — ใช้ 2-5% พองตัวเร็ว"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c38a8e54-3be7-4197-98c7-711e119f9704', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 35, 'ผู้ป่วย G6PD deficiency มาพบแพทย์ด้วยอาการ jaundice ยาใดน่าจะเป็นสาเหตุ', NULL, '[{"label":"A","text":"Amoxicillin"},{"label":"B","text":"Chlorpheniramine"},{"label":"C","text":"Paracetamol"},{"label":"D","text":"Ofloxacin"},{"label":"E","text":"HCTZ"}]'::jsonb, 'D', 'Ofloxacin (fluoroquinolone) ทำให้เกิด hemolysis ใน G6PD — ยาที่ต้องระวัง: Primaquine, Dapsone, Nitrofurantoin, Quinolones, Sulfonamides', '{"summary":"ยาที่ทำให้เกิด hemolysis ใน G6PD deficiency","reason":"Ofloxacin (fluoroquinolone) ทำให้ oxidative hemolysis ใน G6PD","choices":[{"label":"A","text":"Amoxicillin","explanation":"✗ ผิด — Amoxicillin (penicillin) ปลอดภัยใน G6PD; ไม่ก่อ oxidative stress"},{"label":"B","text":"Chlorpheniramine","explanation":"✗ ผิด — Antihistamine ปลอดภัยใน G6PD"},{"label":"C","text":"Paracetamol","explanation":"✗ ผิด — Paracetamol ปลอดภัยใน G6PD ในขนาดปกติ"},{"label":"D","text":"Ofloxacin","explanation":"✓ ถูก — Fluoroquinolones (Ofloxacin, Ciprofloxacin) ทำให้ oxidative hemolysis ใน G6PD — ต้องหลีกเลี่ยง"},{"label":"E","text":"HCTZ","explanation":"✗ ผิด — Thiazide diuretics ไม่ก่อ hemolysis ใน G6PD"}],"key_takeaway":"G6PD hemolysis drugs: Primaquine, Dapsone, Nitrofurantoin, Quinolones, Sulfonamides, Rasburicase — จำ PNQSR"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('859289be-7ad8-4d08-9fce-bee8c5c81b08', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 36, 'ผู้ป่วย G6PD ได้รับ Chlorpheniramine + Paracetamol น่าจะเกิด hemolytic anemia เมื่อใด', NULL, '[{"label":"A","text":"ทันทีหลังรับยา"},{"label":"B","text":"1 ชั่วโมงหลังรับยา"},{"label":"C","text":"1 วันหลังรับยา"},{"label":"D","text":"3-7 วันหลังเริ่มยา"},{"label":"E","text":"หลังหยุดยา 2 สัปดาห์"}]'::jsonb, 'D', 'Hemolytic anemia ใน G6PD มักเกิด 1-3 วันหลังเริ่มยา, peak ~7-10 วัน, recover หลังหยุดยา', '{"summary":"เวลาที่เกิด hemolytic anemia ใน G6PD","reason":"Hemolysis ใน G6PD มักเกิดช้า 3-7 วันหลังเริ่มยา ไม่ได้เกิดทันที","choices":[{"label":"A","text":"ทันทีหลังรับยา","explanation":"✗ ผิด — Hemolysis ใน G6PD ไม่ได้เกิดทันที ต้องใช้เวลาสะสม oxidative damage"},{"label":"B","text":"1 ชั่วโมงหลังรับยา","explanation":"✗ ผิด — เร็วเกินไป; acute hemolytic reaction แบบนี้เกิดใน anaphylaxis หรือ intravascular hemolysis จาก mismatch blood"},{"label":"C","text":"1 วันหลังรับยา","explanation":"✗ ผิด — ยังเร็วเกินไป"},{"label":"D","text":"3-7 วันหลังเริ่มยา","explanation":"✓ ถูก — Hemolytic anemia ใน G6PD typically เกิดหลัง exposure 1-3 วัน และ peak ~7-10 วัน หลังหยุดยา RBC ปกติใหม่ใน 3-6 สัปดาห์"},{"label":"E","text":"หลังหยุดยา 2 สัปดาห์","explanation":"✗ ผิด — Hemolysis เกิดระหว่างที่ยังใช้ยา ไม่ใช่หลังหยุดยา"}],"key_takeaway":"G6PD hemolysis: เริ่ม 1-3 วัน peak 7-10 วัน recovery 3-6 สัปดาห์หลังหยุด offending drug"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:05') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('00831c14-5918-4dbd-ae1f-3d2632333f72', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 37, 'วันที่ 7 หยุดยา Ofloxacin ควร recheck CBC เมื่อใด', NULL, '[{"label":"A","text":"20 ชั่วโมงหลังหยุดยา"},{"label":"B","text":"2 วันหลังหยุดยา"},{"label":"C","text":"1 วันหลังหยุด Ofloxacin"},{"label":"D","text":"5 วันหลังหยุดยา"},{"label":"E","text":"3 วันหลังหยุดยา"}]'::jsonb, 'C', 'หลังหยุดยาที่ก่อ hemolysis ควร recheck CBC เพื่อดูการฟื้นตัว (reticulocytosis จะเพิ่มขึ้นก่อน)', '{"summary":"การ monitor CBC หลังหยุดยาที่ก่อ hemolysis ใน G6PD","reason":"Recheck CBC 1 วันหลังหยุดยาเพื่อติดตามการฟื้นตัว (reticulocytosis)","choices":[{"label":"A","text":"20 ชั่วโมงหลังหยุดยา","explanation":"✗ ผิด — เร็วเกินไป; RBC ใช้เวลาฟื้นตัว reticulocyte count เพิ่งเริ่มเพิ่ม"},{"label":"B","text":"2 วันหลังหยุดยา","explanation":"✗ ผิด — ไม่ตรงกับ convention"},{"label":"C","text":"1 วันหลังหยุด Ofloxacin","explanation":"✓ ถูก — Recheck CBC หลังหยุดยา 1 วัน เพื่อดู reticulocytosis (สัญญาณฟื้นตัว) และ Hb trend"},{"label":"D","text":"5 วันหลังหยุดยา","explanation":"✗ ผิด — นานเกินไป; อาจพลาดการ monitor ช่วง critical"},{"label":"E","text":"3 วันหลังหยุดยา","explanation":"✗ ผิด — อาจ acceptable แต่ไม่ใช่คำตอบที่ดีที่สุด"}],"key_takeaway":"G6PD management: หยุด offending drug, CBC ติดตาม, rehydration, blood transfusion ถ้า severe anemia"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c423fb59-a74d-4bd3-959c-df6c2513cde0', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 38, 'กลไกของ hemolytic anemia ใน G6PD deficiency คืออะไร', NULL, '[{"label":"A","text":"Oxidative hemolysis"},{"label":"B","text":"Immune-mediated hemolysis"},{"label":"C","text":"Mechanical hemolysis"},{"label":"D","text":"Osmotic hemolysis"},{"label":"E","text":"Autoimmune hemolysis"}]'::jsonb, 'A', 'G6PD ขาด → NADPH ลด → ไม่สามารถ reduce glutathione → oxidative damage → Heinz bodies → hemolysis', '{"summary":"กลไกของ hemolytic anemia ใน G6PD deficiency","reason":"G6PD ขาด → NADPH ลด → Glutathione ลด → Oxidative damage → Heinz bodies → Hemolysis","choices":[{"label":"A","text":"Oxidative hemolysis","explanation":"✓ ถูก — G6PD ขาด → NADPH ลด (penthose phosphate pathway) → reduced glutathione ลด → oxidized Hb (Heinz bodies) → RBC หักเปราะ → hemolysis"},{"label":"B","text":"Immune-mediated hemolysis","explanation":"✗ ผิด — Immune hemolysis เกิดจาก autoantibodies (AIHA) หรือ drug-induced immune hemolysis คนละกลไก"},{"label":"C","text":"Mechanical hemolysis","explanation":"✗ ผิด — Mechanical hemolysis เกิดจาก prosthetic heart valve หรือ microangiopathy"},{"label":"D","text":"Osmotic hemolysis","explanation":"✗ ผิด — Osmotic hemolysis เกิดใน hereditary spherocytosis หรือ hypotonic solution"},{"label":"E","text":"Autoimmune hemolysis","explanation":"✗ ผิด — Autoimmune = AIHA มี positive Coombs test; G6PD hemolysis = Coombs negative"}],"key_takeaway":"G6PD pathway: Glucose→G6P→(G6PD)→6PG + NADPH; NADPH → reduced glutathione → protect RBC from oxidative stress"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f28c4ef8-347c-4948-8f47-7068e4866017', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 39, 'Hydrochloric acid ใน Ciprofloxacin Ophthalmic solution ทำหน้าที่อะไร', NULL, '[{"label":"A","text":"Antioxidant"},{"label":"B","text":"Non-aqueous solvent"},{"label":"C","text":"Adjust pH"},{"label":"D","text":"Preservative"},{"label":"E","text":"Viscosity enhancer"}]'::jsonb, 'C', 'HCl ใช้ปรับ pH ของ ophthalmic solution ให้อยู่ในช่วง 6.5-7.4 ที่เหมาะสมสำหรับตา', '{"summary":"หน้าที่ของ HCl ใน Ciprofloxacin Ophthalmic Solution","reason":"HCl ใช้ปรับ pH ให้เหมาะสำหรับตา (6.5-7.4)","choices":[{"label":"A","text":"Antioxidant","explanation":"✗ ผิด — Antioxidant เช่น Na2EDTA, sodium metabisulfite ไม่ใช่ HCl"},{"label":"B","text":"Non-aqueous solvent","explanation":"✗ ผิด — HCl เป็น aqueous acid ไม่ใช่ non-aqueous solvent"},{"label":"C","text":"Adjust pH","explanation":"✓ ถูก — HCl ใช้ปรับ pH ของ ophthalmic solution ให้อยู่ใน acceptable range (6.5-7.4) ซึ่งเหมาะกับ tear pH ปกติ และลด ocular irritation"},{"label":"D","text":"Preservative","explanation":"✗ ผิด — Preservative คือ BAK หรือ chlorhexidine ไม่ใช่ HCl"},{"label":"E","text":"Viscosity enhancer","explanation":"✗ ผิด — Viscosity enhancer เช่น HPMC, carbomer ไม่ใช่ HCl"}],"key_takeaway":"Ophthalmic pH: tear pH ≈ 7.4; acceptable 6.5-7.4; ใช้ HCl (acid) หรือ NaOH (base) adjust pH"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('086486ae-b4ca-4f56-83ca-6fa0e3746d2e', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 40, 'USP Ofloxacin Tablets กำหนด ASSAY ด้วยวิธีใด', NULL, '[{"label":"A","text":"LA-HPLC NMT 110%"},{"label":"B","text":"Liquid chromatography (HPLC)"},{"label":"C","text":"Dissolution ≥80% ใน 30 min (D)"},{"label":"D","text":"Uniformity ≤5%"},{"label":"E","text":"Impurity ≤0.5%"}]'::jsonb, 'B', 'USP Ofloxacin Tablets: ASSAY ด้วย Liquid chromatography (HPLC) — Dissolution ≥80% Q ใน 30 นาที', '{"summary":"USP Ofloxacin Tablets — Assay method","reason":"Ofloxacin tablets ใช้ Liquid chromatography (HPLC) สำหรับ assay","choices":[{"label":"A","text":"LA-HPLC NMT 110%","explanation":"✗ ผิด — ไม่ใช่ terminology ที่ถูกต้อง"},{"label":"B","text":"Liquid chromatography (HPLC)","explanation":"✓ ถูก — USP Ofloxacin Tablets: ASSAY ด้วย Liquid chromatography ได้ความจำเพาะและความแม่นยำสูง; Acceptance criteria 90.0-110.0%"},{"label":"C","text":"Dissolution ≥80% ใน 30 min (D)","explanation":"✗ ผิด — นี่คือ Dissolution test ไม่ใช่ ASSAY method"},{"label":"D","text":"Uniformity ≤5%","explanation":"✗ ผิด — Uniformity of dosage units ≤ 6.0% RSD ไม่ใช่ ASSAY"},{"label":"E","text":"Impurity ≤0.5%","explanation":"✗ ผิด — นี่คือ Related substances test ไม่ใช่ ASSAY"}],"key_takeaway":"USP Ofloxacin Tablets: ID=IR/HPLC, ASSAY=LC(HPLC), Dissolution≥80%Q/30min, Uniformity ≤6%RSD"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c91ef07c-59bb-4150-b102-8ea8e1d2d2cb', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 41, 'โครงสร้างสารประกอบที่แสดงในโจทย์เป็น Alkaloid ประเภทใด', NULL, '[{"label":"A","text":"Isoquinoline alkaloid"},{"label":"B","text":"Indole alkaloid"},{"label":"C","text":"Tropane alkaloid"},{"label":"D","text":"Purine alkaloid"},{"label":"E","text":"Steroidal alkaloid"}]'::jsonb, 'C', 'Tropane alkaloid มี bicyclic ring: N-methyl piperidine fused with cyclopentane — ตัวอย่าง: Atropine, Scopolamine, Cocaine', '{"summary":"การจำแนกประเภท Alkaloid จากโครงสร้าง","reason":"Tropane alkaloid มี N-methyl piperidine fused with cyclopentane — bicyclic ring","choices":[{"label":"A","text":"Isoquinoline alkaloid","explanation":"✗ ผิด — Isoquinoline มี benzene fused กับ pyridine — ตัวอย่าง: Morphine, Codeine, Papaverine"},{"label":"B","text":"Indole alkaloid","explanation":"✗ ผิด — Indole มี benzene fused กับ pyrrole — ตัวอย่าง: Ergotamine, Reserpine, Vincristine"},{"label":"C","text":"Tropane alkaloid","explanation":"✓ ถูก — Tropane = bicyclic: N-methyl piperidine + cyclopentane ring; ตัวอย่าง: Atropine, Scopolamine, Cocaine"},{"label":"D","text":"Purine alkaloid","explanation":"✗ ผิด — Purine alkaloid เช่น Caffeine, Theophylline มี purine ring (fused pyrimidine+imidazole)"},{"label":"E","text":"Steroidal alkaloid","explanation":"✗ ผิด — Steroidal alkaloid เช่น Solanine มี steroid skeleton"}],"key_takeaway":"Tropane = N-CH₃ bridged bicyclic; Atropine racemic mixture; L-Hyoscyamine = active form; Scopolamine = motion sickness"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2b8a0d64-4315-4364-97f3-1b94f75826c9', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', 'Pharmacyguru', 1, 42, 'T-score ≤ −2.5 ร่วมกับ previous fragility fracture จัดเป็น osteoporosis ระดับใด', NULL, '[{"label":"A","text":"Osteopenia"},{"label":"B","text":"Very High Risk Osteoporosis"},{"label":"C","text":"Normal"},{"label":"D","text":"Severe osteoporosis คำนวณ FRAX"},{"label":"E","text":"Mild osteoporosis"}]'::jsonb, 'B', 'T-score ≤ −2.5 + prior fragility fracture หรือ multiple risk factors = very high risk — AACE: พิจารณา anabolic therapy (Teriparatide)', '{"summary":"T-score ≤ −2.5 + previous fragility fracture = risk level อะไร","reason":"T-score ≤ −2.5 + fragility fracture = Very High Risk → พิจารณา anabolic therapy","choices":[{"label":"A","text":"Osteopenia","explanation":"✗ ผิด — Osteopenia = T-score −1.0 to −2.5; ข้อนี้ต่ำกว่า −2.5"},{"label":"B","text":"Very High Risk Osteoporosis","explanation":"✓ ถูก — AACE: Very High Risk = T-score ≤ −2.5 + fragility fracture หรือ multiple risk factors → พิจารณา anabolic therapy (Teriparatide/Romosozumab) ก่อน antiresorptive"},{"label":"C","text":"Normal","explanation":"✗ ผิด — Normal = T-score ≥ −1.0"},{"label":"D","text":"Severe osteoporosis คำนวณ FRAX","explanation":"✗ ผิด — FRAX ใช้ใน intermediate risk ที่ยังไม่ถึง treatment threshold; ข้อนี้มี established fracture แล้ว"},{"label":"E","text":"Mild osteoporosis","explanation":"✗ ผิด — Mild OP ไม่มีนิยามทาง WHO; classification คือ OP + severity"}],"key_takeaway":"AACE Risk stratification: High risk = T≤−2.5 หรือ fracture; Very high = T≤−2.5 + fracture → anabolic first"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('721ef690-45a3-4cd5-839b-1a63858e793b', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 43, 'การวิเคราะห์ Calcium carbonate โดย USP ใช้วิธี titration ใด', NULL, '[{"label":"A","text":"Precipitation titration"},{"label":"B","text":"Non-aqueous acid-base titration"},{"label":"C","text":"Complexometric titration"},{"label":"D","text":"Residual titration"},{"label":"E","text":"Redox titration"}]'::jsonb, 'C', 'Calcium carbonate → Complexometric titration (EDTA method) ใช้ Eriochrome black T หรือ Calcon เป็น indicator', '{"summary":"วิธี titration วิเคราะห์ Calcium carbonate ตาม USP","reason":"CaCO₃ ใช้ Complexometric titration (EDTA method) — จับ Ca²⁺ ด้วย EDTA","choices":[{"label":"A","text":"Precipitation titration","explanation":"✗ ผิด — Precipitation titration ใช้สำหรับ halides เช่น argentometric (Ag⁺) สำหรับ Cl⁻"},{"label":"B","text":"Non-aqueous acid-base titration","explanation":"✗ ผิด — Non-aqueous titration ใช้กับ weak acids/bases เช่น tablet assay ใน anhydrous acetic acid"},{"label":"C","text":"Complexometric titration","explanation":"✓ ถูก — CaCO₃ + HCl → Ca²⁺ → EDTA chelate Ca²⁺ → endpoint: Eriochrome Black T หรือ Calcon indicator เปลี่ยนสี"},{"label":"D","text":"Residual titration","explanation":"✗ ผิด — Residual titration ใช้ใน back titration บางชนิด"},{"label":"E","text":"Redox titration","explanation":"✗ ผิด — Redox titration ใช้กับ Fe²⁺/Fe³⁺, vitamin C ไม่ใช่ Ca²⁺"}],"key_takeaway":"EDTA titration: pH 12-13 (NaOH), indicator: Calcon (Ca only) หรือ EBT pH 10 (Ca+Mg); endpoint: red→blue"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:06') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('10474930-1011-4ec7-95b3-091e407b181b', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 44, 'Pharmacokinetic ของ Alendronate ข้อใดถูกต้อง', NULL, '[{"label":"A","text":"Bioavailability > 50%"},{"label":"B","text":"Tmax ~1 ชั่วโมง"},{"label":"C","text":"Half-life 2-3 ชั่วโมง"},{"label":"D","text":"ดูดซึมดีพร้อมอาหาร"},{"label":"E","text":"ขับทาง hepatic metabolism"}]'::jsonb, 'B', 'Alendronate: bioavailability < 1%, Tmax ~1 ชั่วโมง, ขับทางไตในรูปยาไม่เปลี่ยนแปลง, ดูดซึมลดลงถ้ากินพร้อมอาหาร', '{"summary":"Pharmacokinetics ของ Alendronate","reason":"Alendronate: bioavailability <1%, Tmax ~1 ชั่วโมง, ขับทางไตโดยไม่เปลี่ยนแปลง","choices":[{"label":"A","text":"Bioavailability > 50%","explanation":"✗ ผิด — Alendronate bioavailability ต่ำมาก < 1% ถ้ากินพร้อมอาหารจะลดอีก"},{"label":"B","text":"Tmax ~1 ชั่วโมง","explanation":"✓ ถูก — Tmax ~1 ชั่วโมง หลังกินตอนท้องว่าง; ยาดูดซึมเข้ากระแสเลือด แล้วจับกับ hydroxyapatite ใน bone"},{"label":"C","text":"Half-life 2-3 ชั่วโมง","explanation":"✗ ผิด — Plasma half-life ~2 ชั่วโมง แต่ elimination half-life จาก bone นานมาก (>10 ปี) เพราะ bisphosphonate ฝังใน bone matrix"},{"label":"D","text":"ดูดซึมดีพร้อมอาหาร","explanation":"✗ ผิด — อาหาร (โดยเฉพาะ Ca, Mg, Fe, coffee) ลด absorption อย่างมาก ต้องกินก่อนอาหาร 30 นาที"},{"label":"E","text":"ขับทาง hepatic metabolism","explanation":"✗ ผิด — Bisphosphonate ไม่ถูก metabolize ใน liver; ขับทางไตในรูปไม่เปลี่ยนแปลง"}],"key_takeaway":"Bisphosphonate PK: bioavail <1%, ไม่ metabolize, renal excretion, bone half-life >10 yr → drug holiday ได้"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4da159fd-df12-45e0-87dd-e13f0fd657f1', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 45, 'USP Calcium carbonate Acceptance criteria คือ', NULL, '[{"label":"A","text":"97.0-103.0%"},{"label":"B","text":"95.0-105.0%"},{"label":"C","text":"98.5-101.5%"},{"label":"D","text":"90.0-110.0%"},{"label":"E","text":"99.0-101.0%"}]'::jsonb, 'C', 'USP: Calcium carbonate ≥ 98.5% และ ≤ 101.5% calculated on dried basis', '{"summary":"USP Acceptance criteria ของ Calcium carbonate","reason":"USP CaCO₃: 98.5-101.5% on dried basis","choices":[{"label":"A","text":"97.0-103.0%","explanation":"✗ ผิด — ไม่ตรงกับ USP monograph"},{"label":"B","text":"95.0-105.0%","explanation":"✗ ผิด — Wide range นี้ใช้กับบางยาไม่ใช่ CaCO₃"},{"label":"C","text":"98.5-101.5%","explanation":"✓ ถูก — USP: CaCO₃ content ≥ 98.5% และ ≤ 101.5% calculated on dried basis — narrow range เพราะเป็น inorganic salt บริสุทธิ์"},{"label":"D","text":"90.0-110.0%","explanation":"✗ ผิด — Wide range ใช้กับ some pharmaceutical preparations ไม่ใช่ pure CaCO₃"},{"label":"E","text":"99.0-101.0%","explanation":"✗ ผิด — แคบเกินไป ไม่ตรงกับ USP"}],"key_takeaway":"Pure inorganic salts (CaCO₃, NaCl, KCl) มักมี narrow acceptance criteria ≥98.5%; pharmaceutical preparations มักใช้ 90-110%"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('bf9f0962-b4e2-48f7-b259-b029f96021c2', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 46, 'Complexometric (EDTA) titration ของ Calcium carbonate ขั้นตอนที่ถูกต้องคือ', NULL, '[{"label":"A","text":"ละลายใน NaOH"},{"label":"B","text":"Titrate ด้วย HCl"},{"label":"C","text":"ใช้ EDTA เป็น titrant กับ indicator Eriochrome black T"},{"label":"D","text":"ใช้ KMnO₄ เป็น titrant"},{"label":"E","text":"ละลายใน ethanol"}]'::jsonb, 'C', 'CaCO₃ ละลายใน HCl เจือจาง, adjust pH 12-13 ด้วย NaOH, titrate ด้วย 0.05M EDTA กับ Calcon indicator', '{"summary":"ขั้นตอน Complexometric titration ของ CaCO₃","reason":"ละลายใน HCl → adjust pH 12-13 ด้วย NaOH → titrate ด้วย EDTA + Calcon indicator","choices":[{"label":"A","text":"ละลายใน NaOH","explanation":"✗ ผิด — CaCO₃ ไม่ละลายใน NaOH; ต้องละลายใน HCl ก่อนเพื่อให้ Ca²⁺ free"},{"label":"B","text":"Titrate ด้วย HCl","explanation":"✗ ผิด — HCl ใช้ละลายตัวอย่าง ไม่ใช่ titrant; titrant คือ EDTA"},{"label":"C","text":"ใช้ EDTA เป็น titrant กับ indicator Eriochrome black T","explanation":"✓ ถูก — Standard procedure: ละลายใน HCl → add NaOH (pH 12-13) → titrate ด้วย 0.05M EDTA ใช้ Calcon (pH 12) หรือ EBT (pH 10, Ca+Mg)"},{"label":"D","text":"ใช้ KMnO₄ เป็น titrant","explanation":"✗ ผิด — KMnO₄ = oxidizing titrant ใน redox titration สำหรับ Fe²⁺, oxalate"},{"label":"E","text":"ละลายใน ethanol","explanation":"✗ ผิด — CaCO₃ ไม่ละลายใน ethanol"}],"key_takeaway":"EDTA complexometry: M²⁺ + EDTA → [M-EDTA] complex; pH สำคัญ: pH 10=Ca+Mg, pH 12=Ca only"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6477ec71-b5df-47d3-a4a9-8e040d9b4737', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 47, 'Alendronate effervescent tablet ใช้กระบวนการ granulation แบบใด', NULL, '[{"label":"A","text":"Wet granulation ด้วยน้ำ"},{"label":"B","text":"Wet granulation ด้วย alcohol"},{"label":"C","text":"Dry granulation"},{"label":"D","text":"Hot melt extrusion"},{"label":"E","text":"Spray drying"}]'::jsonb, 'C', 'Citric acid + Sodium bicarbonate ทำปฏิกิริยากับน้ำทันที → ต้องใช้ dry granulation (roller compaction/slugging)', '{"summary":"กระบวนการผลิต Alendronate effervescent tablet","reason":"Effervescent ประกอบด้วย citric acid + NaHCO₃ ซึ่งทำปฏิกิริยากับน้ำทันที → dry granulation","choices":[{"label":"A","text":"Wet granulation ด้วยน้ำ","explanation":"✗ ผิด — น้ำทำให้ citric acid + NaHCO₃ เกิด CO₂ ทำลาย effervescent blend ทันที"},{"label":"B","text":"Wet granulation ด้วย alcohol","explanation":"✗ ผิด — Alcohol ยังมี moisture บ้าง; ยิ่งกว่านั้น Alendronate ดูดซับ moisture ได้"},{"label":"C","text":"Dry granulation","explanation":"✓ ถูก — Dry granulation (roller compaction) = ไม่ใช้น้ำหรือ solvent; สภาพแห้ง ป้องกัน premature reaction ระหว่าง citric acid กับ NaHCO₃"},{"label":"D","text":"Hot melt extrusion","explanation":"✗ ผิด — ใช้ความร้อนสูง เปลี่ยน physical form อาจทำลายยา"},{"label":"E","text":"Spray drying","explanation":"✗ ผิด — ใช้ความร้อนและ moisture"}],"key_takeaway":"Effervescent tablet: ต้องผลิตใน low humidity (<25% RH) + dry granulation; citric acid + NaHCO₃ = CO₂ เมื่อสัมผัสน้ำ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3174ec73-9ecb-441c-a391-8d4dd273b691', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 48, 'SCr เพิ่มขึ้น 1 mg/dL ภายใน 48 ชั่วโมง Baseline SCr = 1.0 mg/dL ตาม KDIGO 2012 คือ AKI stage ใด', NULL, '[{"label":"A","text":"AKI Stage 0"},{"label":"B","text":"AKI Stage 1"},{"label":"C","text":"AKI Stage 2"},{"label":"D","text":"AKI Stage 3"},{"label":"E","text":"Chronic Kidney Disease"}]'::jsonb, 'B', 'KDIGO 2012 AKI Stage 1: SCr เพิ่ม ≥ 0.3 mg/dL ใน 48 ชั่วโมง หรือเพิ่ม ≥ 1.5× baseline ใน 7 วัน', '{"summary":"KDIGO 2012 AKI Staging","reason":"SCr เพิ่ม ≥0.3 mg/dL ใน 48 ชั่วโมง = AKI Stage 1","choices":[{"label":"A","text":"AKI Stage 0","explanation":"✗ ผิด — AKI Stage 0 ไม่มีใน KDIGO classification"},{"label":"B","text":"AKI Stage 1","explanation":"✓ ถูก — KDIGO 2012: Stage 1 = SCr เพิ่ม ≥0.3 mg/dL ใน 48h หรือ ≥1.5-1.9× baseline ใน 7 วัน หรือ UO <0.5 mL/kg/h ≥6h"},{"label":"C","text":"AKI Stage 2","explanation":"✗ ผิด — Stage 2 = SCr เพิ่ม 2.0-2.9× baseline; ข้อนี้ baseline=1.0 mg/dL เพิ่มเป็น 2.0 = 2× = borderline"},{"label":"D","text":"AKI Stage 3","explanation":"✗ ผิด — Stage 3 = SCr ≥3.0× baseline หรือ ≥4.0 mg/dL หรือ ต้อง RRT"},{"label":"E","text":"Chronic Kidney Disease","explanation":"✗ ผิด — CKD = นาน >3 เดือน; AKI = เฉียบพลัน ≤48 ชั่วโมง"}],"key_takeaway":"KDIGO AKI: S1=SCr≥0.3↑/48h or 1.5-1.9×; S2=2-2.9×; S3=≥3× or ≥4mg/dL or RRT; UO criteria สำคัญด้วย"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('193df30a-9206-48a6-b84c-765eaa621c48', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 49, 'ผู้ป่วยที่มี AKI Stage 1 และรับ Enalapril อยู่ ควรทำอย่างไร', NULL, '[{"label":"A","text":"หยุด Enalapril ชั่วคราว"},{"label":"B","text":"เพิ่มขนาด Enalapril"},{"label":"C","text":"เปลี่ยนเป็น Losartan"},{"label":"D","text":"ไม่ต้องทำอะไร"},{"label":"E","text":"เพิ่ม Furosemide"}]'::jsonb, 'A', 'ACE inhibitor ลด GFR → ไม่เหมาะใน AKI ระยะเฉียบพลัน → หยุดชั่วคราวและ recheck renal function หลัง AKI resolve', '{"summary":"การจัดการ Enalapril ใน AKI Stage 1","reason":"ACEi ลด efferent arteriole tone → ลด GFR → ไม่เหมาะใน AKI → หยุดชั่วคราว","choices":[{"label":"A","text":"หยุด Enalapril ชั่วคราว","explanation":"✓ ถูก — ACEi/ARB ลด GFR ใน AKI เพราะ dilate efferent arteriole → ลด filtration pressure; หยุดชั่วคราวจนกว่า AKI resolve แล้ว resume"},{"label":"B","text":"เพิ่มขนาด Enalapril","explanation":"✗ ผิด — เพิ่มขนาด ACEi ขณะ AKI จะทำให้ renal function แย่ลง"},{"label":"C","text":"เปลี่ยนเป็น Losartan","explanation":"✗ ผิด — ARB ก็มีกลไกเดียวกัน ลด GFR เหมือนกัน ไม่ควรใช้ใน AKI"},{"label":"D","text":"ไม่ต้องทำอะไร","explanation":"✗ ผิด — ต้องหยุดยาที่อาจ worsen AKI"},{"label":"E","text":"เพิ่ม Furosemide","explanation":"✗ ผิด — Loop diuretic อาจเพิ่ม hypovolemia และ worsen AKI ถ้า pre-renal component"}],"key_takeaway":"AKI: หยุด nephrotoxins (NSAIDs, ACEi, ARB, aminoglycosides, contrast); rehydrate; monitor urine output"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ba81c47a-8286-41d3-aef3-6bd63abdef41', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 50, 'โครงสร้างสารประกอบในโจทย์มีลักษณะ N+ ที่มี 4 substituents คือ compound ประเภทใด', NULL, '[{"label":"A","text":"Tertiary amine"},{"label":"B","text":"Primary amine"},{"label":"C","text":"Flavonoid"},{"label":"D","text":"Quaternary ammonium"},{"label":"E","text":"Tertiary alcohol"}]'::jsonb, 'D', 'Quaternary ammonium: N+ มี 4 substituents — ประจุบวกถาวรไม่ขึ้นกับ pH — ตัวอย่าง: Benzalkonium chloride, Cetrimide', '{"summary":"การจำแนก Quaternary ammonium compound จากโครงสร้าง","reason":"N+ มี 4 substituents = Quaternary ammonium — ประจุบวกถาวร","choices":[{"label":"A","text":"Tertiary amine","explanation":"✗ ผิด — Tertiary amine มี N ที่มี 3 substituents + lone pair; ประจุขึ้นกับ pH"},{"label":"B","text":"Primary amine","explanation":"✗ ผิด — Primary amine มี NH₂; มี 1 substituent บน N"},{"label":"C","text":"Flavonoid","explanation":"✗ ผิด — Flavonoid = polyphenol มี benzene ring ไม่เกี่ยวกับ N"},{"label":"D","text":"Quaternary ammonium","explanation":"✓ ถูก — Quaternary ammonium: N⁺ มี 4 substituents → ประจุบวกถาวร ไม่ขึ้นกับ pH → poor GI absorption, antimicrobial"},{"label":"E","text":"Tertiary alcohol","explanation":"✗ ผิด — Tertiary alcohol = C ที่มี OH กับ 3 carbon substituents ไม่เกี่ยวกับ N"}],"key_takeaway":"Quaternary N⁺: ไม่ cross BBB, ไม่ดูดซึม oral (ยกเว้น depot), ใช้เป็น antiseptic (BAK, cetrimide) หรือ neuromuscular blocker"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:07') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f5ac4a88-95cc-4e4f-9d7f-8e777fbe8b9b', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', 'Pharmacyguru', 1, 51, 'ผู้ป่วยได้รับยาผิดแต่ยาไม่ถึงผู้ป่วย ตาม NCC MERP จัดเป็น Category ใด', NULL, '[{"label":"A","text":"Category A"},{"label":"B","text":"Category B"},{"label":"C","text":"Category C"},{"label":"D","text":"Category D"},{"label":"E","text":"Category E"}]'::jsonb, 'B', 'NCC MERP Category B = ความผิดพลาดเกิดขึ้นแต่ไม่ถึงผู้ป่วย ไม่ก่อให้เกิดอันตราย', '{"summary":"NCC MERP Medication Error Categories","reason":"ยาไม่ถึงผู้ป่วย = Category B (error occurred, did not reach patient)","choices":[{"label":"A","text":"Category A","explanation":"✗ ผิด — Category A = Circumstances or events that have the capacity to cause error (ยังไม่เกิด error จริง)"},{"label":"B","text":"Category B","explanation":"✓ ถูก — Category B = Error occurred but did not reach the patient; ยาผิดเตรียมแล้วแต่จับได้ก่อนส่ง"},{"label":"C","text":"Category C","explanation":"✗ ผิด — Category C = Error reached patient but did not cause harm"},{"label":"D","text":"Category D","explanation":"✗ ผิด — Category D = Error reached patient, required monitoring to confirm no harm"},{"label":"E","text":"Category E","explanation":"✗ ผิด — Category E = Error caused temporary harm, required intervention"}],"key_takeaway":"NCC MERP: A=potential, B=no reach, C=reach no harm, D=monitor, E=temp harm, F=temp+hospitalize, G=perm harm, H=near death, I=death"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('03a515bf-a635-4630-b144-134220af58aa', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', 'Pharmacyguru', 1, 52, 'ยาใดเป็น first-line pharmacotherapy สำหรับการเลิกบุหรี่', NULL, '[{"label":"A","text":"Nicotine gum"},{"label":"B","text":"Varenicline"},{"label":"C","text":"Bupropion"},{"label":"D","text":"Cytisine"},{"label":"E","text":"Nortriptyline"}]'::jsonb, 'B', 'Varenicline = partial agonist ที่ nicotinic acetylcholine receptor ลด craving — meta-analysis: ดีกว่า bupropion และ NRT', '{"summary":"First-line pharmacotherapy สำหรับการเลิกบุหรี่","reason":"Varenicline = partial agonist at nAChR → ลด craving + withdrawal; meta-analysis ดีที่สุด","choices":[{"label":"A","text":"Nicotine gum","explanation":"✗ ผิด — NRT (nicotine replacement) มี efficacy แต่ต่ำกว่า Varenicline; เป็น 2nd option"},{"label":"B","text":"Varenicline","explanation":"✓ ถูก — Varenicline (Champix) = partial agonist nicotinic acetylcholine receptor α4β2 → ลด craving และ withdrawal; odds ratio เลิกได้ดีกว่า NRT 1.57× และ Bupropion"},{"label":"C","text":"Bupropion","explanation":"✗ ผิด — Bupropion = 2nd line (NDRI ยับยั้ง dopamine/norepinephrine reuptake); ดีกว่า NRT แต่ด้อยกว่า Varenicline"},{"label":"D","text":"Cytisine","explanation":"✗ ผิด — Cytisine = partial nAChR agonist; ใช้ใน Eastern Europe; ไม่ใช่ standard first-line ใน Thai guidelines"},{"label":"E","text":"Nortriptyline","explanation":"✗ ผิด — Nortriptyline = TCA; ใช้ off-label สำหรับเลิกบุหรี่เป็น 3rd line"}],"key_takeaway":"ลำดับ smoking cessation: Varenicline > Combination NRT > Bupropion SR; Varenicline ควร 12 สัปดาห์"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8b6a0f16-c1e2-4c7d-b704-b0ee73902c76', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', 'Pharmacyguru', 1, 53, 'ผู้ป่วยไม่ได้ตั้งใจเลิกบุหรี่ในอีก 6 เดือนข้างหน้า อยู่ใน Stage ใด ของ Transtheoretical Model', NULL, '[{"label":"A","text":"Precontemplation"},{"label":"B","text":"Contemplation"},{"label":"C","text":"Preparation"},{"label":"D","text":"Action"},{"label":"E","text":"Maintenance"}]'::jsonb, 'A', 'Precontemplation: ไม่มีความตั้งใจเปลี่ยนแปลงพฤติกรรมใน 6 เดือน; Contemplation: คิดจะเปลี่ยนใน 6 เดือน', '{"summary":"Transtheoretical Model (Stages of Change) — Precontemplation","reason":"ไม่ตั้งใจเปลี่ยนพฤติกรรมใน 6 เดือน = Precontemplation","choices":[{"label":"A","text":"Precontemplation","explanation":"✓ ถูก — Precontemplation: ไม่รู้ปัญหาหรือไม่อยากเปลี่ยน ไม่มีแผนเปลี่ยนใน 6 เดือน; ใช้ Motivational Interviewing"},{"label":"B","text":"Contemplation","explanation":"✗ ผิด — Contemplation: คิดจะเปลี่ยนใน 6 เดือน แต่ยังลังเล (ambivalent)"},{"label":"C","text":"Preparation","explanation":"✗ ผิด — Preparation: วางแผนจะเปลี่ยนใน 1 เดือน"},{"label":"D","text":"Action","explanation":"✗ ผิด — Action: กำลังเปลี่ยนพฤติกรรมอยู่ (ภายใน 6 เดือนที่ผ่านมา)"},{"label":"E","text":"Maintenance","explanation":"✗ ผิด — Maintenance: เปลี่ยนแปลงสำเร็จ >6 เดือนและรักษาไว้ได้"}],"key_takeaway":"5 stages: Pre-contemplation → Contemplation → Preparation → Action → Maintenance; Relapse สามารถเกิดได้ทุก stage"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('5f26be1a-7a5d-4961-b27e-ddc1bc4983f1', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 54, 'Nicotine transdermal patch ชั้น Backing layer ทำหน้าที่อะไร', NULL, '[{"label":"A","text":"Reservoir system ของยา"},{"label":"B","text":"Matrix system"},{"label":"C","text":"ชั้นสัมผัสผิวหนัง"},{"label":"D","text":"ชั้นปิดด้านนอก ป้องกันการสูญเสียยา"},{"label":"E","text":"Release liner"}]'::jsonb, 'D', 'Backing layer = ชั้นนอกสุด ทำจาก polymer/metal foil ป้องกันการสูญเสียยาด้านนอก กันน้ำ เป็นรูปทรงของ patch', '{"summary":"หน้าที่ของ Backing Layer ใน Nicotine Transdermal Patch","reason":"Backing layer = ชั้นนอกสุด ป้องกันการสูญเสียยา กันน้ำ เป็นรูปทรง","choices":[{"label":"A","text":"Reservoir system ของยา","explanation":"✗ ผิด — Reservoir (drug-containing layer) อยู่ชั้นในถัดจาก backing layer"},{"label":"B","text":"Matrix system","explanation":"✗ ผิด — Matrix = ชั้นที่ยาผสมอยู่ใน polymer; backing layer อยู่ด้านบนสุด"},{"label":"C","text":"ชั้นสัมผัสผิวหนัง","explanation":"✗ ผิด — ชั้นสัมผัสผิวหนัง = Adhesive layer หรือ membrane ด้านล่าง ไม่ใช่ backing"},{"label":"D","text":"ชั้นปิดด้านนอก ป้องกันการสูญเสียยา","explanation":"✓ ถูก — Backing layer = ชั้นนอกสุดทำจาก polyester/metal foil: กันน้ำ, ป้องกันการสูญเสียยา, เป็นรูปทรงและ support ของ patch"},{"label":"E","text":"Release liner","explanation":"✗ ผิด — Release liner = ชั้นล่างสุดที่ต้องลอกออกก่อนติด ทำจาก silicone-coated paper"}],"key_takeaway":"Patch layers (นอก→ใน): Backing → Drug reservoir/Matrix → Rate-controlling membrane → Adhesive → Release liner"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e77a46f8-1e77-48d9-bbf0-9e30b2571f46', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 55, 'Nicotine transdermal patch ชนิด Matrix system ข้อใดถูกต้อง', NULL, '[{"label":"A","text":"มี Reservoir ยาแยกต่างหาก"},{"label":"B","text":"ยาผสมอยู่ใน polymer matrix โดยตรง"},{"label":"C","text":"ควบคุมการปล่อยด้วย membrane แยก"},{"label":"D","text":"ปล่อยยาเร็วกว่า reservoir system"},{"label":"E","text":"ต้องการ rate-controlling membrane เสมอ"}]'::jsonb, 'B', 'Matrix system: ยาผสมอยู่ใน polymer matrix โดยตรง → diffusion ออกจาก matrix ต่างจาก Reservoir system ที่มียาใน reservoir + membrane', '{"summary":"Nicotine patch Matrix system","reason":"Matrix system: ยาผสมโดยตรงใน polymer matrix; diffusion ออกจาก matrix โดยตรง","choices":[{"label":"A","text":"มี Reservoir ยาแยกต่างหาก","explanation":"✗ ผิด — นี่คือลักษณะของ Reservoir system ไม่ใช่ Matrix"},{"label":"B","text":"ยาผสมอยู่ใน polymer matrix โดยตรง","explanation":"✓ ถูก — Matrix system: active drug ผสมใน adhesive/polymer matrix; release rate ขึ้นกับ drug loading และ polymer properties"},{"label":"C","text":"ควบคุมการปล่อยด้วย membrane แยก","explanation":"✗ ผิด — Reservoir system ใช้ rate-controlling membrane; Matrix ไม่มี separate membrane"},{"label":"D","text":"ปล่อยยาเร็วกว่า reservoir system","explanation":"✗ ผิด — Matrix release เป็น first-order/square root of time; Reservoir system ให้ zero-order release ที่สม่ำเสมอกว่า"},{"label":"E","text":"ต้องการ rate-controlling membrane เสมอ","explanation":"✗ ผิด — Matrix system ไม่ต้องการ rate-controlling membrane; Reservoir system ต้องการ"}],"key_takeaway":"Matrix patch: ง่ายกว่า cheaper กว่า; Reservoir patch: zero-order release ดีกว่า แต่ถ้า membrane รั่ว dose dumping"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('bd14c469-d646-4640-8ad1-8eee4c0e4080', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', 'Pharmacyguru', 1, 56, 'ผู้ป่วยหญิงอายุ 55 ปี H. pylori positive โดย Urea breath test วิธีรักษาที่เหมาะสมที่สุดคือ', NULL, '[{"label":"A","text":"Antacid + PPI"},{"label":"B","text":"PPI monotherapy"},{"label":"C","text":"PPI-based triple therapy (PPI + Amoxicillin + Clarithromycin)"},{"label":"D","text":"High dose antibiotic เดี่ยว"},{"label":"E","text":"H2RA + probiotic"}]'::jsonb, 'C', 'H. pylori standard: PPI-based triple therapy 14 วัน = PPI + Amoxicillin 1g BD + Clarithromycin 500mg BD', '{"summary":"การรักษา H. pylori ใน UBT positive","reason":"PPI-based triple therapy = standard H. pylori eradication regimen","choices":[{"label":"A","text":"Antacid + PPI","explanation":"✗ ผิด — Antacid ไม่มีฤทธิ์ต้าน H. pylori; PPI เดี่ยวก็ไม่เพียงพอ"},{"label":"B","text":"PPI monotherapy","explanation":"✗ ผิด — PPI เพียงอย่างเดียวลด acid แต่ไม่ eradicate H. pylori"},{"label":"C","text":"PPI-based triple therapy (PPI + Amoxicillin + Clarithromycin)","explanation":"✓ ถูก — Standard: PPI BD + Amoxicillin 1g BD + Clarithromycin 500mg BD × 14 วัน; eradication rate ~80-85%"},{"label":"D","text":"High dose antibiotic เดี่ยว","explanation":"✗ ผิด — Monotherapy ดื้อยาสูงมาก ไม่ใช่ standard"},{"label":"E","text":"H2RA + probiotic","explanation":"✗ ผิด — H2RA ไม่มีในปัจจุบัน standard ของ H. pylori; probiotic เป็น adjunct เท่านั้น"}],"key_takeaway":"H. pylori 1st line: PPI+Amox+Clarithro 14d; ถ้าดื้อ Clarithro: Bismuth quadruple (PBMT); ประเมินผล: UBT/stool Ag ≥4 สัปดาห์หลังรักษา"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d4207b0f-8b4a-4654-952e-58afcdc84d0a', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', 'Pharmacyguru', 1, 57, 'Clarithromycin resistance ≥ 15% ในพื้นที่ ควรเปลี่ยน H. pylori regimen อย่างไร', NULL, '[{"label":"A","text":"เปลี่ยน Clarithromycin เป็น Ampicillin"},{"label":"B","text":"เปลี่ยนเป็น Amoxicillin เดี่ยว"},{"label":"C","text":"ใช้ Bismuth quadruple therapy (PPI + Bismuth + Tetracycline + Metronidazole)"},{"label":"D","text":"เพิ่มขนาด Clarithromycin"},{"label":"E","text":"ไม่ต้องเปลี่ยน"}]'::jsonb, 'C', 'Clarithromycin resistance สูง → ใช้ Bismuth quadruple หรือ Levofloxacin-based therapy แทน', '{"summary":"การปรับ regimen เมื่อ Clarithromycin resistance ≥ 15%","reason":"Clarithromycin resistance สูง → Bismuth quadruple therapy (PBMT)","choices":[{"label":"A","text":"เปลี่ยน Clarithromycin เป็น Ampicillin","explanation":"✗ ผิด — Ampicillin ไม่ใช่ standard สำหรับ H. pylori"},{"label":"B","text":"เปลี่ยนเป็น Amoxicillin เดี่ยว","explanation":"✗ ผิด — Amoxicillin monotherapy ไม่เพียงพอ"},{"label":"C","text":"ใช้ Bismuth quadruple therapy (PPI + Bismuth + Tetracycline + Metronidazole)","explanation":"✓ ถูก — PBMT (Pylera) = 2nd line เมื่อ Clarithromycin resistance สูง; bismuth มี synergy กับ Metronidazole; eradication >90%"},{"label":"D","text":"เพิ่มขนาด Clarithromycin","explanation":"✗ ผิด — ยาดื้อแล้ว เพิ่มขนาดก็ไม่ช่วย"},{"label":"E","text":"ไม่ต้องเปลี่ยน","explanation":"✗ ผิด — ต้องเปลี่ยน regimen เมื่อ resistance rate สูง เพื่อเพิ่ม eradication rate"}],"key_takeaway":"H. pylori regimen choice: Clarithro resistance <15% → Triple; ≥15% → Bismuth quadruple; Penicillin allergy → Clarithro+Metronidazole+PPI"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('5893d159-939b-4524-aa7f-8a8e0e2a91de', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', 'Pharmacyguru', 1, 58, 'ผลข้างเคียงใดต่อไปนี้ "ไม่ใช่" ของ Phenobarbital', NULL, '[{"label":"A","text":"Sedation/drowsiness"},{"label":"B","text":"Hyperactivity ในเด็ก"},{"label":"C","text":"Peripheral edema"},{"label":"D","text":"Stevens-Johnson syndrome"},{"label":"E","text":"Osteomalacia (ใช้ระยะยาว)"}]'::jsonb, 'C', 'Peripheral edema ไม่ใช่ ADR ของ Phenobarbital — ADR จริง: sedation, cognitive impairment, hyperactivity (children), SJS, osteomalacia', '{"summary":"ADR ที่ไม่ใช่ของ Phenobarbital","reason":"Peripheral edema ไม่ใช่ ADR ของ Phenobarbital แต่เป็นของ Gabapentin/Pregabalin","choices":[{"label":"A","text":"Sedation/drowsiness","explanation":"✗ ถูก (เป็น ADR จริง) — Phenobarbital = barbiturate → CNS depression → sedation/drowsiness"},{"label":"B","text":"Hyperactivity ในเด็ก","explanation":"✗ ถูก (เป็น ADR จริง) — Paradoxical hyperactivity/irritability ใน pediatric patients พบได้บ่อย"},{"label":"C","text":"Peripheral edema","explanation":"✓ นี่คือข้อที่ไม่ใช่ ADR — Peripheral edema เป็น ADR ของ Gabapentin, Pregabalin, Valproate ไม่ใช่ Phenobarbital"},{"label":"D","text":"Stevens-Johnson syndrome","explanation":"✗ ถูก (เป็น ADR จริง) — Phenobarbital ก่อ SJS/TEN ได้ โดยเฉพาะ HLA-B*1502 (Asian)"},{"label":"E","text":"Osteomalacia (ใช้ระยะยาว)","explanation":"✗ ถูก (เป็น ADR จริง) — Barbiturate/Phenytoin ใช้นาน → induce CYP enzymes → เพิ่ม Vit D catabolism → osteomalacia"}],"key_takeaway":"Phenobarbital ADR: sedation, cognitive impairment, hyperactivity (kids), SJS, osteomalacia, CYP inducer (DDI)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:08') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c4b4b6bc-7738-4f4a-94c0-c8f2ee13d848', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', 'Pharmacyguru', 1, 59, 'AED ใดทำให้น้ำหนักเพิ่มมากที่สุด', NULL, '[{"label":"A","text":"Phenytoin"},{"label":"B","text":"Valproic acid"},{"label":"C","text":"Lamotrigine"},{"label":"D","text":"Topiramate"},{"label":"E","text":"Zonisamide"}]'::jsonb, 'B', 'Valproic acid ทำให้น้ำหนักเพิ่มมากที่สุดใน AED — mechanism: เพิ่ม appetite, ยับยั้ง beta-oxidation; Topiramate/Zonisamide ทำให้น้ำหนักลด', '{"summary":"AED ที่ทำให้น้ำหนักเพิ่มมากที่สุด","reason":"Valproic acid ทำให้น้ำหนักเพิ่มมากที่สุดในกลุ่ม AED","choices":[{"label":"A","text":"Phenytoin","explanation":"✗ ผิด — Phenytoin = weight neutral หรือ เพิ่มเล็กน้อย"},{"label":"B","text":"Valproic acid","explanation":"✓ ถูก — VPA ทำให้น้ำหนักเพิ่มมากที่สุด; กลไก: เพิ่ม appetite (กระตุ้น NPY), ยับยั้ง β-oxidation ของ fatty acid → fat accumulation"},{"label":"C","text":"Lamotrigine","explanation":"✗ ผิด — Lamotrigine = weight neutral"},{"label":"D","text":"Topiramate","explanation":"✗ ผิด — Topiramate = ทำให้น้ำหนักลด (ยับยั้ง carbonic anhydrase + appetite suppression) → ใช้เป็น add-on ใน obesity"},{"label":"E","text":"Zonisamide","explanation":"✗ ผิด — Zonisamide = ทำให้น้ำหนักลดได้"}],"key_takeaway":"AED weight effects: ↑ VPA, Pregabalin, Gabapentin; ↓ Topiramate, Zonisamide, Felbamate; Neutral: LTG, LEV, PHT"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1e93a989-5f7d-46c4-a7a4-c4c445c25b39', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', 'Pharmacyguru', 1, 60, 'Carbamazepine ทำให้เกิด ADR ใดต่อไปนี้บ่อยที่สุดเมื่อใช้ระยะยาว', NULL, '[{"label":"A","text":"Agranulocytosis"},{"label":"B","text":"Hepatomegaly"},{"label":"C","text":"Pancytopenia"},{"label":"D","text":"Peripheral edema"},{"label":"E","text":"Hyponatremia (SIADH)"}]'::jsonb, 'E', 'Carbamazepine → SIADH → Hyponatremia พบได้บ่อย โดยเฉพาะในผู้สูงอายุ ต้อง monitor serum Na+', '{"summary":"ADR ที่พบบ่อยจาก Carbamazepine ระยะยาว","reason":"Carbamazepine → SIADH → Hyponatremia พบบ่อย โดยเฉพาะผู้สูงอายุ","choices":[{"label":"A","text":"Agranulocytosis","explanation":"✗ ผิด — Agranulocytosis พบได้แต่หายาก (<1%); CBC ต้อง monitor แต่ไม่ใช่ที่พบบ่อยที่สุด"},{"label":"B","text":"Hepatomegaly","explanation":"✗ ผิด — Hepatotoxicity พบได้แต่ไม่ใช่ที่พบบ่อยที่สุด"},{"label":"C","text":"Pancytopenia","explanation":"✗ ผิด — Pancytopenia หายาก"},{"label":"D","text":"Peripheral edema","explanation":"✗ ผิด — Peripheral edema ไม่ใช่ ADR หลักของ Carbamazepine"},{"label":"E","text":"Hyponatremia (SIADH)","explanation":"✓ ถูก — Carbamazepine stimulates ADH → SIADH → hyponatremia; พบบ่อยในผู้สูงอายุ ต้อง monitor serum Na⁺"}],"key_takeaway":"CBZ ADR: SJS (HLA-B*1502), SIADH/hyponatremia, agranulocytosis (rare), CYP inducer; ระวัง Carbamazepine-10,11-epoxide (active metabolite)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('613257cc-1391-46f1-be3d-f4444c81b021', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 61, 'Diazepam rectal suppository ที่ใช้ PEG molecular weight ต่ำ เป็น base ประเภทใด', NULL, '[{"label":"A","text":"Oleaginous base"},{"label":"B","text":"Water soluble base"},{"label":"C","text":"Water removable base"},{"label":"D","text":"Emulsion base"},{"label":"E","text":"Absorption base"}]'::jsonb, 'B', 'PEG (Polyethylene glycol) = water-soluble base ละลายน้ำได้ ไม่ต้องการ body heat — ใช้กับยาที่ไม่ชอบน้ำ', '{"summary":"ประเภท suppository base: PEG molecular weight ต่ำ","reason":"PEG (low MW) = water-soluble base ละลายน้ำ ไม่ต้องพึ่ง body temperature","choices":[{"label":"A","text":"Oleaginous base","explanation":"✗ ผิด — Oleaginous base เช่น Cocoa butter, Hard fat ละลายด้วย body heat (35-37°C) ไม่ละลายน้ำ"},{"label":"B","text":"Water soluble base","explanation":"✓ ถูก — PEG (polyethylene glycol) = water-soluble base ละลายในสารคัดหลั่งในทวารหนัก ไม่ต้องพึ่ง body heat; ดีในคลิมาบร้อน"},{"label":"C","text":"Water removable base","explanation":"✗ ผิด — Water removable = emulsion base เช่น cream base ไม่ใช่ PEG"},{"label":"D","text":"Emulsion base","explanation":"✗ ผิด — Emulsion base เช่น o/w cream ไม่ใช่ PEG suppository"},{"label":"E","text":"Absorption base","explanation":"✗ ผิด — Absorption base เช่น Anhydrous lanolin ดูดซับน้ำได้แต่ยังเป็น oleaginous"}],"key_takeaway":"Suppository bases: Oleaginous (Cocoa butter, Witepsol) = melt at body temp; Water-soluble (PEG) = dissolve in secretions"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('92eb7d9a-2daf-4e97-821a-53dbee7a5fdf', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 62, 'Dissolution test สำหรับ Diazepam rectal suppository ใช้ Apparatus ใด', NULL, '[{"label":"A","text":"Apparatus 1 (Basket)"},{"label":"B","text":"Apparatus 2 (Paddle)"},{"label":"C","text":"Apparatus 3 (Reciprocating cylinder)"},{"label":"D","text":"Apparatus 4 (Flow-through cell)"},{"label":"E","text":"Apparatus 5"}]'::jsonb, 'C', 'Suppository dissolution: USP Apparatus 3 (Reciprocating cylinder) เหมาะสมที่สุด', '{"summary":"Dissolution Apparatus สำหรับ Suppository","reason":"USP Apparatus 3 (Reciprocating cylinder) เหมาะสำหรับ suppository dissolution","choices":[{"label":"A","text":"Apparatus 1 (Basket)","explanation":"✗ ผิด — Apparatus 1 = สำหรับ capsule, floating tablets ไม่เหมาะ suppository"},{"label":"B","text":"Apparatus 2 (Paddle)","explanation":"✗ ผิด — Apparatus 2 = standard สำหรับ tablets; ไม่ออกแบบมาสำหรับ suppository"},{"label":"C","text":"Apparatus 3 (Reciprocating cylinder)","explanation":"✓ ถูก — Apparatus 3 = reciprocating cylinder เหมาะสำหรับ suppository และ extended release beads; เลียนแบบ rectal environment"},{"label":"D","text":"Apparatus 4 (Flow-through cell)","explanation":"✗ ผิด — Apparatus 4 = flow-through cell ใช้สำหรับ poorly soluble drugs, implants"},{"label":"E","text":"Apparatus 5","explanation":"✗ ผิด — Apparatus 5 = Paddle over disk ใช้สำหรับ transdermal patch"}],"key_takeaway":"Dissolution apparatuses: 1=Basket, 2=Paddle, 3=Reciprocating, 4=Flow-through, 5=Paddle/disk(transdermal), 6=Rotating cylinder, 7=Reciprocating holder"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('30ccab4f-52d7-4897-9a3b-2bd3ec961978', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', 'Pharmacyguru', 1, 63, 'ยาใดต่อไปนี้ไม่ควรใช้รักษา H. pylori เนื่องจากมีอัตราดื้อยาสูงถ้าใช้เดี่ยว', NULL, '[{"label":"A","text":"Amoxicillin"},{"label":"B","text":"Tetracycline"},{"label":"C","text":"Metronidazole เดี่ยว"},{"label":"D","text":"Bismuth"},{"label":"E","text":"PPI"}]'::jsonb, 'C', 'Metronidazole เดี่ยว = ดื้อยาสูง ไม่ควรใช้ monotherapy แต่ใช้ร่วมใน bismuth quadruple therapy ได้ (bismuth มี synergy)', '{"summary":"ยาที่ไม่ควรใช้ monotherapy รักษา H. pylori","reason":"Metronidazole เดี่ยว = high resistance rate → ต้องใช้ใน combination เท่านั้น","choices":[{"label":"A","text":"Amoxicillin","explanation":"✗ ผิด — Amoxicillin มี low resistance rate ใน H. pylori; ใช้ใน triple/quadruple therapy"},{"label":"B","text":"Tetracycline","explanation":"✗ ผิด — Tetracycline ยังมี good activity ต่อ H. pylori ใช้ใน bismuth quadruple"},{"label":"C","text":"Metronidazole เดี่ยว","explanation":"✓ ถูก — Metronidazole resistance rate สูง (>40% ในหลายพื้นที่) ถ้าใช้เดี่ยว; แต่เมื่อใช้ร่วมกับ Bismuth มี synergistic effect ที่ overcome resistance"},{"label":"D","text":"Bismuth","explanation":"✗ ผิด — Bismuth มี intrinsic antibacterial activity ต่อ H. pylori และ ลด resistance"},{"label":"E","text":"PPI","explanation":"✗ ผิด — PPI ไม่มีฤทธิ์ antibacterial โดยตรง แต่เพิ่ม MIC ของ H. pylori ต่อยาอื่นโดย raise gastric pH"}],"key_takeaway":"H. pylori resistance: Clarithromycin 20-30% (ไทย), Metronidazole >40%; Amoxicillin/Tetracycline ยัง low resistance"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a2abec42-799b-4502-b6d5-992f20e59342', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', 'Pharmacyguru', 1, 64, 'ผู้ป่วยแพ้ Clarithromycin ควรใช้ H. pylori regimen ใด', NULL, '[{"label":"A","text":"PPI + Amoxicillin + Clarithromycin"},{"label":"B","text":"PPI + Amoxicillin + Metronidazole"},{"label":"C","text":"PPI เดี่ยว"},{"label":"D","text":"Amoxicillin + Doxycycline"},{"label":"E","text":"ไม่รักษา"}]'::jsonb, 'B', 'Clarithromycin allergy → ใช้ PPI + Amoxicillin + Metronidazole หรือ Bismuth quadruple therapy (PPI + Bismuth + Tetracycline + Metronidazole)', '{"summary":"H. pylori regimen เมื่อแพ้ Clarithromycin","reason":"Clarithromycin allergy → ใช้ PPI + Amoxicillin + Metronidazole (Non-clarithromycin triple)","choices":[{"label":"A","text":"PPI + Amoxicillin + Clarithromycin","explanation":"✗ ผิด — ไม่ใช้ยาที่แพ้; ห้ามใช้ Clarithromycin"},{"label":"B","text":"PPI + Amoxicillin + Metronidazole","explanation":"✓ ถูก — Non-clarithromycin triple therapy: PPI + Amoxicillin 1g BD + Metronidazole 500mg BD × 14 วัน; alternative ที่ดีเมื่อแพ้ Clarithromycin"},{"label":"C","text":"PPI เดี่ยว","explanation":"✗ ผิด — PPI เดี่ยวไม่ eradicate H. pylori"},{"label":"D","text":"Amoxicillin + Doxycycline","explanation":"✗ ผิด — Combination นี้ไม่ใช่ validated H. pylori regimen"},{"label":"E","text":"ไม่รักษา","explanation":"✗ ผิด — H. pylori positive ต้องรักษาเสมอเพื่อป้องกัน peptic ulcer, MALT lymphoma, gastric cancer"}],"key_takeaway":"H. pylori allergy alternatives: Clarithro allergy → PPI+Amox+Metro; Penicillin allergy → Bismuth quadruple"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('58834ed7-90bf-437d-a462-49e6f774eb35', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', 'Pharmacyguru', 1, 65, 'PPI ระยะยาวมีผลข้างเคียงใดที่ต้องระวัง', NULL, '[{"label":"A","text":"Agranulocytosis"},{"label":"B","text":"Hepatotoxicity"},{"label":"C","text":"เพิ่มความเสี่ยง Clostridium difficile infection"},{"label":"D","text":"Pneumonia"},{"label":"E","text":"Hypercalcemia"}]'::jsonb, 'C', 'Long-term PPI: เพิ่มความเสี่ยง C. difficile, Mg²⁺ deficiency, Vitamin B12 deficiency, Hip fracture, Community-acquired pneumonia', '{"summary":"ผลข้างเคียงของ PPI ระยะยาว","reason":"Long-term PPI เพิ่มความเสี่ยง C. difficile infection (CDI)","choices":[{"label":"A","text":"Agranulocytosis","explanation":"✗ ผิด — Agranulocytosis ไม่ใช่ ADR ของ PPI"},{"label":"B","text":"Hepatotoxicity","explanation":"✗ ผิด — PPI hepatotoxicity พบน้อยมาก"},{"label":"C","text":"เพิ่มความเสี่ยง Clostridium difficile infection","explanation":"✓ ถูก — Long-term PPI: ↑ gastric pH → ↑ C. difficile spore survival → ↑ CDI risk; ยังเพิ่ม Mg²⁺ def, Vit B12 def, hip fracture"},{"label":"D","text":"Pneumonia","explanation":"✗ ผิด — มีหลักฐาน PPI อาจเพิ่ม community-acquired pneumonia เล็กน้อย แต่ไม่ใช่ ADR หลักที่ต้องระวัง"},{"label":"E","text":"Hypercalcemia","explanation":"✗ ผิด — Hypercalcemia ไม่ใช่ ADR ของ PPI"}],"key_takeaway":"Long-term PPI ADR: CDI, Hypomagnesemia, Vit B12 deficiency, Hip fracture (ลด Ca absorption), CKD (controversial)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('20f2b7b8-f06b-4193-90a4-a9dbc8798d67', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 66, 'Cotrimoxazole (TMP-SMX) ใช้รักษาโรคใดใน HIV เป็นหลัก', NULL, '[{"label":"A","text":"MAC infection"},{"label":"B","text":"Pneumocystis jirovecii pneumonia (PCP) prophylaxis/treatment"},{"label":"C","text":"CMV retinitis"},{"label":"D","text":"Cryptococcal meningitis"},{"label":"E","text":"Aspergillosis"}]'::jsonb, 'B', 'Cotrimoxazole = drug of choice สำหรับ PCP (CD4 < 200 → prophylaxis) — ยังป้องกัน Toxoplasma ด้วย', '{"summary":"Cotrimoxazole ใน HIV","reason":"Cotrimoxazole = drug of choice สำหรับ PCP prophylaxis และ treatment","choices":[{"label":"A","text":"MAC infection","explanation":"✗ ผิด — MAC prophylaxis/treatment ใช้ Azithromycin/Clarithromycin + Ethambutol"},{"label":"B","text":"Pneumocystis jirovecii pneumonia (PCP) prophylaxis/treatment","explanation":"✓ ถูก — TMP-SMX = drug of choice: PCP treatment (high dose) และ PCP prophylaxis (CD4<200/mm³); ยังป้องกัน Toxoplasma (CD4<100)"},{"label":"C","text":"CMV retinitis","explanation":"✗ ผิด — CMV retinitis ใช้ Ganciclovir/Valganciclovir หรือ Foscarnet"},{"label":"D","text":"Cryptococcal meningitis","explanation":"✗ ผิด — Cryptococcus ใช้ Amphotericin B + Flucytosine (induction) → Fluconazole (maintenance)"},{"label":"E","text":"Aspergillosis","explanation":"✗ ผิด — Aspergillosis ใช้ Voriconazole หรือ Amphotericin B"}],"key_takeaway":"HIV OI prophylaxis: CD4<200→TMP-SMX (PCP); CD4<100→ + Toxo prophylaxis; CD4<50→ + MAC (Azithromycin weekly)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:09') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('eead0f08-4993-481d-999e-61719fdb363b', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 67, 'กลไกการออกฤทธิ์ของ Doxorubicin (Anthracycline) คือ', NULL, '[{"label":"A","text":"ยับยั้ง purine base guanine"},{"label":"B","text":"ยับยั้ง tyrosine kinase"},{"label":"C","text":"ยับยั้ง pyrimidine analogue"},{"label":"D","text":"ยับยั้ง Topoisomerase II"},{"label":"E","text":"ยับยั้ง dihydrofolate reductase"}]'::jsonb, 'D', 'Doxorubicin: intercalates DNA + inhibits Topoisomerase II → DNA double strand breaks; free radicals → cardiotoxicity', '{"summary":"กลไกการออกฤทธิ์ของ Doxorubicin (Anthracycline)","reason":"Doxorubicin intercalates DNA + inhibits Topoisomerase II → DNA strand breaks","choices":[{"label":"A","text":"ยับยั้ง purine base guanine","explanation":"✗ ผิด — MMF/Mycophenolic acid ยับยั้ง IMPDH → ลด guanosine synthesis"},{"label":"B","text":"ยับยั้ง tyrosine kinase","explanation":"✗ ผิด — Tyrosine kinase inhibitors = Imatinib, Erlotinib, Gefitinib"},{"label":"C","text":"ยับยั้ง pyrimidine analogue","explanation":"✗ ผิด — Pyrimidine analogues = 5-FU, Capecitabine, Cytarabine"},{"label":"D","text":"ยับยั้ง Topoisomerase II","explanation":"✓ ถูก — Doxorubicin: intercalate DNA (ขัดขวาง replication/transcription) + inhibit Topoisomerase II → DNA DSBs → apoptosis; free radicals → cardiotoxicity"},{"label":"E","text":"ยับยั้ง dihydrofolate reductase","explanation":"✗ ผิด — DHFR inhibitor = Methotrexate (antifolate)"}],"key_takeaway":"Anthracycline: Doxorubicin, Daunorubicin, Epirubicin; Cardiotoxicity cumulative dose >450-550 mg/m² → dilated cardiomyopathy"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c07a8bd7-3b12-4c04-81ae-76a2d117a723', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 68, 'AC regimen: Doxorubicin 60 mg/m² สำหรับผู้ป่วย BSA 1.4 m² ขนาด Doxorubicin ที่ได้รับ', NULL, '[{"label":"A","text":"85 mg"},{"label":"B","text":"120 mg"},{"label":"C","text":"860 mg"},{"label":"D","text":"1,200 mg"},{"label":"E","text":"3,900 mg"}]'::jsonb, 'A', 'Doxorubicin = 60 mg/m² × 1.4 m² = 84 mg ≈ 85 mg (rounded); Cyclophosphamide = 600 × 1.4 = 840 mg', '{"summary":"คำนวณขนาด Doxorubicin ใน AC regimen","reason":"Doxorubicin 60 mg/m² × BSA 1.4 m² = 84 mg ≈ 85 mg","choices":[{"label":"A","text":"85 mg","explanation":"✓ ถูก — 60 mg/m² × 1.4 m² = 84 mg ≈ 85 mg (rounded); สอดคล้องกับ 5 mg increment rounding"},{"label":"B","text":"120 mg","explanation":"✗ ผิด — 120 mg = 60 × 2.0 m²; BSA ผิด"},{"label":"C","text":"860 mg","explanation":"✗ ผิด — หน่วยผิด; คำนวณผิด"},{"label":"D","text":"1,200 mg","explanation":"✗ ผิด — นี่คือขนาด Cyclophosphamide (600 mg/m² × 2.0 = 1200 mg) ไม่ใช่ Doxorubicin"},{"label":"E","text":"3,900 mg","explanation":"✗ ผิด — ผิดพลาดอย่างมาก"}],"key_takeaway":"BSA-based dosing: Dose = mg/m² × BSA; BSA คำนวณด้วย Mosteller: BSA = √(H×W/3600); AC = Doxorubicin 60 + Cyclophosphamide 600 mg/m²"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('aaa12bda-8850-4ac1-875f-24aa2f348871', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 69, 'Antiemetic สำหรับ Highly Emetogenic Chemotherapy (HEC) ที่ถูกต้องคือ', NULL, '[{"label":"A","text":"Progestin-only pill"},{"label":"B","text":"Ondansetron + Aprepitant + Dexamethasone"},{"label":"C","text":"Ondansetron + Dexamethasone เท่านั้น"},{"label":"D","text":"Granisetron เดี่ยว"},{"label":"E","text":"Dolasetron เดี่ยว"}]'::jsonb, 'B', 'HEC triple antiemetic: 5HT3 antagonist + NK1 antagonist (Aprepitant) + Dexamethasone — NCCN guidelines', '{"summary":"Antiemetic สำหรับ Highly Emetogenic Chemotherapy (HEC)","reason":"HEC: 5HT3 antagonist + NK1 antagonist (Aprepitant) + Dexamethasone = triple regimen","choices":[{"label":"A","text":"Progestin-only pill","explanation":"✗ ผิด — Progestin ไม่ใช้สำหรับ chemotherapy-induced nausea"},{"label":"B","text":"Ondansetron + Aprepitant + Dexamethasone","explanation":"✓ ถูก — NCCN: HEC (เช่น Cisplatin, AC regimen) → Triple: 5HT3-RA (Ondansetron) + NK1-RA (Aprepitant/Fosaprepitant) + Dexamethasone; ± Olanzapine"},{"label":"C","text":"Ondansetron + Dexamethasone เท่านั้น","explanation":"✗ ผิด — Double therapy เพียงพอสำหรับ MEC (Moderately Emetogenic) ไม่ใช่ HEC"},{"label":"D","text":"Granisetron เดี่ยว","explanation":"✗ ผิด — 5HT3-RA เดี่ยวไม่เพียงพอสำหรับ HEC"},{"label":"E","text":"Dolasetron เดี่ยว","explanation":"✗ ผิด — Dolasetron เดี่ยวไม่เพียงพอสำหรับ HEC"}],"key_takeaway":"HEC antiemetic: 5HT3-RA + NK1-RA + Dex ± Olanzapine; MEC: 5HT3-RA + Dex; Dexamethasone ใช้ D1-D3/D4"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('19e49d92-dc0e-45ac-93ec-df84ecab2c14', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', 'Pharmacyguru', 1, 70, 'ผู้ป่วย COPD ที่ใช้ Tiotropium Handihaler 18 mcg/วัน อยู่ใน GOLD stage ใด', NULL, '[{"label":"A","text":"GOLD 1 (Mild)"},{"label":"B","text":"GOLD 2 (Moderate)"},{"label":"C","text":"GOLD 3 (Severe)"},{"label":"D","text":"GOLD 4 (Very severe)"},{"label":"E","text":"ไม่สามารถระบุได้"}]'::jsonb, 'B', 'GOLD 2 (Moderate): FEV1 50-79% — LAMA (Tiotropium) เป็น first-line ใน GOLD B/E ที่มีอาการ', '{"summary":"COPD GOLD stage ที่ใช้ Tiotropium Handihaler","reason":"Tiotropium LAMA = first-line maintenance ใน GOLD 2 (Moderate) ขึ้นไป","choices":[{"label":"A","text":"GOLD 1 (Mild)","explanation":"✗ ผิด — GOLD 1 FEV1≥80%; SABA PRN เพียงพอ; LAMA ไม่จำเป็นใน GOLD 1 ที่ไม่มีอาการ"},{"label":"B","text":"GOLD 2 (Moderate)","explanation":"✓ ถูก — GOLD 2: FEV1 50-79%; LAMA (Tiotropium) เป็น preferred maintenance ใน GOLD 2 ที่มีอาการ (Group B/E)"},{"label":"C","text":"GOLD 3 (Severe)","explanation":"✗ ผิด — ใช้ได้ใน GOLD 3 ด้วย แต่โจทย์ถามว่า stage ใดที่ match กับ Tiotropium เดี่ยว; GOLD 3 มักต้อง LAMA+LABA หรือ triple"},{"label":"D","text":"GOLD 4 (Very severe)","explanation":"✗ ผิด — GOLD 4 FEV1<30%; มักต้อง triple therapy"},{"label":"E","text":"ไม่สามารถระบุได้","explanation":"✗ ผิด — Tiotropium เดี่ยวเหมาะสมที่สุดกับ GOLD 2 Group B/E ที่มีอาการ"}],"key_takeaway":"GOLD 2024: GOLD A=SABA PRN, GOLD B=LAMA or LABA, GOLD E=LAMA+LABA; ICS เพิ่มเมื่อ exacerbation ≥2 หรือ eos≥300"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9b81388a-9dbb-46e2-8c0f-7983a5f544ee', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', 'Pharmacyguru', 1, 71, 'ข้อใด "ไม่ถูกต้อง" เกี่ยวกับ LAMA (Tiotropium) ใน COPD', NULL, '[{"label":"A","text":"บรรเทาอาการได้น้อยกว่า SABA ใน acute bronchospasm"},{"label":"B","text":"ลด exacerbation ได้ดีกว่า LABA ในบางกรณี"},{"label":"C","text":"ออกฤทธิ์ยาวนาน 24 ชั่วโมง"},{"label":"D","text":"เป็น M3 muscarinic antagonist"},{"label":"E","text":"ใช้เป็น maintenance therapy"}]'::jsonb, 'A', 'LAMA เป็น maintenance therapy ไม่ใช่ rescue drug — ใน acute bronchospasm ใช้ SABA (ออกฤทธิ์เร็วกว่า)', '{"summary":"ข้อที่ไม่ถูกต้องเกี่ยวกับ LAMA (Tiotropium) ใน COPD","reason":"LAMA เป็น maintenance therapy ไม่ใช่ rescue drug; ใน acute bronchospasm ใช้ SABA","choices":[{"label":"A","text":"บรรเทาอาการได้น้อยกว่า SABA ใน acute bronchospasm","explanation":"✓ นี่คือข้อที่ผิด — ข้อความนี้ถูกต้อง: LAMA onset ช้ากว่า SABA; ใน acute attack ต้องใช้ SABA (Salbutamol) ไม่ใช่ LAMA; คำถามถามข้อ ''ไม่ถูกต้อง'' = ข้อที่เป็น false statement"},{"label":"B","text":"ลด exacerbation ได้ดีกว่า LABA ในบางกรณี","explanation":"✗ คำตอบนี้ถูกต้อง — UPLIFT trial: Tiotropium ลด exacerbation ได้ดีกว่า LABA ในบางกลุ่ม"},{"label":"C","text":"ออกฤทธิ์ยาวนาน 24 ชั่วโมง","explanation":"✗ ถูก — Tiotropium = once daily (24h duration); Ipratropium = short-acting (4-6h)"},{"label":"D","text":"เป็น M3 muscarinic antagonist","explanation":"✗ ถูก — Tiotropium = selective M3 antagonist → bronchodilation; Ipratropium = non-selective"},{"label":"E","text":"ใช้เป็น maintenance therapy","explanation":"✗ ถูก — LAMA = maintenance ไม่ใช่ rescue"}],"key_takeaway":"LAMA: onset 30-60 min → ไม่ใช่ rescue; SABA: onset 5 min → rescue; Tiotropium kinetically selective M3"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c5f7e081-8e05-4725-8ded-25e3138287f9', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', 'Pharmacyguru', 1, 72, 'ผู้ป่วย COPD GOLD กลุ่ม B ยาใดเป็น first-line maintenance therapy', NULL, '[{"label":"A","text":"LAMA หรือ LABA เดี่ยว"},{"label":"B","text":"ICS/LABA combination"},{"label":"C","text":"Triple therapy"},{"label":"D","text":"SABA + SAMA"},{"label":"E","text":"Theophylline"}]'::jsonb, 'A', 'GOLD 2024 กลุ่ม B → เริ่มด้วย LAMA หรือ LABA เดี่ยว; ถ้า GOLD E (≥2 exacerbations) → เพิ่ม ICS', '{"summary":"First-line maintenance therapy ใน COPD GOLD Group B","reason":"GOLD 2024 Group B → เริ่มด้วย LAMA หรือ LABA เดี่ยว","choices":[{"label":"A","text":"LAMA หรือ LABA เดี่ยว","explanation":"✓ ถูก — GOLD 2024: Group B (few symptoms, few exacerbations) → LAMA or LABA as initial maintenance; preferably LAMA"},{"label":"B","text":"ICS/LABA combination","explanation":"✗ ผิด — ICS/LABA ใช้ใน Group E (≥2 exacerbations หรือ ≥1 hospitalization หรือ eos≥300); ไม่ใช่ first-line ใน Group B"},{"label":"C","text":"Triple therapy","explanation":"✗ ผิด — Triple (LAMA+LABA+ICS) ใช้ใน severe/uncontrolled Group E"},{"label":"D","text":"SABA + SAMA","explanation":"✗ ผิด — Short-acting combination ใช้ PRN ไม่ใช่ scheduled maintenance"},{"label":"E","text":"Theophylline","explanation":"✗ ผิด — Theophylline narrow TI, drug interactions มาก; ไม่ใช่ first-line"}],"key_takeaway":"GOLD 2024 Groups: A=PRN SABA, B=LAMA or LABA, E=LAMA+LABA ± ICS (eos≥300); ICS ไม่ใช้ใน COPD ที่ไม่มี asthma overlap"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('60b8dace-677d-4a69-bd04-b49f505c1754', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', 'Pharmacyguru', 1, 73, 'ผลข้างเคียงใด "ไม่ควร" เกิดจาก anticholinergic mechanism ของ Tiotropium', NULL, '[{"label":"A","text":"Dry mouth"},{"label":"B","text":"Urinary retention"},{"label":"C","text":"Constipation"},{"label":"D","text":"Diabetes mellitus"},{"label":"E","text":"Blurred vision"}]'::jsonb, 'D', 'Anticholinergic ADR: dry mouth, urinary retention, constipation, blurred vision, tachycardia — Diabetes ไม่ใช่', '{"summary":"ADR ที่ไม่ใช่ของ Anticholinergic (Tiotropium)","reason":"Diabetes ไม่ใช่ ADR ของ anticholinergic mechanism","choices":[{"label":"A","text":"Dry mouth","explanation":"✗ ถูก (เป็น ADR จริง) — Anticholinergic ยับยั้ง M3 ใน salivary gland → dry mouth; ADR พบบ่อยที่สุดของ Tiotropium"},{"label":"B","text":"Urinary retention","explanation":"✗ ถูก (เป็น ADR จริง) — ยับยั้ง M3 ใน detrusor → urinary retention; ระวังใน BPH"},{"label":"C","text":"Constipation","explanation":"✗ ถูก (เป็น ADR จริง) — ยับยั้ง M3 ใน GI smooth muscle → ลด peristalsis → constipation"},{"label":"D","text":"Diabetes mellitus","explanation":"✓ นี่คือข้อที่ไม่ใช่ ADR — Diabetes ไม่ใช่ผลของ anticholinergic mechanism; ไม่มี M3 receptor ที่ควบคุม glucose metabolism"},{"label":"E","text":"Blurred vision","explanation":"✗ ถูก (เป็น ADR จริง) — ยับยั้ง M3 ใน ciliary muscle/iris sphincter → mydriasis + cycloplegia → blurred vision"}],"key_takeaway":"Anticholinergic ADRs: ''DUMBELLS'' reversed = Dry mouth, Urinary retention, Mydriasis, Blurred vision, ↓ GI, Tachycardia, ↓ secretions"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:10') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9df7b71b-60a9-4a91-981b-9c30669ad222', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', 'Pharmacyguru', 1, 74, 'ผู้ป่วย COPD ใช้ Tiotropium แต่ยังมี exacerbation ≥2 ครั้ง/ปี ควรเพิ่มยาใด', NULL, '[{"label":"A","text":"SABA เพิ่ม"},{"label":"B","text":"เพิ่ม ICS/LABA (เป็น triple therapy)"},{"label":"C","text":"เปลี่ยนเป็น Theophylline"},{"label":"D","text":"หยุด LAMA เปลี่ยนเป็น LABA"},{"label":"E","text":"ไม่ต้องเพิ่ม"}]'::jsonb, 'B', 'COPD escalation: LAMA + ICS/LABA = triple therapy ลด exacerbation ในผู้ป่วย eosinophil สูง หรือ exacerbation บ่อย', '{"summary":"การ escalate ยาเมื่อ COPD ยังมี exacerbation ≥2 ครั้ง/ปี","reason":"LAMA + ICS/LABA = triple therapy → ลด exacerbation","choices":[{"label":"A","text":"SABA เพิ่ม","explanation":"✗ ผิด — SABA เป็น rescue ไม่ใช่ maintenance; เพิ่ม SABA ไม่ลด exacerbation"},{"label":"B","text":"เพิ่ม ICS/LABA (เป็น triple therapy)","explanation":"✓ ถูก — IMPACT/ETHOS trial: Triple therapy (LAMA+ICS/LABA) ลด exacerbation อย่างมีนัยสำคัญในผู้ป่วยที่มี eosinophils สูงหรือ exacerbation ≥2 ครั้ง"},{"label":"C","text":"เปลี่ยนเป็น Theophylline","explanation":"✗ ผิด — Theophylline ไม่ใช่ preferred escalation; side effects สูง, DDI มาก"},{"label":"D","text":"หยุด LAMA เปลี่ยนเป็น LABA","explanation":"✗ ผิด — ไม่ลดขนาดการรักษา; ควรเพิ่มไม่ใช่เปลี่ยน"},{"label":"E","text":"ไม่ต้องเพิ่ม","explanation":"✗ ผิด — ≥2 exacerbations/ปี = ต้องปรับขึ้น therapy"}],"key_takeaway":"COPD escalation: LAMA → LAMA+LABA → Triple (LAMA+ICS/LABA); ICS ช่วยเมื่อ eos≥100-300 หรือ exacerbation ≥2"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6ea55ec4-d61e-425d-9364-95f15a047739', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 75, 'โครงสร้างเคมีที่แสดง เป็น Alkaloid ประเภทใด', NULL, '[{"label":"A","text":"Isoquinoline alkaloid"},{"label":"B","text":"Indole alkaloid"},{"label":"C","text":"Tropane alkaloid"},{"label":"D","text":"Purine alkaloid"},{"label":"E","text":"Steroidal alkaloid"}]'::jsonb, 'C', 'Tropane alkaloid มี bicyclic ring system — ตัวอย่าง: Atropine, Scopolamine, Hyoscyamine, Cocaine', '{"summary":"การจำแนก Alkaloid จากโครงสร้างเคมี (ข้อ 75)","reason":"Tropane alkaloid = N-methyl bridged bicyclic ring; ตัวอย่าง: Atropine, Scopolamine","choices":[{"label":"A","text":"Isoquinoline alkaloid","explanation":"✗ ผิด — Isoquinoline มี fused benzene+pyridine; ตัวอย่าง: Morphine, Tubocurarine, Berberine"},{"label":"B","text":"Indole alkaloid","explanation":"✗ ผิด — Indole มี fused benzene+pyrrole; ตัวอย่าง: LSD, Ergotamine, Strychnine"},{"label":"C","text":"Tropane alkaloid","explanation":"✓ ถูก — Tropane ring = N-methyl piperidine fused cyclopentane = ecgonine backbone; ตัวอย่าง: Atropine, Scopolamine, Cocaine, Hyoscyamine"},{"label":"D","text":"Purine alkaloid","explanation":"✗ ผิด — Purine alkaloids: Caffeine (trimethylxanthine), Theophylline, Theobromine"},{"label":"E","text":"Steroidal alkaloid","explanation":"✗ ผิด — Steroidal alkaloids เช่น Solanine (potato), Veratridine; มี steroid skeleton"}],"key_takeaway":"สังเกต Tropane: มี N หักมุม + bicyclic; Cocaine = tropane; Atropine = racemic hyoscyamine"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9e3c75db-2dc3-404e-8561-a1fb9217c5b1', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', 'Pharmacyguru', 1, 76, 'ยาใดต่อไปนี้เป็น Muscarinic receptor antagonist', NULL, '[{"label":"A","text":"Atenolol"},{"label":"B","text":"Prazosin"},{"label":"C","text":"Amlodipine"},{"label":"D","text":"Ipratropium / Tiotropium"},{"label":"E","text":"Metformin"}]'::jsonb, 'D', 'Tiotropium/Ipratropium = M3 muscarinic receptor antagonist → bronchodilation — ใช้ใน COPD และ asthma', '{"summary":"Muscarinic receptor antagonist","reason":"Ipratropium/Tiotropium = M3 muscarinic receptor antagonist → bronchodilation","choices":[{"label":"A","text":"Atenolol","explanation":"✗ ผิด — Atenolol = cardioselective β1 blocker ไม่ใช่ muscarinic antagonist"},{"label":"B","text":"Prazosin","explanation":"✗ ผิด — Prazosin = α1 adrenergic blocker ใช้ใน hypertension/BPH"},{"label":"C","text":"Amlodipine","explanation":"✗ ผิด — Amlodipine = calcium channel blocker (dihydropyridine) ไม่มีผลต่อ muscarinic receptor"},{"label":"D","text":"Ipratropium / Tiotropium","explanation":"✓ ถูก — Tiotropium/Ipratropium = anticholinergic/antimuscarinic (M3 antagonist) → ลด bronchoconstriction และ secretions; ใช้ใน COPD"},{"label":"E","text":"Metformin","explanation":"✗ ผิด — Metformin = biguanide ยา antidiabetic ไม่มีผลต่อ muscarinic receptor"}],"key_takeaway":"Muscarinic antagonists: Atropine (nonselective), Ipratropium (inhaled, short-acting), Tiotropium (inhaled, long-acting M3 selective)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('380095a5-a489-4bc5-a87b-0d2d4da20be6', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 77, 'ยาใดเป็น first-line สำหรับ Ascariasis (พยาธิไส้เดือน)', NULL, '[{"label":"A","text":"Albendazole"},{"label":"B","text":"Mebendazole"},{"label":"C","text":"Niclosamide"},{"label":"D","text":"Praziquantel"},{"label":"E","text":"Ivermectin"}]'::jsonb, 'A', 'Albendazole 400 mg single dose = first-line สำหรับ Ascariasis, hookworm, trichuris — Mebendazole ก็ใช้ได้', '{"summary":"First-line สำหรับ Ascariasis (พยาธิไส้เดือน)","reason":"Albendazole single dose = first-line สำหรับ soil-transmitted helminths","choices":[{"label":"A","text":"Albendazole","explanation":"✓ ถูก — Albendazole 400 mg single dose = first-line สำหรับ Ascariasis, hookworm, trichuriasis, enterobiasis; benzimidazole → ยับยั้ง beta-tubulin"},{"label":"B","text":"Mebendazole","explanation":"✗ ผิด — Mebendazole 500 mg single dose ก็ใช้ได้ แต่ Albendazole ดีกว่า bioavailability และ preferred"},{"label":"C","text":"Niclosamide","explanation":"✗ ผิด — Niclosamide ใช้สำหรับ cestodes (tapeworm) เฉพาะ intestinal; ไม่ใช่ nematodes"},{"label":"D","text":"Praziquantel","explanation":"✗ ผิด — Praziquantel ใช้สำหรับ trematodes (flukes) และ tapeworm ไม่ใช่ Ascariasis"},{"label":"E","text":"Ivermectin","explanation":"✗ ผิด — Ivermectin ใช้สำหรับ Strongyloides, Onchocerca; ไม่ใช่ first-line สำหรับ Ascaris"}],"key_takeaway":"STH (Soil-Transmitted Helminths): Albendazole 400mg single dose ครอบคลุม roundworm, hookworm, whipworm, pinworm"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c582c7e6-dabb-43c4-8824-9dccdf3d4858', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 78, 'ยาใดใช้รักษา Taenia (พยาธิตัวตืด) ได้ผลดีที่สุด', NULL, '[{"label":"A","text":"Albendazole"},{"label":"B","text":"Praziquantel"},{"label":"C","text":"Niclosamide"},{"label":"D","text":"Mebendazole"},{"label":"E","text":"Ivermectin"}]'::jsonb, 'B', 'Praziquantel = drug of choice สำหรับ Cestode (Taenia) และ Trematode (Schistosoma, Clonorchis) ทุกชนิด', '{"summary":"ยาที่ดีที่สุดสำหรับ Taenia (พยาธิตัวตืด)","reason":"Praziquantel = drug of choice สำหรับ Cestoda (tapeworm) ทุกชนิด","choices":[{"label":"A","text":"Albendazole","explanation":"✗ ผิด — Albendazole ใช้กับ nematodes เป็นหลัก; สำหรับ tapeworm มีฤทธิ์อ่อนกว่า Praziquantel"},{"label":"B","text":"Praziquantel","explanation":"✓ ถูก — Praziquantel = drug of choice สำหรับ Cestodes (Taenia, Diphyllobothrium) และ Trematodes (Schistosoma, Clonorchis, Opisthorchis, Paragonimus)"},{"label":"C","text":"Niclosamide","explanation":"✗ ผิด — Niclosamide ใช้ได้สำหรับ intestinal tapeworm แต่ Praziquantel preferred; Niclosamide ไม่ absorbed ลำไส้จึงไม่ใช้กับ systemic disease"},{"label":"D","text":"Mebendazole","explanation":"✗ ผิด — Mebendazole ใช้กับ nematodes เป็นหลัก"},{"label":"E","text":"Ivermectin","explanation":"✗ ผิด — Ivermectin ใช้กับ Strongyloides, filarial, scabies ไม่ใช่ tapeworm"}],"key_takeaway":"Praziquantel กลไก: เพิ่ม Ca²⁺ permeability → spastic paralysis ของพยาธิ; ใช้ได้กับ Schistosoma, Taenia, Opisthorchis"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9adf630f-f401-479e-a1ec-13ab0f13bf86', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 79, 'กลไกของ Albendazole ในการฆ่าพยาธิ', NULL, '[{"label":"A","text":"ยับยั้ง acetylcholinesterase"},{"label":"B","text":"กล้ามเนื้อพยาธิหดเกร็ง"},{"label":"C","text":"ยับยั้ง beta-tubulin → microtubule disruption"},{"label":"D","text":"เพิ่ม Cl- influx → hyperpolarization"},{"label":"E","text":"ยับยั้ง dihydrofolate reductase"}]'::jsonb, 'C', 'Benzimidazoles: ยับยั้ง beta-tubulin polymerization → ทำลาย microtubule → ยับยั้งการดูดซึม glucose ของพยาธิ → ตาย', '{"summary":"กลไกของ Albendazole ในการฆ่าพยาธิ","reason":"Benzimidazoles ยับยั้ง beta-tubulin → microtubule disruption → ลด glucose uptake → พยาธิตาย","choices":[{"label":"A","text":"ยับยั้ง acetylcholinesterase","explanation":"✗ ผิด — Organophosphate ยับยั้ง AChE ไม่ใช่ benzimidazoles"},{"label":"B","text":"กล้ามเนื้อพยาธิหดเกร็ง","explanation":"✗ ผิด — Piperazine ทำให้ atonic paralysis; Levamisole ทำ spastic paralysis; Benzimidazole ไม่ใช่กลไกนี้"},{"label":"C","text":"ยับยั้ง beta-tubulin → microtubule disruption","explanation":"✓ ถูก — Albendazole/Mebendazole ยับยั้งการ polymerization ของ beta-tubulin → ทำลาย microtubule ของพยาธิ → ลดการดูดซึม glucose → ATP ลด → พยาธิตาย"},{"label":"D","text":"เพิ่ม Cl- influx → hyperpolarization","explanation":"✗ ผิด — Ivermectin กลไกนี้: เพิ่ม Cl⁻ conductance ผ่าน GluCl channels → hyperpolarization → paralysis"},{"label":"E","text":"ยับยั้ง dihydrofolate reductase","explanation":"✗ ผิด — DHFR inhibitor = Pyrimethamine (antiprotozoal), Trimethoprim (antibacterial)"}],"key_takeaway":"Benzimidazole MOA: beta-tubulin inhibition (colchicine-binding site) → microtubule disruption → no glucose uptake → ATP depletion"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('feeda7f1-a68b-4d40-95a9-da7b2466074e', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 80, 'ข้อใดถูกต้องเกี่ยวกับ Ciprofloxacin ophthalmic solution', NULL, '[{"label":"A","text":"ต้องเป็น sterile product"},{"label":"B","text":"ไม่ต้อง isotonic"},{"label":"C","text":"pH ไม่สำคัญ"},{"label":"D","text":"ไม่ต้อง preservative"},{"label":"E","text":"สามารถมี particulate matter ได้บ้าง"}]'::jsonb, 'A', 'Ophthalmic preparation: ต้องเป็น sterile เสมอ, isotonic (~280-320 mOsm), pH 6.5-7.4, ปราศจาก particulate matter', '{"summary":"คุณสมบัติที่จำเป็นของ Ophthalmic Solution","reason":"Ophthalmic solution ต้องเป็น sterile เสมอ เพราะตาเสี่ยงต่อ infection","choices":[{"label":"A","text":"ต้องเป็น sterile product","explanation":"✓ ถูก — Ophthalmic preparation ต้องเป็น sterile เสมอ เพราะตาไม่มี immune defense ที่ดี; non-sterile → bacterial endophthalmitis"},{"label":"B","text":"ไม่ต้อง isotonic","explanation":"✗ ผิด — ต้อง isotonic (~280-320 mOsm) ไม่เช่นนั้นทำให้ discomfort และ cell damage"},{"label":"C","text":"pH ไม่สำคัญ","explanation":"✗ ผิด — pH สำคัญมาก: ต้องอยู่ในช่วง 6.5-7.4 ใกล้เคียง tear fluid; pH ต่างมากทำให้เจ็บตา"},{"label":"D","text":"ไม่ต้อง preservative","explanation":"✗ ผิด — Multi-dose ophthalmic ต้อง preservative; single-dose preservative-free ก็ต้อง sterile เหมือนกัน"},{"label":"E","text":"สามารถมี particulate matter ได้บ้าง","explanation":"✗ ผิด — ต้องปราศจาก particulate matter เด็ดขาด; อาจทำให้ corneal scratch หรือ inflammation"}],"key_takeaway":"Ophthalmic requirements: Sterile + Isotonic (280-320 mOsm) + pH 6.5-7.4 + Particulate-free + Preserved (multi-dose)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('77ca856b-18f3-4640-92ad-1cb8f0d19ff0', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 81, 'Ciprofloxacin ophthalmic solution ใช้รักษาโรคตาชนิดใด', NULL, '[{"label":"A","text":"Allergic conjunctivitis"},{"label":"B","text":"Bacterial conjunctivitis"},{"label":"C","text":"Viral conjunctivitis"},{"label":"D","text":"Hordeolum (กุ้งยิง)"},{"label":"E","text":"Trachoma"}]'::jsonb, 'B', 'Ciprofloxacin ophthalmic = fluoroquinolone → bacterial conjunctivitis, bacterial keratitis (กระจกตาอักเสบจากเชื้อ)', '{"summary":"Ciprofloxacin Ophthalmic Solution ใช้รักษาโรคตาชนิดใด","reason":"Ciprofloxacin ophthalmic = fluoroquinolone → bacterial conjunctivitis/keratitis","choices":[{"label":"A","text":"Allergic conjunctivitis","explanation":"✗ ผิด — Allergic conjunctivitis ใช้ antihistamine eye drops (Ketotifen, Olopatadine) หรือ mast cell stabilizers"},{"label":"B","text":"Bacterial conjunctivitis","explanation":"✓ ถูก — Ciprofloxacin ophthalmic 0.3% = fluoroquinolone antimicrobial; ใช้ bacterial conjunctivitis, bacterial keratitis, corneal ulcer จากเชื้อแบคทีเรีย"},{"label":"C","text":"Viral conjunctivitis","explanation":"✗ ผิด — Viral conjunctivitis (adenovirus) ใช้ supportive treatment; antibiotic ไม่มีผล"},{"label":"D","text":"Hordeolum (กุ้งยิง)","explanation":"✗ ผิด — Hordeolum = S. aureus abscess; ใช้ warm compress ± topical antibiotic (เช่น fucidic acid) ไม่ใช่ fluoroquinolone primarily"},{"label":"E","text":"Trachoma","explanation":"✗ ผิด — Trachoma (Chlamydia trachomatis) ใช้ Azithromycin systemic หรือ Tetracycline eye ointment"}],"key_takeaway":"Ciprofloxacin ophthalmic: broad-spectrum gram-negative/positive; bacteria keratitis เลือก fluoroquinolone (Cipro, Moxiflo)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:11') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ab9ad90a-dd99-422d-8be4-0d0962b2d7d0', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 82, 'ข้อใดต่อไปนี้ "ไม่ใช่" คุณสมบัติที่ต้องการของ ophthalmic solution', NULL, '[{"label":"A","text":"Sterility"},{"label":"B","text":"Isotonicity"},{"label":"C","text":"Appropriate pH"},{"label":"D","text":"Viscosity enhancer จำเป็นในทุกสูตร"},{"label":"E","text":"Preserved หรือ preservative-free"}]'::jsonb, 'D', 'Ophthalmic solution ไม่จำเป็นต้องมี viscosity enhancer ทุกสูตร — มีเฉพาะสูตรที่ต้องการเพิ่ม contact time', '{"summary":"คุณสมบัติที่ไม่จำเป็นใน Ophthalmic Solution ทุกสูตร","reason":"Viscosity enhancer ไม่จำเป็นในทุกสูตร — เพิ่มเฉพาะสูตรที่ต้องการ contact time ยาวขึ้น","choices":[{"label":"A","text":"Sterility","explanation":"✗ ถูก (จำเป็น) — Sterility จำเป็นในทุก ophthalmic preparation"},{"label":"B","text":"Isotonicity","explanation":"✗ ถูก (จำเป็น) — Isotonicity จำเป็นเพื่อ comfort และป้องกัน cell damage"},{"label":"C","text":"Appropriate pH","explanation":"✗ ถูก (จำเป็น) — pH 6.5-7.4 จำเป็นสำหรับ comfort และ stability"},{"label":"D","text":"Viscosity enhancer จำเป็นในทุกสูตร","explanation":"✓ นี่คือข้อที่ไม่ถูก — Viscosity enhancer (HPMC, PVA) ไม่จำเป็นในทุกสูตร เพิ่มเฉพาะสูตร eye drops ที่ต้องการยืด contact time (เช่น artificial tears)"},{"label":"E","text":"Preserved หรือ preservative-free","explanation":"✗ ถูก (จำเป็น) — ต้องเลือกว่าจะ preserved หรือ preservative-free ขึ้นกับ packaging และ indication"}],"key_takeaway":"Ophthalmic optional: viscosity enhancer, tonicity agents, antioxidants; ต้องมีเสมอ: sterility, appropriate pH, isotonic"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('29897998-d439-4486-a6bb-27effbd18dd1', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 83, 'Ciprofloxacin ophthalmic solution ใช้ buffer ประเภทใด', NULL, '[{"label":"A","text":"Phosphate"},{"label":"B","text":"Borate"},{"label":"C","text":"Citrate"},{"label":"D","text":"Carbonate"},{"label":"E","text":"Acetate"}]'::jsonb, 'A', 'Phosphate buffer ใช้บ่อยที่สุดใน ophthalmic preparation — compatible กับ eye tissue, รักษา pH ช่วง 6-8', '{"summary":"Buffer ที่ใช้บ่อยที่สุดใน Ophthalmic Solution","reason":"Phosphate buffer ใช้บ่อยที่สุดใน ophthalmic preparation — compatible กับ eye tissue","choices":[{"label":"A","text":"Phosphate","explanation":"✓ ถูก — Phosphate buffer (Na₂HPO₄/NaH₂PO₄) ใช้บ่อยที่สุดใน ophthalmic; compatible กับ eye tissue, รักษา pH 6-8, ไม่ระคายเคือง"},{"label":"B","text":"Borate","explanation":"✗ ผิด — Borate buffer ใช้ได้แต่ไม่เหมาะกับ eye ที่มี soft contact lens; ทำ complex กับ polyol"},{"label":"C","text":"Citrate","explanation":"✗ ผิด — Citrate buffer ใช้ในยาฉีด IV มากกว่า ophthalmic"},{"label":"D","text":"Carbonate","explanation":"✗ ผิด — Carbonate buffer ไม่เหมาะ ophthalmic เพราะ pH สูงเกินไป"},{"label":"E","text":"Acetate","explanation":"✗ ผิด — Acetate buffer ใช้ใน parenteral formulation มากกว่า ophthalmic"}],"key_takeaway":"Ophthalmic buffers: Phosphate (most common), Borate (avoid contact lens), Acetate (low pH range); pH 6.5-7.4"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d5deadf1-a807-47ac-b831-2080114786ca', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 84, 'USP Ciprofloxacin ophthalmic solution — test ใดต่อไปนี้ "ไม่ใช่" test ที่กำหนดสำหรับ solution', NULL, '[{"label":"A","text":"ASSAY ด้วย Liquid chromatography"},{"label":"B","text":"Identification"},{"label":"C","text":"pH testing"},{"label":"D","text":"Uniformity of dosage unit"},{"label":"E","text":"Sterility testing"}]'::jsonb, 'D', 'Uniformity of dosage unit ใช้กับ solid dosage form (tablet, capsule) ไม่ใช่ solution', '{"summary":"Test ที่ไม่ใช่ของ Ophthalmic Solution ตาม USP","reason":"Uniformity of dosage unit ใช้กับ solid dosage form ไม่ใช่ solution","choices":[{"label":"A","text":"ASSAY ด้วย Liquid chromatography","explanation":"✗ ถูก (มีใน USP) — ASSAY เป็น test มาตรฐานสำหรับ ophthalmic solution"},{"label":"B","text":"Identification","explanation":"✗ ถูก (มีใน USP) — Identity test มีในทุก USP monograph"},{"label":"C","text":"pH testing","explanation":"✗ ถูก (มีใน USP) — pH testing สำคัญสำหรับ ophthalmic"},{"label":"D","text":"Uniformity of dosage unit","explanation":"✓ นี่คือ test ที่ไม่ใช่ — Uniformity of dosage units ใช้กับ tablets, capsules; solutions ใช้ Uniformity of content (ถ้าจำเป็น) หรือ ASSAY แทน"},{"label":"E","text":"Sterility testing","explanation":"✗ ถูก (มีใน USP) — Sterility testing จำเป็นสำหรับ ophthalmic solutions (Sterility test; membrane filtration method)"}],"key_takeaway":"USP Ophthalmic tests: ID, ASSAY, pH, Sterility, Particulate matter, Leakage test; ไม่มี uniformity of dosage units"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('eb1bef83-9370-4602-a408-75ef59c88f23', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 85, 'USP Ciprofloxacin Ophthalmic Solution กำหนด Relative Standard Deviation (RSD) ของ ASSAY ไม่เกินเท่าใด', NULL, '[{"label":"A","text":"NMT 5% (inorganic impurities)"},{"label":"B","text":"NMT 2%"},{"label":"C","text":"NMT 10%"},{"label":"D","text":"NMT 0.5%"},{"label":"E","text":"NMT 15%"}]'::jsonb, 'A', 'Standard deviation สำหรับ ophthalmic ASSAY: RSD NMT 5% (ตาม USP monograph)', '{"summary":"RSD ของ ASSAY สำหรับ Ciprofloxacin Ophthalmic Solution","reason":"RSD NMT 5% ตาม USP monograph สำหรับ inorganic impurities/ASSAY","choices":[{"label":"A","text":"NMT 5% (inorganic impurities)","explanation":"✓ ถูก — USP Ciprofloxacin Ophthalmic Solution: RSD ≤ 5% สำหรับ system suitability ใน ASSAY"},{"label":"B","text":"NMT 2%","explanation":"✗ ผิด — 2% เข้มงวดเกินไปสำหรับ ophthalmic solution ASSAY"},{"label":"C","text":"NMT 10%","explanation":"✗ ผิด — ≤10% หลวมเกินไป; ใช้สำหรับบางชนิด"},{"label":"D","text":"NMT 0.5%","explanation":"✗ ผิด — 0.5% เข้มงวดมากเกินไปสำหรับ routine ASSAY"},{"label":"E","text":"NMT 15%","explanation":"✗ ผิด — หลวมเกินไปสำหรับ ASSAY"}],"key_takeaway":"System suitability RSD ใน HPLC ASSAY ทั่วไป: ≤2% (USP strict), ≤5% (บางสูตร); Check specific monograph เสมอ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a3e92849-3a6b-48ae-b96a-adbabfb19b39', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 86, 'Acceptance criteria ของ ASSAY Ciprofloxacin Ophthalmic Solution ตาม USP คือ', NULL, '[{"label":"A","text":"90.0-110.0%"},{"label":"B","text":"95.0-105.0%"},{"label":"C","text":"90.0-115.0%"},{"label":"D","text":"98.0-102.0%"},{"label":"E","text":"97.0-103.0%"}]'::jsonb, 'C', 'USP Ciprofloxacin Ophthalmic Solution: 90.0-115.0% of labeled amount', '{"summary":"Acceptance criteria ASSAY ของ Ciprofloxacin Ophthalmic Solution","reason":"USP Ciprofloxacin Ophthalmic Solution: 90.0-115.0%","choices":[{"label":"A","text":"90.0-110.0%","explanation":"✗ ผิด — 90-110% ใช้กับ tablet/capsule มาตรฐาน ไม่ใช่ ophthalmic solution"},{"label":"B","text":"95.0-105.0%","explanation":"✗ ผิด — 95-105% แคบเกินไปสำหรับ ophthalmic solution"},{"label":"C","text":"90.0-115.0%","explanation":"✓ ถูก — USP Ciprofloxacin Ophthalmic Solution acceptance criteria: 90.0-115.0% of labeled amount (wider upper limit เพราะ concentration loss ต่ำกว่าสม่ำเสมอ)"},{"label":"D","text":"98.0-102.0%","explanation":"✗ ผิด — แคบเกินไป; ใช้กับ pure chemicals เช่น CaCO₃"},{"label":"E","text":"97.0-103.0%","explanation":"✗ ผิด — ยังแคบเกินไปสำหรับ ophthalmic solution"}],"key_takeaway":"Acceptance criteria: pure chemical 98.5-101.5%; tablets 90-110%; some ophthalmic 90-115%; check USP monograph เสมอ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('83c6fecc-a88b-450b-a39b-39affaa77e72', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 87, 'Herpes labialis (cold sore) ส่วนใหญ่เกิดจากเชื้อใด', NULL, '[{"label":"A","text":"Cytomegalovirus"},{"label":"B","text":"Herpes simplex virus type 1 (HSV-1)"},{"label":"C","text":"Varicella zoster virus"},{"label":"D","text":"Herpes simplex virus type 2"},{"label":"E","text":"Human Papilloma virus"}]'::jsonb, 'B', 'HSV-1 = สาเหตุหลักของ herpes labialis; HSV-2 = genital herpes; VZV = chickenpox/shingles', '{"summary":"เชื้อก่อ Herpes labialis (Cold sore)","reason":"HSV-1 = สาเหตุหลักของ herpes labialis/cold sore บริเวณริมฝีปาก","choices":[{"label":"A","text":"Cytomegalovirus","explanation":"✗ ผิด — CMV ทำให้เกิด mononucleosis, retinitis, congenital CMV ไม่ใช่ cold sore"},{"label":"B","text":"Herpes simplex virus type 1 (HSV-1)","explanation":"✓ ถูก — HSV-1 = primary cause ของ herpes labialis (cold sore); latent ใน trigeminal ganglion → reactivate → oral lesion"},{"label":"C","text":"Varicella zoster virus","explanation":"✗ ผิด — VZV ทำให้ chickenpox (primary) และ shingles (reactivation); herpes zoster ≠ herpes labialis"},{"label":"D","text":"Herpes simplex virus type 2","explanation":"✗ ผิด — HSV-2 = primary cause ของ genital herpes; แต่ cross-infection ได้"},{"label":"E","text":"Human Papilloma virus","explanation":"✗ ผิด — HPV ทำให้ warts, condyloma, cervical cancer ไม่ใช่ cold sore"}],"key_takeaway":"HSV-1: oral herpes, encephalitis; HSV-2: genital herpes; ทั้งคู่ latent ใน sensory ganglia → recurrence trigger: stress, UV, fever"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b0da0511-a2c4-4b01-baa9-fa8434f6c626', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 88, 'กลไกการออกฤทธิ์ของ Acyclovir ต้านไวรัส Herpes คือ', NULL, '[{"label":"A","text":"Protease inhibitor"},{"label":"B","text":"DNA polymerase inhibitor แบบ competitive"},{"label":"C","text":"DNA polymerase inhibitor (chain terminator)"},{"label":"D","text":"Reverse transcriptase inhibitor"},{"label":"E","text":"Neuraminidase inhibitor"}]'::jsonb, 'C', 'Acyclovir → phosphorylated by viral TK → Acyclovir triphosphate → competitive inhibitor + chain terminator ของ viral DNA polymerase', '{"summary":"กลไกการออกฤทธิ์ของ Acyclovir","reason":"Acyclovir → phosphorylated by viral TK → chain terminator ของ viral DNA polymerase","choices":[{"label":"A","text":"Protease inhibitor","explanation":"✗ ผิด — HIV protease inhibitors (Ritonavir, Lopinavir) ใช้กับ HIV ไม่ใช่ Herpes"},{"label":"B","text":"DNA polymerase inhibitor แบบ competitive","explanation":"✗ ผิด — Acyclovir-TP เป็นทั้ง competitive inhibitor AND chain terminator; ไม่ใช่แค่ competitive"},{"label":"C","text":"DNA polymerase inhibitor (chain terminator)","explanation":"✓ ถูก — Acyclovir → viral TK phosphorylates → Acyclovir-TP → ขัดขวาง viral DNA polymerase: competitive inhibitor + chain terminator (ไม่มี 3''-OH → DNA elongation หยุด)"},{"label":"D","text":"Reverse transcriptase inhibitor","explanation":"✗ ผิด — NRTI/NNRTI ใช้กับ HIV ไม่ใช่ HSV"},{"label":"E","text":"Neuraminidase inhibitor","explanation":"✗ ผิด — Oseltamivir/Zanamivir = neuraminidase inhibitor ใช้กับ Influenza"}],"key_takeaway":"Acyclovir selectivity: ต้อง viral TK (HSV/VZV) phosphorylate → ปลอดภัยกว่า Ganciclovir ซึ่ง cellular kinase phosphorylate ด้วย → myelosuppression"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:12') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b43c02c2-2b83-4a91-b78b-73e3929e7151', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 89, 'ยาใดต่อไปนี้ต้องใช้ยาอื่นแทน Acyclovir เนื่องจาก Acyclovir มีประสิทธิภาพต่ำ', NULL, '[{"label":"A","text":"Cytomegalovirus (CMV) infection"},{"label":"B","text":"Varicella zoster"},{"label":"C","text":"Herpes simplex"},{"label":"D","text":"Epstein-Barr virus"},{"label":"E","text":"Human herpesvirus 6"}]'::jsonb, 'A', 'CMV ขาด thymidine kinase → ไม่สามารถ phosphorylate acyclovir → ต้องใช้ Ganciclovir/Valganciclovir แทน', '{"summary":"กรณีที่ต้องใช้ยาอื่นแทน Acyclovir","reason":"CMV ขาด thymidine kinase → Acyclovir ไม่ถูก activate → ไม่มีประสิทธิภาพ","choices":[{"label":"A","text":"Cytomegalovirus (CMV) infection","explanation":"✓ ถูก — CMV ไม่มี thymidine kinase ที่จะ phosphorylate Acyclovir → ต้องใช้ Ganciclovir (activated by UL97 kinase) หรือ Valganciclovir, Foscarnet"},{"label":"B","text":"Varicella zoster","explanation":"✗ ผิด — VZV มี TK → Acyclovir ใช้ได้ แต่ต้องใช้ขนาดสูงกว่า HSV (800 mg 5×/วัน); Valacyclovir preferred"},{"label":"C","text":"Herpes simplex","explanation":"✗ ผิด — HSV มี TK → Acyclovir ใช้ได้ดี เป็น drug of choice"},{"label":"D","text":"Epstein-Barr virus","explanation":"✗ ผิด — EBV มี TK แต่ Acyclovir efficacy ต่ำ; ไม่มี standard antiviral ที่ชัดเจนสำหรับ EBV"},{"label":"E","text":"Human herpesvirus 6","explanation":"✗ ผิด — HHV-6 ไม่ตอบสนองต่อ Acyclovir ดี; ใช้ Ganciclovir/Foscarnet แต่ไม่ใช่ standard indication ที่ต้องพิสูจน์ TK absence"}],"key_takeaway":"CMV treatment: Ganciclovir IV (first-line), Valganciclovir PO, Foscarnet (GCV-resistant), Cidofovir; ไม่ใช้ Acyclovir"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('90fa6fd6-c1d8-492b-be95-4ccda5efe252', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 90, 'ขนาดยา Acyclovir สำหรับรักษา Herpes simplex genitalis (first episode) คือ', NULL, '[{"label":"A","text":"200 mg TID 5 วัน"},{"label":"B","text":"400 mg TID นาน 7-10 วัน"},{"label":"C","text":"800 mg BID"},{"label":"D","text":"800 mg 5×/วัน"},{"label":"E","text":"1,200 mg วันละ 1 ครั้ง"}]'::jsonb, 'B', 'HSV genital first episode: Acyclovir 400 mg TID หรือ 200 mg 5×/วัน นาน 7-10 วัน', '{"summary":"ขนาด Acyclovir สำหรับ Herpes genitalis first episode","reason":"HSV genitalis first episode: Acyclovir 400 mg TID × 7-10 วัน","choices":[{"label":"A","text":"200 mg TID 5 วัน","explanation":"✗ ผิด — 200 mg TID ใช้สำหรับ suppressive therapy ไม่ใช่ acute treatment; 5 วันสั้นเกินไปสำหรับ first episode"},{"label":"B","text":"400 mg TID นาน 7-10 วัน","explanation":"✓ ถูก — CDC guidelines: Acyclovir 400 mg TID × 7-10 วัน หรือ 200 mg 5×/วัน × 7-10 วัน สำหรับ HSV genitalis first episode"},{"label":"C","text":"800 mg BID","explanation":"✗ ผิด — 800 mg BID ใช้สำหรับ chronic suppressive therapy ไม่ใช่ first episode acute"},{"label":"D","text":"800 mg 5×/วัน","explanation":"✗ ผิด — 800 mg 5×/วัน ใช้สำหรับ VZV (Varicella/Zoster) ไม่ใช่ HSV genitalis"},{"label":"E","text":"1,200 mg วันละ 1 ครั้ง","explanation":"✗ ผิด — ไม่ใช่ standard dosing ของ Acyclovir"}],"key_takeaway":"Acyclovir dosing: HSV genital acute 400mg TID; VZV 800mg 5×/d; Suppression 400mg BD; IV severe: 5-10 mg/kg q8h"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('67c25ced-6f0e-4f54-8280-ed77b8f6da66', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 91, 'Acyclovir 1,200 mg sustained release matrix tablet ใช้ชั้น membrane ประเภทใดควบคุมการปล่อยยา', NULL, '[{"label":"A","text":"Semipermeable membrane"},{"label":"B","text":"Prolonged release system"},{"label":"C","text":"Controlled release matrix"},{"label":"D","text":"Delayed release"},{"label":"E","text":"Immediate release"}]'::jsonb, 'A', 'OROS: semipermeable membrane ให้น้ำผ่านแต่ไม่ให้ยาผ่าน → osmotic pressure ขับยาออกทาง orifice ใน rate คงที่', '{"summary":"Membrane ควบคุมการปล่อยยาใน Acyclovir SR matrix tablet","reason":"OROS osmotic pump = semipermeable membrane; water เข้า → osmotic pressure → ดันยาออก","choices":[{"label":"A","text":"Semipermeable membrane","explanation":"✓ ถูก — OROS (Osmotic Release Oral System): Semipermeable membrane ให้น้ำผ่านเข้า แต่ไม่ให้ยาผ่าน → osmotic pressure ดันยาออก orifice ใน zero-order rate"},{"label":"B","text":"Prolonged release system","explanation":"✗ ผิด — นี่เป็นคำอธิบาย release pattern ไม่ใช่ membrane ชนิด"},{"label":"C","text":"Controlled release matrix","explanation":"✗ ผิด — Matrix system ไม่มี semipermeable membrane; ยาแพร่จาก matrix โดยตรง"},{"label":"D","text":"Delayed release","explanation":"✗ ผิด — Delayed release = enteric coat ชะลอการปล่อยยาจนเข้า intestine"},{"label":"E","text":"Immediate release","explanation":"✗ ผิด — SR = sustained release ตรงข้ามกับ immediate release"}],"key_takeaway":"OROS: semipermeable membrane (cellulose acetate) + laser-drilled orifice → zero-order release; ตัวอย่าง: Glucotrol XL, Procardia XL"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('76a5b494-e6ad-4e0d-b74a-8e5af79fbd61', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 92, 'Powder: Bulk density = 0.28 g/mL, Tapped density = 1.02 g/mL ค่า Carr''s Compressibility Index และระดับ flowability คือ', NULL, '[{"label":"A","text":"5% (Excellent)"},{"label":"B","text":"72.5% (Very poor → ต้องทำ granulation)"},{"label":"C","text":"20% (Fair)"},{"label":"D","text":"25.5% (Poor)"},{"label":"E","text":"35% (Very poor)"}]'::jsonb, 'B', 'Carr''s Index = (1.02−0.28)/1.02 × 100 = 72.5% — Very poor flowability → ต้องทำ granulation ก่อน direct compression ไม่ได้', '{"summary":"Carr''s Compressibility Index และ Flowability","reason":"CI = (Tapped - Bulk)/Tapped × 100 = (1.02-0.28)/1.02 × 100 = 72.5% = Very poor","choices":[{"label":"A","text":"5% (Excellent)","explanation":"✗ ผิด — CI 5-15% = Excellent flowability; ข้อนี้ CI 72.5% ซึ่ง very poor"},{"label":"B","text":"72.5% (Very poor → ต้องทำ granulation)","explanation":"✓ ถูก — CI = (1.02-0.28)/1.02 × 100 = 72.5%; CI >40% = Very poor/Extremely poor flowability → ต้องทำ granulation ก่อน tablet compression"},{"label":"C","text":"20% (Fair)","explanation":"✗ ผิด — CI 18-25% = Passable/Fair; ข้อนี้ CI = 72.5%"},{"label":"D","text":"25.5% (Poor)","explanation":"✗ ผิด — CI 25-35% = Poor; ข้อนี้ CI = 72.5%"},{"label":"E","text":"35% (Very poor)","explanation":"✗ ผิด — CI 35-45% = Very poor ใกล้เคียงกว่าแต่ยังไม่ถูก; ข้อนี้ CI = 72.5%"}],"key_takeaway":"Carr''s Index: <15=Excellent, 15-25=Good, 25-35=Passable, 35-45=Poor, >45=Very poor; Hausner Ratio = Tapped/Bulk (<1.25=Good)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6e36883f-147d-4b6c-955b-69d5e5d90474', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 93, 'Terbinafine cream 1% (o/w) ต้องการ HLB = 13 ใช้ Span 20 (HLB 8.6) + Tween 60 (HLB 14.9) อัตราส่วนใดถูกต้อง', NULL, '[{"label":"A","text":"Span 5g + Tween 5g"},{"label":"B","text":"Span 2g + Tween 8g"},{"label":"C","text":"Span 6g + Tween 4g"},{"label":"D","text":"Span 3g + Tween 7g"},{"label":"E","text":"Span 3g + Tween 7g (HLB ≈ 13.0)"}]'::jsonb, 'E', 'HLB = (3×8.6 + 7×14.9)/10 = (25.8+104.3)/10 = 13.01 ≈ 13 ✓', '{"summary":"คำนวณอัตราส่วน Span 20 : Tween 60 สำหรับ HLB 13","reason":"Span 3g + Tween 7g = HLB = (3×8.6 + 7×14.9)/10 = 13.01 ≈ 13","choices":[{"label":"A","text":"Span 5g + Tween 5g","explanation":"✗ ผิด — HLB = (5×8.6 + 5×14.9)/10 = (43+74.5)/10 = 11.75 ≠ 13"},{"label":"B","text":"Span 2g + Tween 8g","explanation":"✗ ผิด — HLB = (2×8.6 + 8×14.9)/10 = (17.2+119.2)/10 = 13.64 ≠ 13"},{"label":"C","text":"Span 6g + Tween 4g","explanation":"✗ ผิด — HLB = (6×8.6 + 4×14.9)/10 = (51.6+59.6)/10 = 11.12 ≠ 13"},{"label":"D","text":"Span 3g + Tween 7g","explanation":"✗ ผิด — HLB = (3×8.6 + 7×14.9)/10 = (25.8+104.3)/10 = 13.01 ✓ ซ้ำกับ E"},{"label":"E","text":"Span 3g + Tween 7g (HLB ≈ 13.0)","explanation":"✓ ถูก — HLB = (3×8.6 + 7×14.9)/10 = 13.01 ≈ 13.0; ตรงกับ required HLB สำหรับ o/w cream"}],"key_takeaway":"HLB blending: HLB_mix = Σ(weight fraction × HLB); o/w emulsion ต้องการ HLB 8-16; w/o ต้องการ HLB 3-6"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6507dae4-e95a-420d-be7a-41734af99a3c', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 94, 'White petrolatum ในสูตรตำรับ cream ทำหน้าที่อะไร', NULL, '[{"label":"A","text":"Emulsifier"},{"label":"B","text":"Emollient (occlusive)"},{"label":"C","text":"Preservative"},{"label":"D","text":"Humectant"},{"label":"E","text":"Surfactant"}]'::jsonb, 'B', 'White petrolatum (Vaseline) = occlusive emollient/moisture barrier — Span/Tween = emulsifiers, PG = humectant', '{"summary":"หน้าที่ของ White Petrolatum ใน Cream","reason":"White petrolatum = occlusive emollient/moisture barrier","choices":[{"label":"A","text":"Emulsifier","explanation":"✗ ผิด — Emulsifier คือ Span 20, Tween 60 (surfactants); White petrolatum ไม่มี HLB ชัดเจน"},{"label":"B","text":"Emollient (occlusive)","explanation":"✓ ถูก — White petrolatum (Vaseline) = occlusive emollient ปิดผิวหนัง ลดการสูญเสียน้ำ (TEWL) ให้ความชุ่มชื้น"},{"label":"C","text":"Preservative","explanation":"✗ ผิด — Preservative เช่น methylparaben, propylparaben, BAK ไม่ใช่ petrolatum"},{"label":"D","text":"Humectant","explanation":"✗ ผิด — Humectant เช่น Glycerin, PG, Sorbitol ดึงน้ำจาก atmosphere หรือ dermis มาผิวหนัง"},{"label":"E","text":"Surfactant","explanation":"✗ ผิด — Surfactant เป็น amphiphilic ลด surface tension; petrolatum ไม่มีคุณสมบัตินี้"}],"key_takeaway":"Emollient types: Occlusive (petrolatum, mineral oil) = barrier; Humectant (glycerin, PG) = attract water; Emollient (lanolin) = lubricate"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d545e8ee-b407-4119-995c-76ec10232389', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 95, 'ใน Terbinafine cream สารใดเป็น emollient', NULL, '[{"label":"A","text":"Span 20"},{"label":"B","text":"Tween 60"},{"label":"C","text":"Propylene glycol"},{"label":"D","text":"White petrolatum"},{"label":"E","text":"Sodium lauryl sulfate"}]'::jsonb, 'D', 'White petrolatum = emollient ให้ความชุ่มชื้น — Span/Tween = emulsifiers, PG = humectant/solvent', '{"summary":"สาร Emollient ใน Terbinafine cream","reason":"White petrolatum = emollient ในสูตรตำรับ; Span/Tween = emulsifiers","choices":[{"label":"A","text":"Span 20","explanation":"✗ ผิด — Span 20 (HLB 8.6) = lipophilic emulsifier (w/o tendency)"},{"label":"B","text":"Tween 60","explanation":"✗ ผิด — Tween 60 (HLB 14.9) = hydrophilic emulsifier (o/w tendency)"},{"label":"C","text":"Propylene glycol","explanation":"✗ ผิด — PG = humectant/co-solvent ช่วยละลายยา และดึงน้ำ"},{"label":"D","text":"White petrolatum","explanation":"✓ ถูก — White petrolatum = emollient/occlusive agent ให้ความชุ่มชื้น ปิดผิวหนัง"},{"label":"E","text":"Sodium lauryl sulfate","explanation":"✗ ผิด — SLS = anionic surfactant ไม่มีในสูตรตำรับ Terbinafine cream ทั่วไป"}],"key_takeaway":"Cream composition: Drug + Emulsifiers (Span+Tween) + Oil phase (petrolatum) + Water phase + Humectant (PG) + Preservative"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('96fb5653-2901-494a-b3ff-0b0f679dc22c', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 96, 'เหตุใด Alendronate effervescent tablet จึงต้องใช้ dry granulation', NULL, '[{"label":"A","text":"เพื่อเพิ่ม binding"},{"label":"B","text":"เพราะ water sensitive เหมือนกัน"},{"label":"C","text":"เพราะง่ายที่สุด"},{"label":"D","text":"Alendronate + effervescent ไวต่อความชื้น → ต้องหลีกเลี่ยงน้ำ"},{"label":"E","text":"เพื่อลด particle size"}]'::jsonb, 'D', 'Citric acid + Sodium bicarbonate ทำปฏิกิริยากับน้ำทันที → ต้องผลิตในสภาพ dry (dry granulation/roller compaction)', '{"summary":"เหตุผลที่ Alendronate effervescent ต้องใช้ Dry Granulation","reason":"Effervescent + Alendronate ทั้งคู่ไวต่อความชื้น → dry granulation หลีกเลี่ยงน้ำ","choices":[{"label":"A","text":"เพื่อเพิ่ม binding","explanation":"✗ ผิด — Dry granulation ใช้แรงอัด (mechanical compaction) ไม่ใช่ binder solution"},{"label":"B","text":"เพราะ water sensitive เหมือนกัน","explanation":"✗ ผิด — ตอบไม่ครบ ไม่ได้อธิบายกลไกที่ชัดเจน"},{"label":"C","text":"เพราะง่ายที่สุด","explanation":"✗ ผิด — Dry granulation ไม่ใช่กระบวนการที่ง่ายที่สุด; เหตุผลคือ chemistry ไม่ใช่ความสะดวก"},{"label":"D","text":"Alendronate + effervescent ไวต่อความชื้น → ต้องหลีกเลี่ยงน้ำ","explanation":"✓ ถูก — Citric acid + NaHCO₃ ทำปฏิกิริยากับน้ำทันที → CO₂ → effervescent system เสีย; Alendronate ยังดูดความชื้น → hydrolysis; dry granulation เป็นทางเดียวที่เหมาะ"},{"label":"E","text":"เพื่อลด particle size","explanation":"✗ ผิด — Dry granulation เพิ่ม particle size (agglomeration) ไม่ใช่ลด"}],"key_takeaway":"Effervescent granulation ต้องทำใน controlled humidity (<25% RH); dry granulation (roller compaction/slugging)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:13') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9f6f1126-0169-4531-a059-3824b77ac7bd', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 97, 'ใน tablet สูตร (MCC, Mg stearate, Lactose, PVP, Colloidal silicon dioxide, Sodium starch glycolate) PVP ทำหน้าที่อะไร', NULL, '[{"label":"A","text":"Disintegrant"},{"label":"B","text":"Binder"},{"label":"C","text":"Lubricant"},{"label":"D","text":"Glidant"},{"label":"E","text":"Diluent"}]'::jsonb, 'B', 'PVP (Povidone) = Binder ใน wet granulation ยึดอนุภาค — MCC/Lactose = Diluent, Mg stearate = Lubricant, Na starch glycolate = Disintegrant', '{"summary":"หน้าที่ของ PVP ใน Tablet Formulation","reason":"PVP (Povidone) = binder ใน wet granulation ยึดอนุภาค powder เข้าหากัน","choices":[{"label":"A","text":"Disintegrant","explanation":"✗ ผิด — Disintegrant เช่น Sodium starch glycolate, Croscarmellose sodium ทำให้ tablet แตกตัว"},{"label":"B","text":"Binder","explanation":"✓ ถูก — PVP (Povidone K30/K29-32) = binder ใน wet granulation; ละลายใน water/alcohol เป็น granulating solution ยึด primary particles"},{"label":"C","text":"Lubricant","explanation":"✗ ผิด — Lubricant เช่น Mg stearate, stearic acid ลดแรงเสียดทาน"},{"label":"D","text":"Glidant","explanation":"✗ ผิด — Glidant เช่น Colloidal SiO₂, Talc ช่วย flowability"},{"label":"E","text":"Diluent","explanation":"✗ ผิด — Diluent เช่น MCC, Lactose เพิ่ม bulk ไม่ใช่ PVP"}],"key_takeaway":"Tablet excipients: Diluent (MCC/Lactose), Binder (PVP/HPC), Disintegrant (SSG), Lubricant (MgSt), Glidant (SiO₂)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('38ee6969-708e-414e-8a7f-be0e38d2c7ec', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 98, 'สารใดช่วยลด sedimentation rate ใน suspension โดยเพิ่ม viscosity ของ medium', NULL, '[{"label":"A","text":"Simethicone"},{"label":"B","text":"Glycerin"},{"label":"C","text":"Colloidal silicon dioxide"},{"label":"D","text":"Sorbitol"},{"label":"E","text":"Methyl cellulose"}]'::jsonb, 'E', 'Methyl cellulose (HPMC, Carbomer, Xanthan gum) = viscosity enhancer ลด sedimentation rate ตาม Stokes'' Law', '{"summary":"สารที่ลด Sedimentation Rate โดยเพิ่ม Viscosity","reason":"Methyl cellulose/HPMC เพิ่ม viscosity ของ medium → ลด v ตาม Stokes'' Law","choices":[{"label":"A","text":"Simethicone","explanation":"✗ ผิด — Simethicone = antifoaming agent ลดฟอง ไม่ใช่ viscosity enhancer"},{"label":"B","text":"Glycerin","explanation":"✗ ผิด — Glycerin ใช้เป็น humectant/sweetener; viscosity ต่ำเกินไปที่จะลด sedimentation อย่างมีนัยสำคัญ"},{"label":"C","text":"Colloidal silicon dioxide","explanation":"✗ ผิด — Colloidal SiO₂ ใช้เป็น glidant ใน solid dosage form"},{"label":"D","text":"Sorbitol","explanation":"✗ ผิด — Sorbitol เป็น sweetener/humectant"},{"label":"E","text":"Methyl cellulose","explanation":"✓ ถูก — Methyl cellulose/HPMC/Carbomer/Xanthan gum = viscosity enhancers ใน suspension; เพิ่ม η (viscosity) → ลด v ตาม Stokes'' Law v = 2r²Δρg/9η"}],"key_takeaway":"Stokes: v ∝ r² และ Δρ; v ∝ 1/η; ลด sedimentation โดย: ลด particle size, ลด Δρ, เพิ่ม viscosity"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('83757e37-0651-420b-b66b-a6b5b1b827d7', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 99, 'Glycerin ทำหน้าที่อะไรใน suspension เป็นหลัก', NULL, '[{"label":"A","text":"Humectant"},{"label":"B","text":"Flocculating agent"},{"label":"C","text":"Preservative"},{"label":"D","text":"Wetting agent"},{"label":"E","text":"Sweetener"}]'::jsonb, 'A', 'Glycerin = Humectant ดึงน้ำ ป้องกันผลิตภัณฑ์แห้ง — ยังใช้เป็น sweetener และ vehicle ในบางสูตร', '{"summary":"หน้าที่หลักของ Glycerin ใน Suspension","reason":"Glycerin = humectant ป้องกันการแห้ง และช่วยรักษาความชุ่มชื้น","choices":[{"label":"A","text":"Humectant","explanation":"✓ ถูก — Glycerin = hygroscopic humectant ดึงน้ำจาก atmosphere ป้องกัน suspension แห้งและ caking; ยังเป็น sweetener/cosolvent"},{"label":"B","text":"Flocculating agent","explanation":"✗ ผิด — Flocculating agent เช่น electrolyte (NaCl) ทำให้อนุภาค flocculat"},{"label":"C","text":"Preservative","explanation":"✗ ผิด — Glycerin มีคุณสมบัติ antimicrobial ที่ความเข้มข้นสูง แต่ไม่ใช้เป็น primary preservative"},{"label":"D","text":"Wetting agent","explanation":"✗ ผิด — Wetting agent เช่น Polysorbate 80, SLS ลด contact angle ช่วย dispersibility"},{"label":"E","text":"Sweetener","explanation":"✗ ผิด — Glycerin เป็น sweetener ได้ แต่ไม่ใช่หน้าที่หลักใน pharmaceutical suspension"}],"key_takeaway":"Glycerin roles: humectant (ป้องกันแห้ง), solvent, cosolvent, sweetener, plasticizer; ความเข้มข้น 15-20% = antimicrobial"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('fbeb21d0-1723-4ba9-b75b-da903884db21', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 100, 'ตาม Stokes'' Law ปัจจัยใด "เพิ่ม" sedimentation rate', NULL, '[{"label":"A","text":"เพิ่ม viscosity ของ medium"},{"label":"B","text":"ลด particle size"},{"label":"C","text":"เพิ่มผลต่างความหนาแน่น (ρ_p − ρ_m)"},{"label":"D","text":"เพิ่ม temperature"},{"label":"E","text":"ลด particle density"}]'::jsonb, 'C', 'Stokes: v = 2r²(ρ_p−ρ_m)g/9η → เพิ่ม (ρ_p−ρ_m) = เพิ่ม rate; เพิ่ม viscosity = ลด rate; ลด r = ลด rate มาก', '{"summary":"ปัจจัยที่เพิ่ม Sedimentation Rate ตาม Stokes'' Law","reason":"Stokes: v = 2r²(ρₚ-ρₘ)g/9η; เพิ่ม Δρ = เพิ่ม sedimentation rate","choices":[{"label":"A","text":"เพิ่ม viscosity ของ medium","explanation":"✗ ผิด — เพิ่ม η → ลด v (ตัวหาร); ตรงข้าม"},{"label":"B","text":"ลด particle size","explanation":"✗ ผิด — ลด r → ลด v อย่างมาก (r² term); ลดขนาดอนุภาค = วิธีหลักลด sedimentation"},{"label":"C","text":"เพิ่มผลต่างความหนาแน่น (ρ_p − ρ_m)","explanation":"✓ ถูก — v ∝ (ρₚ-ρₘ); เพิ่ม Δρ (เช่น ใช้ particle หนักกว่า medium มาก) → เพิ่ม sedimentation rate"},{"label":"D","text":"เพิ่ม temperature","explanation":"✗ ผิด — เพิ่ม temperature → ลด viscosity → เพิ่ม v แต่ไม่ใช่ primary factor ที่ถามในบริบทนี้ และ ρ ก็เปลี่ยนด้วย"},{"label":"E","text":"ลด particle density","explanation":"✗ ผิด — ลด ρₚ → ลด Δρ → ลด v ถ้า ρₚ > ρₘ"}],"key_takeaway":"Stokes: v = 2r²(ρₚ−ρₘ)g/9η; ลด sedimentation: ↓r (micronize), ↑η (thickener), ↓Δρ, flocculation"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f8f576e6-a80a-4e17-b734-9562babcd321', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 101, 'วิธีการให้ Potassium chloride ข้อใด "ไม่ปลอดภัย"', NULL, '[{"label":"A","text":"เพิ่ม Furosemide"},{"label":"B","text":"เพิ่ม Spironolactone"},{"label":"C","text":"ผสม KCl ใน NSS drip ช้าๆ"},{"label":"D","text":"KCl IV bolus โดยตรง ไม่เจือจาง"},{"label":"E","text":"KCl tablet รับประทาน"}]'::jsonb, 'D', 'IV KCl bolus = ห้ามเด็ดขาด → Cardiac arrest (ventricular fibrillation) — ต้องเจือจางและให้ไม่เกิน 10-20 mEq/hr', '{"summary":"การให้ KCl ที่ไม่ปลอดภัย","reason":"IV KCl bolus โดยตรง = cardiac arrest; ต้องเจือจางและให้ช้าๆ เสมอ","choices":[{"label":"A","text":"เพิ่ม Furosemide","explanation":"✗ ผิด — Furosemide ขับ K⁺ ออก → hypokalemia; ไม่ใช่วิธีให้ KCl"},{"label":"B","text":"เพิ่ม Spironolactone","explanation":"✗ ผิด — Spironolactone เก็บ K⁺ = K-sparing; ไม่ใช่วิธีให้ KCl"},{"label":"C","text":"ผสม KCl ใน NSS drip ช้าๆ","explanation":"✗ ผิด — นี่คือวิธีที่ปลอดภัยและถูกต้อง"},{"label":"D","text":"KCl IV bolus โดยตรง ไม่เจือจาง","explanation":"✓ ถูก — KCl IV bolus = ห้ามเด็ดขาด → High K⁺ ทันที → Ventricular fibrillation → Cardiac arrest; KCl สารพิษถ้าให้เร็ว"},{"label":"E","text":"KCl tablet รับประทาน","explanation":"✗ ผิด — Oral KCl ปลอดภัย ดูดซึมช้า ไม่ทำ hyperkalemia ฉับพลัน"}],"key_takeaway":"KCl IV safety: ห้าม bolus; เจือจาง ≤40 mEq/L peripheral or ≤80 mEq/L central; อัตรา ≤10-20 mEq/hr + cardiac monitor"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('25f16072-0f53-4a08-a9b9-0cf6148da461', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 102, 'วิธีการให้ potassium replacement ใน hypokalemia รุนแรงที่ถูกต้อง', NULL, '[{"label":"A","text":"Dipotassium phosphate IV bolus"},{"label":"B","text":"KCl ผสม D5W ให้ใน 30 นาที"},{"label":"C","text":"KCl ผสม NSS 0.9% ให้ ≤ 20 mEq/hr พร้อม cardiac monitoring"},{"label":"D","text":"KCl 40 mEq IV bolus"},{"label":"E","text":"KCl elixir รับประทาน"}]'::jsonb, 'C', 'KCl IV: เจือจางใน NSS (ไม่ใช่ D5W เพราะ insulin อาจดัน K+ เข้าเซลล์) ≤ 20 mEq/hr พร้อม cardiac monitor', '{"summary":"วิธีให้ Potassium replacement ใน Severe Hypokalemia ที่ถูกต้อง","reason":"KCl ใน NSS (ไม่ใช่ D5W), ≤20 mEq/hr, พร้อม cardiac monitoring","choices":[{"label":"A","text":"Dipotassium phosphate IV bolus","explanation":"✗ ผิด — IV bolus ห้ามเด็ดขาด; DiKPO₄ ยังเพิ่ม phosphate เสี่ยง hypocalcemia"},{"label":"B","text":"KCl ผสม D5W ให้ใน 30 นาที","explanation":"✗ ผิด — ผสม D5W ไม่ดี: insulin-mediated glucose uptake จะดัน K⁺ เข้าเซลล์ → เพิ่ม hypokalemia; 30 นาทีเร็วเกินไป"},{"label":"C","text":"KCl ผสม NSS 0.9% ให้ ≤ 20 mEq/hr พร้อม cardiac monitoring","explanation":"✓ ถูก — NSS ไม่มี glucose → ไม่ดัน K⁺ เข้าเซลล์; อัตรา ≤20 mEq/hr ปลอดภัย; cardiac monitor ป้องกัน arrhythmia"},{"label":"D","text":"KCl 40 mEq IV bolus","explanation":"✗ ผิด — Bolus → cardiac arrest"},{"label":"E","text":"KCl elixir รับประทาน","explanation":"✗ ผิด — Oral ใช้ได้ใน mild-moderate hypokalemia ไม่เหมาะ severe ที่ต้องแก้เร็ว"}],"key_takeaway":"KCl replacement: severe → IV KCl in NSS ≤20 mEq/hr + cardiac monitor; mild → Oral KCl; ต้อง correct hypomagnesemia ด้วย"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('55c0b7c7-70e1-4c3f-acff-283d7cd39534', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 103, 'อัตราการให้ KCl ทาง IV ที่ปลอดภัยสูงสุดในผู้ใหญ่ทั่วไปคือ', NULL, '[{"label":"A","text":"5 mEq/hr"},{"label":"B","text":"10-20 mEq/hr"},{"label":"C","text":"40 mEq/hr เสมอ"},{"label":"D","text":"80 mEq/hr"},{"label":"E","text":"ไม่มีขีดจำกัด"}]'::jsonb, 'B', 'Maximum KCl IV rate = 10-20 mEq/hr (peripheral) ในกรณีฉุกเฉิน max 40 mEq/hr ทาง central line + cardiac monitoring', '{"summary":"อัตรา IV KCl ที่ปลอดภัยสูงสุดในผู้ใหญ่","reason":"Peripheral IV: max 10-20 mEq/hr; Central line emergency: max 40 mEq/hr","choices":[{"label":"A","text":"5 mEq/hr","explanation":"✗ ผิด — 5 mEq/hr ปลอดภัยแต่ช้าเกินไปในกรณีที่ต้องแก้ไขเร็ว"},{"label":"B","text":"10-20 mEq/hr","explanation":"✓ ถูก — Standard maximum rate = 10-20 mEq/hr ทาง peripheral IV; ในกรณีฉุกเฉิน max 40 mEq/hr ต้องทาง central line พร้อม cardiac monitoring"},{"label":"C","text":"40 mEq/hr เสมอ","explanation":"✗ ผิด — 40 mEq/hr เฉพาะ central line + cardiac monitoring ในกรณีฉุกเฉินเท่านั้น ไม่ใช่ ''เสมอ''"},{"label":"D","text":"80 mEq/hr","explanation":"✗ ผิด — เร็วเกินไปและเสี่ยง cardiac arrest"},{"label":"E","text":"ไม่มีขีดจำกัด","explanation":"✗ ผิด — มีขีดจำกัดชัดเจน ขึ้นกับ route, concentration, clinical status"}],"key_takeaway":"KCl IV rate: Peripheral ≤10-20 mEq/hr, Central emergency ≤40 mEq/hr; concentration: peripheral ≤40 mEq/L, central ≤80 mEq/L"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1c8bc544-a362-43e4-94cd-6bdecc1f0993', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 104, 'ผลข้างเคียงหลักของ Dipotassium phosphate IV มากเกินขนาดคือ', NULL, '[{"label":"A","text":"Hypokalemia"},{"label":"B","text":"Hypernatremia"},{"label":"C","text":"Hyperkalemia และ Hyperphosphatemia"},{"label":"D","text":"Hypocalcemia เท่านั้น"},{"label":"E","text":"Metabolic alkalosis"}]'::jsonb, 'C', 'Dipotassium phosphate: เพิ่ม K+ และ PO₄³⁻ → Hyperkalemia + Hyperphosphatemia (phosphate สูง → hypocalcemia ตามมา)', '{"summary":"ADR ของ Dipotassium Phosphate IV มากเกินขนาด","reason":"DiKPO₄ เพิ่ม K⁺ + PO₄³⁻ → Hyperkalemia + Hyperphosphatemia → hypocalcemia ตามมา","choices":[{"label":"A","text":"Hypokalemia","explanation":"✗ ผิด — DiKPO₄ ให้ K⁺ เพิ่ม → hyperkalemia ไม่ใช่ hypokalemia"},{"label":"B","text":"Hypernatremia","explanation":"✗ ผิด — DiKPO₄ ไม่มี Na⁺"},{"label":"C","text":"Hyperkalemia และ Hyperphosphatemia","explanation":"✓ ถูก — DiKPO₄ (K₂HPO₄): K⁺ → hyperkalemia; PO₄³⁻ → hyperphosphatemia → chelate Ca²⁺ → hypocalcemia → tetany, seizures"},{"label":"D","text":"Hypocalcemia เท่านั้น","explanation":"✗ ผิด — Hypocalcemia เป็น consequence ของ hyperphosphatemia แต่ hyperkalemia + hyperphosphatemia เป็น direct effect ด้วย"},{"label":"E","text":"Metabolic alkalosis","explanation":"✗ ผิด — Phosphate เป็น buffer ไม่ก่อ metabolic alkalosis"}],"key_takeaway":"DiKPO₄ overdose: K⁺ excess → hyperkalemia → arrhythmia; PO₄³⁻ excess → hypocalcemia → tetany; monitor ECG"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8dac9cd0-fe3d-4e52-9c3c-8338b0baca3f', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', 'Pharmacyguru', 1, 105, 'ผู้ป่วยใช้ Losartan ร่วมกับ ACE inhibitor ความเสี่ยงที่ต้องระวังมากที่สุดคือ', NULL, '[{"label":"A","text":"Hyperkalemia"},{"label":"B","text":"Hypokalemia"},{"label":"C","text":"Hypernatremia"},{"label":"D","text":"Hyponatremia"},{"label":"E","text":"Hypocalcemia"}]'::jsonb, 'A', 'Double RAAS blockade (ARB + ACEi): เพิ่ม hyperkalemia, hypotension, AKI อย่างมีนัยสำคัญ — ONTARGET trial', '{"summary":"ความเสี่ยงจากการใช้ Losartan ร่วมกับ ACE inhibitor","reason":"Double RAAS blockade → Hyperkalemia + Hypotension + AKI","choices":[{"label":"A","text":"Hyperkalemia","explanation":"✓ ถูก — Double RAAS blockade (ARB+ACEi): ทั้งคู่ลด aldosterone → เก็บ K⁺ → hyperkalemia สูงมาก; ONTARGET trial แสดงว่า dual blockade เพิ่ม adverse outcomes"},{"label":"B","text":"Hypokalemia","explanation":"✗ ผิด — RAAS blockade เก็บ K⁺ ทำให้ hyperkalemia ไม่ใช่ hypokalemia"},{"label":"C","text":"Hypernatremia","explanation":"✗ ผิด — RAAS blockade ลด aldosterone → Na⁺ ขับออกมากขึ้น → hyponatremia possible ไม่ใช่ hypernatremia"},{"label":"D","text":"Hyponatremia","explanation":"✗ ผิด — เป็นไปได้เล็กน้อย แต่ไม่ใช่ความเสี่ยงหลักที่ต้องระวัง"},{"label":"E","text":"Hypocalcemia","explanation":"✗ ผิด — RAAS blockade ไม่มีผลโดยตรงต่อ Ca²⁺"}],"key_takeaway":"ONTARGET: ACEi+ARB dual blockade → ↑ hyperkalemia, ↑ AKI, ↑ hypotension; ไม่แนะนำ combination นี้"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b6d72dfc-d329-47fb-b53c-92483f594617', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 106, 'Vitamin E ร่วมกับ Simvastatin อาจมีปฏิสัมพันธ์อย่างไร', NULL, '[{"label":"A","text":"ลด statin absorption"},{"label":"B","text":"เพิ่ม statin efficacy"},{"label":"C","text":"Antioxidant อาจลด statin efficacy บางส่วน"},{"label":"D","text":"ไม่มีปฏิสัมพันธ์"},{"label":"E","text":"เพิ่ม hepatotoxicity"}]'::jsonb, 'C', 'Theoretical: antioxidant (Vit E) อาจ interfere กับ oxidative stress pathway ที่ statin ออกฤทธิ์ — หลักฐานยังไม่ชัดเจน', '{"summary":"ปฏิสัมพันธ์ระหว่าง Vitamin E กับ Simvastatin","reason":"Antioxidant (Vit E) อาจลด statin efficacy ผ่าน oxidative pathway (theoretical)","choices":[{"label":"A","text":"ลด statin absorption","explanation":"✗ ผิด — Vit E ไม่ลด oral absorption ของ statin"},{"label":"B","text":"เพิ่ม statin efficacy","explanation":"✗ ผิด — ไม่มีหลักฐานว่า Vit E เพิ่ม statin efficacy"},{"label":"C","text":"Antioxidant อาจลด statin efficacy บางส่วน","explanation":"✓ ถูก — Theoretical DDI: antioxidants (Vit E, C, A) อาจ attenuate statin benefits โดยเฉพาะ HDL-raising effect และ vasoprotective mechanism ที่เกี่ยวกับ oxidative stress; หลักฐานยังไม่ชัดเจนใน clinical practice"},{"label":"D","text":"ไม่มีปฏิสัมพันธ์","explanation":"✗ ผิด — มี theoretical DDI ที่รายงานในการศึกษาบางชิ้น"},{"label":"E","text":"เพิ่ม hepatotoxicity","explanation":"✗ ผิด — ไม่มีหลักฐานว่า Vit E เพิ่ม statin hepatotoxicity"}],"key_takeaway":"Vit E + statin: ไม่แนะนำ high-dose antioxidant supplement ร่วมกับ statin (HPS trial); ใน formulation Vit E เป็น antioxidant excipient ไม่ใช่ active supplement"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('79b560bd-27af-40ee-82a6-c74689933db4', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 107, 'Vitamin E ใน statin capsule ทำหน้าที่อะไรในสูตรตำรับ', NULL, '[{"label":"A","text":"Active ingredient"},{"label":"B","text":"Antioxidant (กันยาเสื่อมจาก oxidation)"},{"label":"C","text":"Lubricant"},{"label":"D","text":"Binder"},{"label":"E","text":"Disintegrant"}]'::jsonb, 'B', 'Vitamin E (dl-alpha-tocopherol acetate) = antioxidant ในสูตรตำรับ capsule ป้องกัน statin จากการ oxidize', '{"summary":"หน้าที่ของ Vitamin E ในสูตรตำรับ Capsule","reason":"Vitamin E ในสูตรตำรับ = antioxidant excipient ป้องกัน statin oxidize","choices":[{"label":"A","text":"Active ingredient","explanation":"✗ ผิด — Vitamin E ในสูตรตำรับนี้เป็น excipient ไม่ใช่ active drug"},{"label":"B","text":"Antioxidant (กันยาเสื่อมจาก oxidation)","explanation":"✓ ถูก — dl-alpha-tocopherol acetate (Vitamin E) ทำหน้าที่ antioxidant ใน capsule formulation ป้องกัน statin (ซึ่งมี double bonds) จาก oxidative degradation → ยืด shelf life"},{"label":"C","text":"Lubricant","explanation":"✗ ผิด — Lubricant เช่น Mg stearate, hydrogenated vegetable oil ไม่ใช่ Vit E"},{"label":"D","text":"Binder","explanation":"✗ ผิด — Binder เช่น PVP, HPC ไม่ใช่ Vit E"},{"label":"E","text":"Disintegrant","explanation":"✗ ผิด — Disintegrant เช่น SSG, CCS ไม่ใช่ Vit E"}],"key_takeaway":"Common antioxidants ใน formulation: BHA, BHT, Vitamin E (tocopherol), Na metabisulfite, Na ascorbate; ใช้ป้องกัน oxidative degradation"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f1325203-1a51-487a-b6f5-638e2126a3de', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 108, 'Epinephrine 1 mg ผสม NSS รวม 10 mL ได้ความเข้มข้น', NULL, '[{"label":"A","text":"0.01 mg/mL"},{"label":"B","text":"0.1 mg/mL (1:10,000)"},{"label":"C","text":"0.09 mg/mL"},{"label":"D","text":"1 mg/mL"},{"label":"E","text":"0.001 mg/mL"}]'::jsonb, 'B', 'Epi 1 mg ใน 10 mL = 0.1 mg/mL = 1:10,000 — ใช้ใน cardiac arrest (IV/IO) และ severe bradycardia', '{"summary":"ความเข้มข้นของ Epinephrine 1 mg ใน 10 mL","reason":"1 mg ใน 10 mL = 0.1 mg/mL = 1:10,000","choices":[{"label":"A","text":"0.01 mg/mL","explanation":"✗ ผิด — 0.01 mg/mL = 1 mg ใน 100 mL; ผิด"},{"label":"B","text":"0.1 mg/mL (1:10,000)","explanation":"✓ ถูก — 1 mg ÷ 10 mL = 0.1 mg/mL; เป็น 1:10,000 concentration ใช้สำหรับ cardiac arrest (IV/IO 1 mg = 10 mL), bradycardia"},{"label":"C","text":"0.09 mg/mL","explanation":"✗ ผิด — ไม่ใช่ตัวเลขมาตรฐาน"},{"label":"D","text":"1 mg/mL","explanation":"✗ ผิด — 1 mg/mL = 1:1,000 ซึ่งเป็น Epinephrine สำหรับ anaphylaxis IM (0.3-0.5 mL = 0.3-0.5 mg)"},{"label":"E","text":"0.001 mg/mL","explanation":"✗ ผิด — 0.001 mg/mL = 1 mg ใน 1,000 mL; ผิด"}],"key_takeaway":"Epinephrine concentrations: 1:1000 = 1mg/mL (anaphylaxis IM); 1:10,000 = 0.1mg/mL (cardiac arrest IV); 1:100,000 (local anesthesia)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('37edd75c-87c0-4d89-a4aa-7df65cafbb67', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 109, 'Epinephrine HCl solution มีคุณสมบัติใด', NULL, '[{"label":"A","text":"เสถียรใน alkaline pH"},{"label":"B","text":"เก็บอุณหภูมิห้องได้นาน"},{"label":"C","text":"ต้องป้องกันแสง เพราะ oxidize เป็น adrenochrome (สีน้ำตาล)"},{"label":"D","text":"pH 7-9"},{"label":"E","text":"ผสมกับ NaHCO₃ ได้"}]'::jsonb, 'C', 'Epinephrine ไวต่อ oxidation และแสง → เก็บในขวดสีชา, pH 2-5 (acidic เพื่อความเสถียร), ห้ามผสมกับ NaHCO₃', '{"summary":"คุณสมบัติของ Epinephrine HCl Solution","reason":"Epinephrine ไวต่อ oxidation และแสง → เก็บในขวดสีชา pH 2-5","choices":[{"label":"A","text":"เสถียรใน alkaline pH","explanation":"✗ ผิด — Epinephrine เสถียรใน acidic pH 2-5; alkaline pH → oxidize เร็วขึ้น → adrenochrome"},{"label":"B","text":"เก็บอุณหภูมิห้องได้นาน","explanation":"✗ ผิด — ต้องเก็บในที่เย็น เพราะ oxidize ได้ง่าย; ภายหลังเปิดใช้ควรใช้ทันที"},{"label":"C","text":"ต้องป้องกันแสง เพราะ oxidize เป็น adrenochrome (สีน้ำตาล)","explanation":"✓ ถูก — Epinephrine catecholamine ไวต่อ light และ oxidation → adrenochrome (brown) + norepinephrine → ยาหมดฤทธิ์; เก็บในขวดสีชา, pH 2-5, N₂ headspace"},{"label":"D","text":"pH 7-9","explanation":"✗ ผิด — pH 7-9 = alkaline → Epi oxidize เร็ว → ต้อง pH 2-5 acidic"},{"label":"E","text":"ผสมกับ NaHCO₃ ได้","explanation":"✗ ผิด — NaHCO₃ เพิ่ม pH → alkaline → Epi oxidize ทันที; ห้ามผสม"}],"key_takeaway":"Catecholamine stability: oxidize by air, light, metal ions, alkaline pH; ป้องกัน: acidic pH + amber vial + N₂ + EDTA chelate metal"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('050715df-5558-46c7-9025-e1d21479bd29', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 110, 'NaCl 2.5% จัดเป็น solution ประเภทใด', NULL, '[{"label":"A","text":"Hypertonic"},{"label":"B","text":"Isotonic"},{"label":"C","text":"Hypotonic"},{"label":"D","text":"Isoosmotic"},{"label":"E","text":"Non-electrolyte solution"}]'::jsonb, 'A', 'NaCl isotonic = 0.9% — NaCl 2.5% > 0.9% = Hypertonic → ใช้รักษา severe hyponatremia หรือ cerebral edema', '{"summary":"การจัดประเภท NaCl 2.5% Solution","reason":"NaCl isotonic = 0.9%; NaCl 2.5% > 0.9% → Hypertonic","choices":[{"label":"A","text":"Hypertonic","explanation":"✓ ถูก — NaCl 2.5% osmolarity >> plasma (~308 mOsm/L → ~856 mOsm/L); > 0.9% isotonic = hypertonic; ใช้ severe hyponatremia, cerebral edema"},{"label":"B","text":"Isotonic","explanation":"✗ ผิด — Isotonic NaCl = 0.9%; plasma osmolarity ~280-320 mOsm/L"},{"label":"C","text":"Hypotonic","explanation":"✗ ผิด — Hypotonic < 0.9% NaCl (เช่น 0.45% half normal saline)"},{"label":"D","text":"Isoosmotic","explanation":"✗ ผิด — Isoosmotic ≈ isotonic = 0.9% NaCl ≈ 308 mOsm/L"},{"label":"E","text":"Non-electrolyte solution","explanation":"✗ ผิด — NaCl = electrolyte; non-electrolyte เช่น glucose, mannitol"}],"key_takeaway":"Tonicity: <0.9% NaCl=hypotonic, 0.9%=isotonic, >0.9%=hypertonic; ใช้ hypertonic saline ใน severe hyponatremia (Na<120 mEq/L) + symptoms"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f9177dcf-8d84-4448-8cb0-3c2a8b5619fe', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 111, 'Sodium chloride equivalent (E-value) ใช้ประโยชน์ในการคำนวณอะไร', NULL, '[{"label":"A","text":"Tonicity adjustment ของ ophthalmic/parenteral solution"},{"label":"B","text":"Drug dosage calculation"},{"label":"C","text":"pH adjustment"},{"label":"D","text":"Solubility prediction"},{"label":"E","text":"Stability testing"}]'::jsonb, 'A', 'E-value = amount of NaCl equivalent ใน tonicity ต่อ 1 g drug → คำนวณปริมาณ NaCl เพิ่ม/ลดเพื่อทำ isotonic solution', '{"summary":"ประโยชน์ของ Sodium Chloride Equivalent (E-value)","reason":"E-value ใช้คำนวณ tonicity adjustment สำหรับ ophthalmic/parenteral solution","choices":[{"label":"A","text":"Tonicity adjustment ของ ophthalmic/parenteral solution","explanation":"✓ ถูก — E-value (NaCl equivalent) = จำนวน g NaCl ที่มี osmolarity เท่ากับ drug 1 g; ใช้คำนวณปริมาณ NaCl ที่ต้องเพิ่มหรือลดเพื่อให้ solution isotonic"},{"label":"B","text":"Drug dosage calculation","explanation":"✗ ผิด — Drug dosage คำนวณจาก mg/kg หรือ BSA-based ไม่ใช้ E-value"},{"label":"C","text":"pH adjustment","explanation":"✗ ผิด — pH adjustment ใช้ acid/base titration และ Henderson-Hasselbalch equation"},{"label":"D","text":"Solubility prediction","explanation":"✗ ผิด — Solubility ใช้ HSP (Hansen Solubility Parameter) หรือ Rule of 5"},{"label":"E","text":"Stability testing","explanation":"✗ ผิด — Stability testing ใช้ ICH Q1A guidelines; E-value ไม่เกี่ยว"}],"key_takeaway":"E-value formula: ปริมาณ NaCl = 0.9 - Σ(drug%×E-value) g/100 mL; ถ้าได้ negative = หายิ่งกว่า isotonic"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('5e0cd97a-fa72-4228-ab55-6829da47ac6f', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 112, 'IV infusion 500 mL ใน 4 ชั่วโมง infusion set 20 drops/mL อัตราหยดคือ', NULL, '[{"label":"A","text":"8 drops/min"},{"label":"B","text":"10 drops/min"},{"label":"C","text":"42 drops/min"},{"label":"D","text":"125 drops/min"},{"label":"E","text":"20 drops/min"}]'::jsonb, 'C', 'Rate = 500 mL × 20 drops/mL ÷ 240 min = 10,000/240 = 41.7 ≈ 42 drops/min', '{"summary":"คำนวณอัตราหยด IV Infusion","reason":"Rate = Volume × Drop factor ÷ Time(min) = 500×20÷240 = 41.7 ≈ 42 drops/min","choices":[{"label":"A","text":"8 drops/min","explanation":"✗ ผิด — 8 drops/min = 500×20÷1250; ผิด"},{"label":"B","text":"10 drops/min","explanation":"✗ ผิด — 10 drops/min = 500×12÷600; ผิด"},{"label":"C","text":"42 drops/min","explanation":"✓ ถูก — Rate = (500 mL × 20 drops/mL) ÷ (4×60 min) = 10,000 ÷ 240 = 41.67 ≈ 42 drops/min"},{"label":"D","text":"125 drops/min","explanation":"✗ ผิด — 125 drops/min เร็วเกินไป; ≈ 500 mL ใน 1 ชั่วโมง"},{"label":"E","text":"20 drops/min","explanation":"✗ ผิด — 20 drops/min = 500×20÷500; หมายถึง 500 mL ใน 500 นาที ≈ 8 ชั่วโมง"}],"key_takeaway":"IV rate formula: drops/min = Volume(mL) × Drop factor(drops/mL) ÷ Time(min); mL/hr = Volume ÷ Hours"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('24e1905a-cfb1-4f79-968a-64213bfa3152', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 113, 'Adrenaline infusion 0.1 mcg/kg/min น้ำหนัก 70 kg ผสม 1 mg ใน NSS 50 mL อัตรา pump คือ', NULL, '[{"label":"A","text":"8 mL/hr"},{"label":"B","text":"21 mL/hr"},{"label":"C","text":"0.42 mL/hr"},{"label":"D","text":"4.2 mL/hr"},{"label":"E","text":"42 mL/hr"}]'::jsonb, 'B', 'Dose = 0.1×70 = 7 mcg/min = 420 mcg/hr; Conc = 1,000/50 = 20 mcg/mL; Rate = 420/20 = 21 mL/hr', '{"summary":"คำนวณอัตรา Pump สำหรับ Adrenaline Infusion","reason":"Dose=7 mcg/min=420 mcg/hr; Conc=1000/50=20 mcg/mL; Rate=420/20=21 mL/hr","choices":[{"label":"A","text":"8 mL/hr","explanation":"✗ ผิด — 8 mL/hr = 8×20 = 160 mcg/hr = 2.3 mcg/kg/min; ผิด"},{"label":"B","text":"21 mL/hr","explanation":"✓ ถูก — Dose=0.1×70=7 mcg/min×60=420 mcg/hr; Conc=1,000 mcg/50 mL=20 mcg/mL; Rate=420÷20=21 mL/hr"},{"label":"C","text":"0.42 mL/hr","explanation":"✗ ผิด — หน่วยผิด; คำนวณผิด"},{"label":"D","text":"4.2 mL/hr","explanation":"✗ ผิด — 4.2 mL/hr×20 mcg/mL = 84 mcg/hr = 1.4 mcg/kg/min × 70 kg ≠ 0.1"},{"label":"E","text":"42 mL/hr","explanation":"✗ ผิด — 42 mL/hr×20 = 840 mcg/hr = 14 mcg/min = 0.2 mcg/kg/min ≠ 0.1"}],"key_takeaway":"Infusion rate: Rate(mL/hr) = Dose(mcg/kg/min) × Weight(kg) × 60 ÷ Concentration(mcg/mL)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7266f100-529f-482f-b954-4ceb67cc4b72', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 114, 'Dissolution S1 (n=6): Q=80%, ผล: 75,78,82,80,79,77% ผลการทดสอบเป็นอย่างไร', NULL, '[{"label":"A","text":"ผ่าน S1"},{"label":"B","text":"ผ่าน S2"},{"label":"C","text":"ไม่ผ่าน S1 → ต้องทดสอบ S2"},{"label":"D","text":"Fail ทุกขั้นตอน"},{"label":"E","text":"ผ่านระดับ 2"}]'::jsonb, 'C', 'Mean = 78.5% < Q (80%) → ไม่ผ่าน S1 → ต้องทำ S2 (อีก 6 เม็ด รวม 12 เม็ด)', '{"summary":"Dissolution Test S1/S2 Staging — Interpretation","reason":"ค่าเฉลี่ย S1 < Q = ไม่ผ่าน S1 → ต้องทดสอบ S2 ต่อ","choices":[{"label":"A","text":"ผ่าน S1","explanation":"✗ ผิด — S1 ผ่านได้เมื่อ ทุก unit ≥ Q−15% และ mean ≥ Q; ข้อนี้ mean = 78.5% < Q 80% = ไม่ผ่าน"},{"label":"B","text":"ผ่าน S2","explanation":"✗ ผิด — ยังไม่ได้ทำ S2 ยังไม่สามารถบอกว่าผ่าน S2"},{"label":"C","text":"ไม่ผ่าน S1 → ต้องทดสอบ S2","explanation":"✓ ถูก — S1 criteria: 1) ไม่มี unit < Q-15% = 80-15=65% (ทุก unit ≥65%) 2) mean ≥ Q = mean 78.5% < 80% → ไม่ผ่าน S1 → ต้องทำ S2 (n=6 เพิ่ม รวม 12 units)"},{"label":"D","text":"Fail ทุกขั้นตอน","explanation":"✗ ผิด — ยังสรุปไม่ได้ว่า fail โดยรวม ต้องทำ S2 ก่อน"},{"label":"E","text":"ผ่านระดับ 2","explanation":"✗ ผิด — ยังไม่ได้ทำ S2"}],"key_takeaway":"USP Dissolution: S1(n=6): mean≥Q, ไม่มี<Q-15%; S2(n=12): mean≥Q, ≤2 units<Q-15%; S3(n=24): mean≥Q, ไม่มี<Q-25%"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0a8c4101-0497-45f7-839d-754abada0029', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', 'Pharmacyguru', 1, 115, 'RR = 1.3, 95% CI (0.85-1.17) ข้อสรุปที่ถูกต้อง', NULL, '[{"label":"A","text":"Amoxicillin/Clavulanate ดีกว่า Cefixime"},{"label":"B","text":"ไม่มีความแตกต่างอย่างมีนัยสำคัญ (95% CI ครอบ 1.0)"},{"label":"C","text":"Cefixime ดีกว่า"},{"label":"D","text":"ยังสรุปไม่ได้"},{"label":"E","text":"Amoxicillin/Clavulanate แย่กว่า"}]'::jsonb, 'B', '95% CI (0.85-1.17) ครอบค่า 1.0 → ไม่มีความแตกต่าง significant (p > 0.05)', '{"summary":"การแปลผล RR = 1.3, 95% CI (0.85-1.17)","reason":"95% CI ครอบ 1.0 → ไม่มีความแตกต่างอย่างมีนัยสำคัญ","choices":[{"label":"A","text":"Amoxicillin/Clavulanate ดีกว่า Cefixime","explanation":"✗ ผิด — ถ้า significant RR > 1 และ CI ไม่ครอบ 1.0; ข้อนี้ CI ครอบ 1.0"},{"label":"B","text":"ไม่มีความแตกต่างอย่างมีนัยสำคัญ (95% CI ครอบ 1.0)","explanation":"✓ ถูก — 95% CI (0.85-1.17) ครอบค่า 1.0 → p > 0.05 → ไม่มีความแตกต่างอย่างมีนัยสำคัญ; แม้ RR = 1.3 แต่ confidence interval กว้างและครอบ null"},{"label":"C","text":"Cefixime ดีกว่า","explanation":"✗ ผิด — ถ้า Cefixime ดีกว่า RR < 1 และ CI < 1.0 ทั้งหมด"},{"label":"D","text":"ยังสรุปไม่ได้","explanation":"✗ ผิด — สรุปได้ชัดเจน: ไม่มีนัยสำคัญ เพราะ CI ครอบ 1.0"},{"label":"E","text":"Amoxicillin/Clavulanate แย่กว่า","explanation":"✗ ผิด — ถ้า Amoxiclav แย่กว่า RR < 1 และ CI < 1.0 ทั้งหมด"}],"key_takeaway":"สรุป CI ของ RR: ถ้า CI ครอบ 1.0 = not significant; ไม่ครอบ 1.0 = significant; ขนาด CI บอก precision ของการศึกษา"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4a309228-726d-4500-a0df-f335e532e1d0', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 116, 'ต้องการทดสอบว่า adherence (ดี/ไม่ดี) แตกต่างกันระหว่าง 2 กลุ่ม ควรใช้ test ใด', NULL, '[{"label":"A","text":"Chi-square test"},{"label":"B","text":"Logistic regression"},{"label":"C","text":"Pearson correlation"},{"label":"D","text":"ANOVA"},{"label":"E","text":"Paired t-test"}]'::jsonb, 'A', 'ข้อมูล categorical 2×2 (adherence ดี/ไม่ดี × กลุ่ม) → Chi-square test เหมาะที่สุด', '{"summary":"Statistical test สำหรับ categorical outcome ระหว่าง 2 กลุ่ม","reason":"Adherence ดี/ไม่ดี × กลุ่ม = 2×2 table → Chi-square test","choices":[{"label":"A","text":"Chi-square test","explanation":"✓ ถูก — ข้อมูล categorical (adherence: ดี/ไม่ดี) × 2 กลุ่ม = contingency table → Chi-square test; ถ้า expected frequency < 5 ใช้ Fisher''s exact test แทน"},{"label":"B","text":"Logistic regression","explanation":"✗ ผิด — Logistic regression ใช้เพื่อ predict outcome จาก multiple predictors ไม่ใช่แค่เปรียบเทียบ 2 กลุ่ม"},{"label":"C","text":"Pearson correlation","explanation":"✗ ผิด — Pearson correlation ใช้กับ 2 continuous variables ไม่ใช่ categorical"},{"label":"D","text":"ANOVA","explanation":"✗ ผิด — ANOVA เปรียบเทียบ mean ของ continuous variable ≥ 3 กลุ่ม"},{"label":"E","text":"Paired t-test","explanation":"✗ ผิด — Paired t-test ใช้กับ continuous variable ที่วัด 2 ครั้งใน subject เดียวกัน"}],"key_takeaway":"Statistical test selection: Categorical→Chi-square/Fisher; Continuous 2 groups→t-test; ≥3 groups→ANOVA; Correlation→Pearson/Spearman"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9a303f4f-8547-48a6-a8a7-2fef564997e1', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 117, 'ต้องการหาปัจจัยทำนาย adherence (binary: ดี/ไม่ดี) ควรใช้ test ใด', NULL, '[{"label":"A","text":"Chi-square test"},{"label":"B","text":"Logistic regression"},{"label":"C","text":"Pearson correlation"},{"label":"D","text":"ANOVA"},{"label":"E","text":"Paired t-test"}]'::jsonb, 'B', 'Binary outcome + multiple predictors → Multiple logistic regression — ให้ Odds Ratio ของแต่ละปัจจัย', '{"summary":"Statistical test สำหรับ predict Binary Outcome จาก Multiple Predictors","reason":"Binary outcome + multiple predictors → Logistic Regression","choices":[{"label":"A","text":"Chi-square test","explanation":"✗ ผิด — Chi-square ใช้เปรียบเทียบ 2 กลุ่ม ไม่ใช่ predictive model ที่มี multiple variables"},{"label":"B","text":"Logistic regression","explanation":"✓ ถูก — Binary outcome (adherence ดี/ไม่ดี) + multiple predictors (age, sex, dose, etc.) → Multiple logistic regression; ให้ Odds Ratio (OR) ของแต่ละ predictor"},{"label":"C","text":"Pearson correlation","explanation":"✗ ผิด — Pearson ใช้กับ continuous variables ไม่ใช่ binary outcome"},{"label":"D","text":"ANOVA","explanation":"✗ ผิด — ANOVA วิเคราะห์ continuous outcome ไม่ใช่ binary"},{"label":"E","text":"Paired t-test","explanation":"✗ ผิด — ไม่เกี่ยวกับ predictors"}],"key_takeaway":"Logistic regression: binary outcome → OR; Linear regression: continuous outcome → β coefficient; Cox regression: time-to-event → Hazard Ratio"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4e348c7a-0376-474d-aeb6-e852dd0e9f27', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', 'Pharmacyguru', 1, 118, 'ABC inventory analysis: รายการยาที่มูลค่าสูง ~80% ของมูลค่าทั้งหมด จัดเป็น class ใด', NULL, '[{"label":"A","text":"Class A"},{"label":"B","text":"Class B"},{"label":"C","text":"Class C"},{"label":"D","text":"Class D"},{"label":"E","text":"Class E"}]'::jsonb, 'A', 'ABC: A = 20% ของรายการ → 80% มูลค่า; B = 30% รายการ → 15%; C = 50% รายการ → 5% — Class A ควบคุมเข้มงวดที่สุด', '{"summary":"ABC Inventory Analysis","reason":"Class A = 20% ของรายการยา แต่มีมูลค่า ~80% ของทั้งหมด","choices":[{"label":"A","text":"Class A","explanation":"✓ ถูก — ABC analysis (Pareto principle): Class A = ~20% รายการ → ~80% มูลค่าทั้งหมด; ควบคุมเข้มงวดที่สุด; จัดเก็บน้อยชิ้น monitor stock บ่อย"},{"label":"B","text":"Class B","explanation":"✗ ผิด — Class B = ~30% รายการ → ~15% มูลค่า; ระดับกลาง"},{"label":"C","text":"Class C","explanation":"✗ ผิด — Class C = ~50% รายการ → ~5% มูลค่า; ควบคุมน้อยสุด สั่งซื้อครั้งละมาก"},{"label":"D","text":"Class D","explanation":"✗ ผิด — ไม่มี Class D ใน standard ABC analysis"},{"label":"E","text":"Class E","explanation":"✗ ผิด — ไม่มี Class E ใน standard ABC analysis"}],"key_takeaway":"ABC: A=vital, B=essential, C=desirable; Inventory method: A=periodic review (frequent), C=fixed order quantity"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('fd700929-a394-4190-9705-05cf515db7ce', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', 'Pharmacyguru', 1, 119, 'Mycophenolate mofetil (MMF) มีกลไกการออกฤทธิ์อย่างไร', NULL, '[{"label":"A","text":"ยับยั้ง purine base guanine ใช้ adenine"},{"label":"B","text":"ยับยั้ง tyrosine kinase"},{"label":"C","text":"ยับยั้ง pyrimidine analogue"},{"label":"D","text":"ยับยั้ง IMPDH → ลด de novo guanosine synthesis"},{"label":"E","text":"ยับยั้ง calcineurin"}]'::jsonb, 'D', 'MMF → Mycophenolic acid → ยับยั้ง IMPDH → ลด guanosine → selective antiproliferative บน T และ B lymphocytes', '{"summary":"กลไกการออกฤทธิ์ของ Mycophenolate Mofetil (MMF)","reason":"MMF → Mycophenolic acid → ยับยั้ง IMPDH → ลด de novo guanosine → antiproliferative","choices":[{"label":"A","text":"ยับยั้ง purine base guanine ใช้ adenine","explanation":"✗ ผิด — คำอธิบายไม่ถูกต้อง; IMPDH ยับยั้ง → ลด guanosine (purine) synthesis ทั้งหมด"},{"label":"B","text":"ยับยั้ง tyrosine kinase","explanation":"✗ ผิด — TKI เช่น Imatinib, Erlotinib; ไม่ใช่ MMF"},{"label":"C","text":"ยับยั้ง pyrimidine analogue","explanation":"✗ ผิด — Pyrimidine synthesis inhibitor เช่น Leflunomide (DHODH inhibitor)"},{"label":"D","text":"ยับยั้ง IMPDH → ลด de novo guanosine synthesis","explanation":"✓ ถูก — MMF hydrolyzed to MPA → inhibit IMPDH (inosine monophosphate dehydrogenase) → block de novo guanosine synthesis → lymphocytes depend on de novo pathway → selective antiproliferative on T and B cells"},{"label":"E","text":"ยับยั้ง calcineurin","explanation":"✗ ผิด — Calcineurin inhibitors = Cyclosporine, Tacrolimus; ยับยั้ง IL-2 production"}],"key_takeaway":"MMF/MPA → IMPDH inhibition → ↓GMP → ↓lymphocyte proliferation; non-lymphocyte cells ใช้ salvage pathway จึงไม่ affected มาก"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('227a19e4-ff98-4d27-9e2c-a195c57b5e87', '0a7f8e61-3786-494c-9c54-b6edc17b03b6', 'PLE-CC1', 'Pharmacyguru', 1, 120, 'ใน direct compression การใช้ Magnesium stearate มากเกินไปจะส่งผลอย่างไร', NULL, '[{"label":"A","text":"เพิ่ม hardness"},{"label":"B","text":"ไม่มีผล"},{"label":"C","text":"เพิ่ม dissolution rate"},{"label":"D","text":"ลด dissolution rate (hydrophobic coating บน particle)"},{"label":"E","text":"เพิ่ม disintegration time"}]'::jsonb, 'D', 'Mg stearate hydrophobic → มากเกินหรือ mix นานเกิน → coat บน particle → ลด wettability → ลด dissolution rate', '{"summary":"ผลของ Magnesium Stearate มากเกินไปใน Direct Compression","reason":"Mg stearate hydrophobic → over-mixing → hydrophobic coating บน particle → ลด dissolution","choices":[{"label":"A","text":"เพิ่ม hardness","explanation":"✗ ผิด — Mg stearate ลด hardness เพราะขัดขวาง particle-particle binding ใน compression"},{"label":"B","text":"ไม่มีผล","explanation":"✗ ผิด — Mg stearate มากเกินไปหรือ mix นานเกินไปมีผลมาก"},{"label":"C","text":"เพิ่ม dissolution rate","explanation":"✗ ผิด — ตรงข้าม; Mg stearate ลด dissolution"},{"label":"D","text":"ลด dissolution rate (hydrophobic coating บน particle)","explanation":"✓ ถูก — Mg stearate hydrophobic; over-mixing → hydrophobic film เคลือบบน drug particles → ลด wettability → น้ำแทรกซึมได้น้อยลง → dissolution rate ลด; ควรใช้ 0.1-1% และ mix สั้นๆ"},{"label":"E","text":"เพิ่ม disintegration time","explanation":"✗ ผิด — Mg stearate ไม่ได้ส่งผลต่อ disintegration โดยตรง แต่ส่งผลต่อ dissolution ผ่าน wettability"}],"key_takeaway":"Mg stearate: ใช้ 0.1-1%; mix เวลาสั้น (<5 นาที); มากเกิน/นานเกิน → hydrophobic coating → ↓dissolution; ใช้ hydrophilic lubricant (SDS) แทนบางครั้ง"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-28 15:56:17') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3abb23ca-8438-46fd-8d89-1825de0182e8', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยเบาหวานชนิดที่ 2 รายใหม่ ไม่มีโรคร่วม ค่า HbA1c = 8.5% แพทย์ต้องการเริ่มยาเม็ดลดน้ำตาล ยาตัวแรกที่ควรเลือกคือข้อใด', NULL, '[{"label":"A","text":"Glibenclamide"},{"label":"B","text":"Metformin"},{"label":"C","text":"Sitagliptin"},{"label":"D","text":"Pioglitazone"},{"label":"E","text":"Acarbose"}]'::jsonb, 'B', 'Metformin เป็นยาลำดับแรกสำหรับเบาหวานชนิดที่ 2 ตาม ADA guideline เนื่องจากมีประสิทธิภาพสูง ราคาถูก ปลอดภัย และลด cardiovascular mortality', '{"summary":"Metformin คือยาลำดับแรก (first-line) สำหรับ DM type 2 ตาม ADA/EASD guidelines","reason":"Metformin ลด HbA1c ได้ 1-2% มีหลักฐานลด cardiovascular event ปลอดภัย ไม่ทำให้น้ำหนักขึ้น ราคาถูก และไม่ทำให้ hypoglycemia เมื่อใช้เดี่ยว","choices":[{"label":"A","text":"Glibenclamide","explanation":"✗ ผิด — Sulfonylurea ไม่ใช่ยาลำดับแรก เสี่ยง hypoglycemia และน้ำหนักขึ้น"},{"label":"B","text":"Metformin","explanation":"✓ ถูก — First-line therapy สำหรับ DM type 2 ทุก guideline ระดับโลก"},{"label":"C","text":"Sitagliptin","explanation":"✗ ผิด — DPP-4 inhibitor เป็น second-line ราคาแพง ประสิทธิภาพน้อยกว่า metformin"},{"label":"D","text":"Pioglitazone","explanation":"✗ ผิด — TZD ทำให้น้ำหนักขึ้น บวมน้ำ และเสี่ยงต่อ heart failure"},{"label":"E","text":"Acarbose","explanation":"✗ ผิด — Alpha-glucosidase inhibitor ประสิทธิภาพต่ำ ผลข้างเคียงทางเดินอาหารมาก"}],"key_takeaway":"Metformin = first-line DM type 2 เว้นแต่มีข้อห้าม (eGFR < 30, ตับวาย, ภาวะขาดออกซิเจน)"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7ffd195a-6fa0-40e2-818a-9d4114b31fa0', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วย DM type 2 มี eGFR = 25 mL/min/1.73m² ยาใดในกลุ่มต่อไปนี้ที่ควรหลีกเลี่ยงที่สุด', NULL, '[{"label":"A","text":"Insulin glargine"},{"label":"B","text":"Sitagliptin (ปรับขนาด)"},{"label":"C","text":"Metformin"},{"label":"D","text":"Repaglinide"},{"label":"E","text":"Glipizide"}]'::jsonb, 'C', 'Metformin ห้ามใช้เมื่อ eGFR < 30 mL/min/1.73m² เนื่องจากเสี่ยงต่อ lactic acidosis จากการสะสมของยา', '{"summary":"Metformin มีข้อห้ามใช้ใน CKD stage 4-5 (eGFR < 30)","reason":"Metformin ขับออกทางไตเป็นหลัก เมื่อไตเสื่อม ยาสะสมทำให้เกิด lactic acidosis ซึ่งอันตรายถึงชีวิต FDA แนะนำพิจารณาความเสี่ยงเมื่อ eGFR 30-45 และห้ามใช้เมื่อ eGFR < 30","choices":[{"label":"A","text":"Insulin glargine","explanation":"✗ ผิด — Insulin ไม่ขับทางไต ใช้ได้ใน CKD แต่ต้องระวัง hypoglycemia"},{"label":"B","text":"Sitagliptin (ปรับขนาด)","explanation":"✗ ผิด — DPP-4 inhibitor ใช้ได้ใน CKD แต่ต้องลดขนาดยา"},{"label":"C","text":"Metformin","explanation":"✓ ถูก — ห้ามใช้เมื่อ eGFR < 30 เสี่ยง lactic acidosis"},{"label":"D","text":"Repaglinide","explanation":"✗ ผิด — Repaglinide ขับทางอุจจาระเป็นหลัก ใช้ได้ใน CKD"},{"label":"E","text":"Glipizide","explanation":"✗ ผิด — Glipizide ใช้ได้ใน CKD ดีกว่า glibenclamide เพราะ metabolite ไม่ active"}],"key_takeaway":"Metformin: ห้ามใช้ eGFR < 30, ระวัง eGFR 30-45, หยุดก่อนฉีด contrast"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('08e30e8d-689f-4404-b155-b736cb34b59d', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยเบาหวานชนิดที่ 1 อายุ 22 ปี มาด้วยคลื่นไส้ อาเจียน หายใจหอบ ลึก (Kussmaul breathing) ระดับน้ำตาล 450 mg/dL ควรรักษาด้วยวิธีใดก่อน', NULL, '[{"label":"A","text":"ให้ sodium bicarbonate IV ทันที"},{"label":"B","text":"ให้ Regular insulin IV infusion และสารน้ำ 0.9% NaCl"},{"label":"C","text":"ให้ insulin glargine ฉีดใต้ผิวหนัง"},{"label":"D","text":"ให้ glucose 50% IV เพื่อป้องกัน hypoglycemia"},{"label":"E","text":"ให้ metformin ทางปาก"}]'::jsonb, 'B', 'DKA รักษาด้วย Regular insulin IV infusion ร่วมกับ 0.9% NSS เพื่อแก้ไข dehydration และ hyperglycemia พร้อมแก้ electrolyte imbalance', '{"summary":"DKA (Diabetic Ketoacidosis) รักษาด้วย IV fluid + Regular insulin IV","reason":"DKA เกิดจากขาด insulin ทำให้ ketone สะสม เลือดเป็นกรด การรักษาหลัก: (1) IV fluid NSS ชดเชย dehydration, (2) Regular insulin IV 0.1 unit/kg/hr ยับยั้ง ketogenesis, (3) แก้ electrolyte โดยเฉพาะ K+","choices":[{"label":"A","text":"ให้ sodium bicarbonate IV ทันที","explanation":"✗ ผิด — NaHCO3 ใน DKA ใช้เฉพาะ pH < 6.9 เท่านั้น ไม่ใช่ first-line"},{"label":"B","text":"ให้ Regular insulin IV infusion และสารน้ำ 0.9% NaCl","explanation":"✓ ถูก — มาตรฐานการรักษา DKA: IV fluid + Regular insulin IV infusion"},{"label":"C","text":"ให้ insulin glargine ฉีดใต้ผิวหนัง","explanation":"✗ ผิด — Long-acting insulin ไม่เหมาะใน DKA ต้องการ Regular insulin IV ที่ออกฤทธิ์เร็วและปรับได้"},{"label":"D","text":"ให้ glucose 50% IV เพื่อป้องกัน hypoglycemia","explanation":"✗ ผิด — ผู้ป่วยน้ำตาล 450 mg/dL ไม่ต้องการ glucose ตอนนี้ (ให้ D5 เมื่อน้ำตาลลดถึง 200-250 mg/dL)"},{"label":"E","text":"ให้ metformin ทางปาก","explanation":"✗ ผิด — Metformin ห้ามใช้ใน DKA และไม่มีฤทธิ์เพียงพอ"}],"key_takeaway":"DKA: IV NSS + Regular insulin IV + KCl replacement + monitor glucose/electrolytes"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4809ab8d-0273-4eee-a060-f4a19eca5e67', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยเบาหวานได้รับ insulin NPH ก่อนนอน พบว่ามีระดับน้ำตาลตอนเช้าสูงกว่าปกติ (Fasting hyperglycemia) หากต้องการแยก Somogyi effect ออกจาก Dawn phenomenon ควรตรวจน้ำตาลเพิ่มเติมเวลาใด', NULL, '[{"label":"A","text":"02:00-03:00 น."},{"label":"B","text":"06:00 น."},{"label":"C","text":"08:00 น."},{"label":"D","text":"12:00 น."},{"label":"E","text":"18:00 น."}]'::jsonb, 'A', 'ตรวจน้ำตาลช่วง 02:00-03:00 น. หากต่ำ = Somogyi effect (rebound hyperglycemia หลัง nocturnal hypoglycemia) หากปกติหรือสูง = Dawn phenomenon', '{"summary":"แยก Somogyi vs Dawn phenomenon ด้วยการตรวจน้ำตาลตี 2-3","reason":"Somogyi effect: NPH ออกฤทธิ์สูงสุดตี 2-3 ทำให้ hypoglycemia → counter-regulatory hormones หลั่ง → rebound hyperglycemia ตอนเช้า | Dawn phenomenon: GH/cortisol สูงตอนเช้าตรู่ → ดื้อ insulin → น้ำตาลสูงตอนเช้า","choices":[{"label":"A","text":"02:00-03:00 น.","explanation":"✓ ถูก — ตรวจตี 2-3 เพื่อดูว่ามี nocturnal hypoglycemia หรือไม่ แยก Somogyi vs Dawn"},{"label":"B","text":"06:00 น.","explanation":"✗ ผิด — สายเกินไป ทั้ง Somogyi และ Dawn จะให้ผลน้ำตาลสูงเหมือนกันตอนเช้า"},{"label":"C","text":"08:00 น.","explanation":"✗ ผิด — เป็นเวลา fasting ที่ตรวจอยู่แล้ว ไม่ช่วยแยก"},{"label":"D","text":"12:00 น.","explanation":"✗ ผิด — ไม่เกี่ยวข้องกับ nocturnal mechanism"},{"label":"E","text":"18:00 น.","explanation":"✗ ผิด — ไม่เกี่ยวข้อง"}],"key_takeaway":"Somogyi: ตี 2-3 ต่ำ → ลด NPH | Dawn: ตี 2-3 ปกติ → เพิ่ม NPH หรือเปลี่ยนเป็น insulin glargine"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d0824a3d-80ea-4f1c-ab40-bafe3cf215d3', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี มาด้วยใจสั่น น้ำหนักลด ขี้ร้อน มือสั่น ตรวจพบ TSH < 0.01 mIU/L, Free T4 สูง วินิจฉัย Graves'' disease ยาที่เหมาะสมที่สุดในการควบคุมอาการเร็วคือ', NULL, '[{"label":"A","text":"Methimazole เพียงอย่างเดียว"},{"label":"B","text":"Propranolol ร่วมกับ Methimazole"},{"label":"C","text":"Levothyroxine"},{"label":"D","text":"Radioactive iodine ทันที"},{"label":"E","text":"Potassium iodide เพียงอย่างเดียว"}]'::jsonb, 'B', 'Propranolol ควบคุมอาการ sympathetic (ใจสั่น มือสั่น) ได้รวดเร็ว ส่วน Methimazole ยับยั้งการสร้างฮอร์โมนไทรอยด์ใหม่ ใช้ร่วมกันเพื่อผลลัพธ์ที่ดีที่สุด', '{"summary":"Graves'' disease: Methimazole + Propranolol เพื่อควบคุมทั้ง hormone synthesis และอาการ","reason":"Methimazole ยับยั้ง thyroid peroxidase หยุดสร้าง T3/T4 ใหม่ แต่ต้องใช้เวลา 4-8 สัปดาห์ Propranolol ลดอาการ adrenergic ได้ทันทีและยับยั้ง T4→T3 conversion บางส่วน","choices":[{"label":"A","text":"Methimazole เพียงอย่างเดียว","explanation":"✗ ผิด — ใช้ได้แต่ไม่ควบคุมอาการเฉียบพลัน ต้องรอสัปดาห์กว่าจะเห็นผล"},{"label":"B","text":"Propranolol ร่วมกับ Methimazole","explanation":"✓ ถูก — Propranolol บรรเทาอาการเร็ว + Methimazole แก้ที่ต้นเหตุ"},{"label":"C","text":"Levothyroxine","explanation":"✗ ผิด — ห้ามใช้ใน hyperthyroidism จะทำให้อาการแย่ลง"},{"label":"D","text":"Radioactive iodine ทันที","explanation":"✗ ผิด — RAI เป็นทางเลือกระยะยาว ไม่ใช่ acute control ห้ามใช้ในหญิงตั้งครรภ์"},{"label":"E","text":"Potassium iodide เพียงอย่างเดียว","explanation":"✗ ผิด — KI ใช้เฉพาะในกรณี thyroid storm หรือก่อนผ่าตัด ไม่ใช่ long-term treatment"}],"key_takeaway":"Hyperthyroidism: Methimazole (ATD) + Beta-blocker สำหรับอาการ | PTU ใช้ใน T1 pregnancy/thyroid storm"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4e3336d9-6783-4be8-bb34-5868ea7ddd09', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงตั้งครรภ์ไตรมาสแรก ตรวจพบ hyperthyroidism ยาต้านไทรอยด์ที่เหมาะสมที่สุดในช่วงนี้คือ', NULL, '[{"label":"A","text":"Methimazole"},{"label":"B","text":"Propylthiouracil (PTU)"},{"label":"C","text":"Carbimazole"},{"label":"D","text":"Radioactive iodine"},{"label":"E","text":"ไม่รักษา รอจนคลอด"}]'::jsonb, 'B', 'PTU เป็นยาที่เลือกในไตรมาสแรกของการตั้งครรภ์ เนื่องจาก Methimazole สัมพันธ์กับ aplasia cutis และ choanal atresia ในทารก', '{"summary":"Hyperthyroidism ในหญิงตั้งครรภ์: PTU ใน T1, สามารถเปลี่ยนเป็น Methimazole ใน T2-T3","reason":"Methimazole มี teratogenic effect ใน T1 (aplasia cutis, choanal/esophageal atresia) PTU ปลอดภัยกว่าใน T1 แต่มีความเสี่ยง hepatotoxicity จึงแนะนำเปลี่ยนเป็น methimazole ใน T2 Radioactive iodine ห้ามใช้ในหญิงตั้งครรภ์","choices":[{"label":"A","text":"Methimazole","explanation":"✗ ผิด — Teratogenic ใน T1: aplasia cutis, choanal atresia ห้ามใช้ใน T1"},{"label":"B","text":"Propylthiouracil (PTU)","explanation":"✓ ถูก — Drug of choice ใน T1 pregnancy สำหรับ hyperthyroidism"},{"label":"C","text":"Carbimazole","explanation":"✗ ผิด — Prodrug ของ methimazole มีข้อห้ามเช่นเดียวกัน"},{"label":"D","text":"Radioactive iodine","explanation":"✗ ผิด — Absolute contraindication ในหญิงตั้งครรภ์ ทำลาย thyroid ทารก"},{"label":"E","text":"ไม่รักษา รอจนคลอด","explanation":"✗ ผิด — Uncontrolled hyperthyroidism เสี่ยง preeclampsia, preterm, thyroid storm"}],"key_takeaway":"Pregnancy hyperthyroidism: PTU ใน T1 → switch Methimazole ใน T2-T3 | RAI ห้ามใช้ตลอดการตั้งครรภ์"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8eddb5c4-966e-4f2f-bd10-92b4bbb275aa', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี มาด้วยอ่อนเพลีย น้ำหนักขึ้น ขี้หนาว ท้องผูก ผิวแห้ง ตรวจพบ TSH สูง Free T4 ต่ำ วินิจฉัย Primary hypothyroidism การรักษาที่เหมาะสมคือ', NULL, '[{"label":"A","text":"Propylthiouracil"},{"label":"B","text":"Levothyroxine (T4)"},{"label":"C","text":"Liothyronine (T3)"},{"label":"D","text":"Methimazole"},{"label":"E","text":"Radioactive iodine"}]'::jsonb, 'B', 'Levothyroxine (synthetic T4) เป็น drug of choice สำหรับ hypothyroidism มี half-life ยาว (7 วัน) ให้ครั้งเดียวต่อวัน และร่างกายแปลงเป็น T3 เองตามความต้องการ', '{"summary":"Hypothyroidism รักษาด้วย Levothyroxine (T4) ปรับขนาดตาม TSH","reason":"T4 (levothyroxine) มี t½ ~7 วัน ให้วันละครั้ง ตอนเช้าก่อนอาหาร 30-60 นาที ร่างกาย deiodinase แปลง T4→T3 ตามความต้องการ ปรับขนาดทุก 6-8 สัปดาห์โดยดู TSH เป้าหมาย TSH = 0.5-2.5 mIU/L","choices":[{"label":"A","text":"Propylthiouracil","explanation":"✗ ผิด — PTU ยับยั้งการสร้าง thyroid hormone ใช้ใน hyperthyroidism ไม่ใช่ hypo"},{"label":"B","text":"Levothyroxine (T4)","explanation":"✓ ถูก — Drug of choice สำหรับ hypothyroidism ทุกชนิด"},{"label":"C","text":"Liothyronine (T3)","explanation":"✗ ผิด — T3 t½ สั้น ต้องให้หลายครั้ง/วัน ไม่เหมาะเป็น routine ใช้ใน myxedema coma"},{"label":"D","text":"Methimazole","explanation":"✗ ผิด — Methimazole ใช้ใน hyperthyroidism"},{"label":"E","text":"Radioactive iodine","explanation":"✗ ผิด — RAI ทำลาย thyroid ใช้รักษา hyperthyroidism หรือ thyroid cancer"}],"key_takeaway":"Hypothyroidism: Levothyroxine วันละครั้งตอนเช้าท้องว่าง เป้าหมาย TSH 0.5-2.5 | ตั้งครรภ์: เป้าหมาย TSH < 2.5"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:17:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('883e198b-0fdc-4544-83b8-e00998a6aab7', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ยาใดต่อไปนี้ที่ลด HbA1c ได้มากที่สุดเมื่อใช้เป็น monotherapy', NULL, '[{"label":"A","text":"Sitagliptin"},{"label":"B","text":"Acarbose"},{"label":"C","text":"Insulin"},{"label":"D","text":"Empagliflozin"},{"label":"E","text":"Liraglutide"}]'::jsonb, 'C', 'Insulin เป็นยาที่มีประสิทธิภาพสูงสุดในการลด HbA1c ไม่มี ceiling effect ลดได้ไม่จำกัดขึ้นกับขนาดที่ใช้ ต่างจากยาเม็ดที่มี ceiling effect', '{"summary":"Insulin มีประสิทธิภาพลด HbA1c สูงสุด ไม่มี ceiling effect","reason":"การลด HbA1c โดยประมาณ: Insulin = ไม่จำกัด (ขึ้นกับ dose) | Metformin = 1-2% | Sulfonylurea = 1-2% | GLP-1 RA = 1-1.5% | SGLT2i = 0.5-1% | DPP-4i = 0.5-1% | Acarbose = 0.5-1%","choices":[{"label":"A","text":"Sitagliptin","explanation":"✗ ผิด — DPP-4i ลด HbA1c ได้ ~0.5-1% เท่านั้น"},{"label":"B","text":"Acarbose","explanation":"✗ ผิด — ลด HbA1c ได้ ~0.5-0.8% ประสิทธิภาพต่ำ"},{"label":"C","text":"Insulin","explanation":"✓ ถูก — ไม่มี ceiling effect ลด HbA1c ได้ไม่จำกัด ขึ้นกับ dose ที่ใช้"},{"label":"D","text":"Empagliflozin","explanation":"✗ ผิด — SGLT2i ลด HbA1c ได้ ~0.5-1% แต่มีประโยชน์ด้าน CV/renal protection"},{"label":"E","text":"Liraglutide","explanation":"✗ ผิด — GLP-1 RA ลด HbA1c ได้ ~1-1.5% ดีกว่า DPP-4i แต่ยังน้อยกว่า insulin"}],"key_takeaway":"Insulin = most potent glucose-lowering agent | เลือกยาตาม patient profile ไม่ใช่แค่ HbA1c lowering"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3f423f6a-5a84-4d84-a24a-a5c63eb7987d', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วย DM type 2 ร่วมกับ Heart failure with reduced ejection fraction (HFrEF) ควรเพิ่มยากลุ่มใดเพื่อประโยชน์ด้าน cardiovascular outcome', NULL, '[{"label":"A","text":"Sulfonylurea"},{"label":"B","text":"Pioglitazone"},{"label":"C","text":"SGLT2 inhibitor (Empagliflozin/Dapagliflozin)"},{"label":"D","text":"DPP-4 inhibitor (Saxagliptin)"},{"label":"E","text":"Acarbose"}]'::jsonb, 'C', 'SGLT2 inhibitors (empagliflozin, dapagliflozin) ลด hospitalization จาก heart failure และลด CV death ในผู้ป่วย DM+HF มีหลักฐานจาก EMPA-REG, DAPA-HF trials', '{"summary":"SGLT2i เป็น preferred agent ใน DM+HFrEF ลด HF hospitalization และ CV mortality","reason":"SGLT2i ลด afterload/preload ผ่าน glycosuria+natriuresis ลด sympathetic activation และมี direct cardioprotective effect EMPA-REG OUTCOME: empagliflozin ลด CV death 38% DAPA-HF: dapagliflozin ลด HF worsening แม้ใน non-DM","choices":[{"label":"A","text":"Sulfonylurea","explanation":"✗ ผิด — ไม่มี CV benefit อาจเพิ่ม hypoglycemia ที่เป็นอันตรายใน HF"},{"label":"B","text":"Pioglitazone","explanation":"✗ ผิด — TZD ห้ามใช้ใน HF เนื่องจากทำให้ fluid retention และ HF แย่ลง"},{"label":"C","text":"SGLT2 inhibitor (Empagliflozin/Dapagliflozin)","explanation":"✓ ถูก — มีหลักฐานชัดเจนในการลด HF hospitalization และ CV death"},{"label":"D","text":"DPP-4 inhibitor (Saxagliptin)","explanation":"✗ ผิด — Saxagliptin เพิ่มความเสี่ยง HF hospitalization จาก SAVOR-TIMI trial"},{"label":"E","text":"Acarbose","explanation":"✗ ผิด — ไม่มีหลักฐาน CV benefit ใน HF"}],"key_takeaway":"DM + HFrEF: SGLT2i (empagliflozin/dapagliflozin) เป็น class I recommendation | หลีกเลี่ยง TZD และ saxagliptin"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('947b7f37-3f97-4f79-a216-853e50761e11', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'GLP-1 receptor agonist มีประโยชน์ใดที่เหนือกว่ายากลุ่มอื่น ในผู้ป่วย DM type 2 ที่มีน้ำหนักตัวมาก', NULL, '[{"label":"A","text":"ลด HbA1c ได้มากที่สุด"},{"label":"B","text":"ลดน้ำหนักและลด cardiovascular events ในผู้มี established CVD"},{"label":"C","text":"ราคาถูกและสะดวกที่สุด"},{"label":"D","text":"ไม่มีผลข้างเคียงทางเดินอาหาร"},{"label":"E","text":"ปลอดภัยในผู้ป่วย pancreatitis"}]'::jsonb, 'B', 'GLP-1 RA (liraglutide, semaglutide) ลดน้ำหนัก 3-5 kg และลด MACE (major adverse cardiovascular events) ในผู้ป่วย DM+CVD จาก LEADER, SUSTAIN-6 trials', '{"summary":"GLP-1 RA: ลดน้ำหนัก + CV protection ใน established CVD","reason":"GLP-1 RA ลด appetite และ gastric emptying → ลดน้ำหนัก ลด systolic BP และ LDL มีหลักฐาน CV benefit ใน established atherosclerotic CVD LEADER trial (liraglutide) และ SUSTAIN-6 (semaglutide) แสดง 13-26% ลด MACE","choices":[{"label":"A","text":"ลด HbA1c ได้มากที่สุด","explanation":"✗ ผิด — Insulin ลด HbA1c ได้มากที่สุด GLP-1 RA ลดได้ ~1-1.5%"},{"label":"B","text":"ลดน้ำหนักและลด cardiovascular events ในผู้มี established CVD","explanation":"✓ ถูก — จุดเด่นของ GLP-1 RA คือ weight loss + CV protection"},{"label":"C","text":"ราคาถูกและสะดวกที่สุด","explanation":"✗ ผิด — GLP-1 RA ราคาแพงและส่วนใหญ่เป็นยาฉีด (ยกเว้น oral semaglutide)"},{"label":"D","text":"ไม่มีผลข้างเคียงทางเดินอาหาร","explanation":"✗ ผิด — คลื่นไส้ อาเจียน ท้องเสีย เป็น side effect ที่พบบ่อยที่สุด"},{"label":"E","text":"ปลอดภัยในผู้ป่วย pancreatitis","explanation":"✗ ผิด — GLP-1 RA ห้ามใช้หรือระวังในผู้มีประวัติ pancreatitis"}],"key_takeaway":"GLP-1 RA: ลดน้ำหนัก + CV benefit ใน established CVD | SE: คลื่นไส้ อาเจียน | ห้ามใน pancreatitis/MTC"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4837a671-dfc1-4a29-ba79-305a9ff5ff60', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยได้รับ insulin มากเกินไป มีอาการเหงื่อออก ใจสั่น มือสั่น สับสน ระดับน้ำตาล 45 mg/dL ผู้ป่วยยังรู้สึกตัวดี การรักษาเบื้องต้นที่ถูกต้องคือ', NULL, '[{"label":"A","text":"ฉีด glucagon 1 mg IM ทันที"},{"label":"B","text":"ให้ glucose 50% IV 50 mL"},{"label":"C","text":"ให้รับประทานน้ำตาลหรือน้ำผลไม้ 15-20 กรัม"},{"label":"D","text":"ให้ octreotide IV"},{"label":"E","text":"รอสังเกตอาการ ไม่ต้องรักษา"}]'::jsonb, 'C', 'ผู้ป่วยยังรู้สึกตัวดีและกลืนได้ → Rule of 15: ให้คาร์โบไฮเดรต 15-20 กรัม (น้ำผลไม้ กลูโคสเม็ด) รอ 15 นาที แล้วตรวจซ้ำ', '{"summary":"Hypoglycemia ในผู้ป่วยที่รู้สึกตัว: Rule of 15 — carbohydrate 15-20g ทางปาก","reason":"Rule of 15: ให้ carb 15-20g → รอ 15 นาที → ตรวจน้ำตาล ถ้ายังต่ำ ให้ซ้ำ ถ้าหมดสติ/กลืนไม่ได้ → IV glucose หรือ IM glucagon ห้ามให้ glucose IV ในผู้ที่ยังกลืนได้เพราะ invasive เกินไป","choices":[{"label":"A","text":"ฉีด glucagon 1 mg IM ทันที","explanation":"✗ ผิด — Glucagon ใช้เมื่อผู้ป่วยหมดสติหรือกลืนไม่ได้ ผู้ป่วยนี้ยังรู้สึกตัวดี"},{"label":"B","text":"ให้ glucose 50% IV 50 mL","explanation":"✗ ผิด — IV glucose ใช้เมื่อผู้ป่วยให้ทางปากไม่ได้ รู้สึกตัวดีให้ทางปากก่อน"},{"label":"C","text":"ให้รับประทานน้ำตาลหรือน้ำผลไม้ 15-20 กรัม","explanation":"✓ ถูก — Rule of 15: carb 15-20g PO → ตรวจซ้ำ 15 นาที เหมาะสำหรับผู้ป่วยที่รู้สึกตัวดี"},{"label":"D","text":"ให้ octreotide IV","explanation":"✗ ผิด — Octreotide ใช้ใน sulfonylurea-induced hypoglycemia ที่รุนแรง ไม่ใช่ first-line"},{"label":"E","text":"รอสังเกตอาการ ไม่ต้องรักษา","explanation":"✗ ผิด — น้ำตาล 45 mg/dL ต้องรักษาทันที อาจเกิด seizure หรือหมดสติได้"}],"key_takeaway":"Hypoglycemia: รู้สึกตัว → carb 15-20g PO | หมดสติ → D50W IV หรือ glucagon IM/SC"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d702ada9-e195-4729-a552-2e2ad1515540', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยได้รับการวินิจฉัย Cushing''s syndrome จากการใช้ prednisolone ขนาดสูงนาน 6 เดือน แพทย์ต้องการหยุดยา วิธีที่ถูกต้องคือ', NULL, '[{"label":"A","text":"หยุดยาทันทีเพราะสาเหตุเป็นยาภายนอก ไม่ใช่ต่อมหมวกไตเอง"},{"label":"B","text":"ลดขนาดยาลงทีละน้อยอย่างช้าๆ (gradual tapering)"},{"label":"C","text":"เปลี่ยนเป็น hydrocortisone ทันทีแล้วหยุดยาทันที"},{"label":"D","text":"ให้ ketoconazole ก่อนหยุดยา"},{"label":"E","text":"ผ่าตัดต่อมหมวกไตออก"}]'::jsonb, 'B', 'การใช้ corticosteroid นานทำให้ HPA axis ถูก suppress ต้องค่อยๆ ลดยาเพื่อให้ต่อมหมวกไตฟื้นตัว หยุดทันทีอาจเกิด adrenal crisis', '{"summary":"Exogenous Cushing''s: ต้อง taper corticosteroid ช้าๆ ห้ามหยุดทันที","reason":"การใช้ corticosteroid ภายนอกนาน → HPA axis suppression → ต่อมหมวกไตฝ่อ หยุดทันทีเกิด adrenal insufficiency/crisis: hypotension, hyponatremia, hypoglycemia ต้อง taper ช้าๆ เพื่อให้ adrenal cortex ฟื้น","choices":[{"label":"A","text":"หยุดยาทันทีเพราะสาเหตุเป็นยาภายนอก ไม่ใช่ต่อมหมวกไตเอง","explanation":"✗ ผิด — แม้สาเหตุเป็น exogenous แต่ HPA axis ถูก suppress แล้ว หยุดทันทีเกิด adrenal crisis"},{"label":"B","text":"ลดขนาดยาลงทีละน้อยอย่างช้าๆ (gradual tapering)","explanation":"✓ ถูก — Standard of care: taper corticosteroid ช้าๆ ให้ HPA axis ฟื้นตัว"},{"label":"C","text":"เปลี่ยนเป็น hydrocortisone ทันทีแล้วหยุดยาทันที","explanation":"✗ ผิด — ยังต้องค่อยๆ ลด hydrocortisone ด้วย"},{"label":"D","text":"ให้ ketoconazole ก่อนหยุดยา","explanation":"✗ ผิด — Ketoconazole ใช้ลด cortisol ใน endogenous Cushing''s ไม่ใช่กรณีนี้"},{"label":"E","text":"ผ่าตัดต่อมหมวกไตออก","explanation":"✗ ผิด — ต่อมหมวกไตปกติ ปัญหาคือยาภายนอก ไม่ต้องผ่าตัด"}],"key_takeaway":"Corticosteroid > 3 สัปดาห์ → ต้อง taper | Adrenal crisis: ให้ hydrocortisone IV ทันที"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6f69401a-6fd3-41ea-89f0-94cb99ca8e34', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 40 ปี มาด้วยปวดหัว ใจสั่น เหงื่อออกมาก ความดันโลหิตสูง 200/110 mmHg เป็นช่วงๆ ตรวจ 24-hr urine metanephrines สูง วินิจฉัย Pheochromocytoma ยาที่ต้องให้ก่อนผ่าตัดคือ', NULL, '[{"label":"A","text":"Beta-blocker ก่อน"},{"label":"B","text":"Alpha-blocker (Phenoxybenzamine) ก่อน แล้วค่อยเพิ่ม Beta-blocker"},{"label":"C","text":"Alpha-blocker และ Beta-blocker พร้อมกัน"},{"label":"D","text":"ACE inhibitor"},{"label":"E","text":"Diuretic เพียงอย่างเดียว"}]'::jsonb, 'B', 'ต้องให้ Alpha-blocker ก่อนเสมอ (phenoxybenzamine หรือ doxazosin) อย่างน้อย 7-14 วัน แล้วค่อยเพิ่ม Beta-blocker ถ้าให้ Beta-blocker ก่อนจะเกิด unopposed alpha stimulation → hypertensive crisis', '{"summary":"Pheochromocytoma preoperative: Alpha-block ก่อน ALWAYS → จึงเพิ่ม Beta-block","reason":"Catecholamine กระตุ้นทั้ง α และ β receptor ถ้าให้ β-blocker ก่อน: α receptor ไม่ถูกบล็อก → vasoconstriction รุนแรง → hypertensive crisis Alpha-blocker ก่อน 7-14 วัน → ให้ beta-blocker ถ้า tachycardia/arrhythmia","choices":[{"label":"A","text":"Beta-blocker ก่อน","explanation":"✗ ผิด — อันตราย! Beta-block ก่อน → unopposed alpha → severe hypertension, pulmonary edema"},{"label":"B","text":"Alpha-blocker (Phenoxybenzamine) ก่อน แล้วค่อยเพิ่ม Beta-blocker","explanation":"✓ ถูก — Standard: alpha-block ก่อน 7-14 วัน ก่อนผ่าตัด จึงเพิ่ม beta-block"},{"label":"C","text":"Alpha-blocker และ Beta-blocker พร้อมกัน","explanation":"✗ ผิด — ควร alpha-block ก่อนเพื่อให้แน่ใจว่า alpha blocked เพียงพอ"},{"label":"D","text":"ACE inhibitor","explanation":"✗ ผิด — ไม่ใช่ยาที่เลือกใน pheochromocytoma"},{"label":"E","text":"Diuretic เพียงอย่างเดียว","explanation":"✗ ผิด — ไม่ตรงเหตุ และทำให้ volume depletion แย่ลงก่อนผ่าตัด"}],"key_takeaway":"Pheo: Alpha-blocker FIRST (phenoxybenzamine) → then Beta-blocker | ห้าม Beta-block ก่อน!"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c8ea1017-4469-426f-abd3-c1387da006a2', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยได้รับการวินิจฉัย Primary Adrenal Insufficiency (Addison''s disease) ยาทดแทนฮอร์โมนที่ต้องให้คือ', NULL, '[{"label":"A","text":"Hydrocortisone อย่างเดียว"},{"label":"B","text":"Hydrocortisone + Fludrocortisone"},{"label":"C","text":"Dexamethasone อย่างเดียว"},{"label":"D","text":"Fludrocortisone อย่างเดียว"},{"label":"E","text":"Prednisolone + Spironolactone"}]'::jsonb, 'B', 'Primary adrenal insufficiency ขาดทั้ง glucocorticoid (cortisol) และ mineralocorticoid (aldosterone) ต้องทดแทนทั้งสอง: Hydrocortisone (glucocorticoid) + Fludrocortisone (mineralocorticoid)', '{"summary":"Addison''s disease: ทดแทน glucocorticoid + mineralocorticoid","reason":"Primary AI: ต่อมหมวกไตเสียหาย → ขาดทั้ง cortisol และ aldosterone | Hydrocortisone: glucocorticoid ทดแทน (15-25 mg/day แบ่ง 2-3 ครั้ง) | Fludrocortisone: mineralocorticoid ทดแทน (0.05-0.1 mg/day) Secondary AI: ขาดแค่ glucocorticoid ไม่ต้องการ fludrocortisone","choices":[{"label":"A","text":"Hydrocortisone อย่างเดียว","explanation":"✗ ผิด — เพียงพอสำหรับ secondary AI แต่ primary AI ขาด aldosterone ด้วย"},{"label":"B","text":"Hydrocortisone + Fludrocortisone","explanation":"✓ ถูก — ทดแทนทั้ง glucocorticoid และ mineralocorticoid ครบ"},{"label":"C","text":"Dexamethasone อย่างเดียว","explanation":"✗ ผิด — Dexamethasone ไม่มี mineralocorticoid activity และไม่เหมาะสำหรับ long-term replacement"},{"label":"D","text":"Fludrocortisone อย่างเดียว","explanation":"✗ ผิด — มีแค่ mineralocorticoid effect ขาด glucocorticoid"},{"label":"E","text":"Prednisolone + Spironolactone","explanation":"✗ ผิด — Spironolactone เป็น aldosterone antagonist ไม่ใช่ทดแทน"}],"key_takeaway":"Addison''s: Hydrocortisone (GC) + Fludrocortisone (MC) | เพิ่มขนาดในภาวะเจ็บป่วย/ผ่าตัด (sick day rule)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6664c2ee-ca38-433d-940f-96d23de410c4', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'เป้าหมาย HbA1c ที่เหมาะสมสำหรับผู้ป่วยเบาหวานสูงอายุ (อายุ > 75 ปี) ที่มี multiple comorbidities และ life expectancy สั้น ตาม ADA guideline คือ', NULL, '[{"label":"A","text":"< 6.5%"},{"label":"B","text":"< 7.0%"},{"label":"C","text":"< 7.5%"},{"label":"D","text":"< 8.0-8.5%"},{"label":"E","text":"ไม่ต้องควบคุม HbA1c"}]'::jsonb, 'D', 'ผู้สูงอายุที่มี comorbidity มาก อายุขัยสั้น เป้าหมาย HbA1c ผ่อนปรนได้ถึง < 8.0-8.5% เพื่อหลีกเลี่ยง hypoglycemia ที่อันตรายกว่าใน elderly', '{"summary":"HbA1c targets ตาม patient profile: สุขภาพดี < 7% | ปานกลาง < 7.5-8% | comorbid มาก < 8-8.5%","reason":"ADA แบ่ง elderly เป็น 3 กลุ่ม: Healthy (few chronic conditions, good functional status): < 7-7.5% | Complex (multiple comorbidities): < 8% | Very complex/poor health: < 8.5% Hypoglycemia ในผู้สูงอายุอันตรายกว่า → ล้ม → กระดูกหัก → เสียชีวิต","choices":[{"label":"A","text":"< 6.5%","explanation":"✗ ผิด — เข้มงวดเกินไปสำหรับ elderly comorbid เสี่ยง hypoglycemia สูง"},{"label":"B","text":"< 7.0%","explanation":"✗ ผิด — เหมาะสำหรับ healthy younger adults ไม่ใช่ elderly comorbid"},{"label":"C","text":"< 7.5%","explanation":"✗ ผิด — เหมาะสำหรับ elderly ที่สุขภาพพอดี แต่ไม่ใช่ very complex"},{"label":"D","text":"< 8.0-8.5%","explanation":"✓ ถูก — เหมาะสำหรับ elderly ที่ multiple comorbidities/life expectancy สั้น"},{"label":"E","text":"ไม่ต้องควบคุม HbA1c","explanation":"✗ ผิด — ยังต้องควบคุมอาการ hyperglycemia (polyuria, infection) แม้ผ่อนปรนเป้าหมาย"}],"key_takeaway":"Elderly DM: individualize target | Healthy < 7-7.5% | Complex < 8% | Very complex < 8.5% | หลีกเลี่ยง hypoglycemia"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b0ad6b6e-94fa-42dd-835a-7e91c5cd76da', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี ได้รับการวินิจฉัย SIADH (Syndrome of Inappropriate ADH secretion) Na = 118 mEq/L ไม่มีอาการ seizure/coma การรักษาเบื้องต้นที่เหมาะสมคือ', NULL, '[{"label":"A","text":"ให้ 3% NaCl IV อย่างเร็ว"},{"label":"B","text":"จำกัดน้ำ (fluid restriction) 800-1000 mL/วัน"},{"label":"C","text":"ให้ 0.9% NaCl IV"},{"label":"D","text":"ให้ furosemide ขนาดสูง"},{"label":"E","text":"ให้ aldosterone"}]'::jsonb, 'B', 'SIADH ที่ไม่มีอาการรุนแรง รักษาด้วยการจำกัดน้ำ (fluid restriction) เป็น first-line เพื่อให้ร่างกายขับน้ำส่วนเกินออก', '{"summary":"SIADH: mild-moderate → fluid restriction | severe/symptomatic → 3% NaCl","reason":"SIADH: ADH หลั่งมากเกินโดยไม่เหมาะสม → ไตดูดน้ำกลับมาก → dilutional hyponatremia Fluid restriction ลดน้ำเข้า → Na ค่อยๆ สูงขึ้น ไม่เกิน 8-10 mEq/L/24hr (ป้องกัน osmotic demyelination syndrome) 3% NaCl ใช้เมื่อ symptomatic (seizure, altered consciousness)","choices":[{"label":"A","text":"ให้ 3% NaCl IV อย่างเร็ว","explanation":"✗ ผิด — 3% NaCl ใช้ใน symptomatic hyponatremia (seizure/coma) การแก้เร็วเกินเสี่ยง osmotic demyelination"},{"label":"B","text":"จำกัดน้ำ (fluid restriction) 800-1000 mL/วัน","explanation":"✓ ถูก — First-line ใน asymptomatic/mild SIADH ลด free water intake"},{"label":"C","text":"ให้ 0.9% NaCl IV","explanation":"✗ ผิด — Isotonic saline ใน SIADH อาจทำให้ hyponatremia แย่ลงได้"},{"label":"D","text":"ให้ furosemide ขนาดสูง","explanation":"✗ ผิด — Furosemide ใช้เสริมร่วมกับ salt tablet ใน SIADH บางราย ไม่ใช่ first-line"},{"label":"E","text":"ให้ aldosterone","explanation":"✗ ผิด — ไม่ใช่การรักษา SIADH aldosterone เพิ่ม Na retention แต่ไม่ใช่กลไกของ SIADH"}],"key_takeaway":"SIADH: Na ต่ำ + urine concentrated + euvolemic | Rx: fluid restriction | Severe: 3% NaCl แก้ไม่เกิน 8-10 mEq/L/24hr"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:17:47') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0a2f5aa8-b3d5-400d-87ce-6f6628fa3f3e', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'Insulin ชนิดใดที่มีระยะออกฤทธิ์นานที่สุดและไม่มี peak effect ทำให้เสี่ยง nocturnal hypoglycemia น้อยที่สุด', NULL, '[{"label":"A","text":"Insulin NPH"},{"label":"B","text":"Insulin Regular"},{"label":"C","text":"Insulin Lispro"},{"label":"D","text":"Insulin Glargine (U-100)"},{"label":"E","text":"Insulin 70/30"}]'::jsonb, 'D', 'Insulin Glargine (U-100) มีระยะออกฤทธิ์ ~24 ชั่วโมง ไม่มี peak effect ทำให้ระดับ insulin คงที่ตลอดวัน เสี่ยง nocturnal hypoglycemia น้อยกว่า NPH', '{"summary":"Insulin kinetics: Glargine/Degludec = peakless long-acting | NPH = intermediate มี peak","reason":"NPH: onset 2-4h, peak 4-10h, duration 10-18h → peak ช่วงดึกทำให้ nocturnal hypoglycemia | Glargine: onset 2-4h, NO significant peak, duration ~24h | Degludec: duration >42h | Regular: onset 30-60min, peak 2-4h, duration 5-8h | Lispro/Aspart/Glulisine: rapid-acting","choices":[{"label":"A","text":"Insulin NPH","explanation":"✗ ผิด — Intermediate-acting มี peak 4-10h เสี่ยง nocturnal hypoglycemia"},{"label":"B","text":"Insulin Regular","explanation":"✗ ผิด — Short-acting มี peak 2-4h ใช้ก่อนมื้ออาหาร"},{"label":"C","text":"Insulin Lispro","explanation":"✗ ผิด — Rapid-acting analog มี peak 1-2h ใช้ช่วง mealtime"},{"label":"D","text":"Insulin Glargine (U-100)","explanation":"✓ ถูก — Long-acting peakless ~24h เสี่ยง hypoglycemia น้อยที่สุดในกลุ่ม basal insulin"},{"label":"E","text":"Insulin 70/30","explanation":"✗ ผิด — Premixed (70% NPH + 30% Regular) มี peak จาก NPH component"}],"key_takeaway":"Basal insulin: Glargine/Detemir/Degludec = peakless ดีกว่า NPH ลด nocturnal hypoglycemia | ให้ครั้งเดียวก่อนนอน"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:47') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c9b59419-a253-4323-b352-1dcd6a81632c', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี ตรวจพบ Fasting plasma glucose 128 mg/dL สองครั้ง ห่างกัน 1 สัปดาห์ ค่า HbA1c 7.2% ควรให้การวินิจฉัยว่าอย่างไร', NULL, '[{"label":"A","text":"ปกติ ไม่ต้องรักษา"},{"label":"B","text":"Impaired fasting glucose (Pre-diabetes)"},{"label":"C","text":"Diabetes mellitus"},{"label":"D","text":"Impaired glucose tolerance"},{"label":"E","text":"ต้องทำ OGTT ก่อนจึงวินิจฉัยได้"}]'::jsonb, 'C', 'ADA criteria สำหรับ DM: FPG ≥ 126 mg/dL สองครั้ง หรือ HbA1c ≥ 6.5% ผู้ป่วยมี FPG 128 mg/dL สองครั้ง (≥ 126) และ HbA1c 7.2% (≥ 6.5%) วินิจฉัย DM ได้ทันที', '{"summary":"ADA DM criteria: FPG ≥ 126 (×2), HbA1c ≥ 6.5%, 2h OGTT ≥ 200, Random glucose ≥ 200 + symptoms","reason":"เกณฑ์วินิจฉัย DM (ADA): 1) FPG ≥ 126 mg/dL (ซ้ำสองครั้ง) 2) HbA1c ≥ 6.5% 3) 2-hr glucose ≥ 200 mg/dL ใน OGTT 4) Random glucose ≥ 200 + อาการ Pre-diabetes: FPG 100-125 หรือ HbA1c 5.7-6.4%","choices":[{"label":"A","text":"ปกติ ไม่ต้องรักษา","explanation":"✗ ผิด — FPG 128 และ HbA1c 7.2% เกินเกณฑ์ปกติมาก"},{"label":"B","text":"Impaired fasting glucose (Pre-diabetes)","explanation":"✗ ผิด — IFG: FPG 100-125 mg/dL ผู้ป่วยมี FPG 128 ≥ 126 แล้ว"},{"label":"C","text":"Diabetes mellitus","explanation":"✓ ถูก — FPG ≥ 126 สองครั้ง + HbA1c ≥ 6.5% ครบเกณฑ์วินิจฉัย DM"},{"label":"D","text":"Impaired glucose tolerance","explanation":"✗ ผิด — IGT วินิจฉัยด้วย OGTT 2h glucose 140-199 mg/dL ต่างจากกรณีนี้"},{"label":"E","text":"ต้องทำ OGTT ก่อนจึงวินิจฉัยได้","explanation":"✗ ผิด — FPG ≥ 126 สองครั้งเพียงพอสำหรับวินิจฉัย DM ไม่ต้อง OGTT"}],"key_takeaway":"DM diagnosis: FPG ≥ 126 (×2) หรือ HbA1c ≥ 6.5% หรือ OGTT 2h ≥ 200 หรือ Random ≥ 200 + sx"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:17:47') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7dfde7e4-e769-4345-b0e6-5bac31d97dce', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับประทาน Metformin 1000 mg วันละสองครั้ง มาเป็นเวลา 2 ปี ผลข้างเคียงระยะยาวที่สำคัญซึ่งควรติดตามคือ', NULL, '[{"label":"A","text":"Hepatotoxicity"},{"label":"B","text":"Vitamin B12 deficiency"},{"label":"C","text":"Osteoporosis"},{"label":"D","text":"Nephrolithiasis"},{"label":"E","text":"Agranulocytosis"}]'::jsonb, 'B', 'Metformin ระยะยาวลดการดูดซึม Vitamin B12 ในลำไส้เล็ก ควรตรวจ B12 ทุก 1-2 ปี และให้ B12 supplement หากจำเป็น', '{"summary":"Metformin long-term SE: Vitamin B12 deficiency → peripheral neuropathy, anemia","reason":"Metformin ลดการดูดซึม B12 ที่ ileum ผ่าน calcium-dependent mechanism พบ B12 deficiency ~10-30% ในผู้ใช้นาน อาการ: peripheral neuropathy, megaloblastic anemia ติดตาม: ตรวจ B12 ทุก 1-2 ปี ให้ calcium supplement ช่วยลดปัญหาได้","choices":[{"label":"A","text":"Hepatotoxicity","explanation":"✗ ผิด — Metformin ไม่ทำให้ตับเสีย (ต่างจาก thiazolidinedione รุ่นเก่า)"},{"label":"B","text":"Vitamin B12 deficiency","explanation":"✓ ถูก — Long-term SE ที่สำคัญ ลดการดูดซึม B12 ควร monitor ทุก 1-2 ปี"},{"label":"C","text":"Osteoporosis","explanation":"✗ ผิด — Metformin ไม่ทำให้กระดูกบาง (TZD ต่างหากที่เพิ่มความเสี่ยง fracture)"},{"label":"D","text":"Nephrolithiasis","explanation":"✗ ผิด — ไม่เกี่ยวข้องกับ metformin"},{"label":"E","text":"Agranulocytosis","explanation":"✗ ผิด — เป็น SE ของ carbimazole/methimazole/PTU ไม่ใช่ metformin"}],"key_takeaway":"Metformin long-term: ตรวจ B12 ทุก 1-2 ปี | SE อื่น: GI (ลดได้โดยกินพร้อมอาหาร) | ไม่ทำให้ hypo เมื่อใช้เดี่ยว"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:17:47') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('bf693a2f-20b7-4a3b-b4ba-e9177e252c21', '3c30613d-83c7-4be5-b3e3-ee9240e7552a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยเบาหวานที่มี established atherosclerotic cardiovascular disease (ASCVD) และ HbA1c ยังไม่ถึงเป้าหมายแม้ใช้ Metformin แล้ว ควรเพิ่มยากลุ่มใดก่อนตาม ADA 2024 guideline', NULL, '[{"label":"A","text":"Sulfonylurea"},{"label":"B","text":"DPP-4 inhibitor"},{"label":"C","text":"GLP-1 receptor agonist ที่มี proven CV benefit (liraglutide/semaglutide)"},{"label":"D","text":"Acarbose"},{"label":"E","text":"Insulin NPH"}]'::jsonb, 'C', 'ADA guideline: ผู้ป่วย DM+ASCVD ควรได้ GLP-1 RA ที่มี proven CV benefit (liraglutide/semaglutide/dulaglutide) หรือ SGLT2i เพิ่มจาก metformin โดยพิจารณาจาก CV benefit ไม่ใช่แค่ HbA1c', '{"summary":"DM + ASCVD: เพิ่ม GLP-1 RA หรือ SGLT2i ที่มี proven CV benefit เหนือ HbA1c control","reason":"ADA 2024: การเลือกยาใน DM ต้องพิจารณา complication ร่วม ไม่ใช่แค่ HbA1c ASCVD: GLP-1 RA (liraglutide LEADER, semaglutide SUSTAIN-6, dulaglutide REWIND) หรือ SGLT2i (empagliflozin EMPA-REG, canagliflozin CANVAS) Heart failure: SGLT2i เป็นอันดับแรก CKD: SGLT2i (dapagliflozin DAPA-CKD)","choices":[{"label":"A","text":"Sulfonylurea","explanation":"✗ ผิด — ไม่มี CV benefit อาจเพิ่ม CV risk เสี่ยง hypoglycemia"},{"label":"B","text":"DPP-4 inhibitor","explanation":"✗ ผิด — CV neutral เท่านั้น ไม่ลด MACE ใน ASCVD"},{"label":"C","text":"GLP-1 receptor agonist ที่มี proven CV benefit (liraglutide/semaglutide)","explanation":"✓ ถูก — Proven CV benefit ใน ASCVD ลด MACE 13-26%"},{"label":"D","text":"Acarbose","explanation":"✗ ผิด — ไม่มีหลักฐาน CV benefit ประสิทธิภาพต่ำ"},{"label":"E","text":"Insulin NPH","explanation":"✗ ผิด — ไม่มี CV benefit เสี่ยง hypoglycemia สูง ไม่ใช่ second-line ตาม guideline ใหม่"}],"key_takeaway":"DM + ASCVD: GLP-1 RA หรือ SGLT2i (proven CV benefit) เป็น preferred add-on | DM + HF: SGLT2i first | DM + CKD: SGLT2i first"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:17:47') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0281b1a9-4657-4037-9e80-57bd1d832a43', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 25 ปี วินิจฉัย Schizophrenia รับ Haloperidol อยู่ 4 สัปดาห์ พบอาการ Akathisia ข้อใดอธิบาย Akathisia ได้ถูกต้องที่สุด', NULL, '[{"label":"A","text":"กล้ามเนื้อคอบิด (torticollis)"},{"label":"B","text":"ความรู้สึกอยู่ไม่สุข ต้องขยับตัวตลอดเวลา"},{"label":"C","text":"กล้ามเนื้อแข็งเกร็งทั้งตัว"},{"label":"D","text":"การเคลื่อนไหวผิดปกติช้าๆ ของปากและลิ้น"},{"label":"E","text":"อาการสั่นขณะพัก (resting tremor)"}]'::jsonb, 'B', 'Akathisia คือความรู้สึกกระวนกระวาย อยู่ไม่สุข จำเป็นต้องเดินหรือขยับตัวตลอดเวลา เป็น EPS ที่พบบ่อยจาก antipsychotics รักษาด้วย propranolol หรือ benzodiazepine', '{"summary":"EPS จาก antipsychotics แบ่งเป็น 4 ชนิด: Akathisia, Acute dystonia, Parkinsonism, Tardive dyskinesia","reason":"Akathisia: ความรู้สึก subjective restlessness ต้องการเคลื่อนไหว | Acute dystonia: กล้ามเนื้อหดเกร็งเฉียบพลัน (torticollis, oculogyric crisis) | Drug-induced Parkinsonism: bradykinesia, rigidity, tremor | Tardive dyskinesia: การเคลื่อนไหวช้าๆ ผิดปกติของปาก ลิ้น ใบหน้า (ระยะยาว)","choices":[{"label":"A","text":"กล้ามเนื้อคอบิด (torticollis)","explanation":"✗ ผิด — Torticollis เป็น acute dystonia ไม่ใช่ akathisia"},{"label":"B","text":"ความรู้สึกอยู่ไม่สุข ต้องขยับตัวตลอดเวลา","explanation":"✓ ถูก — คำนิยามของ akathisia: subjective restlessness + objective motor restlessness"},{"label":"C","text":"กล้ามเนื้อแข็งเกร็งทั้งตัว","explanation":"✗ ผิด — Rigidity เป็นอาการของ drug-induced Parkinsonism หรือ NMS"},{"label":"D","text":"การเคลื่อนไหวผิดปกติช้าๆ ของปากและลิ้น","explanation":"✗ ผิด — Tardive dyskinesia: choreoathetoid movement ของปาก ลิ้น หลังใช้ยานาน"},{"label":"E","text":"อาการสั่นขณะพัก (resting tremor)","explanation":"✗ ผิด — Resting tremor เป็นอาการของ drug-induced Parkinsonism"}],"key_takeaway":"Akathisia รักษา: Propranolol 10-40 mg/day (first-line) หรือ benzodiazepine | ไม่ใช่ lorazepam IM อย่าง acute dystonia"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:56') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b535aefa-0e3c-4060-9b8d-e2e61f0819e2', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับ Clozapine 300 mg/day มา 6 เดือน การติดตามที่สำคัญที่สุดในผู้ป่วยรายนี้คือ', NULL, '[{"label":"A","text":"ตรวจ LFT ทุก 3 เดือน"},{"label":"B","text":"ตรวจ CBC โดยเฉพาะ WBC และ ANC อย่างสม่ำเสมอ"},{"label":"C","text":"ตรวจ renal function ทุกเดือน"},{"label":"D","text":"ตรวจ ECG ทุก 6 เดือน"},{"label":"E","text":"ตรวจ thyroid function ทุก 3 เดือน"}]'::jsonb, 'B', 'Clozapine เสี่ยง agranulocytosis (~1-2%) ซึ่งอาจถึงตาย ต้องตรวจ CBC/WBC/ANC ตาม schedule: ทุกสัปดาห์ 6 เดือนแรก → ทุก 2 สัปดาห์ 6 เดือนต่อมา → ทุกเดือน', '{"summary":"Clozapine: ต้อง monitor CBC เพื่อตรวจ agranulocytosis ซึ่งเป็น black box warning","reason":"Clozapine ทำให้ agranulocytosis: ANC < 500/mm³ ต้องหยุดยาทันที ใน 6 เดือนแรกเสี่ยงสูงที่สุด ถ้า WBC < 3,000 หรือ ANC < 1,500 ให้ monitor ถี่ขึ้น ถ้า ANC < 1,000 ให้หยุดยา REMS program บังคับให้ monitor CBC ก่อนจ่ายยา","choices":[{"label":"A","text":"ตรวจ LFT ทุก 3 เดือน","explanation":"✗ ผิด — LFT ไม่ใช่ priority หลักของ clozapine (แม้จะมี hepatotoxicity บ้าง)"},{"label":"B","text":"ตรวจ CBC โดยเฉพาะ WBC และ ANC อย่างสม่ำเสมอ","explanation":"✓ ถูก — Agranulocytosis เป็น life-threatening ADR ของ clozapine ต้อง monitor CBC ตาม schedule"},{"label":"C","text":"ตรวจ renal function ทุกเดือน","explanation":"✗ ผิด — Clozapine ไม่ toxic ต่อไตโดยตรง"},{"label":"D","text":"ตรวจ ECG ทุก 6 เดือน","explanation":"✗ ผิด — Clozapine อาจยืด QTc แต่ไม่ใช่ priority หลักเท่า agranulocytosis"},{"label":"E","text":"ตรวจ thyroid function ทุก 3 เดือน","explanation":"✗ ผิด — ไม่ใช่ required monitoring สำหรับ clozapine"}],"key_takeaway":"Clozapine monitoring: CBC สัปดาห์ละครั้ง ×6 เดือน → 2 สัปดาห์ครั้ง ×6 เดือน → เดือนละครั้ง | หยุดทันทีถ้า ANC < 1,000"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:56') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f041c512-465d-4396-890e-472972ac74de', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับ Lithium เพื่อรักษา Bipolar disorder ระดับ Lithium ในเลือด = 2.5 mEq/L อาการใดที่ต้องระวังมากที่สุด', NULL, '[{"label":"A","text":"Polyuria และ Polydipsia"},{"label":"B","text":"น้ำหนักขึ้น"},{"label":"C","text":"Tremor มือละเอียด"},{"label":"D","text":"ชัก สับสน หมดสติ (Lithium toxicity รุนแรง)"},{"label":"E","text":"ผื่นสิว"}]'::jsonb, 'D', 'ระดับ Lithium > 2.0 mEq/L คือ severe toxicity มีอาการ neurotoxicity รุนแรง: seizure, confusion, coma อาจเสียชีวิตได้ ต้องหยุดยาและรักษาสนับสนุนทันที ระดับ therapeutic = 0.6-1.2 mEq/L', '{"summary":"Lithium toxicity: >1.5 mild, >2.0 moderate-severe (neuro toxic), >3.0 life-threatening","reason":"Lithium therapeutic range: 0.6-1.2 mEq/L (acute mania: 0.8-1.2) | 1.5-2.0: mild (tremor, GI, confusion) | 2.0-2.5: moderate (ataxia, slurred speech, marked confusion) | >2.5: severe (seizure, coma, death) รักษา: IV NS + hemodialysis ถ้า severe","choices":[{"label":"A","text":"Polyuria และ Polydipsia","explanation":"✗ ผิด — เป็น SE ที่พบบ่อยในการใช้ lithium ระยะยาว (nephrogenic DI) ไม่ใช่ฉุกเฉิน"},{"label":"B","text":"น้ำหนักขึ้น","explanation":"✗ ผิด — เป็น SE ที่พบบ่อยแต่ไม่อันตราย"},{"label":"C","text":"Tremor มือละเอียด","explanation":"✗ ผิด — Fine tremor เป็น SE ปกติของ lithium ระดับ therapeutic"},{"label":"D","text":"ชัก สับสน หมดสติ (Lithium toxicity รุนแรง)","explanation":"✓ ถูก — Lithium 2.5 mEq/L = severe toxicity ต้องรักษาฉุกเฉิน hemodialysis"},{"label":"E","text":"ผื่นสิว","explanation":"✗ ผิด — Acne เป็น SE ทางผิวหนังของ lithium ไม่อันตราย"}],"key_takeaway":"Lithium toxic range: >2.0 mEq/L → neurologic emergency | Rx: หยุดยา + IV NS + dialysis | ป้องกัน: monitor level ทุก 3-6 เดือน"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:25:56') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7a3f0eb2-807f-444c-91ce-4324e940b986', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 32 ปี วินิจฉัย Major Depressive Disorder ยาต้านเศร้ากลุ่มใดที่เป็น first-line treatment', NULL, '[{"label":"A","text":"Tricyclic antidepressants (TCA)"},{"label":"B","text":"Monoamine oxidase inhibitors (MAOI)"},{"label":"C","text":"Selective serotonin reuptake inhibitors (SSRI)"},{"label":"D","text":"Typical antipsychotics"},{"label":"E","text":"Benzodiazepines"}]'::jsonb, 'C', 'SSRI เป็น first-line สำหรับ MDD เนื่องจากมีประสิทธิภาพดี ผลข้างเคียงน้อยกว่า TCA ปลอดภัยใน overdose และใช้ง่ายกว่า MAOI', '{"summary":"MDD first-line: SSRI (fluoxetine, sertraline, escitalopram) หรือ SNRI","reason":"SSRI: serotoninergic specific ผลข้างเคียงน้อย ปลอดภัยใน overdose ใช้ครั้งเดียวต่อวัน | TCA: anticholinergic, antihistamine, alpha-blocking มี cardiac toxicity ใน overdose | MAOI: food and drug interaction มาก (tyramine reaction) ใช้เป็น last resort | Benzo: ไม่ใช่ antidepressant ใช้สำหรับ anxiety","choices":[{"label":"A","text":"Tricyclic antidepressants (TCA)","explanation":"✗ ผิด — มีผลข้างเคียงมาก (anticholinergic, cardiac) อันตรายใน overdose ใช้เป็น second-line"},{"label":"B","text":"Monoamine oxidase inhibitors (MAOI)","explanation":"✗ ผิด — interaction มาก (tyramine → hypertensive crisis) ใช้เป็น last resort"},{"label":"C","text":"Selective serotonin reuptake inhibitors (SSRI)","explanation":"✓ ถูก — First-line: ประสิทธิภาพดี ปลอดภัย ผลข้างเคียงน้อย"},{"label":"D","text":"Typical antipsychotics","explanation":"✗ ผิด — ใช้รักษา psychosis ไม่ใช่ first-line ใน MDD (ยกเว้น psychotic depression)"},{"label":"E","text":"Benzodiazepines","explanation":"✗ ผิด — ไม่ใช่ antidepressant อาจใช้ระยะสั้นสำหรับ anxiety/insomnia ร่วม"}],"key_takeaway":"MDD first-line: SSRI/SNRI | ระยะเวลาขั้นต่ำ 6-9 เดือน | ประเมิน suicide risk ทุกครั้ง"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('28443ee1-abb9-4aab-a623-4d73fbe75fe9', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับ Fluoxetine มาแล้ว 3 วัน พบอาการ: ไข้ ชัก กล้ามเนื้อกระตุก (myoclonus) เหงื่อออกมาก ใจสั่น ควรนึกถึงภาวะใดก่อน', NULL, '[{"label":"A","text":"Neuroleptic Malignant Syndrome (NMS)"},{"label":"B","text":"Serotonin Syndrome"},{"label":"C","text":"Anticholinergic toxicity"},{"label":"D","text":"SSRI discontinuation syndrome"},{"label":"E","text":"Tardive dyskinesia"}]'::jsonb, 'B', 'Serotonin syndrome เกิดจาก serotonin excess ใน CNS อาการ: mental status change + autonomic instability + neuromuscular abnormality (myoclonus, hyperreflexia, clonus) มักเกิดภายใน 24 ชั่วโมง', '{"summary":"Serotonin syndrome: triad = altered mental status + autonomic instability + neuromuscular findings","reason":"Hunter criteria สำหรับ Serotonin syndrome: clonus (spontaneous/inducible/ocular) + agitation/diaphoresis + tremor + hyperreflexia | เกิดจาก: SSRI+MAOI, SSRI+Tramadol, SSRI+Triptan, SSRI+Linezolid | รักษา: หยุดยา, cyproheptadine, benzodiazepine, supportive","choices":[{"label":"A","text":"Neuroleptic Malignant Syndrome (NMS)","explanation":"✗ ผิด — NMS เกิดจาก antipsychotics: ไข้สูง, rigidity (lead-pipe), altered consciousness, elevated CPK, autonomic instability เริ่มช้ากว่า (วัน-สัปดาห์)"},{"label":"B","text":"Serotonin Syndrome","explanation":"✓ ถูก — ไข้ + myoclonus + diaphoresis + tachycardia หลังเริ่ม SSRI = serotonin syndrome"},{"label":"C","text":"Anticholinergic toxicity","explanation":"✗ ผิด — Anticholinergic: dry (ปากแห้ง ผิวแห้ง), hot, blind, mad, tachycardia ไม่มี myoclonus"},{"label":"D","text":"SSRI discontinuation syndrome","explanation":"✗ ผิด — เกิดเมื่อ หยุดยาเร็ว ไม่ใช่เริ่มยา อาการ: FINISH (Flu-like, Insomnia, Nausea, Imbalance, Sensory disturbance, Hyperarousal)"},{"label":"E","text":"Tardive dyskinesia","explanation":"✗ ผิด — TD เกิดหลังใช้ antipsychotics นาน ไม่ใช่ SSRI และไม่มีไข้"}],"key_takeaway":"Serotonin syndrome: ใน 24hr หลังเพิ่ม serotonergic drug | NMS: ในสัปดาห์หลังเริ่ม/เปลี่ยน antipsychotic | แยกด้วย: Rigidity (NMS) vs Myoclonus/clonus (SS)"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('74454314-e449-454b-a81d-09fcbef2006b', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ยาต้านซึมเศร้าชนิดใดที่เหมาะสมที่สุดสำหรับผู้ป่วย MDD ที่มี neuropathic pain ร่วมด้วย', NULL, '[{"label":"A","text":"Fluoxetine"},{"label":"B","text":"Sertraline"},{"label":"C","text":"Duloxetine (SNRI)"},{"label":"D","text":"Escitalopram"},{"label":"E","text":"Fluvoxamine"}]'::jsonb, 'C', 'Duloxetine (SNRI) มีข้อบ่งใช้ทั้ง MDD และ neuropathic pain (diabetic peripheral neuropathy, fibromyalgia) เนื่องจากยับยั้งทั้ง serotonin และ norepinephrine reuptake', '{"summary":"SNRI (duloxetine, venlafaxine) มีประโยชน์ทั้ง depression และ pain conditions","reason":"Duloxetine FDA approved: MDD, GAD, Diabetic peripheral neuropathy, Fibromyalgia, Chronic musculoskeletal pain | Norepinephrine pathway สำคัญในการควบคุมความเจ็บปวด SSRI อย่างเดียว (fluoxetine, sertraline) ไม่มี indication สำหรับ pain","choices":[{"label":"A","text":"Fluoxetine","explanation":"✗ ผิด — SSRI ไม่มี indication ใน neuropathic pain"},{"label":"B","text":"Sertraline","explanation":"✗ ผิด — SSRI เช่นกัน ไม่มีหลักฐานใน neuropathic pain"},{"label":"C","text":"Duloxetine (SNRI)","explanation":"✓ ถูก — FDA approved ทั้ง MDD และ diabetic neuropathy/fibromyalgia"},{"label":"D","text":"Escitalopram","explanation":"✗ ผิด — SSRI ไม่มี indication ใน pain"},{"label":"E","text":"Fluvoxamine","explanation":"✗ ผิด — SSRI ใช้หลักใน OCD ไม่มี indication ใน pain"}],"key_takeaway":"Pain + Depression: Duloxetine (SNRI) ดีที่สุด | TCAs (amitriptyline) ก็ใช้ได้แต่ SE มากกว่า | Pregabalin/Gabapentin ใช้สำหรับ pain โดยเฉพาะ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('705dae9b-4b17-49b3-8c2f-04b4e0de6cd2', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วย Bipolar I disorder ในระยะ acute manic episode ยาที่เป็น first-line treatment คือ', NULL, '[{"label":"A","text":"Antidepressant (SSRI)"},{"label":"B","text":"Lithium หรือ Valproate ± Antipsychotic"},{"label":"C","text":"Benzodiazepine เพียงอย่างเดียว"},{"label":"D","text":"Carbamazepine เป็นยาเดี่ยว"},{"label":"E","text":"Haloperidol เพียงอย่างเดียว"}]'::jsonb, 'B', 'Acute mania: Lithium หรือ Valproate (mood stabilizer) ± Antipsychotic (olanzapine/risperidone/quetiapine) เป็น first-line ห้ามให้ antidepressant เพียงอย่างเดียวเพราะอาจ trigger mania', '{"summary":"Bipolar mania first-line: Mood stabilizer (Li/VPA) ± Atypical antipsychotic","reason":"Acute mania รุนแรง: Lithium + Antipsychotic หรือ Valproate + Antipsychotic | ไม่รุนแรง: Lithium หรือ Valproate เดี่ยว | Antidepressant ห้ามใช้ใน mania เพราะทำให้ worse | Carbamazepine: alternative แต่ drug interaction มาก | Benzodiazepine: ช่วย agitation แต่ไม่ใช่ definitive treatment","choices":[{"label":"A","text":"Antidepressant (SSRI)","explanation":"✗ ผิด — ห้ามใช้ใน acute mania! อาจ trigger switch เป็น mania หนักขึ้น"},{"label":"B","text":"Lithium หรือ Valproate ± Antipsychotic","explanation":"✓ ถูก — First-line ตาม guideline: mood stabilizer ± atypical antipsychotic"},{"label":"C","text":"Benzodiazepine เพียงอย่างเดียว","explanation":"✗ ผิด — Benzo ช่วย agitation แต่ไม่ใช่ mood stabilizer ไม่เพียงพอ"},{"label":"D","text":"Carbamazepine เป็นยาเดี่ยว","explanation":"✗ ผิด — Carbamazepine เป็น alternative แต่ไม่ใช่ first-line มี drug interaction มาก"},{"label":"E","text":"Haloperidol เพียงอย่างเดียว","explanation":"✗ ผิด — Antipsychotic เดี่ยวโดยไม่มี mood stabilizer ไม่เพียงพอสำหรับ bipolar"}],"key_takeaway":"Bipolar mania: Lithium/Valproate + Atypical antipsychotic | Maintenance: Lithium (gold standard) | ห้าม antidepressant เดี่ยว"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1d000656-3403-4f97-ae64-f19456712d21', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 28 ปี วินิจฉัย Generalized Anxiety Disorder (GAD) ยาที่เป็น first-line treatment ที่เหมาะสมที่สุดคือ', NULL, '[{"label":"A","text":"Alprazolam ระยะยาว"},{"label":"B","text":"SSRI (เช่น Escitalopram) หรือ SNRI"},{"label":"C","text":"Haloperidol"},{"label":"D","text":"Phenobarbital"},{"label":"E","text":"Hydroxyzine เป็นยาหลัก"}]'::jsonb, 'B', 'SSRI/SNRI เป็น first-line สำหรับ GAD ระยะยาว Benzodiazepine ใช้ระยะสั้นเท่านั้น (< 4 สัปดาห์) เพราะเสี่ยง dependence', '{"summary":"GAD first-line: SSRI/SNRI (long-term) | Benzo: short-term adjunct เท่านั้น","reason":"SSRI (sertraline, escitalopram) และ SNRI (venlafaxine, duloxetine) FDA approved ใน GAD ปลอดภัย ใช้ระยะยาว | Buspirone: non-benzo anxiolytic ใช้ GAD ได้แต่ onset ช้า 2-4 สัปดาห์ | Benzodiazepine: ใช้ระยะสั้นช่วง gap ก่อน SSRI/SNRI ออกฤทธิ์ เสี่ยง dependence และ cognitive impairment","choices":[{"label":"A","text":"Alprazolam ระยะยาว","explanation":"✗ ผิด — Benzodiazepine ระยะยาวเสี่ยง dependence, tolerance, cognitive impairment ไม่แนะนำ"},{"label":"B","text":"SSRI (เช่น Escitalopram) หรือ SNRI","explanation":"✓ ถูก — First-line สำหรับ GAD ระยะยาว ปลอดภัย ไม่เสี่ยง dependence"},{"label":"C","text":"Haloperidol","explanation":"✗ ผิด — Antipsychotic ไม่ใช่ treatment สำหรับ GAD"},{"label":"D","text":"Phenobarbital","explanation":"✗ ผิด — Barbiturate ไม่ใช่ยา anxiety ในปัจจุบัน อันตรายและเสี่ยง dependence สูง"},{"label":"E","text":"Hydroxyzine เป็นยาหลัก","explanation":"✗ ผิด — Hydroxyzine (antihistamine) ช่วย anxiety ได้บ้างแต่ไม่ใช่ first-line ทำให้ง่วงมาก"}],"key_takeaway":"GAD first-line: SSRI/SNRI (ระยะยาว) | Buspirone: alternative | Benzo: short-term adjunct เท่านั้น"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('77e69451-0693-4bb5-a4c7-7a43ed8b482c', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'Risperidone ต่างจาก Haloperidol (typical antipsychotic) อย่างไร', NULL, '[{"label":"A","text":"Risperidone มีประสิทธิภาพน้อยกว่า"},{"label":"B","text":"Risperidone มี EPS น้อยกว่าและรักษา negative symptoms ได้ดีกว่า"},{"label":"C","text":"Risperidone ไม่ทำให้ QTc ยืดเลย"},{"label":"D","text":"Risperidone ไม่มีผลต่อ dopamine"},{"label":"E","text":"Risperidone ปลอดภัยกว่าในผู้ป่วยสูงอายุ"}]'::jsonb, 'B', 'Atypical antipsychotics (Risperidone, Olanzapine, Quetiapine) มี EPS น้อยกว่า typical (Haloperidol, Chlorpromazine) และรักษา negative symptoms (alogia, avolition, flat affect) ของ schizophrenia ได้ดีกว่า', '{"summary":"Atypical vs Typical antipsychotic: Atypical มี EPS น้อย + ดีกว่าสำหรับ negative symptoms","reason":"Typical (D2 blocker): EPS สูง, ไม่ช่วย negative symptoms | Atypical (D2+5HT2A blocker): EPS น้อย, ช่วย negative symptoms, แต่มี metabolic side effects (น้ำหนักขึ้น, DM, dyslipidemia) | Risperidone ยังมี EPS มากกว่า quetiapine/olanzapine เมื่อใช้ขนาดสูง","choices":[{"label":"A","text":"Risperidone มีประสิทธิภาพน้อยกว่า","explanation":"✗ ผิด — Atypical มีประสิทธิภาพเทียบเท่าหรือดีกว่า typical สำหรับ positive symptoms"},{"label":"B","text":"Risperidone มี EPS น้อยกว่าและรักษา negative symptoms ได้ดีกว่า","explanation":"✓ ถูก — จุดเด่นหลักของ atypical antipsychotics"},{"label":"C","text":"Risperidone ไม่ทำให้ QTc ยืดเลย","explanation":"✗ ผิด — Risperidone ก็ยืด QTc ได้ (น้อยกว่า haloperidol IV แต่ก็มี)"},{"label":"D","text":"Risperidone ไม่มีผลต่อ dopamine","explanation":"✗ ผิด — Risperidone บล็อก D2 receptor เช่นกัน แต่บล็อก 5HT2A ด้วย"},{"label":"E","text":"Risperidone ปลอดภัยกว่าในผู้ป่วยสูงอายุ","explanation":"✗ ผิด — ทั้ง typical และ atypical เพิ่มความเสี่ยง stroke/mortality ในผู้สูงอายุที่มี dementia"}],"key_takeaway":"Atypical AP: EPS น้อย + negative symptoms ดีกว่า แต่แลกกับ metabolic syndrome | Clozapine: most effective แต่ agranulocytosis"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0b37cfa3-bf13-4d16-b99a-a4f05a974aa3', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับ Antipsychotic มาได้ 2 ปี พบอาการขยับปากซ้ำๆ ดูดปาก ขยับลิ้น โดยที่ผู้ป่วยไม่ทราบตัว ควรวินิจฉัยว่าอะไร และรักษาอย่างไร', NULL, '[{"label":"A","text":"Acute dystonia รักษาด้วย Diphenhydramine IM"},{"label":"B","text":"Tardive dyskinesia รักษาด้วย Valbenazine หรือ Deutetrabenazine"},{"label":"C","text":"Akathisia รักษาด้วย Propranolol"},{"label":"D","text":"Parkinsonism รักษาด้วย Trihexyphenidyl"},{"label":"E","text":"Serotonin syndrome รักษาด้วย Cyproheptadine"}]'::jsonb, 'B', 'Tardive dyskinesia (TD): การเคลื่อนไหวผิดปกติของปาก ลิ้น ใบหน้า แบบ choreoathetoid โดยผู้ป่วยไม่รู้ตัว หลังใช้ dopamine blocker นาน ≥3 เดือน รักษาด้วย VMAT2 inhibitor (Valbenazine, Deutetrabenazine)', '{"summary":"Tardive dyskinesia: involuntary choreoathetoid movement ปาก/ลิ้น/ใบหน้า หลังใช้ antipsychotic นาน","reason":"TD เกิดจาก D2 receptor upregulation หลัง chronic blockade อาการ: lip smacking, tongue protrusion, facial grimacing, choreoathetoid limb movement ผู้ป่วยมักไม่รู้ตัว | AIMS scale ประเมิน | รักษา: VMAT2 inhibitor (valbenazine/deutetrabenazine) ลด dopamine release | ลด/เปลี่ยนเป็น atypical antipsychotic","choices":[{"label":"A","text":"Acute dystonia รักษาด้วย Diphenhydramine IM","explanation":"✗ ผิด — Acute dystonia เกิดใน 4 วันแรก กล้ามเนื้อ spasm เฉียบพลัน ไม่ใช่ขยับซ้ำๆ"},{"label":"B","text":"Tardive dyskinesia รักษาด้วย Valbenazine หรือ Deutetrabenazine","explanation":"✓ ถูก — TD: ขยับซ้ำๆ ไม่รู้ตัว หลัง antipsychotic นาน รักษาด้วย VMAT2i"},{"label":"C","text":"Akathisia รักษาด้วย Propranolol","explanation":"✗ ผิด — Akathisia: รู้สึกอยู่ไม่สุข ต้องขยับ ผู้ป่วยรู้ตัว"},{"label":"D","text":"Parkinsonism รักษาด้วย Trihexyphenidyl","explanation":"✗ ผิด — Drug-induced Parkinsonism: resting tremor, rigidity, bradykinesia ไม่ใช่ lip smacking"},{"label":"E","text":"Serotonin syndrome รักษาด้วย Cyproheptadine","explanation":"✗ ผิด — Serotonin syndrome: ไข้ myoclonus เกิดเฉียบพลัน ไม่ใช่ chronic movement disorder"}],"key_takeaway":"TD: เกิดหลัง ≥3 เดือน involuntary movement | รักษา: Valbenazine/Deutetrabenazine (VMAT2i) | ป้องกัน: ใช้ atypical AP, ลด dose เป็นระยะ"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:25:57') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b8b9a8c4-0566-49d3-8eb8-a02f3319a855', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยได้รับยา Amitriptyline ผลข้างเคียงจากคุณสมบัติ Anticholinergic ที่พบบ่อยคือข้อใด', NULL, '[{"label":"A","text":"ท้องเสีย น้ำลายไหลมาก"},{"label":"B","text":"ปากแห้ง ท้องผูก ปัสสาวะขัด สายตาพร่า"},{"label":"C","text":"น้ำหนักลด ขี้ร้อน"},{"label":"D","text":"ความดันต่ำขณะออกกำลัง"},{"label":"E","text":"เหงื่อออกมาก หัวใจเต้นช้า"}]'::jsonb, 'B', 'Anticholinergic effects (SLUD opposite): ปากแห้ง ท้องผูก ปัสสาวะขัด สายตาพร่า (mydriasis) ผิวแดงแห้งร้อน ใจสั่น สับสน (ในผู้สูงอายุ)', '{"summary":"Anticholinergic toxidrome: DUMB → Dry, Urinary retention, Mydriasis, Blurred vision + Bowel obstipation","reason":"Amitriptyline มี anticholinergic activity สูงมาก: ปากแห้ง ท้องผูก ปัสสาวะขัด สายตาพร่า ผิวแห้งแดง ใจสั่น hyperthermia delirium (ผู้สูงอายุ) | TCA ควรระวังในผู้สูงอายุ, BPH, narrow-angle glaucoma, ท้องผูกเรื้อรัง | Beers criteria: ห้ามใช้ TCA ใน elderly","choices":[{"label":"A","text":"ท้องเสีย น้ำลายไหลมาก","explanation":"✗ ผิด — เป็น cholinergic effect (SLUD: Salivation, Lacrimation, Urination, Defecation) ตรงข้ามกับ anticholinergic"},{"label":"B","text":"ปากแห้ง ท้องผูก ปัสสาวะขัด สายตาพร่า","explanation":"✓ ถูก — Classic anticholinergic side effects ของ amitriptyline/TCA"},{"label":"C","text":"น้ำหนักลด ขี้ร้อน","explanation":"✗ ผิด — อาการของ hyperthyroidism ไม่ใช่ anticholinergic"},{"label":"D","text":"ความดันต่ำขณะออกกำลัง","explanation":"✗ ผิด — Orthostatic hypotension ของ TCA เกิดจาก alpha-1 blockade ไม่ใช่ anticholinergic"},{"label":"E","text":"เหงื่อออกมาก หัวใจเต้นช้า","explanation":"✗ ผิด — Anticholinergic ทำให้ เหงื่อออกน้อย และ tachycardia ไม่ใช่ bradycardia"}],"key_takeaway":"TCA anticholinergic: Dry mouth, Constipation, Urinary retention, Blurred vision, Tachycardia, Delirium | ระวังใน elderly, BPH, glaucoma"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0a086303-8ae0-4464-a310-5846105520d9', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยใช้ SSRI มา 2 สัปดาห์แล้วหยุดยาเองกะทันหัน พบอาการ ปวดหัว คลื่นไส้ รู้สึกเหมือนไฟฟ้าช็อต (electric shock sensation) วิงเวียน นึกถึงภาวะใด', NULL, '[{"label":"A","text":"Serotonin syndrome"},{"label":"B","text":"SSRI Discontinuation syndrome"},{"label":"C","text":"MDD relapse"},{"label":"D","text":"Anxiety attack"},{"label":"E","text":"Hypoglycemia"}]'::jsonb, 'B', 'SSRI Discontinuation syndrome เกิดเมื่อหยุด SSRI กะทันหัน อาการ FINISH: Flu-like, Insomnia, Nausea, Imbalance, Sensory disturbance (brain zap), Hyperarousal/anxiety ใน 1-3 วัน', '{"summary":"SSRI Discontinuation: หยุดยาเร็ว → FINISH symptoms ใน 1-3 วัน","reason":"Brain zap (electric shock sensation) เป็นอาการ pathognomonic ของ SSRI discontinuation รักษา: reintroduce SSRI แล้วค่อย taper ช้าๆ Paroxetine และ Venlafaxine มี discontinuation syndrome บ่อยที่สุด (t½ สั้น) Fluoxetine น้อยที่สุด (t½ ยาวมาก ~4-6 วัน)","choices":[{"label":"A","text":"Serotonin syndrome","explanation":"✗ ผิด — Serotonin syndrome เกิดเมื่อ serotonin สูงเกิน (เริ่มยา/เพิ่มยา) ไม่ใช่หยุดยา"},{"label":"B","text":"SSRI Discontinuation syndrome","explanation":"✓ ถูก — Brain zap + คลื่นไส้ + วิงเวียน หลังหยุด SSRI กะทันหัน = classic discontinuation syndrome"},{"label":"C","text":"MDD relapse","explanation":"✗ ผิด — MDD relapse ใช้เวลานานกว่า ไม่มี brain zap"},{"label":"D","text":"Anxiety attack","explanation":"✗ ผิด — Panic attack ไม่มี brain zap และไม่สัมพันธ์กับการหยุดยา"},{"label":"E","text":"Hypoglycemia","explanation":"✗ ผิด — Hypoglycemia: เหงื่อออก ใจสั่น สับสน ไม่มี brain zap"}],"key_takeaway":"SSRI หยุดเร็ว → FINISH | Brain zap = pathognomonic | Fluoxetine หยุดง่ายที่สุด (t½ ยาว) | Paroxetine/Venlafaxine หยุดยากที่สุด"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('40d0117a-9403-4f21-aaec-399963caae10', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'Valproate ใช้รักษาโรคใดได้บ้าง (เลือกที่ถูกต้องที่สุด)', NULL, '[{"label":"A","text":"Bipolar disorder เท่านั้น"},{"label":"B","text":"Epilepsy เท่านั้น"},{"label":"C","text":"Bipolar disorder, Epilepsy และ Migraine prophylaxis"},{"label":"D","text":"Schizophrenia และ Depression"},{"label":"E","text":"GAD และ Panic disorder"}]'::jsonb, 'C', 'Valproate มี FDA approved indications หลายอย่าง: Epilepsy (complex partial, absence, generalized), Bipolar mania, Migraine prophylaxis นอกจากนี้ยังใช้ off-label ใน neuropathic pain', '{"summary":"Valproate: triple indication — Epilepsy + Bipolar mania + Migraine prevention","reason":"Valproate กลไก: เพิ่ม GABA, บล็อก sodium channel, บล็อก T-type Ca channel | Epilepsy: ทุกชนิดโดยเฉพาะ generalized | Bipolar: acute mania และ maintenance | Migraine prophylaxis: ลดความถี่ได้ 50% | ข้อห้าม: ตั้งครรภ์ (neural tube defects, teratogenic), โรคตับ","choices":[{"label":"A","text":"Bipolar disorder เท่านั้น","explanation":"✗ ผิด — Valproate ใช้ทั้ง epilepsy และ migraine ด้วย"},{"label":"B","text":"Epilepsy เท่านั้น","explanation":"✗ ผิด — ใช้ใน bipolar และ migraine prophylaxis ด้วย"},{"label":"C","text":"Bipolar disorder, Epilepsy และ Migraine prophylaxis","explanation":"✓ ถูก — ครบ 3 indications หลักของ valproate"},{"label":"D","text":"Schizophrenia และ Depression","explanation":"✗ ผิด — ไม่ใช่ indication ของ valproate"},{"label":"E","text":"GAD และ Panic disorder","explanation":"✗ ผิด — Benzodiazepine/SSRI ใช้ใน anxiety disorders ไม่ใช่ valproate"}],"key_takeaway":"Valproate: Epilepsy + Bipolar mania + Migraine prevention | ห้ามใช้ตั้งครรภ์ (teratogenic: NTD, cognitive impairment in children)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4b35dea9-b671-412f-877a-befa3575ebe3', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยรับ Olanzapine มา 6 เดือน พบว่าน้ำหนักขึ้น 8 kg ระดับน้ำตาลสูง ไขมันในเลือดสูง ควรติดตามอะไร', NULL, '[{"label":"A","text":"CBC และ LFT"},{"label":"B","text":"Metabolic parameters: น้ำหนัก BMI ระดับน้ำตาล HbA1c ไขมัน ความดัน"},{"label":"C","text":"Renal function ทุกเดือน"},{"label":"D","text":"Thyroid function ทุก 6 เดือน"},{"label":"E","text":"ECG ทุก 3 เดือน"}]'::jsonb, 'B', 'Atypical antipsychotics โดยเฉพาะ Olanzapine และ Clozapine มีความเสี่ยงสูงสำหรับ metabolic syndrome ต้อง monitor น้ำหนัก, BMI, waist, FPG, HbA1c, lipid, BP ตาม ADA/APA guideline', '{"summary":"Olanzapine/Clozapine: Metabolic syndrome risk สูงที่สุดใน atypical AP group","reason":"ความเสี่ยง metabolic syndrome ของ atypical AP: Clozapine = Olanzapine > Quetiapine > Risperidone > Aripiprazole/Ziprasidone | Monitor: baseline → 4 สัปดาห์ → 8 สัปดาห์ → 12 สัปดาห์ → ทุก 3 เดือน: น้ำหนัก, FPG, lipid, BP | พิจารณาเปลี่ยนยาถ้า metabolic syndrome แย่ลง","choices":[{"label":"A","text":"CBC และ LFT","explanation":"✗ ผิด — CBC สำคัญสำหรับ clozapine แต่ไม่ใช่ priority หลักสำหรับ olanzapine"},{"label":"B","text":"Metabolic parameters: น้ำหนัก BMI ระดับน้ำตาล HbA1c ไขมัน ความดัน","explanation":"✓ ถูก — Metabolic syndrome monitoring เป็น priority หลักของ olanzapine"},{"label":"C","text":"Renal function ทุกเดือน","explanation":"✗ ผิด — Olanzapine ไม่ toxic ต่อไตโดยตรง"},{"label":"D","text":"Thyroid function ทุก 6 เดือน","explanation":"✗ ผิด — ไม่ใช่ required monitoring สำหรับ olanzapine"},{"label":"E","text":"ECG ทุก 3 เดือน","explanation":"✗ ผิด — QTc monitoring สำคัญกว่าสำหรับ ziprasidone/haloperidol IV ไม่ใช่ olanzapine"}],"key_takeaway":"Olanzapine: Metabolic monitoring ทุก 3 เดือน | เสี่ยง DM/dyslipidemia สูง | พิจารณา switch เป็น aripiprazole ถ้า metabolic SE มาก"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e7903fcf-6db9-41b5-a405-3104cebbe0ff', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 30 ปี วินิจฉัย ADHD ยาที่เป็น first-line สำหรับผู้ใหญ่คือ', NULL, '[{"label":"A","text":"Methylphenidate หรือ Amphetamine salts"},{"label":"B","text":"Risperidone"},{"label":"C","text":"Diazepam"},{"label":"D","text":"Haloperidol"},{"label":"E","text":"Sertraline"}]'::jsonb, 'A', 'Stimulants (Methylphenidate, Amphetamine) เป็น first-line สำหรับ ADHD ทั้งในเด็กและผู้ใหญ่ มีประสิทธิภาพสูงสุด ลด inattention และ hyperactivity ได้ดี Atomoxetine เป็น non-stimulant alternative', '{"summary":"ADHD first-line: Stimulants (Methylphenidate/Amphetamine) | Non-stimulant: Atomoxetine, Guanfacine","reason":"Methylphenidate: บล็อก DAT/NET → เพิ่ม DA/NE ใน PFC | Amphetamine: เพิ่ม release DA/NE | ประสิทธิภาพ effect size ~0.8 | Non-stimulant: Atomoxetine (SNRI-like), Guanfacine/Clonidine (alpha-2 agonist) ใช้ถ้า stimulant ไม่ได้ผล/ข้อห้าม | ข้อควรระวัง: ประวัติ substance abuse → Atomoxetine/non-stimulant ดีกว่า","choices":[{"label":"A","text":"Methylphenidate หรือ Amphetamine salts","explanation":"✓ ถูก — Stimulants เป็น first-line ADHD ทุก guideline ประสิทธิภาพสูงสุด"},{"label":"B","text":"Risperidone","explanation":"✗ ผิด — Antipsychotic ไม่ใช่ first-line ADHD ใช้เฉพาะถ้ามี comorbid mania/psychosis"},{"label":"C","text":"Diazepam","explanation":"✗ ผิด — Benzodiazepine ไม่มีประสิทธิภาพใน ADHD อาจทำให้แย่ลง"},{"label":"D","text":"Haloperidol","explanation":"✗ ผิด — Typical antipsychotic ไม่ใช่ treatment ADHD"},{"label":"E","text":"Sertraline","explanation":"✗ ผิด — SSRI ไม่มีประสิทธิภาพใน ADHD (Bupropion มีหลักฐานมากกว่าแต่ก็ไม่ใช่ first-line)"}],"key_takeaway":"ADHD: Stimulants (MPH/AMPH) first-line | Atomoxetine: non-stimulant alternative | ระวัง substance abuse, cardiovascular, tic disorders"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b4f5953a-975e-438b-b2d4-01de3f7fa028', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยที่รับ MAOIs (Phenelzine) รับประทานอาหารที่มี Tyramine สูง (เนยแข็ง ไวน์แดง) จะเกิดอะไรขึ้น', NULL, '[{"label":"A","text":"Hypoglycemia รุนแรง"},{"label":"B","text":"Hypertensive crisis (Cheese reaction)"},{"label":"C","text":"Serotonin syndrome"},{"label":"D","text":"Hypotension รุนแรง"},{"label":"E","text":"QTc prolongation"}]'::jsonb, 'B', 'MAOIs ยับยั้ง MAO-A ซึ่งย่อย Tyramine ในลำไส้และตับ เมื่อทาน Tyramine สูง → Tyramine สะสม → NE release มาก → Hypertensive crisis (severe headache, stroke risk)', '{"summary":"MAOI + Tyramine = Cheese reaction → Hypertensive crisis","reason":"MAO-A ปกติย่อย tyramine ก่อนเข้าระบบ เมื่อบล็อก MAO: tyramine เข้าเส้นเลือด → เข้าปลายประสาท sympathetic → displace NE → massive NE release → severe HTN → risk of hemorrhagic stroke | อาหาร tyramine สูง: aged cheese, cured meat, fermented food, red wine, beer | รักษา hypertensive crisis: Phentolamine IV (alpha-blocker)","choices":[{"label":"A","text":"Hypoglycemia รุนแรง","explanation":"✗ ผิด — MAOI อาจมีผล glycemic แต่ไม่ใช่ interaction หลักกับ tyramine"},{"label":"B","text":"Hypertensive crisis (Cheese reaction)","explanation":"✓ ถูก — Classic MAOI-Tyramine interaction: severe HTN, thunderclap headache, risk of stroke"},{"label":"C","text":"Serotonin syndrome","explanation":"✗ ผิด — Serotonin syndrome เกิดจาก MAOI + serotonergic drug ไม่ใช่ tyramine"},{"label":"D","text":"Hypotension รุนแรง","explanation":"✗ ผิด — Tyramine ทำให้ NE release มาก → ความดันสูง ไม่ใช่ต่ำ"},{"label":"E","text":"QTc prolongation","explanation":"✗ ผิด — ไม่เกี่ยวกับ tyramine-MAOI interaction"}],"key_takeaway":"MAOI: ห้ามกิน tyramine-rich food (aged cheese, red wine, cured meat) | ห้ามใช้ร่วม serotonergic drugs (→ Serotonin syndrome) | Wash-out 14 วันก่อนเปลี่ยนยา"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('34604e6b-166c-4814-980e-626c30f77b8e', 'beee26b1-72c2-4c70-be73-24d7fa036f19', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยที่รับยา Haloperidol IM ฉุกเฉิน พบอาการ Oculogyric crisis (ตากลอกขึ้นข้างบน กล้ามเนื้อคอแข็ง) ควรรักษาด้วยอะไรทันที', NULL, '[{"label":"A","text":"Propranolol 40 mg PO"},{"label":"B","text":"Diphenhydramine 50 mg IV/IM หรือ Benztropine 2 mg IV/IM"},{"label":"C","text":"Valbenazine PO"},{"label":"D","text":"Clonazepam 2 mg PO"},{"label":"E","text":"Flumazenil IV"}]'::jsonb, 'B', 'Oculogyric crisis เป็น acute dystonia ที่ต้องรักษาด้วย Anticholinergic drugs: Diphenhydramine (Benadryl) IV/IM หรือ Benztropine IV/IM ทำให้อาการหายภายในนาที', '{"summary":"Acute dystonia รักษาด้วย Anticholinergic (Diphenhydramine/Benztropine) IV/IM","reason":"Acute dystonia เกิดในช่วง 4 วันแรกของการใช้ D2 blocker dopamine ที่ถูกบล็อก → กล้ามเนื้อ hyper → sustained contraction (torticollis, opisthotonus, oculogyric crisis) รักษา: Diphenhydramine 50mg IV หรือ Benztropine 2mg IV ออกฤทธิ์เร็ว 5-10 นาที ควรให้ anticholinergic ป้องกันด้วยถ้าใช้ high-potency AP","choices":[{"label":"A","text":"Propranolol 40 mg PO","explanation":"✗ ผิด — Propranolol ใช้สำหรับ akathisia ไม่ใช่ acute dystonia"},{"label":"B","text":"Diphenhydramine 50 mg IV/IM หรือ Benztropine 2 mg IV/IM","explanation":"✓ ถูก — Anticholinergic IM/IV รักษา acute dystonia ได้ทันที"},{"label":"C","text":"Valbenazine PO","explanation":"✗ ผิด — VMAT2i ใช้สำหรับ tardive dyskinesia ไม่ใช่ acute dystonia"},{"label":"D","text":"Clonazepam 2 mg PO","explanation":"✗ ผิด — Benzodiazepine ช่วย akathisia แต่ไม่ใช่ first-line acute dystonia และ PO ช้าเกินไป"},{"label":"E","text":"Flumazenil IV","explanation":"✗ ผิด — Flumazenil เป็น benzodiazepine antagonist ไม่เกี่ยวกับ EPS"}],"key_takeaway":"Acute dystonia: Diphenhydramine 50mg IV/IM หรือ Benztropine 2mg IV/IM → หายใน 5-10 นาที | ป้องกัน: ให้ benztropine ร่วมกับ high-potency AP"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:25:58') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6c34bb12-f442-4c7f-8afa-33dbd69116c5', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี มีอาการสั่นขณะพัก (resting tremor) กล้ามเนื้อแข็งเกร็ง (rigidity) เดินช้า ก้าวเล็ก (bradykinesia) การวินิจฉัยและยาที่เหมาะสมคือ', NULL, '[{"label":"A","text":"Essential tremor รักษาด้วย Propranolol"},{"label":"B","text":"Parkinson''s disease รักษาด้วย Levodopa/Carbidopa"},{"label":"C","text":"Huntington''s disease รักษาด้วย Tetrabenazine"},{"label":"D","text":"Multiple sclerosis รักษาด้วย Interferon beta"},{"label":"E","text":"Myasthenia gravis รักษาด้วย Pyridostigmine"}]'::jsonb, 'B', 'อาการ cardinal features ของ Parkinson''s disease: resting tremor, rigidity, bradykinesia, postural instability รักษาด้วย Levodopa/Carbidopa (gold standard) ที่เพิ่ม dopamine ใน striatum', '{"summary":"Parkinson''s disease: TRAP = Tremor(rest), Rigidity, Akinesia/Bradykinesia, Postural instability","reason":"Levodopa: precursor ของ dopamine ผ่าน BBB ได้ | Carbidopa: peripheral DOPA decarboxylase inhibitor ลด peripheral conversion → เพิ่ม levodopa เข้า CNS + ลด nausea | ยาอื่น: Dopamine agonists (pramipexole, ropinirole), MAO-B inhibitors (selegiline, rasagiline), Amantadine, Anticholinergics (สำหรับ tremor)","choices":[{"label":"A","text":"Essential tremor รักษาด้วย Propranolol","explanation":"✗ ผิด — Essential tremor: action/postural tremor ไม่ใช่ resting tremor ไม่มี rigidity/bradykinesia"},{"label":"B","text":"Parkinson''s disease รักษาด้วย Levodopa/Carbidopa","explanation":"✓ ถูก — TRAP features + Levodopa/Carbidopa เป็น most effective treatment"},{"label":"C","text":"Huntington''s disease รักษาด้วย Tetrabenazine","explanation":"✗ ผิด — HD: chorea, cognitive decline, ถ่ายทอดทาง autosomal dominant ไม่มี resting tremor"},{"label":"D","text":"Multiple sclerosis รักษาด้วย Interferon beta","explanation":"✗ ผิด — MS: relapsing-remitting neurologic symptoms, young adult, ไม่มี resting tremor"},{"label":"E","text":"Myasthenia gravis รักษาด้วย Pyridostigmine","explanation":"✗ ผิด — MG: fatigable muscle weakness, ptosis, diplopia ไม่มี resting tremor/rigidity"}],"key_takeaway":"PD: Levodopa/Carbidopa = gold standard | เริ่มช้าเพื่อลด motor complications | Dopamine agonists: ใช้แทนในผู้ป่วยอายุน้อย"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:33:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('75e4a86f-d372-4d87-a46e-321fd6f50264', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยใช้ Levodopa/Carbidopa มา 5 ปี เริ่มมีปัญหา ''Wearing off'' คืออาการกลับมาก่อนถึงเวลากิน ยาใดที่เพิ่มได้เพื่อแก้ปัญหานี้', NULL, '[{"label":"A","text":"เพิ่มขนาด Levodopa เป็น 2 เท่า"},{"label":"B","text":"เพิ่ม MAO-B inhibitor (Rasagiline) หรือ COMT inhibitor (Entacapone)"},{"label":"C","text":"เพิ่ม Haloperidol"},{"label":"D","text":"เพิ่ม Propranolol"},{"label":"E","text":"หยุด Levodopa แล้วเปลี่ยนเป็น Anticholinergic"}]'::jsonb, 'B', 'Wearing off แก้ได้โดย: 1) MAO-B inhibitor (rasagiline/selegiline): ยับยั้งการสลาย dopamine 2) COMT inhibitor (entacapone/tolcapone): ยับยั้งการสลาย levodopa ทำให้ออกฤทธิ์นานขึ้น 3) เพิ่มความถี่ยา ไม่ใช่ขนาด', '{"summary":"Wearing off: ยาหมดฤทธิ์ก่อนเวลา → เพิ่ม MAO-Bi หรือ COMTi เพื่อยืดฤทธิ์ levodopa","reason":"Wearing off เกิดจาก dopaminergic neurons เสื่อมลง buffer dopamine ได้น้อยลง รักษา: (1) MAO-B inhibitor: selegiline/rasagiline ยับยั้ง MAO-B (ย่อย dopamine ใน brain) | (2) COMT inhibitor: entacapone ยับยั้ง COMT (ย่อย levodopa ใน periphery) → levodopa t½ ยาวขึ้น | (3) Dopamine agonist | (4) Extended-release levodopa","choices":[{"label":"A","text":"เพิ่มขนาด Levodopa เป็น 2 เท่า","explanation":"✗ ผิด — เพิ่มขนาดทำให้ dyskinesia มากขึ้น ควรเพิ่มความถี่แทน"},{"label":"B","text":"เพิ่ม MAO-B inhibitor (Rasagiline) หรือ COMT inhibitor (Entacapone)","explanation":"✓ ถูก — ทั้งสองช่วยยืดฤทธิ์ dopamine/levodopa ลด wearing off"},{"label":"C","text":"เพิ่ม Haloperidol","explanation":"✗ ผิด — Antipsychotic บล็อก D2 receptor ทำให้ PD แย่ลง ห้ามใช้ใน PD"},{"label":"D","text":"เพิ่ม Propranolol","explanation":"✗ ผิด — Beta-blocker ไม่มีประโยชน์ใน PD motor complications"},{"label":"E","text":"หยุด Levodopa แล้วเปลี่ยนเป็น Anticholinergic","explanation":"✗ ผิด — Levodopa ยังมีประสิทธิภาพดีที่สุด Anticholinergic ใช้เสริมสำหรับ tremor เท่านั้น"}],"key_takeaway":"Wearing off: เพิ่มความถี่ยา + เพิ่ม MAO-Bi/COMTi | Dyskinesia: ลดขนาด levodopa + เพิ่ม dopamine agonist"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:33:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('dbd60151-f8af-4508-b55f-d4a4d3fcec2c', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี มีอาการชาครึ่งซีก ตามัว อ่อนแรงขา เป็นๆ หายๆ ตลอด 2 ปี MRI พบ demyelinating lesions ที่ white matter วินิจฉัยและยา first-line คือ', NULL, '[{"label":"A","text":"Parkinson''s disease รักษาด้วย Levodopa"},{"label":"B","text":"Multiple Sclerosis รักษาด้วย Interferon beta-1a หรือ Glatiramer acetate"},{"label":"C","text":"Epilepsy รักษาด้วย Valproate"},{"label":"D","text":"Migraine รักษาด้วย Sumatriptan"},{"label":"E","text":"Myasthenia gravis รักษาด้วย Pyridostigmine"}]'::jsonb, 'B', 'Multiple Sclerosis: relapsing-remitting neurologic symptoms ใน young adults, demyelinating lesions ใน MRI รักษา disease-modifying therapy (DMT): Interferon beta หรือ Glatiramer acetate เป็น first-line', '{"summary":"MS: young female, relapsing-remitting, demyelination on MRI → DMT (Interferon/Glatiramer)","reason":"MS criteria (McDonald): ≥2 attacks + ≥2 lesions | DMT first-line: Interferon beta (1a/1b) หรือ Glatiramer acetate | High-efficacy: Natalizumab, Ocrelizumab, Alemtuzumab | Acute relapse: IV Methylprednisolone 1g/day × 3-5 วัน | ห้ามใช้ Natalizumab ถ้า JC virus antibody positive (risk PML)","choices":[{"label":"A","text":"Parkinson''s disease รักษาด้วย Levodopa","explanation":"✗ ผิด — PD ในผู้สูงอายุ มี TRAP features ไม่ใช่ relapsing-remitting"},{"label":"B","text":"Multiple Sclerosis รักษาด้วย Interferon beta-1a หรือ Glatiramer acetate","explanation":"✓ ถูก — RRMS + demyelination → DMT first-line"},{"label":"C","text":"Epilepsy รักษาด้วย Valproate","explanation":"✗ ผิด — Epilepsy: recurrent seizures ไม่มีชา/อ่อนแรง ไม่มี MRI demyelination"},{"label":"D","text":"Migraine รักษาด้วย Sumatriptan","explanation":"✗ ผิด — Migraine: episodic headache ไม่มี objective neurologic deficits"},{"label":"E","text":"Myasthenia gravis รักษาด้วย Pyridostigmine","explanation":"✗ ผิด — MG: fatigable weakness, ptosis, diplopia ไม่มี MRI demyelination"}],"key_takeaway":"MS: DMT ลด relapse rate 30-70% | Acute relapse: IV Methylprednisolone | Symptomatic: fatigue(amantadine), spasticity(baclofen), bladder(oxybutynin)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('fc152e55-5697-4206-ae8a-14694c373a4c', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี มีอาการปวดศีรษะรุนแรงฉับพลัน (thunderclap headache) สูงสุดทันที ไม่เคยเจ็บปวดแบบนี้มาก่อน ควรนึกถึงและรักษาอย่างไร', NULL, '[{"label":"A","text":"Tension headache รับประทาน Paracetamol แล้วกลับบ้าน"},{"label":"B","text":"Migraine ให้ Sumatriptan ฉีด"},{"label":"C","text":"Subarachnoid hemorrhage รีบทำ CT head ฉุกเฉิน"},{"label":"D","text":"Cluster headache ให้ Oxygen 100% สูดดม"},{"label":"E","text":"Hypertensive headache รักษาความดันแล้วกลับบ้าน"}]'::jsonb, 'C', 'Thunderclap headache = worst headache of life ที่เริ่มทันทีและรุนแรงสูงสุด ต้องนึกถึง Subarachnoid hemorrhage (SAH) ก่อน รีบทำ CT head ถ้าลบต้อง lumbar puncture ห้ามส่งกลับบ้าน', '{"summary":"Thunderclap headache = SAH until proven otherwise → CT head STAT","reason":"SAH: thunderclap headache + nuchal rigidity + photophobia | CT head ตรวจจับ SAH ได้ 98% ใน 12 ชั่วโมงแรก | ถ้า CT negative → Lumbar puncture ตรวจ xanthochromia | สาเหตุ: ruptured berry aneurysm (85%), AVM | รักษา: nimodipine (calcium channel blocker: ป้องกัน vasospasm), surgical clipping/endovascular coiling | ห้ามให้ anticoagulant","choices":[{"label":"A","text":"Tension headache รับประทาน Paracetamol แล้วกลับบ้าน","explanation":"✗ ผิด — อันตรายมาก Thunderclap headache ไม่ใช่ tension-type ต้องตรวจ CT ก่อนเสมอ"},{"label":"B","text":"Migraine ให้ Sumatriptan ฉีด","explanation":"✗ ผิด — Migraine มีอาการค่อยๆ เพิ่ม ไม่ใช่ thunderclap อย่าวินิจฉัย migraine ครั้งแรกโดยไม่ exclude SAH"},{"label":"C","text":"Subarachnoid hemorrhage รีบทำ CT head ฉุกเฉิน","explanation":"✓ ถูก — Thunderclap headache = SAH until proven otherwise ต้องทำ CT head STAT"},{"label":"D","text":"Cluster headache ให้ Oxygen 100% สูดดม","explanation":"✗ ผิด — Cluster headache: unilateral periorbital pain รุนแรง ระยะสั้น 15-180 นาที มี autonomic features ไม่ใช่ thunderclap"},{"label":"E","text":"Hypertensive headache รับประทาน antihypertensive แล้วกลับบ้าน","explanation":"✗ ผิด — SAH อาจทำให้ความดันสูงได้ ไม่ใช่ความดันเป็นสาเหตุ"}],"key_takeaway":"Thunderclap headache: CT head STAT → ถ้า negative → LP (xanthochromia) | SAH Rx: Nimodipine + Neurosurgery consult"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d99eac6f-0ff5-475e-be6a-d8cb6bcee53f', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี มีอาการปวดศีรษะข้างเดียว ร่วมกับคลื่นไส้ กลัวแสง กลัวเสียง ก่อนปวดมีอาการตามัวเป็นเส้นๆ (aura) ยาที่ใช้รักษา acute migraine attack ที่มีประสิทธิภาพที่สุด', NULL, '[{"label":"A","text":"Paracetamol 500 mg"},{"label":"B","text":"Sumatriptan (Triptan)"},{"label":"C","text":"Diazepam 5 mg"},{"label":"D","text":"Prednisolone"},{"label":"E","text":"Carbamazepine"}]'::jsonb, 'B', 'Triptans (Sumatriptan, Rizatriptan) เป็น 5-HT1B/1D agonist เป็น specific migraine treatment ที่มีประสิทธิภาพสูงสุด ลด vasodilation และการปล่อย neuropeptide ที่เป็นสาเหตุ migraine', '{"summary":"Acute migraine: Triptans (5-HT1B/1D agonist) = most effective specific therapy","reason":"Migraine acute Rx: Step therapy: NSAIDs/Paracetamol → Triptans → Ergotamine | Triptans: สูดดม/ฉีด เร็วกว่าแบบเม็ด ห้ามใช้ใน hemiplegic migraine, basilar migraine, CAD, uncontrolled HTN | ห้ามใช้ MAOI ร่วมกับ triptan (serotonin syndrome) | Prophylaxis: Propranolol, Valproate, Amitriptyline, Topiramate","choices":[{"label":"A","text":"Paracetamol 500 mg","explanation":"✗ ผิด — ใช้ได้ในบางราย แต่ประสิทธิภาพน้อยกว่า triptan สำหรับ moderate-severe migraine"},{"label":"B","text":"Sumatriptan (Triptan)","explanation":"✓ ถูก — 5-HT1B/1D agonist เป็น specific migraine abortive therapy ที่มีประสิทธิภาพสูงสุด"},{"label":"C","text":"Diazepam 5 mg","explanation":"✗ ผิด — Benzodiazepine ไม่มีประสิทธิภาพสำหรับ migraine pain"},{"label":"D","text":"Prednisolone","explanation":"✗ ผิด — Corticosteroid ไม่ใช่ first-line acute migraine แต่ใช้ป้องกัน rebound ได้บ้าง"},{"label":"E","text":"Carbamazepine","explanation":"✗ ผิด — Carbamazepine ใช้รักษา trigeminal neuralgia และ epilepsy ไม่ใช่ migraine"}],"key_takeaway":"Migraine acute: NSAIDs/Paracetamol → Triptans | Prophylaxis: Propranolol/Valproate/Topiramate/Amitriptyline | ห้าม triptan ใน hemiplegic/basilar migraine, CAD"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('eb9e5055-0999-4edf-8340-61e57b83dc43', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'เด็กหญิงอายุ 8 ปี มีอาการหยุดชะงักกะทันหัน (staring spell) วันละหลายครั้ง ระยะสั้นๆ 5-30 วินาที EEG พบ 3Hz spike-and-wave discharge ควรรักษาด้วยยาใด', NULL, '[{"label":"A","text":"Phenytoin"},{"label":"B","text":"Ethosuximide"},{"label":"C","text":"Carbamazepine"},{"label":"D","text":"Phenobarbital"},{"label":"E","text":"Gabapentin"}]'::jsonb, 'B', 'Childhood absence epilepsy: staring spell สั้น 5-30 วินาที EEG 3Hz spike-wave รักษาด้วย Ethosuximide (drug of choice สำหรับ pure absence) หรือ Valproate', '{"summary":"Absence epilepsy: Ethosuximide (DOC) หรือ Valproate | Carbamazepine ห้ามใช้ (ทำให้แย่ลง)","reason":"Ethosuximide: บล็อก T-type Ca channel ใน thalamus ซึ่งเป็น pacemaker ของ 3Hz spike-wave | Valproate: ทางเลือกถ้ามี generalized tonic-clonic ร่วมด้วย | Carbamazepine, Phenytoin, Gabapentin ห้ามใช้ใน absence → อาจทำให้ absence แย่ลง | Lamotrigine: alternative แต่ตอบสนองช้ากว่า","choices":[{"label":"A","text":"Phenytoin","explanation":"✗ ผิด — Phenytoin ใช้สำหรับ focal/generalized tonic-clonic ไม่มีประสิทธิภาพใน absence และอาจทำให้แย่ลง"},{"label":"B","text":"Ethosuximide","explanation":"✓ ถูก — Drug of choice สำหรับ childhood absence epilepsy บล็อก T-type Ca channel"},{"label":"C","text":"Carbamazepine","explanation":"✗ ผิด — ห้ามใช้ใน absence epilepsy ทำให้ absence บ่อยขึ้น"},{"label":"D","text":"Phenobarbital","explanation":"✗ ผิด — ไม่มีประสิทธิภาพใน absence ทำให้ cognitive impairment ในเด็ก"},{"label":"E","text":"Gabapentin","explanation":"✗ ผิด — ไม่มีประสิทธิภาพใน absence epilepsy อาจทำให้แย่ลง"}],"key_takeaway":"Absence epilepsy: Ethosuximide (pure absence) หรือ Valproate (ถ้ามี GTCS ร่วม) | ห้าม: Carbamazepine, Phenytoin, Gabapentin"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e09c6eeb-a3e0-4498-a423-015697c5e8f6', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี เป็น Epilepsy ควบคุมได้ดีด้วย Phenytoin นาน 10 ปี ควรติดตามอะไรเป็นพิเศษ', NULL, '[{"label":"A","text":"Liver function ทุก 6 เดือน"},{"label":"B","text":"Renal function ทุก 3 เดือน"},{"label":"C","text":"Serum Phenytoin level, CBC, LFT, Bone density"},{"label":"D","text":"Thyroid function ทุก 6 เดือน"},{"label":"E","text":"Serum K+ ทุกเดือน"}]'::jsonb, 'C', 'Phenytoin ระยะยาว: ตรวจ serum level (therapeutic 10-20 mcg/mL), CBC (megaloblastic anemia), LFT (hepatotoxicity), Bone density (osteoporosis เพราะเร่ง vitamin D metabolism)', '{"summary":"Phenytoin long-term monitoring: drug level + CBC + LFT + bone density","reason":"Phenytoin SE ระยะยาว: Gingival hyperplasia | Hirsutism | Coarsening facial features | Megaloblastic anemia (ลด folate absorption) | Osteoporosis (induces CYP → เร่ง vitamin D catabolism → ลด Ca absorption) | Cerebellar atrophy | Peripheral neuropathy | Teratogenic (fetal hydantoin syndrome) | Phenytoin: narrow therapeutic index, non-linear (zero-order) kinetics → เพิ่มขนาดนิดเดียวระดับยาพุ่งสูง","choices":[{"label":"A","text":"Liver function ทุก 6 เดือน","explanation":"✗ ผิด — LFT ต้อง monitor แต่ไม่ครบ ต้องตรวจ level/CBC/bone density ด้วย"},{"label":"B","text":"Renal function ทุก 3 เดือน","explanation":"✗ ผิด — Phenytoin ไม่ toxic ต่อไตโดยตรง"},{"label":"C","text":"Serum Phenytoin level, CBC, LFT, Bone density","explanation":"✓ ถูก — ครบ monitoring ที่จำเป็นสำหรับ phenytoin ระยะยาว"},{"label":"D","text":"Thyroid function ทุก 6 เดือน","explanation":"✗ ผิด — ไม่ใช่ required monitoring สำหรับ phenytoin"},{"label":"E","text":"Serum K+ ทุกเดือน","explanation":"✗ ผิด — K+ ไม่ได้รับผลจาก phenytoin โดยตรง"}],"key_takeaway":"Phenytoin: therapeutic level 10-20 mcg/mL | SE ระยะยาว: gingival hyperplasia, hirsutism, osteoporosis, megaloblastic anemia | ระวัง drug interactions (enzyme inducer)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f8094338-a110-4ab6-b409-707709bbe4c4', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี Myasthenia gravis มีอาการหนังตาตก (ptosis) กลืนลำบาก แน่นหน้าอก Cholinergic crisis จาก Pyridostigmine เกินขนาด มีอาการใดต่างจาก Myasthenic crisis', NULL, '[{"label":"A","text":"Cholinergic: กล้ามเนื้ออ่อนแรง | Myasthenic: กล้ามเนื้อแข็ง"},{"label":"B","text":"Cholinergic: SLUDGE (น้ำลายมาก ท้องเสีย ปัสสาวะบ่อย) + กล้ามเนื้ออ่อนแรง | Myasthenic: กล้ามเนื้ออ่อนแรง ไม่มี SLUDGE"},{"label":"C","text":"ไม่แตกต่างกัน รักษาเหมือนกัน"},{"label":"D","text":"Cholinergic: ความดันสูง | Myasthenic: ความดันต่ำ"},{"label":"E","text":"Cholinergic: ไข้สูง | Myasthenic: ไม่มีไข้"}]'::jsonb, 'B', 'Cholinergic crisis (pyridostigmine overdose): SLUDGE/DUMBELS + fasciculations + weakness | Myasthenic crisis (ยาไม่พอ): weakness เพียงอย่างเดียว ไม่มี cholinergic symptoms แยกด้วย Edrophonium (Tensilon) test', '{"summary":"Cholinergic crisis: SLUDGE + weakness | Myasthenic crisis: weakness เท่านั้น | แยกด้วย Tensilon test","reason":"SLUDGE: Salivation, Lacrimation, Urination, Defecation, GI cramps, Emesis | Cholinergic crisis: pyridostigmine เกินขนาด → acetylcholine สะสม → SLUDGE + miosis + fasciculations + weakness | Myasthenic crisis: crisis จากยาไม่พอ/trigger (infection, surgery) → weakness ไม่มี SLUDGE | Tensilon test: ให้ Edrophonium IV → ถ้า MG crisis: weakness ดีขึ้น ถ้า cholinergic crisis: แย่ลง | รักษา cholinergic crisis: หยุด pyridostigmine + Atropine","choices":[{"label":"A","text":"Cholinergic: กล้ามเนื้ออ่อนแรง | Myasthenic: กล้ามเนื้อแข็ง","explanation":"✗ ผิด — ทั้งคู่ทำให้กล้ามเนื้ออ่อนแรง ไม่มีแบบ rigid"},{"label":"B","text":"Cholinergic: SLUDGE (น้ำลายมาก ท้องเสีย ปัสสาวะบ่อย) + กล้ามเนื้ออ่อนแรง | Myasthenic: กล้ามเนื้ออ่อนแรง ไม่มี SLUDGE","explanation":"✓ ถูก — SLUDGE เป็น key differentiator สำหรับ cholinergic crisis"},{"label":"C","text":"ไม่แตกต่างกัน รักษาเหมือนกัน","explanation":"✗ ผิด — รักษาตรงข้ามกัน! Cholinergic: หยุดยา + atropine | Myasthenic: เพิ่มยา + plasmapheresis/IVIG"},{"label":"D","text":"Cholinergic: ความดันสูง | Myasthenic: ความดันต่ำ","explanation":"✗ ผิด — ไม่ใช่ discriminating feature ที่ชัดเจน"},{"label":"E","text":"Cholinergic: ไข้สูง | Myasthenic: ไม่มีไข้","explanation":"✗ ผิด — Cholinergic crisis ไม่มีไข้ (MG crisis อาจมีไข้ถ้า trigger คือ infection)"}],"key_takeaway":"MG crisis: Myasthenic (ยาไม่พอ) → เพิ่มยา | Cholinergic (ยาเกิน) → หยุดยา + Atropine | แยกด้วย SLUDGE และ Tensilon test"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b592d58d-2d3e-47e2-a6ae-2d82120f09c4', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี เบาหวาน ความดัน มีอาการอ่อนแรงข้างขวาเฉียบพลัน พูดไม่ออก ส่ง ER ภายใน 2 ชั่วโมง CT brain ไม่มี hemorrhage ควรรักษาอย่างไร', NULL, '[{"label":"A","text":"ให้ Aspirin 300 mg ทันที"},{"label":"B","text":"ให้ IV Alteplase (rt-PA) ภายใน 4.5 ชั่วโมงจาก onset"},{"label":"C","text":"ให้ IV Heparin ทันที"},{"label":"D","text":"รอสังเกตอาการ 24 ชั่วโมง"},{"label":"E","text":"ผ่าตัด craniotomy ฉุกเฉิน"}]'::jsonb, 'B', 'Ischemic stroke ที่มาภายใน 4.5 ชั่วโมง CT ไม่มี hemorrhage → IV Alteplase (rt-PA thrombolysis) 0.9 mg/kg (max 90mg) เป็น standard of care ที่ลด disability ได้อย่างมีนัยสำคัญ', '{"summary":"Acute ischemic stroke ภายใน 4.5h + CT ไม่มีเลือด = IV Alteplase (thrombolysis)","reason":"IV Alteplase: recombinant tissue plasminogen activator ละลายลิ่มเลือด | Time window: ≤4.5h จาก symptom onset | Dose: 0.9 mg/kg IV (10% bolus, 90% infusion ใน 60 นาที) | ข้อห้าม: BP >185/110, เลือดออก, INR >1.7, ผ่าตัดใน 14 วัน, stroke/TBI ใน 3 เดือน | Endovascular thrombectomy: ถ้า large vessel occlusion ภายใน 6-24 ชั่วโมง","choices":[{"label":"A","text":"ให้ Aspirin 300 mg ทันที","explanation":"✗ ผิด — Aspirin ใช้หลังจาก 24h post-thrombolysis ถ้าให้ก่อน alteplase เพิ่มความเสี่ยงเลือดออก"},{"label":"B","text":"ให้ IV Alteplase (rt-PA) ภายใน 4.5 ชั่วโมงจาก onset","explanation":"✓ ถูก — Standard of care ชัดเจน: CT ไม่มีเลือด + onset ≤4.5h → IV rtPA"},{"label":"C","text":"ให้ IV Heparin ทันที","explanation":"✗ ผิด — Heparin ไม่ได้รับการพิสูจน์ใน acute ischemic stroke routine และเพิ่มความเสี่ยง hemorrhagic transformation"},{"label":"D","text":"รอสังเกตอาการ 24 ชั่วโมง","explanation":"✗ ผิด — ''Time is brain'' ทุกนาทีที่เสียไปทำลาย neurons 1.9 ล้านตัว ต้องรักษาเร็วที่สุด"},{"label":"E","text":"ผ่าตัด craniotomy ฉุกเฉิน","explanation":"✗ ผิด — Ischemic stroke ไม่ผ่าตัด (ยกเว้น malignant MCA infarction ที่บวมมาก)"}],"key_takeaway":"Acute ischemic stroke: IV Alteplase ≤4.5h | ''Time is brain'' | ข้อห้าม: hemorrhage, BP >185/110, anticoagulant | หลัง 24h: Aspirin + Statin"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:33:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('50009e2c-7f59-467d-9cf7-54a63598413b', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ยาใดที่ใช้รักษา Trigeminal neuralgia เป็น first-line', NULL, '[{"label":"A","text":"Sumatriptan"},{"label":"B","text":"Gabapentin"},{"label":"C","text":"Carbamazepine"},{"label":"D","text":"Amitriptyline"},{"label":"E","text":"Morphine"}]'::jsonb, 'C', 'Carbamazepine เป็น drug of choice สำหรับ Trigeminal neuralgia (TN) มีหลักฐานสูงสุด ลดอาการปวดแบบ electric shock ที่แก้มหรือขากรรไกรได้ดีมาก', '{"summary":"Trigeminal neuralgia: Carbamazepine = drug of choice | Oxcarbazepine = alternative","reason":"Trigeminal neuralgia: ปวดแบบ electric shock ที่ใบหน้าข้างเดียว เป็นพักๆ วินาที Carbamazepine บล็อก Na channel ลด ectopic discharge ของ trigeminal nerve | Oxcarbazepine: ทนได้ดีกว่า carbamazepine ผลข้างเคียงน้อยกว่า | Baclofen: GABA-B agonist ใช้เสริม | Gabapentin: ใช้บ้างแต่หลักฐานน้อยกว่า | Surgical: microvascular decompression","choices":[{"label":"A","text":"Sumatriptan","explanation":"✗ ผิด — Triptan ใช้ migraine ไม่มีหลักฐานใน TN"},{"label":"B","text":"Gabapentin","explanation":"✗ ผิด — ใช้ได้บ้างแต่ไม่ใช่ first-line เหมือน carbamazepine"},{"label":"C","text":"Carbamazepine","explanation":"✓ ถูก — Drug of choice TN มี RCT evidence ที่แข็งแกร่งที่สุด"},{"label":"D","text":"Amitriptyline","explanation":"✗ ผิด — TCA ใช้ใน neuropathic pain และ migraine prophylaxis แต่ไม่ใช่ DOC สำหรับ TN"},{"label":"E","text":"Morphine","explanation":"✗ ผิด — Opioid ไม่มีประสิทธิภาพดีใน neuropathic/trigeminal pain"}],"key_takeaway":"Trigeminal neuralgia: Carbamazepine (DOC) → Oxcarbazepine → Baclofen + Carbamazepine | Surgical: MVD ถ้ายาไม่ได้ผล"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('326c8a91-c9ef-4c95-be96-3a9bccce8434', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 25 ปี ตั้งครรภ์ 8 สัปดาห์ มีประวัติ Epilepsy ควบคุมด้วย Valproate ควรแนะนำอย่างไร', NULL, '[{"label":"A","text":"หยุดยาทันที ไม่มียาใดปลอดภัยในตั้งครรภ์"},{"label":"B","text":"ปรึกษาแพทย์เพื่อพิจารณาเปลี่ยนเป็น Lamotrigine หรือ Levetiracetam และให้ Folic acid"},{"label":"C","text":"เพิ่มขนาด Valproate เป็น 2 เท่าเพื่อความแน่ใจ"},{"label":"D","text":"เปลี่ยนเป็น Phenobarbital ทันที"},{"label":"E","text":"ใช้ Carbamazepine แทน Valproate โดยไม่ต้องปรึกษาแพทย์"}]'::jsonb, 'B', 'Valproate เป็น teratogen ที่รุนแรงที่สุดในบรรดา AEDs ทำให้ neural tube defects, cognitive impairment ในบุตร ควรปรึกษาแพทย์เพื่อเปลี่ยนเป็น Lamotrigine หรือ Levetiracetam (ปลอดภัยกว่า) + Folic acid 5 mg/day', '{"summary":"Valproate: teratogen ที่สุดใน AEDs | ตั้งครรภ์: เปลี่ยนเป็น Lamotrigine/Levetiracetam + Folic acid","reason":"Valproate teratogenic risk: Neural tube defects (spina bifida ~1-2%), Fetal valproate syndrome (craniofacial), Cognitive impairment ในบุตร (IQ ต่ำกว่า 9 คะแนน) | Lamotrigine + Levetiracetam: ปลอดภัยที่สุดใน pregnancy | Folic acid 5 mg/day: ลด NTD | ห้ามหยุดยาเองเพราะ seizure ขณะตั้งครรภ์อันตรายกว่า | Carbamazepine ก็ทำให้ NTD ได้แต่น้อยกว่า valproate","choices":[{"label":"A","text":"หยุดยาทันที ไม่มียาใดปลอดภัยในตั้งครรภ์","explanation":"✗ ผิด — ห้ามหยุดยาเอง seizure ขณะตั้งครรภ์อันตรายต่อแม่และทารก Lamotrigine/Levetiracetam ปลอดภัยกว่า"},{"label":"B","text":"ปรึกษาแพทย์เพื่อพิจารณาเปลี่ยนเป็น Lamotrigine หรือ Levetiracetam และให้ Folic acid","explanation":"✓ ถูก — ถูกต้องที่สุด: ปรึกษาผู้เชี่ยวชาญ เปลี่ยนยา + Folic acid"},{"label":"C","text":"เพิ่มขนาด Valproate เป็น 2 เท่าเพื่อความแน่ใจ","explanation":"✗ ผิด — เพิ่ม teratogenic risk มากขึ้น"},{"label":"D","text":"เปลี่ยนเป็น Phenobarbital ทันที","explanation":"✗ ผิด — Phenobarbital ก็ teratogenic (cleft lip/palate, cardiac defects) ไม่ดีกว่า valproate"},{"label":"E","text":"ใช้ Carbamazepine แทน Valproate โดยไม่ต้องปรึกษาแพทย์","explanation":"✗ ผิด — Carbamazepine ก็ teratogenic (NTD 0.5%) และไม่ควรเปลี่ยนยาเองโดยไม่ปรึกษาแพทย์"}],"key_takeaway":"Epilepsy ตั้งครรภ์: Lamotrigine/Levetiracetam ปลอดภัยที่สุด | Valproate = most teratogenic AED | Folic acid 5mg/day ก่อนตั้งครรภ์"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f46af63f-60c8-4220-9467-d7aa72fb9cbd', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'Status epilepticus (SE) ที่ชักนานกว่า 5 นาที ยาที่ให้เป็น first-line ทาง IV คือ', NULL, '[{"label":"A","text":"Phenytoin IV"},{"label":"B","text":"Lorazepam IV หรือ Diazepam IV"},{"label":"C","text":"Valproate IV"},{"label":"D","text":"Levetiracetam IV"},{"label":"E","text":"Propofol IV"}]'::jsonb, 'B', 'Status epilepticus first-line: Benzodiazepine IV (Lorazepam 4mg IV หรือ Diazepam 10mg IV) ออกฤทธิ์เร็วและมีประสิทธิภาพสูงสุดในการหยุด SE ถ้าไม่มี IV access: Diazepam rectal หรือ Midazolam buccal/IM', '{"summary":"SE first-line: Benzodiazepine IV | Second-line: Fosphenytoin/Valproate/Levetiracetam IV","reason":"SE protocol: (1) Lorazepam 0.1 mg/kg IV (max 4mg) หรือ Diazepam 0.15 mg/kg IV → (2) ถ้าไม่หยุด: Fosphenytoin 20 PE/kg IV หรือ Valproate 40 mg/kg IV หรือ Levetiracetam 60 mg/kg IV → (3) ถ้าไม่หยุด: Refractory SE → Propofol/Midazolam/Pentobarbital infusion | Non-IV: Midazolam IM/buccal/intranasal, Diazepam rectal","choices":[{"label":"A","text":"Phenytoin IV","explanation":"✗ ผิด — Phenytoin/Fosphenytoin เป็น second-line ออกฤทธิ์ช้ากว่า benzodiazepine"},{"label":"B","text":"Lorazepam IV หรือ Diazepam IV","explanation":"✓ ถูก — Benzodiazepine = first-line SE ออกฤทธิ์เร็ว (ใน 1-3 นาที)"},{"label":"C","text":"Valproate IV","explanation":"✗ ผิด — Valproate IV เป็น second-line option"},{"label":"D","text":"Levetiracetam IV","explanation":"✗ ผิด — Levetiracetam IV เป็น second-line option"},{"label":"E","text":"Propofol IV","explanation":"✗ ผิด — Propofol ใช้สำหรับ refractory SE เท่านั้น ต้อง intubation"}],"key_takeaway":"SE: Benzo IV (first) → Fosphenytoin/VPA/LEV IV (second) → Propofol/Midazolam infusion (refractory) | Time critical: ทุกนาทีเพิ่ม neuronal damage"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('071e2c8d-7c5e-46e3-a944-ff8c31aaf540', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 40 ปี ปวดศีรษะเป็นประจำทุกวัน สัมพันธ์กับการใช้ยาแก้ปวดทุกวัน (Paracetamol > 15 วัน/เดือน) วินิจฉัยและรักษาอย่างไร', NULL, '[{"label":"A","text":"Migraine รักษาด้วย Sumatriptan ทุกวัน"},{"label":"B","text":"Medication Overuse Headache (MOH) รักษาด้วยการหยุดยาแก้ปวดและทำ detoxification"},{"label":"C","text":"Tension headache รักษาด้วย Amitriptyline"},{"label":"D","text":"Cluster headache รักษาด้วย Oxygen therapy"},{"label":"E","text":"Secondary headache จาก tumor รักษาด้วย Dexamethasone"}]'::jsonb, 'B', 'Medication Overuse Headache (MOH/Rebound headache): ปวดหัวทุกวัน สัมพันธ์กับการใช้ยาแก้ปวด > 10-15 วัน/เดือน รักษาด้วยการหยุดยาที่ใช้เกิน (detoxification) และ prophylaxis', '{"summary":"MOH: ปวดหัวทุกวัน + ใช้ยาแก้ปวดเกินขีด → หยุดยา (detox) + prophylaxis","reason":"MOH criteria: Headache ≥15 วัน/เดือน + Simple analgesic ≥15 วัน/เดือน หรือ Triptan/ergot ≥10 วัน/เดือน รักษา: (1) หยุดยาที่ใช้เกิน (ทันทีหรือค่อยๆ ลด) (2) Prophylaxis: Topiramate, Valproate, Propranolol, Amitriptyline (3) อาจ bridge therapy ด้วย prednisolone ระยะสั้น","choices":[{"label":"A","text":"Migraine รักษาด้วย Sumatriptan ทุกวัน","explanation":"✗ ผิด — Triptan ทุกวัน ทำให้ MOH! ห้ามใช้ > 10 วัน/เดือน"},{"label":"B","text":"Medication Overuse Headache (MOH) รักษาด้วยการหยุดยาแก้ปวดและทำ detoxification","explanation":"✓ ถูก — MOH = ปวดหัวทุกวัน + ยาเกินขีด รักษาด้วย detoxification"},{"label":"C","text":"Tension headache รักษาด้วย Amitriptyline","explanation":"✗ ผิด — Amitriptyline ใช้ prophylaxis แต่ต้องหยุดยาที่ใช้เกินก่อน"},{"label":"D","text":"Cluster headache รักษาด้วย Oxygen therapy","explanation":"✗ ผิด — Cluster: unilateral severe orbital pain 15-180 นาที มี autonomic features ไม่ใช่กรณีนี้"},{"label":"E","text":"Secondary headache จาก tumor รักษาด้วย Dexamethasone","explanation":"✗ ผิด — Brain tumor headache: morning headache, papilledema, progressive ไม่สัมพันธ์กับยาแก้ปวด"}],"key_takeaway":"MOH: ปวดหัวทุกวัน + ยาแก้ปวดเกิน → หยุดยา + prophylaxis | ป้องกัน: ไม่ใช้ analgesic > 10-15 วัน/เดือน"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3055d8a9-2cd6-4100-b47c-1ee5158d9063', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี เบาหวาน มีอาการชาปลายมือปลายเท้าสมมาตรทั้งสองข้าง แพทย์วินิจฉัย Diabetic peripheral neuropathy ยาที่เหมาะสมที่สุดสำหรับ neuropathic pain คือ', NULL, '[{"label":"A","text":"Tramadol เป็น first-line"},{"label":"B","text":"Pregabalin หรือ Duloxetine"},{"label":"C","text":"Aspirin"},{"label":"D","text":"Metformin เพิ่ม dose"},{"label":"E","text":"Insulin เปลี่ยนชนิด"}]'::jsonb, 'B', 'Diabetic peripheral neuropathy pain: First-line ได้แก่ Pregabalin (alpha-2-delta ligand), Duloxetine (SNRI) และ Gabapentin มีหลักฐาน level A จาก AAN guideline', '{"summary":"Diabetic neuropathy pain: Pregabalin/Duloxetine/Gabapentin = first-line | Tricyclics: effective แต่ SE มาก","reason":"AAN guideline first-line: Pregabalin (FDA approved), Duloxetine (FDA approved), Gabapentin | Second-line: Venlafaxine, Amitriptyline, Opioids (Tramadol) | Pregabalin: บล็อก voltage-gated Ca channel (alpha-2-delta subunit) ลด pain neurotransmitter release | Duloxetine: SNRI เพิ่ม NE/5HT ใน descending pain pathway | ควบคุมน้ำตาลให้ดีด้วย","choices":[{"label":"A","text":"Tramadol เป็น first-line","explanation":"✗ ผิด — Tramadol เป็น second/third-line เสี่ยง dependence/serotonin syndrome"},{"label":"B","text":"Pregabalin หรือ Duloxetine","explanation":"✓ ถูก — FDA approved และ AAN guideline Level A สำหรับ diabetic neuropathy pain"},{"label":"C","text":"Aspirin","explanation":"✗ ผิด — NSAID ไม่มีประสิทธิภาพสำหรับ neuropathic pain"},{"label":"D","text":"Metformin เพิ่ม dose","explanation":"✗ ผิด — การควบคุมน้ำตาลช่วยป้องกัน แต่ metformin ไม่ใช่ยาแก้ neuropathic pain"},{"label":"E","text":"Insulin เปลี่ยนชนิด","explanation":"✗ ผิด — การควบคุมน้ำตาลดีช่วยชะลอการดำเนิน แต่ไม่ใช่ยาแก้ neuropathic pain"}],"key_takeaway":"Diabetic neuropathy pain: Pregabalin/Duloxetine (FDA approved) first-line | Gabapentin/Amitriptyline: alternative | Opioids: last resort"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0d428bb5-ed71-416c-9a75-2c4e977457f9', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงตั้งครรภ์ 36 สัปดาห์ มีอาการชามือกลางดึก ปวดแบบ electric ที่นิ้วโป้ง นิ้วชี้ นิ้วกลาง ดีขึ้นเมื่อสะบัดมือ (flick sign) วินิจฉัยและรักษาอย่างไร', NULL, '[{"label":"A","text":"Peripheral neuropathy จาก vitamin B12 ขาด ให้ B12 supplement"},{"label":"B","text":"Carpal Tunnel Syndrome รักษาด้วย Wrist splint และ NSAIDs"},{"label":"C","text":"Thoracic outlet syndrome รักษาด้วย Physiotherapy"},{"label":"D","text":"Cervical radiculopathy รักษาด้วย Traction"},{"label":"E","text":"Raynaud''s phenomenon รักษาด้วย Calcium channel blocker"}]'::jsonb, 'B', 'Carpal Tunnel Syndrome (CTS): ชา/ปวดที่นิ้วโป้ง ชี้ กลาง และครึ่งนิ้วนาง (median nerve distribution) worse at night, flick sign (+) ตั้งครรภ์เสี่ยงสูง รักษาด้วย wrist splint (conservative) ± corticosteroid injection', '{"summary":"CTS: median nerve compression ที่ carpal tunnel | Flick sign = pathognomonic | Rx: wrist splint ± steroid injection","reason":"CTS: ชาใน median nerve territory (นิ้ว 1-3 ½) กลางดึก Phalen''s test (+), Tinel''s sign (+), Flick sign (+) | ตั้งครรภ์: fluid retention → carpal tunnel pressure สูง | Rx: wrist splint กลางคืน, corticosteroid injection ใน carpal tunnel | ผ่าตัด: surgical decompression ถ้าไม่ตอบสนอง/atrophy of thenar muscles | ใน pregnancy: มักดีขึ้นหลังคลอด","choices":[{"label":"A","text":"Peripheral neuropathy จาก vitamin B12 ขาด ให้ B12 supplement","explanation":"✗ ผิด — B12 deficiency: symmetric stockings-gloves distribution ไม่ใช่ specific digits"},{"label":"B","text":"Carpal Tunnel Syndrome รักษาด้วย Wrist splint และ NSAIDs","explanation":"✓ ถูก — Flick sign + median nerve distribution + worse at night = CTS | Wrist splint เป็น first-line"},{"label":"C","text":"Thoracic outlet syndrome รักษาด้วย Physiotherapy","explanation":"✗ ผิด — TOS: ปวดแขนทั้งแขน มักสัมพันธ์กับท่าทาง ไม่ใช่ specific finger distribution"},{"label":"D","text":"Cervical radiculopathy รักษาด้วย Traction","explanation":"✗ ผิด — Cervical radiculopathy: ปวดร้าวจากคอ Spurling test (+) ไม่มี flick sign"},{"label":"E","text":"Raynaud''s phenomenon รักษาด้วย Calcium channel blocker","explanation":"✗ ผิด — Raynaud''s: color change (white→blue→red) เมื่อเย็น ไม่มีชาแบบ specific distribution"}],"key_takeaway":"CTS: Median nerve compression | Flick sign = pathognomonic | Rx: splint → steroid injection → surgical decompression | ตั้งครรภ์: มักดีขึ้นหลังคลอด"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:33:37') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e55441f9-9562-4060-9e6e-445b84516f58', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 52 ปี มี GERD มาหลายปี แพทย์สั่ง Omeprazole 20 mg OD นาน 4 สัปดาห์ ยังมีอาการอยู่ ยาใดที่ควรปรับ', NULL, '["เพิ่มขนาด Omeprazole เป็น 40 mg OD","เปลี่ยนเป็น H2-blocker","เพิ่ม Antacid เสริม","ลด Omeprazole เป็น 10 mg OD"]'::jsonb, 'A', 'GERD ที่ไม่ตอบสนอง PPI ขนาดมาตรฐาน ควรเพิ่มขนาดเป็น 40 mg OD หรือให้ BID', '{"A":"ถูก — GERD refractory to standard PPI dose: escalate to double dose (40 mg OD หรือ 20 mg BID) ก่อน","B":"ผิด — H2-blocker ด้อยกว่า PPI ใน erosive GERD ไม่ควรใช้แทน","C":"ผิด — Antacid เป็น symptomatic relief ชั่วคราว ไม่ใช่การรักษา","D":"ผิด — ลดขนาดยาทำให้แย่ลง"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f8c55c75-18ee-4091-8c37-128cab503625', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี ติดเชื้อ H. pylori ตรวจพบจาก urea breath test แพทย์จะรักษาด้วย triple therapy มาตรฐาน ยากลุ่มใดที่ต้องใช้ร่วมกัน 3 ชนิด', NULL, '["PPI + Amoxicillin + Clarithromycin","H2-blocker + Metronidazole + Tetracycline","PPI + Metronidazole + Amoxicillin + Bismuth","PPI + Clarithromycin + Levofloxacin"]'::jsonb, 'A', 'Standard triple therapy สำหรับ H. pylori คือ PPI + Amoxicillin + Clarithromycin นาน 7-14 วัน', '{"A":"ถูก — CAM triple therapy: PPI BID + Amoxicillin 1g BID + Clarithromycin 500 mg BID × 14 วัน","B":"ผิด — H2-blocker ไม่ใช้ใน H. pylori eradication regimen","C":"ผิด — นั่นคือ quadruple therapy (4 ตัว) ใช้เมื่อ triple therapy ล้มเหลว","D":"ผิด — Levofloxacin-based triple เป็น salvage therapy ไม่ใช่ first-line"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:36:02') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('089d9d29-1d72-4dd8-8029-00de2ca6e77b', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี ได้รับ NSAIDs เรื้อรังเพื่อรักษา OA และมีประวัติแผลในกระเพาะ ควรให้ยาป้องกันชนิดใด', NULL, '["Antacid ตามอาการ","H2-blocker ขนาดมาตรฐาน","PPI ทุกวันตลอดการใช้ NSAIDs","Misoprostol 200 mcg QID"]'::jsonb, 'C', 'ผู้ป่วย high-risk GI (ประวัติแผลในกระเพาะ + NSAIDs เรื้อรัง) ควรได้ PPI เพื่อป้องกัน gastroprotection', '{"A":"ผิด — Antacid ไม่มีหลักฐานป้องกันแผลจาก NSAIDs","B":"ผิด — H2-blocker ด้อยกว่า PPI ในการป้องกัน NSAID-induced ulcer","C":"ถูก — PPI เป็น gold standard สำหรับ gastroprotection ใน high-risk NSAID users","D":"ผิด — Misoprostol ใช้ได้แต่ผลข้างเคียง (ท้องเสีย ปวดท้อง) สูง ไม่ใช่ first-choice"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('79b80589-7486-4e14-a65d-1e0107db40cc', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี IBS-D (Irritable Bowel Syndrome with diarrhea) มีอาการปวดท้องและถ่ายบ่อย ยาใดที่ช่วยลดอาการปวดท้องได้ดีที่สุด', NULL, '["Loperamide","Dicyclomine (Anticholinergic)","Psyllium fiber","Lactulose"]'::jsonb, 'B', 'Antispasmodic เช่น Dicyclomine ช่วยลด visceral pain และ spasm ในผู้ป่วย IBS', '{"A":"ผิด — Loperamide ลดความถี่ถ่าย (antidiarrheal) แต่ไม่ลด abdominal pain","B":"ถูก — Antispasmodic (Dicyclomine, Hyoscine) ลด bowel spasm และ pain ใน IBS ได้ดี","C":"ผิด — Fiber เหมาะกับ IBS-C ไม่ใช่ IBS-D","D":"ผิด — Lactulose เป็น laxative ใช้ใน constipation"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('06ad0224-834d-4664-98a7-0f9477a97716', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี ตรวจพบ C. difficile colitis ได้รับการรักษา Metronidazole 500 mg TID นาน 10 วัน แต่กลับเป็นซ้ำ ยาที่เหมาะสมสำหรับครั้งที่ 2 คือ', NULL, '["ให้ Metronidazole อีกรอบ","Vancomycin oral 125 mg QID × 10 วัน","Ciprofloxacin","Rifaximin"]'::jsonb, 'B', 'C. difficile recurrence ควรรักษาด้วย oral Vancomycin ซึ่งดีกว่า Metronidazole สำหรับกรณีกลับซ้ำ', '{"A":"ผิด — Metronidazole ซ้ำมักไม่ได้ผลใน recurrent CDI","B":"ถูก — Oral Vancomycin 125 mg QID × 10 วัน เป็น standard ของ recurrent CDI (IDSA guidelines)","C":"ผิด — Ciprofloxacin ไม่มีประสิทธิภาพต่อ C. difficile","D":"ผิด — Rifaximin อาจใช้เป็น follow-on therapy หลัง Vancomycin ไม่ใช่ treatment หลัก"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3411ad65-9e9b-4583-a7c6-3d63694d85b0', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 50 ปี มีตับแข็ง Child-Pugh B และ hepatic encephalopathy ยาใดที่ใช้ลด ammonia และป้องกัน encephalopathy', NULL, '["Metronidazole","Lactulose","Neomycin sulfate","Rifaximin"]'::jsonb, 'B', 'Lactulose เป็น first-line ใน hepatic encephalopathy — ลด NH3 โดยทำให้ pH ลงและระบายท้อง', '{"A":"ผิด — Metronidazole ไม่ใช่การรักษา encephalopathy","B":"ถูก — Lactulose first-line: acidify colon → NH4+ trap → ลด NH3 absorption เป้าหมาย 2-3 ครั้ง/วัน","C":"ผิด — Neomycin ใช้ได้แต่มี nephrotoxicity/ototoxicity สูง ไม่นิยมแล้ว","D":"ผิด — Rifaximin ใช้เป็น adjunct หรือ secondary prevention ไม่ใช่ monotherapy first-line"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('27b7e0d8-a795-45b6-b1fa-37500428ed39', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 48 ปี วินิจฉัย Crohn''s disease ลำไส้เล็กส่วน terminal ileum อาการปานกลาง-รุนแรง ยาใดที่เหมาะสมเป็น induction therapy', NULL, '["Mesalazine oral","Prednisolone 40 mg/day","Sulfasalazine","Methotrexate"]'::jsonb, 'B', 'Corticosteroid (Prednisolone) เป็น first-line induction ของ moderate-severe Crohn''s disease', '{"A":"ผิด — Mesalazine (5-ASA) ใช้ใน Ulcerative Colitis ไม่มีหลักฐานชัดเจนใน Crohn''s","B":"ถูก — Prednisolone 40 mg/day หรือ Budesonide สำหรับ ileocecal Crohn''s เป็น standard induction","C":"ผิด — Sulfasalazine มีประสิทธิภาพต่ำใน Crohn''s small bowel","D":"ผิด — Methotrexate ใช้เป็น maintenance ไม่ใช่ induction"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b5fbd4ec-d3d9-4163-8d1c-de16f42f8d46', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 40 ปี ได้รับการวินิจฉัย Ulcerative Colitis (UC) mildly active ควรเริ่มรักษาด้วยยากลุ่มใด', NULL, '["5-ASA (Mesalazine) oral + rectal","Prednisolone high dose","Azathioprine","Infliximab"]'::jsonb, 'A', 'Mild UC: 5-ASA เป็น first-line ทั้ง oral และ rectal (suppository/enema) ให้ผล remission ดีกว่า oral อย่างเดียว', '{"A":"ถูก — 5-ASA oral + topical (rectal) เป็น first-line สำหรับ mild-moderate UC","B":"ผิด — Corticosteroid ใช้กรณี moderate-severe หรือ fail 5-ASA","C":"ผิด — Azathioprine เป็น steroid-sparing maintenance ไม่ใช่ first-line induction","D":"ผิด — Anti-TNF (Infliximab) เป็น biologic สำหรับ severe/refractory UC"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9b1f6f79-ca2d-49d8-976b-08d89010548f', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี ตับแข็งจากแอลกอฮอล์ มี esophageal varices grade 2 ยาใดที่ใช้ป้องกัน primary bleeding', NULL, '["Propranolol non-selective beta-blocker","Atenolol selective beta-blocker","Isosorbide mononitrate เดี่ยว","Furosemide"]'::jsonb, 'A', 'Non-selective beta-blocker (Propranolol, Nadolol) ลด portal hypertension โดยลด cardiac output + vasoconstriction → เป็น primary prophylaxis', '{"A":"ถูก — Propranolol/Nadolol ลด portal pressure → ป้องกัน variceal bleeding เป็น first-line primary prophylaxis","B":"ผิด — Selective beta-blocker (Atenolol) ออกฤทธิ์แค่ heart rate ไม่ลด portal pressure เพียงพอ","C":"ผิด — Nitrate เดี่ยวไม่มีหลักฐานป้องกัน primary bleeding","D":"ผิด — Furosemide รักษา ascites ไม่ใช่ป้องกัน variceal bleeding"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:03') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('83108150-9e0f-4bdb-9391-0d2368ba85a6', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 55 ปี ตับแข็ง มีอาการท้องมาน (ascites) แรกพบ ควรรักษาด้วยอะไรเป็น first-line', NULL, '["Furosemide 40 mg/day เดี่ยว","Spironolactone 100 mg/day เดี่ยว","Spironolactone 100 mg + Furosemide 40 mg ร่วมกัน","Albumin infusion"]'::jsonb, 'C', 'AASLD guideline แนะนำ Spironolactone + Furosemide ร่วมกันตั้งแต่เริ่มรักษา ascites อัตราส่วน 100:40', '{"A":"ผิด — Furosemide เดี่ยวทำให้ hypokalemia และไม่ effective เท่า combination","B":"ผิด — Spironolactone เดี่ยวใช้ได้แต่ AASLD แนะนำ combination therapy","C":"ถูก — Spironolactone 100 mg + Furosemide 40 mg ratio 2.5:1 ป้องกัน electrolyte imbalance","D":"ผิด — Albumin ใช้หลัง large volume paracentesis หรือ SBP ไม่ใช่ first-line ascites"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3d703cc5-af18-4367-9960-82b70382abaa', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 30 ปี มีอาการคลื่นไส้อาเจียนรุนแรงหลังเคมีบำบัด Cisplatin ยาแก้อาเจียนกลุ่มใดมีประสิทธิภาพสูงสุด', NULL, '["Metoclopramide","5-HT3 antagonist (Ondansetron)","Promethazine","Domperidone"]'::jsonb, 'B', '5-HT3 antagonist เช่น Ondansetron เป็น gold standard สำหรับ CINV (chemotherapy-induced nausea/vomiting) โดยเฉพาะ highly emetogenic chemo', '{"A":"ผิด — Metoclopramide มี EPS ที่ขนาดสูง ประสิทธิภาพน้อยกว่า 5-HT3 ใน CINV","B":"ถูก — Ondansetron/Granisetron เป็น first-line สำหรับ acute CINV จาก highly emetogenic agents เช่น Cisplatin","C":"ผิด — Promethazine antihistamine ไม่ effective ใน CINV ระดับ severe","D":"ผิด — Domperidone ใช้ใน functional nausea ไม่ใช่ CINV"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('727aab9c-9903-4efd-bc65-4eeea57f8c0d', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี ตั้งครรภ์ไตรมาสแรก มีอาการคลื่นไส้อาเจียนรุนแรง (hyperemesis gravidarum) ยาใดปลอดภัยที่สุดสำหรับแก้อาเจียน', NULL, '["Ondansetron","Doxylamine + Pyridoxine (Vitamin B6)","Metoclopramide","Prochlorperazine"]'::jsonb, 'B', 'Doxylamine + Pyridoxine เป็น FDA category A สำหรับ nausea/vomiting of pregnancy — ปลอดภัยที่สุด', '{"A":"ผิด — Ondansetron มีข้อมูลเพิ่มขึ้นว่าอาจเพิ่มความเสี่ยง cardiac defects ไตรมาสแรก","B":"ถูก — Doxylamine + Vitamin B6 (Pyridoxine) เป็น FDA-approved (category A) first-line สำหรับ NVP","C":"ผิด — Metoclopramide ใช้ได้แต่ EPS เป็นความเสี่ยง","D":"ผิด — Prochlorperazine (phenothiazine) ไม่ใช่ first-line ในตั้งครรภ์"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('58616689-64e3-40ca-a982-4c89fbbeb9d3', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 58 ปี มีอาการท้องผูกเรื้อรัง ลอง fiber และ lifestyle modification แล้วไม่ได้ผล ยา osmotic laxative ที่นิยมใช้มากที่สุดคือ', NULL, '["Bisacodyl","Senna","PEG (Polyethylene glycol)","Docusate sodium"]'::jsonb, 'C', 'PEG เป็น osmotic laxative ที่ปลอดภัย มีหลักฐานดีสำหรับ chronic constipation ในผู้ใหญ่', '{"A":"ผิด — Bisacodyl เป็น stimulant laxative ไม่ใช่ osmotic","B":"ผิด — Senna เป็น stimulant laxative ใช้ระยะสั้น","C":"ถูก — PEG (Macrogol) เป็น osmotic laxative first-line สำหรับ chronic constipation ปลอดภัยระยะยาว","D":"ผิด — Docusate เป็น stool softener ประสิทธิภาพต่ำ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7d19dd80-bc1b-46a6-827c-567323eb4c42', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 42 ปี ตรวจพบ Non-alcoholic fatty liver disease (NAFLD) BMI 32 ยาที่มีหลักฐานว่าช่วยลด liver inflammation ใน NASH คือ', NULL, '["Metformin","Vitamin E (800 IU/day)","Omega-3","Silymarin"]'::jsonb, 'B', 'Vitamin E ขนาดสูง (800 IU/day) มีหลักฐาน RCT (PIVENS trial) ว่าลด histologic inflammation ใน non-diabetic NASH', '{"A":"ผิด — Metformin ไม่มีหลักฐาน histologic benefit ใน NASH","B":"ถูก — Vitamin E 800 IU/day AASLD แนะนำสำหรับ non-diabetic NASH (PIVENS trial)","C":"ผิด — Omega-3 ลด triglyceride แต่ไม่มี histologic evidence ชัดเจนใน NASH","D":"ผิด — Silymarin ไม่มีหลักฐาน RCT ที่แข็งแรงพอ"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('078f9653-e1e4-4c40-96ba-e87d9c731b98', '91eedbf3-4301-4f40-ae3d-3cc6f64c4f8a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 50 ปี ได้รับ Omeprazole มา 1 ปี มารับยาต่อเนื่อง เภสัชกรควรตรวจสอบ drug interaction กับยาใด', NULL, '["Amlodipine","Clopidogrel","Metformin","Simvastatin"]'::jsonb, 'B', 'Omeprazole ยับยั้ง CYP2C19 ลด conversion ของ Clopidogrel เป็น active metabolite → ลด antiplatelet effect', '{"A":"ผิด — Amlodipine ไม่มี significant interaction กับ Omeprazole","B":"ถูก — Omeprazole + Clopidogrel: Omeprazole inhibit CYP2C19 → Clopidogrel active metabolite ลดลง → antiplatelet effect ลดลง แนะนำให้ใช้ Pantoprazole แทน","C":"ผิด — Metformin ไม่มี interaction กับ PPI","D":"ผิด — Simvastatin ไม่มี significant interaction กับ Omeprazole"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:36:04') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('608dd2b4-972b-4687-8f0f-e95ee4e08005', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี สูบบุหรี่ 30 pack-years มีอาการหอบเหนื่อยเวลาออกแรง ไอมีเสมหะเรื้อรัง Spirometry FEV1/FVC = 0.62 (< 0.70) FEV1 = 55% predicted ผู้ป่วยอยู่ใน GOLD stage ใด', NULL, '["GOLD 1 (Mild)","GOLD 2 (Moderate)","GOLD 3 (Severe)","GOLD 4 (Very Severe)"]'::jsonb, 'B', 'GOLD 2: FEV1/FVC < 0.70 และ FEV1 50-79% predicted', '{"A":"ผิด — GOLD 1: FEV1 ≥ 80% predicted","B":"ถูก — GOLD 2 (Moderate): FEV1/FVC < 0.70 และ FEV1 50-79% predicted","C":"ผิด — GOLD 3: FEV1 30-49% predicted","D":"ผิด — GOLD 4: FEV1 < 30% predicted"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:38:31') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ff30ed17-72c7-440c-a191-6bbbc4ad1a9b', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วย COPD GOLD 2 ไม่มี exacerbation บ่อย ควรเริ่มรักษาด้วยยาสูดพ่นชนิดใดเป็น maintenance therapy', NULL, '["SABA (Salbutamol) PRN เท่านั้น","ICS (Fluticasone) เดี่ยว","LAMA (Tiotropium) หรือ LABA เดี่ยว","ICS/LABA ร่วมกัน"]'::jsonb, 'C', 'GOLD 2 ไม่มี exacerbation: LAMA หรือ LABA เป็น first-line monotherapy; ICS ไม่แนะนำใน COPD ที่ไม่มี eos สูง', '{"A":"ผิด — SABA เป็น rescue ไม่ใช่ maintenance","B":"ผิด — ICS เดี่ยวไม่แนะนำใน COPD (แตกต่างจาก asthma)","C":"ถูก — GOLD 2 group A/B: LAMA (Tiotropium) หรือ LABA เป็น first-line maintenance","D":"ผิด — ICS/LABA ใช้ใน GOLD 3-4 หรือผู้มี ≥2 exacerbations/ปี หรือ eos ≥ 300"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:31') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1a2c99c5-4aa8-482d-9646-cac1acc00a9f', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 25 ปี โรคหืด (Asthma) ควบคุมไม่ได้ (uncontrolled) ใช้ Salbutamol inhaler > 3 ครั้ง/สัปดาห์ ยาที่ควรเพิ่มเป็น controller คือ', NULL, '["เพิ่ม SABA dose","เริ่ม ICS low-dose (Budesonide/Beclomethasone)","เริ่ม LABA เดี่ยว","เริ่ม Theophylline"]'::jsonb, 'B', 'Uncontrolled asthma step up จาก SABA PRN → ICS low-dose เป็น standard controller', '{"A":"ผิด — เพิ่ม SABA ไม่แก้ inflammation ที่เป็นสาเหตุ","B":"ถูก — ICS low-dose เป็น step 2 controller เป็น first-line เพื่อลด airway inflammation","C":"ผิด — LABA ไม่ควรใช้เดี่ยวใน asthma (FDA black box warning) ต้องใช้กับ ICS เสมอ","D":"ผิด — Theophylline แนะนำขั้นสูงกว่า มีผลข้างเคียงมาก"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('0b0d4983-3046-4c34-bfb9-b7ad161d8b58', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 40 ปี Asthma ใช้ ICS/LABA (Symbicort) แล้วยังไม่ได้ผล แพทย์ต้องการเพิ่มยา add-on ตัวใด', NULL, '["เพิ่ม SABA ถี่ขึ้น","Leukotriene receptor antagonist (Montelukast)","Oral prednisolone ทุกวัน","Ipratropium inhaler"]'::jsonb, 'B', 'LTRA (Montelukast) เป็น add-on therapy ที่แนะนำเมื่อ ICS/LABA ยังไม่เพียงพอ', '{"A":"ผิด — SABA เพิ่มถี่ไม่ใช่การ step up ที่เหมาะสม","B":"ถูก — Montelukast เป็น add-on สำหรับ uncontrolled asthma บน ICS/LABA โดยเฉพาะกรณี allergic","C":"ผิด — Oral steroid ทุกวันเป็น last resort เพราะผลข้างเคียงมาก","D":"ผิด — Ipratropium (SAMA) เป็น rescue ใน acute asthma ไม่ใช่ add-on maintenance"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a41a2afc-b2c1-4d8f-95f8-466161c6eb88', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 50 ปี วินิจฉัย CAP (Community-Acquired Pneumonia) ไม่รุนแรง ไม่มีโรคร่วม ยา antibiotic first-line คือ', NULL, '["Amoxicillin-clavulanate","Azithromycin","Amoxicillin","Ciprofloxacin"]'::jsonb, 'C', 'CAP ผู้ป่วย outpatient ไม่มีโรคร่วม: Amoxicillin เป็น first-line ตาม IDSA/ATS guidelines', '{"A":"ผิด — Amoxicillin-clavulanate ใช้เมื่อมี risk factors เช่น recent antibiotics, chronic disease","B":"ผิด — Azithromycin ใช้ได้แต่ Amoxicillin preferred เพราะ resistant S. pneumoniae น้อยกว่า","C":"ถูก — Amoxicillin 1g TID เป็น first-line สำหรับ outpatient CAP ไม่มีโรคร่วม","D":"ผิด — Fluoroquinolone สำรองสำหรับ β-lactam allergic หรือ severe cases"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a878f5da-ece9-4459-9ea9-9eb177a2596f', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี COPD รุนแรง (FEV1 28%) มาด้วย acute exacerbation ของ COPD ควรให้ยาสูดพ่นใดก่อนเป็นอันดับแรก', NULL, '["ICS ขนาดสูง","SABA + SAMA นาบิวไลเซอร์","LABA เพียงอย่างเดียว","Theophylline IV"]'::jsonb, 'B', 'Acute COPD exacerbation: SABA (Salbutamol) + SAMA (Ipratropium) nebulizer เป็น first-line bronchodilator', '{"A":"ผิด — ICS ไม่ใช่ยา acute rescue","B":"ถูก — SABA + SAMA (Combivent nebulizer) เป็น short-acting bronchodilator first-line ใน acute COPD","C":"ผิด — LABA ออกฤทธิ์ช้าไม่เหมาะ acute","D":"ผิด — IV Theophylline ไม่แนะนำแล้วใน acute COPD (toxicity สูง ประสิทธิภาพต่ำ)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('5ddb4ab2-e287-4f54-a91b-01c77c02d255', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 30 ปี ไอเรื้อรัง 3 สัปดาห์ ไข้ น้ำหนักลด เหงื่อออกกลางคืน X-ray ปอดพบ upper lobe infiltrate ตรวจ AFB smear positive วินิจฉัย Active Pulmonary TB ควรรักษาด้วย 2HRZE/4HR ยาตัวใดอาจทำให้ตาบอดสีแดง-เขียว', NULL, '["Isoniazid (H)","Rifampicin (R)","Pyrazinamide (Z)","Ethambutol (E)"]'::jsonb, 'D', 'Ethambutol ทำให้เกิด optic neuritis → visual field defect + color blindness (red-green)', '{"A":"ผิด — Isoniazid ผลข้างเคียงหลัก: peripheral neuropathy, hepatotoxicity","B":"ผิด — Rifampicin ผลข้างเคียงหลัก: hepatotoxicity, เปลี่ยนสีปัสสาวะเป็นส้ม, drug interaction","C":"ผิด — Pyrazinamide ผลข้างเคียงหลัก: hepatotoxicity, hyperuricemia","D":"ถูก — Ethambutol: optic neuritis → visual acuity ลด + red-green color blindness ต้องตรวจตาก่อนเริ่ม"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7207c5f4-252f-4efa-ad24-518795204905', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 22 ปี สัมผัส TB (ผู้ป่วยในบ้านเดียวกัน) Tuberculin skin test 12 mm ตรวจ X-ray ปอดปกติ HIV negative ควรให้การรักษาใด', NULL, '["ไม่จำเป็นต้องรักษา เฝ้าสังเกต","Isoniazid preventive therapy (IPT) 9 เดือน","2HRZE/4HR full course","Rifampicin เดี่ยว 4 เดือน"]'::jsonb, 'B', 'Latent TB infection (LTBI): TST ≥ 10 mm ในผู้สัมผัส → ให้ INH preventive therapy 9 เดือน', '{"A":"ผิด — TST ≥ 10 mm ในผู้สัมผัส TB หมายถึง LTBI ต้องรักษาป้องกัน","B":"ถูก — INH 300 mg OD × 9 เดือน เป็น standard LTBI treatment (WHO/CDC)","C":"ผิด — Full TB treatment ใช้ใน active TB ไม่ใช่ LTBI","D":"ผิด — Rifampicin เดี่ยว 4 เดือน ทางเลือกได้แต่ไม่ใช่ first-line ที่นิยม"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('de4526bf-2b2f-4c67-b064-bd39b26b37dc', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี Asthma มีการใช้ยา MDI (Metered Dose Inhaler) ไม่ถูกวิธี เภสัชกรต้องสอนเทคนิคที่สำคัญที่สุดอะไร', NULL, '["กดยาพร้อมกับเริ่มหายใจเข้าช้าๆ ลึกๆ","หายใจออกหลังกดยาทันที","กดยาพร้อมหายใจเข้าเร็วๆ","ไม่ต้องกลั้นหายใจหลังสูด"]'::jsonb, 'A', 'เทคนิค MDI ที่ถูกต้อง: กดยาพร้อมเริ่มหายใจเข้าช้าๆ ลึก จากนั้นกลั้นหายใจ 10 วินาที', '{"A":"ถูก — Coordinate actuation กับ slow deep inhalation เพื่อให้ยาเข้าปอดได้มากที่สุด","B":"ผิด — ต้องกลั้นหายใจ 10 วินาที ไม่ใช่หายใจออกทันที","C":"ผิด — หายใจเร็วทำให้ยาชนท้ายคอมากขึ้น ไม่ถึงปอด","D":"ผิด — กลั้นหายใจ 10 วินาทีสำคัญมากเพื่อให้ยาตกตะกอนในทางเดินหายใจ"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4faae33f-f335-4a85-a0ab-c8df5d9ec9c5', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี COPD ได้รับ Tiotropium Handihaler มา 6 เดือน มีผลข้างเคียงที่ควรระวังอะไร', NULL, '["ไอแห้งเรื้อรัง","ปากแห้ง คอแห้ง ปัสสาวะลำบาก","ผื่นคัน angioedema","Hypokalemia"]'::jsonb, 'B', 'Tiotropium เป็น LAMA (Muscarinic antagonist) → anticholinergic effects: ปากแห้ง, ปัสสาวะลำบาก, ท้องผูก', '{"A":"ผิด — ไอแห้งเป็นผลข้างเคียงของ ACE inhibitor ไม่ใช่ LAMA","B":"ถูก — Anticholinergic effects: dry mouth, urinary retention (ระวังในผู้ชายสูงอายุที่มี BPH), constipation","C":"ผิด — Angioedema ไม่ใช่ผลของ muscarinic antagonist","D":"ผิด — Hypokalemia เป็นผลของ beta-2 agonist ไม่ใช่ LAMA"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:32') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('03e9ef5c-a666-46bd-8256-1da2792cbaed', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี Asthma ระหว่างตั้งครรภ์ ยาสูดพ่น ICS ตัวใดที่มีข้อมูลความปลอดภัยมากที่สุดในหญิงตั้งครรภ์', NULL, '["Fluticasone propionate","Budesonide","Beclomethasone dipropionate","Ciclesonide"]'::jsonb, 'B', 'Budesonide มีข้อมูล pregnancy safety category B มากที่สุด (FDA category B) และ NAEPP แนะนำ', '{"A":"ผิด — Fluticasone category C","B":"ถูก — Budesonide: FDA category B เป็น preferred ICS ระหว่างตั้งครรภ์ (NAEPP guideline)","C":"ผิด — BDP category C","D":"ผิด — Ciclesonide ข้อมูลน้อยกว่า"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:33') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cd2a4644-a00e-4057-9d52-112d0a3a22bf', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 72 ปี COPD รุนแรง มี FEV1 28% มี chronic hypoxemia (SpO2 88%) ในชีวิตประจำวัน ควรให้ Long-term Oxygen Therapy (LTOT) ที่เป้าหมาย SpO2 ใด', NULL, '["SpO2 ≥ 88%","SpO2 ≥ 90%","SpO2 ≥ 94%","SpO2 ≥ 98%"]'::jsonb, 'B', 'LTOT target สำหรับ COPD: SpO2 ≥ 90% (PaO2 ≥ 60 mmHg) ป้องกัน hypoxic pulmonary vasoconstriction', '{"A":"ผิด — 88% ต่ำเกินไป อาจยังเกิด organ hypoxia","B":"ถูก — GOLD guideline: เป้าหมาย SpO2 88-92% สำหรับ COPD (เพื่อหลีกเลี่ยง hypercapnia จาก high O2)","C":"ผิด — SpO2 > 94% ใน COPD อาจกด respiratory drive → hypercapnia","D":"ผิด — 98% อันตรายใน COPD severe"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:38:33') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3b7e4764-6472-4f15-911c-ed64f0d44d2e', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี มาด้วย acute severe asthma exacerbation ที่ ER ให้ nebulized Salbutamol + Ipratropium แล้ว SpO2 ยังต่ำ 88% ยาที่ควรให้เสริมต่อคือ', NULL, '["Oral Prednisolone 40 mg","IV Methylprednisolone 1 mg/kg","IV Magnesium sulfate 2 g","Subcutaneous Epinephrine"]'::jsonb, 'C', 'Severe asthma ไม่ตอบสนองต่อ bronchodilator: IV Magnesium sulfate เป็น adjunct therapy ที่แนะนำ', '{"A":"ผิด — Oral steroid ดูดซึมช้าเกิน ใน acute severe ต้องการ IV","B":"ผิด — IV Methylprednisolone ควรให้ด้วยแต่ไม่ใช่ answer หลัก ใช้ร่วมกัน","C":"ถูก — IV Magnesium sulfate 2g ใน 20 นาที ลด bronchospasm ใน acute severe asthma ที่ refractory","D":"ผิด — Epinephrine SQ ใช้ใน anaphylaxis ไม่ใช่ asthma acute ทั่วไป"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:38:33') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('06a69d37-462d-4340-9acb-03d0e3f3e395', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 58 ปี COPD ใช้ Tiotropium Handihaler มา 3 ปี เภสัชกรสังเกตว่าผู้ป่วยกด capsule ก่อน inhale ไม่ถูก วิธีที่ถูกต้องของ Handihaler คือ', NULL, '["กดปุ่มด้านข้าง 2 ครั้งเพื่อเปิดยา แล้วหายใจเข้า","ใส่ capsule เจาะด้วย Handihaler แล้วหายใจเข้าช้าๆ","เขย่าก่อนใช้แล้วกดยาพร้อมหายใจ","กดปุ่มค้างไว้ขณะหายใจเข้า"]'::jsonb, 'B', 'Handihaler: ใส่ capsule → ปิดฝา → กดปุ่มเจาะ 1 ครั้ง → หายใจออก → วางปากที่ mouthpiece → หายใจเข้าช้าลึก', '{"A":"ผิด — ไม่ใช่กดปุ่ม 2 ครั้ง การเจาะ capsule ทำด้วยปุ่มด้านข้าง 1 ครั้ง","B":"ถูก — Handihaler: ใส่ capsule → close → pierce with side button → slow deep inhalation → breath hold 10 sec","C":"ผิด — Handihaler เป็น DPI ไม่ต้องกดยาพร้อมหายใจ (ไม่ใช่ MDI)","D":"ผิด — ไม่มีการกดค้างขณะหายใจ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:38:33') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a791a6a1-b6c8-4b7b-a3fc-b6d4a9db7fd1', 'cc7ce595-2da4-4207-95a4-9a4bb606bbe0', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 48 ปี ไอเรื้อรัง 3 สัปดาห์ เจ็บหน้าอก ใช้ ACE inhibitor (Enalapril) มา 6 เดือน สาเหตุของไอน่าจะเป็นอะไร', NULL, '["Asthma","GERD","ACE inhibitor-induced cough","Post-nasal drip"]'::jsonb, 'C', 'ACE inhibitor เพิ่ม bradykinin → ไอแห้ง เป็น class effect พบใน 10-15% ของผู้ใช้ (คนเอเชียสูงกว่า ~30-40%)', '{"A":"ผิด — Asthma ไอมักเป็นๆ หายๆ หรือมี wheeze หายใจหอบ","B":"ผิด — GERD ไอมักหลังกินอาหาร นอนราบ","C":"ถูก — ACE inhibitor cough เป็น class effect เกิดจาก bradykinin/substance P สะสม แก้โดยเปลี่ยนเป็น ARB","D":"ผิด — Post-nasal drip มักมีน้ำมูกลงคอ ไม่สัมพันธ์กับยา"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:38:33') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f372dba3-38f4-486e-bb21-4b55fe3e5bd9', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี มีอาการปวดข้อเข่าทั้งสองข้าง เดินลำบาก X-ray พบ joint space narrowing ที่เข่า วินิจฉัย OA (Osteoarthritis) ยาแก้ปวดที่แนะนำเป็น first-line คือ', NULL, '["Celecoxib 200 mg OD","Paracetamol 500-1000 mg PRN/QID","Diclofenac 75 mg BID","Tramadol 50 mg PRN"]'::jsonb, 'B', 'Paracetamol เป็น first-line analgesic ใน OA ตาม ACR/EULAR guideline เนื่องจากปลอดภัยกว่า NSAIDs', '{"A":"ผิด — Celecoxib (COX-2 inhibitor) ใช้เมื่อ Paracetamol ไม่ได้ผลหรือมี GI risk","B":"ถูก — Paracetamol 500-1000 mg สูงสุด 4g/day เป็น first-line ที่ปลอดภัย","C":"ผิด — NSAIDs เป็น second-line หรือ add-on ไม่ใช่ first-line","D":"ผิด — Tramadol เป็นยากลุ่ม opioid ใช้เมื่อ NSAIDs/Paracetamol ไม่เพียงพอ"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7bae685c-00e6-4637-a6e0-31e364b404b1', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี RA (Rheumatoid Arthritis) วินิจฉัยใหม่ แพทย์เริ่ม DMARD ตัวแรก ยาใดที่เป็น anchor drug / first-line DMARD', NULL, '["Hydroxychloroquine","Methotrexate (MTX)","Leflunomide","Sulfasalazine"]'::jsonb, 'B', 'Methotrexate เป็น anchor DMARD first-line สำหรับ RA ทุก guideline (ACR/EULAR 2023)', '{"A":"ผิด — Hydroxychloroquine ใช้ใน mild RA หรือ SLE ไม่ใช่ anchor drug RA","B":"ถูก — MTX 10-25 mg/week + folic acid เป็น first-line csDMARD ทุก RA guideline","C":"ผิด — Leflunomide ใช้เมื่อ MTX ไม่สามารถใช้ได้ เป็น alternative","D":"ผิด — Sulfasalazine ใช้ใน mild-moderate RA หรือ combination ไม่ใช่ anchor drug"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('96f0b017-a88b-45b6-94bf-f4310ed45906', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 35 ปี RA ใช้ Methotrexate 15 mg/week เภสัชกรต้องแนะนำให้รับประทาน Folic acid ทุกวันเพื่ออะไร', NULL, '["เพิ่มประสิทธิภาพ MTX","ลดผลข้างเคียง (mouth sore, GI, hepatotoxicity)","ป้องกัน osteoporosis จาก RA","เสริมภูมิคุ้มกัน"]'::jsonb, 'B', 'Folic acid ลด MTX-induced toxicity: mucositis, GI side effects, hepatotoxicity โดยไม่ลด efficacy', '{"A":"ผิด — Folic acid ไม่เพิ่มประสิทธิภาพ MTX","B":"ถูก — MTX ยับยั้ง DHFR → folate deficiency → mouth sores, nausea, hepatotoxicity; folic acid 1-5 mg/day ลด toxicity เหล่านี้","C":"ผิด — Folic acid ไม่ป้องกัน osteoporosis","D":"ผิด — Folic acid ไม่ใช่ immunomodulator"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('63a0aad6-7d0c-4a5b-b0a3-51cfbe6380bf', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี ปวดข้อนิ้วโป้งเท้าซ้ายเฉียบพลัน บวมแดงร้อน ระดับ uric acid 9.5 mg/dL วินิจฉัย Acute Gouty Arthritis ยา first-line ที่เหมาะสมที่สุดคือ', NULL, '["Allopurinol 300 mg ทันที","Colchicine 1.2 mg แล้วตามด้วย 0.6 mg ใน 1 ชั่วโมง","Febuxostat 80 mg OD","Benzbromarone 50 mg"]'::jsonb, 'B', 'Colchicine เป็น first-line ใน acute gout attack ร่วมกับ NSAIDs หรือ corticosteroid; Allopurinol ไม่ควรเริ่มระหว่าง acute attack', '{"A":"ผิด — Allopurinol ไม่ควรเริ่มหรือเปลี่ยนขนาดระหว่าง acute attack เพราะยิ่งกระตุ้นการโจมตี","B":"ถูก — Colchicine low-dose regimen (1.2 mg + 0.6 mg ใน 1 ชม.) ACR guideline สำหรับ acute gout","C":"ผิด — Febuxostat เป็น urate-lowering therapy ใช้หลังจาก acute ระงับแล้ว ≥2 สัปดาห์","D":"ผิด — Benzbromarone เป็น uricosuric agent ใช้ chronic gout"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('6e84c1b9-4e9a-457e-9b6f-050404335972', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี Chronic Gout มีประวัติ tophi ที่นิ้วมือ uric acid 10 mg/dL ควรเริ่ม Allopurinol โดยมีเป้าหมาย serum uric acid ที่ระดับใด', NULL, '["< 8 mg/dL","< 6 mg/dL","< 4 mg/dL","< 9 mg/dL"]'::jsonb, 'B', 'Serum uric acid target ใน chronic gout: < 6 mg/dL (และ < 5 mg/dL ถ้ามี tophi)', '{"A":"ผิด — 8 mg/dL สูงเกิน ยังมีการตกตะกอน urate crystals","B":"ถูก — ACR 2020 target: SUA < 6 mg/dL สำหรับ gout ทั่วไป; < 5 mg/dL ถ้ามี tophaceous gout","C":"ผิด — < 4 mg/dL ต่ำเกินความจำเป็น","D":"ผิด — 9 mg/dL สูงเกินไป ไม่ใช่ target"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('a6514369-b5aa-4f1a-ad17-dd24fe1112e0', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 65 ปี วัยหมดประจำเดือน 15 ปี ตรวจ DEXA พบ T-score = -2.6 วินิจฉัย Osteoporosis ยา first-line คือ', NULL, '["Calcium + Vitamin D เพียงอย่างเดียว","Bisphosphonate (Alendronate/Risedronate)","HRT (Hormone Replacement Therapy)","Calcitonin nasal spray"]'::jsonb, 'B', 'Bisphosphonate เป็น first-line pharmacotherapy สำหรับ osteoporosis ในผู้หญิงวัยหมดประจำเดือน', '{"A":"ผิด — Calcium + Vitamin D เสริมแต่ไม่ใช่ treatment หลักเมื่อ T-score ≤ -2.5","B":"ถูก — Alendronate 70 mg/week หรือ Risedronate 35 mg/week เป็น first-line antifracture therapy","C":"ผิด — HRT ลดความเสี่ยงกระดูกหักแต่มีความเสี่ยง breast cancer, thrombosis","D":"ผิด — Calcitonin ประสิทธิภาพต่ำกว่า bisphosphonate"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('16308786-8fdb-4e47-929d-24bd178d4ad7', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 50 ปี รับประทาน Alendronate 70 mg/week มา 2 ปี มาพบเภสัชกรเพื่อรับยา เภสัชกรควรให้คำแนะนำอะไร', NULL, '["รับประทานหลังอาหารเช้า","รับประทานก่อนอาหารเช้า 30 นาที นั่งตัวตรงหรือยืน","รับประทานก่อนนอน","รับประทานพร้อมนม"]'::jsonb, 'B', 'Bisphosphonate oral: ต้องรับประทานตอนเช้า ก่อนอาหาร 30-60 นาที กับน้ำเปล่า และต้องนั่งหรือยืนตรงเพื่อป้องกัน esophageal irritation', '{"A":"ผิด — รับประทานหลังอาหารลดการดูดซึม","B":"ถูก — Alendronate ต้องรับประทานตอนเช้า ก่อนอาหาร 30 นาที กับน้ำเปล่า 200 mL นั่งตรงหรือยืนอย่างน้อย 30 นาทีหลังกิน","C":"ผิด — รับประทานก่อนนอน เสี่ยง esophageal ulceration","D":"ผิด — นมลดการดูดซึมอย่างมาก"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:40:53') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('97322a12-016b-4067-aeb2-2789f2428f89', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 40 ปี SLE (Systemic Lupus Erythematosus) รักษาด้วย Hydroxychloroquine มา 2 ปี เภสัชกรต้องแนะนำให้ตรวจตาเพราะเหตุใด', NULL, '["Uveitis จาก SLE","Cataracts จาก Hydroxychloroquine","Retinopathy จาก Hydroxychloroquine","Glaucoma จาก Hydroxychloroquine"]'::jsonb, 'C', 'Hydroxychloroquine สะสมที่ retina → macular toxicity (bull''s eye retinopathy) ควรตรวจตาทุกปีหลังใช้ 5 ปีแรก', '{"A":"ผิด — Uveitis อาจเกิดจาก SLE เอง ไม่ใช่ผลข้างเคียงของ HCQ","B":"ผิด — Cataracts เกิดจาก corticosteroid ไม่ใช่ HCQ","C":"ถูก — Chloroquine/Hydroxychloroquine: retinal toxicity (maculopathy) ขึ้นกับ cumulative dose ตรวจ baseline แล้วทุกปีหลังปีที่ 5","D":"ผิด — Glaucoma ไม่ใช่ผลข้างเคียงของ HCQ"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('d60e5d14-494f-4306-9cd0-299117577650', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 32 ปี RA กำลังจะตั้งครรภ์ ยา DMARD ใดที่ต้องหยุดก่อนตั้งครรภ์อย่างน้อย 3 เดือน', NULL, '["Hydroxychloroquine","Sulfasalazine","Methotrexate","Azathioprine"]'::jsonb, 'C', 'Methotrexate เป็น teratogen ชัดเจน (category X) ต้องหยุดอย่างน้อย 3 เดือนก่อนตั้งครรภ์', '{"A":"ผิด — Hydroxychloroquine ปลอดภัย สามารถใช้ต่อระหว่างตั้งครรภ์","B":"ผิด — Sulfasalazine ใช้ได้ระหว่างตั้งครรภ์ (ต้องให้ folic acid เสริม)","C":"ถูก — MTX teratogenic, abortifacient หยุดอย่างน้อย 3 เดือน (บางแหล่ง 6 เดือน) ก่อนตั้งครรภ์","D":"ผิด — Azathioprine ใช้ได้ระหว่างตั้งครรภ์ใน inflammatory disease"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('092d80f2-3401-48d2-9a2f-8cb2c9e68236', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี ปวดหลังส่วนล่าง (Low Back Pain) เฉียบพลัน 3 วัน ไม่มี red flags ยาที่เหมาะสม first-line คือ', NULL, '["Tramadol 50 mg PRN","Paracetamol 500 mg PRN + Ibuprofen 400 mg TID","Methocarbamol (muscle relaxant)","Gabapentin 300 mg TID"]'::jsonb, 'B', 'Acute LBP ไม่มี red flags: Paracetamol และ NSAIDs เป็น first-line ร่วมกับ non-pharmacological (heat, exercise)', '{"A":"ผิด — Tramadol ไม่ใช่ first-line สำหรับ non-specific LBP","B":"ถูก — Paracetamol ± NSAIDs เป็น first-line pharmacotherapy สำหรับ acute LBP","C":"ผิด — Muscle relaxant เพิ่มเป็น add-on ถ้ามี muscle spasm ชัดเจน ไม่ใช่ first-line","D":"ผิด — Gabapentin ใช้ใน neuropathic pain ไม่ใช่ acute LBP"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('04566e08-74c7-4bc9-9d34-dffbefd471fa', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 60 ปี Osteoporosis รับประทาน Alendronate มา 5 ปี แพทย์จะพิจารณา drug holiday เหตุใดจึงทำ', NULL, '["เพราะ bisphosphonate หมดฤทธิ์หลัง 5 ปี","เพื่อลดความเสี่ยง atypical femoral fracture และ ONJ","เพราะ bone density เพิ่มสูงสุดที่ 5 ปี","เพื่อประหยัดค่าใช้จ่าย"]'::jsonb, 'B', 'Bisphosphonate drug holiday ลด cumulative dose เพื่อลดความเสี่ยง atypical femoral fracture และ osteonecrosis of the jaw (ONJ)', '{"A":"ผิด — Bisphosphonate สะสมในกระดูก ยังมีฤทธิ์ได้นานหลังหยุดยา","B":"ถูก — ผลข้างเคียงหายาก แต่รุนแรง: atypical femoral fracture และ ONJ สัมพันธ์กับ cumulative dose ยาว → drug holiday ลดความเสี่ยง","C":"ผิด — Bone density ไม่ใช่เหตุผลหลัก","D":"ผิด — Drug holiday ไม่ใช่เพื่อประหยัด"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('67265d94-cca0-4376-a19e-5e12113ef640', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 35 ปี Ankylosing Spondylitis (AS) ปวดหลังส่วนล่าง ตอบสนองไม่ดีต่อ NSAIDs หลายชนิด แพทย์จะใช้ biologic ชนิดใดเป็น first-line', NULL, '["Anti-CD20 (Rituximab)","Anti-TNF (Etanercept หรือ Adalimumab)","IL-6 inhibitor (Tocilizumab)","JAK inhibitor (Tofacitinib)"]'::jsonb, 'B', 'Anti-TNF therapy เป็น first-line biologic สำหรับ AS ที่ fail NSAIDs ตาม ASAS/EULAR guideline', '{"A":"ผิด — Rituximab ไม่มีหลักฐานชัดเจนใน AS","B":"ถูก — Anti-TNF (Etanercept, Adalimumab, Certolizumab, Golimumab) เป็น first-line biologic ใน active AS ที่ fail ≥2 NSAIDs","C":"ผิด — Tocilizumab ไม่ได้รับการอนุมัติใน AS","D":"ผิด — JAK inhibitor (Tofacitinib, Upadacitinib) ใช้ได้แต่เป็น second-line หลัง anti-TNF"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('ed47a7ee-81c7-403f-8e37-c9afc92f79e3', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 62 ปี OA เข่า ใช้ Diclofenac 75 mg BID มา 3 เดือน เริ่มมีอาการบวมขาและความดันโลหิตสูงขึ้น สาเหตุที่น่าจะเป็น', NULL, '["RA แย่ลง","NSAIDs-induced sodium/water retention และ hypertension","Methotrexate toxicity","Calcium deficiency"]'::jsonb, 'B', 'NSAIDs ยับยั้ง prostaglandin ซึ่งมีบทบาทใน renal blood flow → sodium retention → บวม, ความดันสูง', '{"A":"ผิด — RA ไม่ใช่ diagnosis ของผู้ป่วยรายนี้","B":"ถูก — NSAIDs: inhibit PGE2/PGI2 → renal sodium retention → oedema, hypertension เป็น class effect","C":"ผิด — ผู้ป่วยไม่ได้รับ MTX","D":"ผิด — Calcium deficiency ไม่ทำให้บวมขาหรือ BP สูง"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('739aa557-60c3-4e89-8a5b-e31ca46515e4', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 70 ปี ปวดข้อทั่วไป ได้รับ Prednisolone 10 mg/day มา 6 เดือน ควรให้ยาเสริมอะไรเพื่อป้องกัน steroid-induced osteoporosis', NULL, '["Vitamin D 1000 IU/day เท่านั้น","Calcium 1000 mg + Vitamin D 800 IU/day","Calcium + Vitamin D + Bisphosphonate (Alendronate)","Estrogen therapy"]'::jsonb, 'C', 'Steroid ≥7.5 mg/day ≥3 เดือน: ACR แนะนำ Calcium + Vitamin D + Bisphosphonate เพื่อป้องกัน fracture', '{"A":"ผิด — Vitamin D เดี่ยวไม่เพียงพอ","B":"ผิด — Calcium + Vitamin D ไม่เพียงพอใน long-term high-dose steroid","C":"ถูก — ACR 2017: steroid ≥7.5 mg/day ≥3 เดือน → Calcium 1000-1200 mg + Vit D 600-800 IU + oral bisphosphonate","D":"ผิด — Estrogen ไม่ใช่ first-line สำหรับ steroid-induced osteoporosis"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:40:54') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2c2d56f8-0040-4be6-a349-05a4b8d2f972', '06991a85-412e-476e-89ff-32b0a7b92e6c', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี ปวดกล้ามเนื้อ Fibromyalgia ยาที่มีหลักฐานดีที่สุดและ FDA-approved สำหรับ Fibromyalgia คือ', NULL, '["Ibuprofen 400 mg TID","Duloxetine 60 mg OD","Codeine 30 mg PRN","Methotrexate"]'::jsonb, 'B', 'Duloxetine (SNRI) เป็นหนึ่งใน 3 ยาที่ FDA อนุมัติสำหรับ Fibromyalgia (อีก 2 คือ Milnacipran, Pregabalin)', '{"A":"ผิด — NSAIDs มีหลักฐานน้อยใน Fibromyalgia เพราะไม่ใช่ inflammatory condition","B":"ถูก — Duloxetine 60 mg/day FDA-approved สำหรับ Fibromyalgia ลด central sensitization","C":"ผิด — Opioid ไม่แนะนำใน Fibromyalgia (ไม่ได้ผล อาจแย่ลง)","D":"ผิด — Methotrexate ใช้ใน autoimmune ไม่ใช่ Fibromyalgia"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:40:55') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c92728a3-0469-43a9-85d9-f9dda6e15d2a', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 22 ปี มีสิวอักเสบ (inflammatory acne) ระดับปานกลาง ยาทาที่เป็น first-line สำหรับ inflammatory acne คือ', NULL, '["Benzoyl peroxide เพียงอย่างเดียว","Topical retinoid (Adapalene/Tretinoin)","Topical antibiotic (Clindamycin) + Benzoyl peroxide","Topical corticosteroid"]'::jsonb, 'C', 'Moderate inflammatory acne: topical antibiotic + benzoyl peroxide เป็น first-line; benzoyl peroxide ป้องกัน antibiotic resistance', '{"A":"ผิด — Benzoyl peroxide เดี่ยวเหมาะ mild acne ไม่เพียงพอสำหรับ moderate","B":"ผิด — Retinoid เหมาะกับ comedonal acne (non-inflammatory) มากกว่า","C":"ถูก — Clindamycin + Benzoyl peroxide (เช่น Duac) เป็น first-line moderate inflammatory acne ป้องกัน resistance","D":"ผิด — Topical steroid ห้ามใช้ใน acne (ทำให้ acne แย่ลง)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:44') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('060c3740-8965-4aa5-bc52-72efa700dc88', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 25 ปี Moderate-Severe Acne ไม่ตอบสนองต่อ topical therapy แพทย์พิจารณา Oral Isotretinoin ผู้ป่วยควรทราบข้อห้ามที่สำคัญที่สุดคืออะไร', NULL, '["ห้ามรับประทานกับอาหาร","ห้ามใช้ในหญิงตั้งครรภ์ (Pregnancy X)","ห้ามรับประทานเกิน 20 mg/day","ห้ามรับประทานร่วมกับ Paracetamol"]'::jsonb, 'B', 'Isotretinoin เป็น teratogen รุนแรง (FDA category X) ห้ามใช้ในตั้งครรภ์ ต้องคุมกำเนิดอย่างเคร่งครัด', '{"A":"ผิด — Isotretinoin ควรรับประทานพร้อมอาหาร (fatty meal) เพื่อเพิ่มการดูดซึม","B":"ถูก — Pregnancy category X teratogen รุนแรง ต้องทำ pregnancy test ก่อนเริ่ม และทุกเดือน + คุมกำเนิด 2 วิธีตลอดการรักษา","C":"ผิด — ขนาดปกติ 0.5-1 mg/kg/day ไม่มีข้อห้าม 20 mg/day","D":"ผิด — ไม่มี significant interaction กับ Paracetamol"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:44') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b70b5c85-9ed8-45cb-91fe-cce37630ffd7', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 40 ปี มี Psoriasis plaque type ที่ข้อศอกและหัวเข่า mild-moderate ยาทาที่เหมาะสม first-line คือ', NULL, '["Topical corticosteroid (Betamethasone valerate)","Topical retinoid","Topical antibiotic","Topical antifungal"]'::jsonb, 'A', 'Topical corticosteroid เป็น first-line สำหรับ mild-moderate plaque psoriasis', '{"A":"ถูก — Medium-high potency topical corticosteroid (Betamethasone valerate, Mometasone) เป็น first-line สำหรับ limited psoriasis","B":"ผิด — Topical retinoid (Tazarotene) ใช้ได้แต่เป็น alternative ไม่ใช่ first-line","C":"ผิด — Psoriasis ไม่ใช่การติดเชื้อ topical antibiotic ไม่มีประสิทธิภาพ","D":"ผิด — Psoriasis ไม่ใช่เชื้อรา topical antifungal ไม่มีประสิทธิภาพ"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:44') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f2f6ab4f-22c3-496b-b5e6-d8e6dfb7d0a9', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี ผื่น Atopic Dermatitis เรื้อรัง ยาทาสเตียรอยด์ทำให้ผิวบาง ควรเปลี่ยนมาใช้ยาใดเป็น maintenance', NULL, '["Topical Tacrolimus หรือ Pimecrolimus (TCI)","Topical antifungal","Topical antibiotic","Topical antihistamine"]'::jsonb, 'A', 'Topical calcineurin inhibitors (TCI): Tacrolimus/Pimecrolimus ใช้เป็น steroid-sparing agent ใน atopic dermatitis โดยไม่ทำให้ผิวบาง', '{"A":"ถูก — TCI (Tacrolimus 0.03%/0.1%, Pimecrolimus 1%) เป็น non-steroidal alternative ไม่ทำให้ skin atrophy","B":"ผิด — Antifungal ไม่มีประสิทธิภาพต่อ atopic dermatitis","C":"ผิด — Topical antibiotic ใช้เมื่อมี secondary bacterial infection","D":"ผิด — Topical antihistamine ไม่แนะนำ (ประสิทธิภาพต่ำ อาจเกิด sensitization)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('577c9520-2816-4357-bebf-73e4bb294dce', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 30 ปี เกิดอาการแพ้ยา Stevens-Johnson Syndrome (SJS) จากยาใดที่พบบ่อยที่สุด', NULL, '["Paracetamol","Allopurinol","Amoxicillin","Metformin"]'::jsonb, 'B', 'Allopurinol เป็นสาเหตุพบบ่อยที่สุดของ SJS/TEN ในเอเชีย โดยเฉพาะผู้ที่มี HLA-B*5801', '{"A":"ผิด — Paracetamol ไม่ค่อยทำให้เกิด SJS","B":"ถูก — Allopurinol + HLA-B*5801 (พบมากในคนเอเชีย) เป็นสาเหตุ SJS/TEN พบบ่อยในไทย; ยาอื่นที่พบบ่อย: aromatic antiepileptics (Carbamazepine, Phenytoin), Sulfonamides","C":"ผิด — Amoxicillin ทำให้ maculopapular rash บ่อย แต่ SJS น้อยกว่า","D":"ผิด — Metformin ไม่พบ SJS"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1a1e28f6-d230-4de4-82d1-ca6225438c58', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี มีผื่นแดงเป็นวงๆ ที่หน้า (butterfly rash) + ข้อ + ไต วินิจฉัย SLE ยาใดที่ใช้ป้องกันการกำเริบและลด mortality ใน SLE ทุก case', NULL, '["Prednisolone","Methotrexate","Hydroxychloroquine","Mycophenolate mofetil"]'::jsonb, 'C', 'Hydroxychloroquine แนะนำให้ทุก SLE patient เพื่อลด disease flare, organ damage, thrombosis และ mortality', '{"A":"ผิด — Prednisolone ใช้ใน active disease ไม่ใช่ baseline treatment ทุก patient","B":"ผิด — Methotrexate ใช้ใน skin/joint SLE ไม่ใช่ baseline ทุก patient","C":"ถูก — HCQ 200-400 mg/day ควรให้ทุก SLE patient ยกเว้น contraindication; ลด flare, thrombosis, mortality","D":"ผิด — MMF ใช้ใน lupus nephritis ไม่ใช่ baseline ทุก SLE"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('23216973-f7ee-4ba0-88aa-6948ffcf3ac9', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี Herpes Zoster (งูสวัด) มีผื่นพุพองที่ด้านซ้ายของหน้าอก เกิดขึ้น 48 ชั่วโมง ควรให้ยา antiviral ใดและเมื่อใด', NULL, '["รอดูก่อน ถ้าแย่ค่อยให้ยา","Acyclovir 800 mg 5 ครั้ง/วัน × 7 วัน เริ่มทันที","Valacyclovir 1000 mg TID × 7 วัน เริ่มทันที","Famciclovir 500 mg TID × 7 วัน เริ่มทันที หรือ Valacyclovir"]'::jsonb, 'D', 'Herpes Zoster: ควรเริ่ม antiviral ภายใน 72 ชั่วโมง Valacyclovir/Famciclovir มี bioavailability ดีกว่า Acyclovir oral', '{"A":"ผิด — การรอจะทำให้ post-herpetic neuralgia และ complications แย่ขึ้น","B":"ผิด — Acyclovir oral ใช้ได้แต่ต้องกิน 5 ครั้ง/วัน compliance ต่ำกว่า; Valacyclovir/Famciclovir preferred","C":"ผิด — Valacyclovir ถูกต้อง แต่ Famciclovir ก็ใช้ได้เท่ากัน ควรระบุทั้งสอง","D":"ถูก — Valacyclovir 1000 mg TID หรือ Famciclovir 500 mg TID × 7 วัน เป็น preferred therapy ใน HZ (better bioavailability)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('be46fc74-d2d3-4d70-b09f-4019cee4a48c', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี ผื่นแพ้สัมผัส (Contact Dermatitis) ที่ข้อมือจากนาฬิกา ผื่นเป็นมา 1 สัปดาห์ ยาที่ใช้บรรเทาอาการในระยะเฉียบพลัน', NULL, '["Topical antifungal","Topical corticosteroid (Hydrocortisone 1%)","Oral antibiotic","Topical antibiotic"]'::jsonb, 'B', 'Acute contact dermatitis: topical corticosteroid ลด inflammation เป็น mainstay treatment', '{"A":"ผิด — Contact dermatitis ไม่ใช่เชื้อรา","B":"ถูก — Topical corticosteroid (hydrocortisone ส่วน face/groin, medium-high potency ส่วน body) ลด inflammation","C":"ผิด — ไม่มีการติดเชื้อแบคทีเรีย","D":"ผิด — ไม่มีการติดเชื้อแบคทีเรีย"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('261d5968-3e04-448e-b95b-78bd4f2cd429', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี มีผื่นเชื้อรา Tinea pedis (Hong Kong foot) ระหว่างนิ้วเท้า ยาทาที่เหมาะสม first-line คือ', NULL, '["Topical corticosteroid","Topical Terbinafine (Lamisil cream)","Oral Fluconazole","Topical Nystatin"]'::jsonb, 'B', 'Tinea pedis (dermatophytosis): topical allylamine (Terbinafine) หรือ azole เป็น first-line', '{"A":"ผิด — Corticosteroid ห้ามใช้กับเชื้อรา (ทำให้แย่ลง)","B":"ถูก — Topical Terbinafine 1% (allylamine) มี cure rate สูงกว่า azoles ใน dermatophyte infections","C":"ผิด — Oral antifungal สำหรับกรณีรุนแรง, extensive, หรือ onycomycosis","D":"ผิด — Nystatin ใช้กับ Candida เท่านั้น ไม่ได้ผลกับ dermatophyte"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:45') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('27196dbd-f5b2-4c60-8b56-b30ed52e5dbb', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 50 ปี มีสีผิวคล้ำเป็นจ้ำที่แก้ม (melasma) ต้องการรักษา ยาทาที่เป็น gold standard คือ', NULL, '["Hydrocortisone cream","Triple combination: Hydroquinone 4% + Tretinoin 0.05% + Hydrocortisone 0.01%","Sunscreen SPF 50 เพียงอย่างเดียว","Vitamin C serum"]'::jsonb, 'B', 'Triple combination cream (Kligman''s formula) เป็น gold standard สำหรับ melasma treatment', '{"A":"ผิด — Hydrocortisone เดี่ยวไม่มีประสิทธิภาพต่อ melasma","B":"ถูก — Kligman''s formula: Hydroquinone (bleaching) + Tretinoin (epidermal turnover) + Hydrocortisone (anti-inflammatory) เป็น first-line","C":"ผิด — Sunscreen สำคัญมากแต่เป็น adjunct ไม่ใช่ treatment หลัก","D":"ผิด — Vitamin C ช่วยได้บ้างแต่ไม่ใช่ gold standard"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4061bd3a-40ed-49b3-900a-2548d5cfea0a', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 30 ปี มีเล็บเป็นเชื้อรา (Onychomycosis) ตรวจพบ Trichophyton rubrum ยา oral ที่เหมาะสมที่สุดคือ', NULL, '["Fluconazole 150 mg weekly × 12 สัปดาห์","Terbinafine 250 mg OD × 12 สัปดาห์ (เล็บเท้า)","Itraconazole 200 mg BID × 7 วัน/เดือน × 3 เดือน","Griseofulvin × 1 ปี"]'::jsonb, 'B', 'Terbinafine oral เป็น first-line สำหรับ onychomycosis จาก dermatophyte (cure rate สูงที่สุด)', '{"A":"ผิด — Fluconazole ใช้ได้แต่ cure rate ต่ำกว่า Terbinafine","B":"ถูก — Terbinafine 250 mg OD × 6 สัปดาห์ (เล็บมือ) หรือ 12 สัปดาห์ (เล็บเท้า) — highest mycological cure rate","C":"ผิด — Itraconazole pulse therapy ใช้ได้แต่ second-line","D":"ผิด — Griseofulvin ล้าสมัย cure rate ต่ำ ต้องใช้นาน"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('100fa1ea-237f-4f04-9c38-ab19c4c9c262', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 20 ปี มีผื่นลมพิษ (Urticaria) เฉียบพลัน ยาที่ให้บรรเทาอาการ first-line คือ', NULL, '["Oral corticosteroid","2nd generation antihistamine (Cetirizine/Loratadine)","1st generation antihistamine (Chlorpheniramine)","Epinephrine IM"]'::jsonb, 'B', 'Non-sedating 2nd generation antihistamine เป็น first-line สำหรับ acute urticaria', '{"A":"ผิด — Oral steroid ใช้เมื่อ severe หรือ angioedema ไม่ใช่ first-line ทั่วไป","B":"ถูก — 2nd gen H1 antihistamine (Cetirizine, Loratadine, Fexofenadine) เป็น first-line ไม่ง่วง","C":"ผิด — 1st gen (Chlorpheniramine) ใช้ได้แต่ง่วงมากกว่า ไม่ใช่ preferred","D":"ผิด — Epinephrine IM ใช้ใน anaphylaxis ไม่ใช่ mild urticaria"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e4d3ebea-b6c4-4ef9-980d-518ff5f98f5a', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 25 ปี Severe Psoriasis ทั่วตัว ใช้ Methotrexate มา 1 ปี เภสัชกรต้องติดตามผลข้างเคียงอะไรบ้าง', NULL, '["ระดับน้ำตาลในเลือด","Liver function test + CBC + Renal function","Serum uric acid","Thyroid function test"]'::jsonb, 'B', 'MTX ผลข้างเคียงสำคัญ: hepatotoxicity, myelosuppression, nephrotoxicity → ติดตาม LFT, CBC, Cr', '{"A":"ผิด — MTX ไม่ทำให้น้ำตาลในเลือดผิดปกติ","B":"ถูก — MTX monitoring: LFT (hepatotoxicity), CBC (myelosuppression — WBC, platelet), Cr/BUN (nephrotoxicity) ทุก 4-8 สัปดาห์","C":"ผิด — Hyperuricemia ไม่ใช่ผลข้างเคียงหลักของ MTX","D":"ผิด — MTX ไม่ส่งผลต่อ thyroid function"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:42:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('915da593-6ee5-492a-80c5-1b080297e595', '12b0b8c1-fe53-49d8-9c4b-e348eba85e36', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี Cellulitis ที่ขาซ้าย ไม่มีโรคร่วม ไม่มีไข้ ยา antibiotic oral first-line คือ', NULL, '["Ciprofloxacin","Cephalexin (Cefalexin)","Clindamycin","Metronidazole"]'::jsonb, 'B', 'Non-purulent cellulitis: Streptococcus เป็นเชื้อหลัก → Cephalexin (1st gen cephalosporin) เป็น first-line', '{"A":"ผิด — Fluoroquinolone ไม่ใช่ first-line สำหรับ Streptococcal cellulitis","B":"ถูก — Cephalexin 500 mg QID × 5-7 วัน เป็น first-line สำหรับ non-purulent cellulitis","C":"ผิด — Clindamycin ใช้เมื่อแพ้ beta-lactam หรือสงสัย MRSA","D":"ผิด — Metronidazole ใช้กับ anaerobes ไม่ใช่ Streptococcal cellulitis"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:42:46') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7afbf5da-51f0-427e-b1bf-2e4dd3f7d9e8', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 30 ปี เกิด Anaphylaxis ทันทีหลังฉีด Penicillin G เริ่มมีลมพิษ หายใจลำบาก ความดันต่ำ ยาที่ต้องให้ทันทีก่อนอื่นคือ', NULL, '["Diphenhydramine IV","Hydrocortisone IV","Epinephrine 1:1000 IM 0.3-0.5 mg","Salbutamol nebulizer"]'::jsonb, 'C', 'Epinephrine IM เป็น first-line และ life-saving treatment ใน anaphylaxis ต้องให้ทันที', '{"A":"ผิด — Antihistamine (Diphenhydramine) เป็น adjunct ช้าเกินสำหรับ anaphylaxis ไม่ควรให้ก่อน epinephrine","B":"ผิด — Corticosteroid ออกฤทธิ์ช้า (1-6 ชม.) ไม่ใช่ first-line","C":"ถูก — Epinephrine 1:1000 IM 0.3-0.5 mg (anterolateral thigh) เป็น first-line ทันที ลด bronchospasm, vasodilation, angioedema","D":"ผิด — Salbutamol nebulizer เป็น adjunct สำหรับ bronchospasm ไม่ใช่ first-line"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7809c6c1-3831-48c0-9a6a-f1d596f20a32', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 25 ปี แพ้ Penicillin (ประวัติ anaphylaxis) ต้องใช้ antibiotic รักษา community-acquired pneumonia ควรใช้ยาใด', NULL, '["Amoxicillin (beta-lactam อื่น)","Cefuroxime (cephalosporin)","Azithromycin หรือ Doxycycline","Ampicillin-sulbactam"]'::jsonb, 'C', 'ประวัติ severe Penicillin allergy (anaphylaxis): ควรหลีกเลี่ยง beta-lactam ทั้งหมดในกรณี severe; Azithromycin/Doxycycline ปลอดภัย', '{"A":"ผิด — Amoxicillin เป็น aminopenicillin ห้ามใช้เด็ดขาด","B":"ผิด — Cephalosporin มี cross-reactivity กับ Penicillin ~2% ระวังใน severe allergy","C":"ถูก — Macrolide (Azithromycin) หรือ Tetracycline (Doxycycline) ปลอดภัยสำหรับ Penicillin-allergic patients","D":"ผิด — Ampicillin-sulbactam ยังเป็น beta-lactam ห้ามใช้"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('fc58824d-deca-41c9-ad10-1a8df7f5d85e', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 35 ปี HIV positive CD4 count 150 cells/mm³ ควรได้รับ prophylaxis ยาใดป้องกัน Pneumocystis pneumonia (PCP)', NULL, '["Fluconazole 200 mg OD","TMP-SMX (Cotrimoxazole) DS OD","Azithromycin 1250 mg weekly","Isoniazid 300 mg OD"]'::jsonb, 'B', 'PCP prophylaxis: TMP-SMX (Cotrimoxazole) เป็น first-line เมื่อ CD4 < 200 cells/mm³', '{"A":"ผิด — Fluconazole ป้องกัน Cryptococcus/Candida ไม่ใช่ PCP","B":"ถูก — TMP-SMX DS OD เป็น first-line PCP prophylaxis เมื่อ CD4 < 200 (และ primary prophylaxis เริ่มที่ CD4 < 200)","C":"ผิด — Azithromycin ป้องกัน MAC (Mycobacterium avium complex) เมื่อ CD4 < 50","D":"ผิด — INH ป้องกัน TB (LTBI) ไม่ใช่ PCP"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('7ac76874-8cd2-4eda-91a5-e34828e14a11', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี HIV positive เพิ่งเริ่ม ARV (Antiretroviral therapy) มาใช้ Efavirenz + Tenofovir + Emtricitabine (TDF/FTC/EFV) เภสัชกรแนะนำว่าควรรับประทาน EFV ตอนใด', NULL, '["ก่อนอาหาร 30 นาที","กับอาหารมัน (fatty meal)","ก่อนนอน บนท้องว่าง","กับนม"]'::jsonb, 'C', 'Efavirenz แนะนำให้รับประทานก่อนนอน บนท้องว่าง เพื่อลด CNS side effects (ฝัน วิงเวียน) ที่มักเกิดช่วงกลางคืน', '{"A":"ผิด — การกินก่อนอาหาร 30 นาทีไม่ใช่คำแนะนำสำหรับ EFV","B":"ผิด — อาหารมัน (high-fat meal) เพิ่ม EFV absorption ถึง 50% เพิ่ม CNS toxicity","C":"ถูก — EFV ก่อนนอน บนท้องว่าง: ลด AUC เล็กน้อย แต่ CNS effects (ฝันผวา, วิงเวียน) เกิดขณะนอนหลับไม่รบกวนกิจวัตร","D":"ผิด — นมไม่มีผลพิเศษ แต่อาหารมันควรหลีกเลี่ยง"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('dc17da31-088c-4ac8-8a02-3c7ba619d480', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 40 ปี Kidney transplant รับ Cyclosporine เป็น immunosuppressant มีอาการ gum hyperplasia ผลข้างเคียงนี้เกิดจากอะไร', NULL, '["Tacrolimus","Cyclosporine","Mycophenolate mofetil","Prednisolone"]'::jsonb, 'B', 'Gingival hyperplasia เป็น adverse effect เฉพาะของ Cyclosporine (Calcineurin inhibitor)', '{"A":"ผิด — Tacrolimus (FK506) ไม่ทำให้ gingival hyperplasia (ข้อดีกว่า CsA)","B":"ถูก — Cyclosporine: gingival hyperplasia, nephrotoxicity, hypertension, hirsutism เป็น classic AEs","C":"ผิด — MMF ผลข้างเคียงหลัก GI (nausea, diarrhea), myelosuppression","D":"ผิด — Corticosteroid ทำให้ moon face, DM, osteoporosis ไม่ทำให้ gum hyperplasia"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cec3a60a-ab40-433d-bb6b-41a464ead6f1', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 33 ปี ผู้บริจาคไต (renal transplant) ได้รับ Tacrolimus เภสัชกรต้องติดตาม drug level ใด', NULL, '["Peak level (2 ชม. หลังกิน)","Trough level (ก่อนกินยาเช้า)","Random level","Area under curve (AUC)"]'::jsonb, 'B', 'Tacrolimus monitoring ใช้ trough level (C0) เก็บตัวอย่างก่อนกินยาเช้า เป้าหมายขึ้นกับช่วงหลัง transplant', '{"A":"ผิด — Peak level ไม่ใช่ standard monitoring parameter สำหรับ Tacrolimus","B":"ถูก — Trough level (C0) ก่อนกินยาเช้า เป็น standard monitoring; target: early post-transplant 8-12 ng/mL, maintenance 5-8 ng/mL","C":"ผิด — Random level ไม่น่าเชื่อถือ","D":"ผิด — AUC ใช้ใน research ไม่ใช่ routine clinical monitoring"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:50') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('694500d8-5159-48c2-bde8-93bc09a319a7', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 50 ปี ได้รับ Tacrolimus หลัง renal transplant 1 ปี เภสัชกรตรวจสอบรายการยา พบว่าผู้ป่วยเพิ่งเริ่มกิน Fluconazole สำหรับ oral candidiasis Drug interaction ที่ต้องระวังคือ', NULL, '["Fluconazole ลดระดับ Tacrolimus","Fluconazole เพิ่มระดับ Tacrolimus (CYP3A4 inhibitor)","ไม่มี interaction ที่สำคัญ","Tacrolimus ลดฤทธิ์ Fluconazole"]'::jsonb, 'B', 'Fluconazole เป็น CYP3A4/CYP2C19 inhibitor → ลดการ metabolize Tacrolimus → Tacrolimus level เพิ่มสูงขึ้น', '{"A":"ผิด — Fluconazole ยับยั้ง ไม่ใช่เพิ่ม CYP3A4 metabolism","B":"ถูก — Fluconazole inhibit CYP3A4 → Tacrolimus ไม่ถูก metabolize → blood level สูงขึ้น → ต้องลดขนาด Tacrolimus และ monitor level อย่างใกล้ชิด","C":"ผิด — เป็น significant interaction ที่ต้องจัดการ","D":"ผิด — Tacrolimus ไม่ inhibit Fluconazole metabolism"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:51') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cdffb99e-bf21-44a8-be5a-2352fa1af37f', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 27 ปี มีอาการแพ้ยา Sulfonamide (TMP-SMX) เช่น ผื่น ควรระวังการใช้ยาใดต่อไปนี้', NULL, '["Amoxicillin","Furosemide (loop diuretic)","Paracetamol","Metformin"]'::jsonb, 'B', 'Furosemide มีโครงสร้าง sulfonamide moiety อาจเกิด cross-reactivity ในผู้แพ้ sulfonamide', '{"A":"ผิด — Amoxicillin ไม่มี cross-reactivity กับ sulfonamide","B":"ถูก — Furosemide, Thiazides, Celecoxib, Sulfonylureas มี sulfonamide group อาจ cross-react แต่ความเสี่ยงต่ำ ควรระวังและติดตาม","C":"ผิด — Paracetamol ไม่มี sulfonamide structure","D":"ผิด — Metformin ไม่มี sulfonamide structure"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:51') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2573f539-68d9-48e8-80e2-a92e20c9780b', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี RA ได้รับ Anti-TNF biologic (Adalimumab) แพทย์ต้องตรวจคัดกรองอะไรก่อนเริ่มยา', NULL, '["HbA1c","Tuberculosis screening (TST หรือ IGRA)","Uric acid level","Thyroid function test"]'::jsonb, 'B', 'Anti-TNF therapy กระตุ้น reactivation ของ latent TB จึงต้องคัดกรอง TB ทุก patient ก่อนเริ่ม', '{"A":"ผิด — HbA1c ไม่ใช่ prerequisite ก่อน anti-TNF","B":"ถูก — TB screening (TST/IGRA + CXR) บังคับก่อนเริ่ม anti-TNF เพราะ TNF สำคัญในการ contain granuloma; ถ้า LTBI ต้องรักษาก่อน","C":"ผิด — Uric acid ไม่เกี่ยวข้อง","D":"ผิด — Thyroid function ไม่ใช่ prerequisite"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:44:51') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1980624d-41a6-4c63-a541-1402a5dd6508', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 30 ปี วินิจฉัย SLE ที่มี lupus nephritis (LN) class III เพิ่งตรวจ renal biopsy ยาที่ใช้เป็น induction therapy คือ', NULL, '["Hydroxychloroquine เดี่ยว","Prednisolone + Mycophenolate mofetil (MMF)","Prednisolone + Methotrexate","Azathioprine เดี่ยว"]'::jsonb, 'B', 'Lupus nephritis class III/IV: high-dose prednisolone + MMF เป็น standard induction therapy (ACR/EULAR 2023)', '{"A":"ผิด — HCQ เดี่ยวไม่เพียงพอสำหรับ LN","B":"ถูก — Prednisolone 1 mg/kg/day + MMF 2-3 g/day หรือ IV Cyclophosphamide เป็น induction therapy LN class III/IV","C":"ผิด — MTX ไม่ใช้ใน LN (มีข้อห้ามใน renal impairment)","D":"ผิด — Azathioprine เป็น maintenance therapy ไม่ใช่ induction"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:51') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cb13ad19-cae4-4d1e-a4aa-0d92c6cd3ea0', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'เด็กชายอายุ 8 ปี ได้รับ MMR vaccine แล้วมีไข้ 38.5°C หลังฉีด 2-3 สัปดาห์ ผู้ปกครองกังวล ควรอธิบายว่า', NULL, '["เด็กติดเชื้อหัดจาก vaccine","เป็น normal vaccine reaction สำหรับ live attenuated vaccine","ต้องหยุด vaccine ทันที","ต้องให้ corticosteroid รักษา"]'::jsonb, 'B', 'MMR เป็น live attenuated vaccine อาจเกิด mild fever + rash 7-21 วันหลังฉีด เป็น normal immune response', '{"A":"ผิด — Vaccine strain ไม่ทำให้เกิดโรคจริง attenuated จนไม่รุนแรง","B":"ถูก — Mild fever 38-39°C + rash หลัง MMR 7-21 วัน เป็น expected reaction ของ live attenuated vaccine บอก parents ให้ Paracetamol ตามอาการ","C":"ผิด — ไม่ต้องหยุด vaccine series","D":"ผิด — Corticosteroid ไม่จำเป็น และอาจ suppress immune response"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:44:51') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c9c3a6ff-10ae-4b78-a265-bf4af207b3c5', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 24 ปี ตั้งครรภ์ 20 สัปดาห์ มีประวัติสัมผัส chicken pox (varicella) เมื่อ 72 ชั่วโมงก่อน ไม่มีประวัติ varicella ควรให้อะไร', NULL, '["Varicella vaccine ทันที","Varicella-Zoster Immune Globulin (VZIG)","Acyclovir prophylaxis","ไม่จำเป็นต้องรักษา"]'::jsonb, 'B', 'หญิงตั้งครรภ์ที่สัมผัส varicella ภายใน 96 ชั่วโมง: VZIG เพื่อ passive immunization ป้องกัน severe varicella', '{"A":"ผิด — Live vaccine ห้ามใช้ในตั้งครรภ์","B":"ถูก — VZIG ภายใน 96 ชั่วโมงหลังสัมผัส ป้องกัน/ลด severity ของ varicella ใน seronegative pregnant women","C":"ผิด — Acyclovir prophylaxis ไม่แนะนำเป็น post-exposure prophylaxis ในตั้งครรภ์","D":"ผิด — ตั้งครรภ์ที่เป็น varicella มีความเสี่ยง maternal (pneumonia) และ fetal (congenital varicella syndrome)"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:52') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8605171e-5ce4-4ff3-a4f6-221e5f22eaa2', 'ccb73060-b09f-4927-8ff8-53190db76d18', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 62 ปี ได้รับ Rituximab (Anti-CD20) สำหรับ NHL มา 6 เดือน มาพบเภสัชกรพร้อมรายการยา ผลข้างเคียงที่ต้องระวังพิเศษจาก Rituximab คือ', NULL, '["Hyperglycemia","Hepatitis B reactivation","Pulmonary fibrosis","Agranulocytosis"]'::jsonb, 'B', 'Rituximab (anti-CD20) กดภูมิคุ้มกัน B cell → HBV reactivation เป็น serious complication ต้องคัดกรอง HBsAg/anti-HBc ก่อนใช้', '{"A":"ผิด — Hyperglycemia ไม่ใช่ผลข้างเคียงหลักของ Rituximab","B":"ถูก — HBV reactivation เป็น black box warning ของ Rituximab ต้องตรวจ HBsAg, anti-HBc; ถ้า positive ต้องให้ antiviral prophylaxis (Entecavir/Tenofovir)","C":"ผิด — Pulmonary fibrosis เกิดจาก Bleomycin ไม่ใช่ Rituximab","D":"ผิด — Agranulocytosis เกิดจาก Clozapine, Carbimazole ไม่ใช่ Rituximab"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:44:52') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('eeb84664-5e40-4c3a-8a83-c9f711286580', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี ตั้งครรภ์ 16 สัปดาห์ ตรวจพบ Hb 9.5 g/dL MCV 68 fL serum ferritin 8 ng/mL วินิจฉัย Iron Deficiency Anemia ยาที่เหมาะสมคือ', NULL, '["Ferrous sulfate 325 mg (elemental Fe 65 mg) OD","Ferrous sulfate 325 mg BID-TID","IV iron sucrose ทันที","ยังไม่ต้องรักษา เฝ้าสังเกต"]'::jsonb, 'B', 'IDA ในตั้งครรภ์: elemental iron 120-200 mg/day (Ferrous sulfate 325 mg = 65 mg elemental Fe × 2-3 ครั้ง)', '{"A":"ผิด — OD เดี่ยวให้ elemental Fe 65 mg/day ต่ำเกินสำหรับ treatment (เหมาะ prevention ปกติ)","B":"ถูก — WHO/ACOG: IDA in pregnancy ต้องการ elemental iron 120-200 mg/day → Ferrous sulfate 325 mg BID หรือ TID","C":"ผิด — IV iron สำรองสำหรับ oral intolerant, severe anemia, หรือ late pregnancy","D":"ผิด — Hb 9.5 ต้องรักษา"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:34') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b0cc1291-3696-44ff-8aef-3399a61bd8fa', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี Vitamin B12 deficiency anemia มี macrocytic anemia + neurological symptoms (numbness) สาเหตุที่พบบ่อยที่สุดในผู้ใหญ่คือ', NULL, '["ขาด B12 จากอาหาร (vegan)","Pernicious anemia (anti-intrinsic factor antibody)","Metformin-induced B12 deficiency","Chronic alcoholism"]'::jsonb, 'B', 'Pernicious anemia (autoimmune gastritis → IF antibody → B12 malabsorption) เป็นสาเหตุพบบ่อยที่สุดของ B12 deficiency ในผู้ใหญ่ตะวันตก', '{"A":"ผิด — Dietary B12 deficiency พบใน strict vegans แต่ไม่ใช่พบบ่อยที่สุด","B":"ถูก — Pernicious anemia: anti-IF antibody → B12 malabsorption → ต้องรักษาด้วย IM B12 (Cyanocobalamin/Hydroxycobalamin)","C":"ผิด — Metformin ลด B12 ดูดซึม แต่ไม่ใช่พบบ่อยที่สุด","D":"ผิด — Alcoholism ทำให้ folate deficiency มากกว่า B12"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:34') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('05a278ce-b879-4945-b7c1-3cfb85b9b068', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี มี DVT (Deep Vein Thrombosis) รักษาด้วย Warfarin ค่า INR เป้าหมายสำหรับ DVT/PE คือ', NULL, '["INR 1.5-2.0","INR 2.0-3.0","INR 2.5-3.5","INR 3.0-4.0"]'::jsonb, 'B', 'INR target สำหรับ DVT/PE prophylaxis และ treatment: 2.0-3.0', '{"A":"ผิด — 1.5-2.0 ต่ำเกิน ไม่ได้ผล","B":"ถูก — INR 2-3 เป็น standard target สำหรับ VTE (DVT/PE) treatment/prevention","C":"ผิด — 2.5-3.5 ใช้ใน mechanical heart valve บางชนิด","D":"ผิด — 3-4 ใช้ใน high-risk mechanical valve เช่น mitral mechanical"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8554a4d1-485d-4c36-b824-6a1a6e5529f1', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 65 ปี AF (Atrial Fibrillation) ได้รับ Warfarin INR = 4.8 ไม่มีเลือดออก ควรจัดการอย่างไร', NULL, '["หยุด Warfarin 1-2 วัน แล้วตรวจ INR ซ้ำ","ให้ Vitamin K1 5-10 mg oral ทันที","ให้ FFP (Fresh Frozen Plasma) ทันที","เพิ่มขนาด Warfarin"]'::jsonb, 'A', 'Warfarin supratherapeutic INR 4-9 ไม่มีเลือดออก: หยุดยา 1-2 วัน รอ INR ลงมาในช่วง therapeutic', '{"A":"ถูก — INR 4.8 ไม่มีเลือดออก: hold Warfarin 1-2 dose แล้ว recheck INR; อาจให้ Vitamin K1 1-2.5 mg oral ถ้า risk สูง","B":"ผิด — Vitamin K1 5-10 mg oral ใช้ใน INR > 9 ไม่มีเลือดออก หรือ INR 4-9 ที่มี risk factor เลือดออกสูง","C":"ผิด — FFP ใช้ใน active severe bleeding หรือก่อนผ่าตัดด่วน","D":"ผิด — ห้ามเพิ่มขนาด"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('3c5b7c20-3b77-4409-88c0-73ceb3635908', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี AF เพิ่งวินิจฉัย แพทย์เลือกใช้ DOAC แทน Warfarin ข้อดีของ DOAC (เช่น Rivaroxaban, Apixaban) เมื่อเทียบกับ Warfarin คือ', NULL, '["ราคาถูกกว่า Warfarin","ไม่ต้องตรวจ INR routine, onset เร็วกว่า","ย้อนกลับด้วย Vitamin K ได้ง่ายกว่า","ใช้ได้ปลอดภัยกว่าใน severe renal impairment"]'::jsonb, 'B', 'DOAC ข้อดี: ไม่ต้อง routine INR monitoring, onset เร็ว (peak 1-4 ชม.), drug interaction น้อยกว่า Warfarin', '{"A":"ผิด — DOAC แพงกว่า Warfarin มาก","B":"ถูก — DOAC: predictable pharmacokinetics → ไม่ต้อง routine monitoring; rapid onset; fewer food/drug interactions","C":"ผิด — DOAC มี specific antidotes (Idarucizumab สำหรับ Dabigatran, Andexanet alfa สำหรับ FXa inhibitors) แต่ไม่ใช่ Vitamin K","D":"ผิด — DOAC ลด dose ใน moderate renal impairment และ ห้ามใช้ใน severe CKD (eGFR < 15-30)"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c4a9d826-b5cf-4ca4-a428-fe53f227ed98', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 25 ปี Sickle Cell Disease มาด้วย Vaso-occlusive pain crisis ยาที่ใช้บรรเทาอาการเฉียบพลันและลด frequency ของ crisis คือ', NULL, '["Hydroxyurea เป็น maintenance","Morphine IV สำหรับ acute pain + Hydroxyurea maintenance","NSAIDs สำหรับ acute pain เพียงอย่างเดียว","Blood transfusion ทุก crisis"]'::jsonb, 'B', 'Sickle cell VOC: opioid (Morphine) เป็น acute pain management; Hydroxyurea ลด HbS polymerization → ลด frequency crisis', '{"A":"ผิด — Hydroxyurea เป็น maintenance disease-modifying therapy ไม่รักษา acute crisis","B":"ถูก — Acute: opioid analgesic (Morphine) + hydration; Maintenance: Hydroxyurea เพิ่ม HbF → ลดการ sickling","C":"ผิด — NSAIDs อย่างเดียวไม่เพียงพอสำหรับ severe VOC + มีความเสี่ยง renal","D":"ผิด — Transfusion ไม่ใช้ routine ทุก crisis; ใช้ใน severe anemia, stroke, ACS"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2b13b325-8676-4749-a8b2-c0839de16bc3', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 68 ปี CLL (Chronic Lymphocytic Leukemia) เพิ่งวินิจฉัย stage I Rai ไม่มีอาการ แนวทางรักษาที่เหมาะสมคือ', NULL, '["เริ่ม chemotherapy ทันที","Watch and Wait (เฝ้าสังเกต)","Bone marrow transplant ทันที","Rituximab ทันที"]'::jsonb, 'B', 'CLL early stage (Rai 0-II ไม่มีอาการ): watch and wait เป็น standard approach เพราะ treatment ไม่ได้เพิ่ม OS', '{"A":"ผิด — Chemotherapy ไม่แนะนำใน asymptomatic early CLL","B":"ถูก — CLL Rai stage I ไม่มีอาการ: watch and wait (active surveillance) จนกว่ามี active disease criteria","C":"ผิด — BMT ไม่ใช่ treatment for early asymptomatic CLL","D":"ผิด — Rituximab ไม่แนะนำ monotherapy ใน early asymptomatic CLL"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('c55842ce-8bd9-4d03-a368-33fc5b7db5c3', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี เพิ่งผ่าตัดเปลี่ยนลิ้นหัวใจ mechanical (mitral valve) ควรได้รับ Warfarin ในช่วง INR เท่าใด', NULL, '["INR 1.5-2.0","INR 2.0-3.0","INR 2.5-3.5","INR 3.5-4.5"]'::jsonb, 'C', 'Mechanical heart valve (mitral): INR target 2.5-3.5 สูงกว่า DVT เนื่องจาก thromboembolism risk สูงกว่า', '{"A":"ผิด — 1.5-2.0 ต่ำเกิน เสี่ยง valve thrombosis","B":"ผิด — 2-3 เหมาะ aortic mechanical valve (lower risk) ไม่ใช่ mitral","C":"ถูก — Mechanical mitral valve: INR 2.5-3.5 (AHA/ACC guideline) เพราะ mitral position มี thromboembolism risk สูงกว่า aortic","D":"ผิด — 3.5-4.5 สูงเกิน เสี่ยงเลือดออก"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:46:35') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('55800413-a25d-4c23-88ed-9618c41f0ae7', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี ITP (Immune Thrombocytopenic Purpura) platelet count 12,000/mm³ มีจ้ำเลือดแต่ไม่มีเลือดออกในอวัยวะสำคัญ ยา first-line คือ', NULL, '["Platelet transfusion ทันที","Prednisolone 1 mg/kg/day","Splenectomy","Rituximab"]'::jsonb, 'B', 'ITP first-line: corticosteroid (Prednisolone/Dexamethasone) เพื่อลด platelet destruction', '{"A":"ผิด — Platelet transfusion ใช้เฉพาะ life-threatening bleeding ใน ITP; ถูก destroy เร็ว","B":"ถูก — Prednisolone 1-2 mg/kg/day หรือ Dexamethasone 40 mg/day × 4 วัน เป็น first-line สำหรับ newly diagnosed ITP","C":"ผิด — Splenectomy เป็น second-line สำหรับ refractory/relapsed ITP","D":"ผิด — Rituximab เป็น second/third-line"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('89a5fcec-42d9-426d-aba1-407b94def21f', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี มี CKD stage 3 (eGFR 35) วินิจฉัย anemia of CKD (Hb 9 g/dL) เหตุใดจึงเกิด anemia ใน CKD', NULL, '["ขาด Vitamin B12 จาก malabsorption","ลดการผลิต Erythropoietin จากไต","Hemolysis จาก uremic toxins","Iron deficiency จากการฟอกเลือด"]'::jsonb, 'B', 'Anemia of CKD สาเหตุหลัก: peritubular cells ของไตผลิต EPO ลดลง → erythropoiesis ลด', '{"A":"ผิด — B12 deficiency ไม่ใช่สาเหตุหลักของ anemia CKD","B":"ถูก — Decreased EPO production จาก damaged peritubular fibroblasts เป็นสาเหตุหลักของ anemia of CKD → รักษาด้วย ESA (Epoetin alfa, Darbepoetin) + iron","C":"ผิด — Hemolysis เกิดได้บ้างแต่ไม่ใช่สาเหตุหลัก","D":"ผิด — Iron deficiency เป็น contributing factor โดยเฉพาะในผู้ที่ฟอกเลือด แต่ไม่ใช่สาเหตุหลัก"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('e3b728f0-b71c-44a3-98f0-d7e957c143d4', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี DVT ใน proximal leg ได้รับ LMWH (Enoxaparin) ขนาดปกติ แต่เนื่องจาก BMI 42 (obese) ควรปรับขนาดยาอย่างไร', NULL, '["ใช้ขนาดตามน้ำหนักจริง (actual body weight)","ใช้ขนาดตาม ideal body weight","ใช้ขนาดตาม adjusted body weight","ไม่ต้องปรับขนาด ใช้ขนาดมาตรฐาน"]'::jsonb, 'A', 'LMWH dose ใน obesity: ใช้ actual body weight (ABW) ถึงแม้จะ obese เพราะ LMWH กระจายไปยัง lean tissue', '{"A":"ถูก — LMWH (Enoxaparin) treatment dose ใช้ actual body weight (ABW) ไม่มี cap แต่บาง guideline แนะนำ anti-Xa monitoring ใน extreme obesity (> 150 kg หรือ BMI > 50)","B":"ผิด — IBW จะ underdose ใน obese patient","C":"ผิด — Adjusted BW ใช้ใน aminoglycosides ไม่ใช่ LMWH","D":"ผิด — Standard dose จะ underdose ใน morbidly obese"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:46:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('75f0e4cb-8542-4161-b91c-57177b30710b', 'ace9965c-285b-4d4a-aaf2-5de9739cc09a', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี NHL รับ CHOP chemotherapy ซึ่งประกอบด้วย Cyclophosphamide, Doxorubicin, Vincristine, Prednisolone ยาใดในรูปแบบนี้ที่ทำให้เกิด hemorrhagic cystitis', NULL, '["Doxorubicin","Vincristine","Cyclophosphamide","Prednisolone"]'::jsonb, 'C', 'Cyclophosphamide metabolite (Acrolein) ทำให้ bladder irritation → hemorrhagic cystitis ป้องกันด้วย Mesna', '{"A":"ผิด — Doxorubicin ผลข้างเคียงหลัก: cardiotoxicity (dilated cardiomyopathy)","B":"ผิด — Vincristine ผลข้างเคียงหลัก: peripheral neuropathy, SIADH","C":"ถูก — Cyclophosphamide → Acrolein metabolite → urothelial toxicity → hemorrhagic cystitis; ป้องกันด้วย Mesna, hydration, frequent voiding","D":"ผิด — Prednisolone ผลข้างเคียง: immunosuppression, hyperglycemia, osteoporosis"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:46:36') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8f0cc54b-5837-4c23-bd5b-16e28e346b30', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 58 ปี ความดันโลหิตสูง 160/95 mmHg ไม่มีโรคร่วม เป้าหมายความดันโลหิตตาม 2023 guideline คือ', NULL, '["< 150/90 mmHg","< 140/90 mmHg","< 130/80 mmHg","< 120/80 mmHg"]'::jsonb, 'C', 'ACC/AHA 2017/2023 เป้าหมาย BP < 130/80 mmHg สำหรับผู้ใหญ่ทั่วไป', '{"A":"ผิด — < 150/90 เป็น older target สำหรับผู้สูงอายุ ≥ 80 ปี","B":"ผิด — < 140/90 เป็น JNC 7 (เก่า) และ ESH 2023 ยังใช้ แต่ ACC/AHA 2017 ใช้ < 130/80","C":"ถูก — ACC/AHA 2017 guideline: target BP < 130/80 mmHg สำหรับ hypertensive adults (high cardiovascular risk และ stage 2)","D":"ผิด — < 120/80 เป็น normal BP ไม่ใช่ target สำหรับ treatment"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('fdffea0b-1032-4097-aae5-9a7247604f16', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 55 ปี HTN + DM type 2 + CKD (proteinuria) ยา antihypertensive first-line ที่เหมาะสมที่สุดคือ', NULL, '["Calcium channel blocker (Amlodipine)","ACE inhibitor หรือ ARB","Beta-blocker (Atenolol)","Thiazide diuretic (HCTZ)"]'::jsonb, 'B', 'HTN + DM + CKD proteinuria: ACEi/ARB เป็น first-line เพราะมี renoprotective effect ลด proteinuria', '{"A":"ผิด — CCB ใช้ได้แต่ไม่มี renoprotective benefit เหมือน ACEi/ARB","B":"ถูก — ACEi (Enalapril, Lisinopril) หรือ ARB (Losartan, Valsartan) ลด proteinuria และชะลอการดำเนินของ CKD — first-line ใน DM + CKD","C":"ผิด — Beta-blocker ไม่ใช่ first-line HTN ทั่วไป ยกเว้นมี heart failure, post-MI","D":"ผิด — Thiazide ใช้ได้แต่ไม่มี renoprotective benefit เพิ่มเติม"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('02cc9cc7-bb60-4eb6-a4d5-450afa26ea63', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 62 ปี STEMI เพิ่งเกิดขึ้น 2 ชั่วโมง ถูกนำส่ง ER ยาใดที่ต้องให้ทันทีก่อน PCI (ภายใน loading dose)', NULL, '["Aspirin 81 mg OD","Aspirin 325 mg + P2Y12 inhibitor (Ticagrelor 180 mg หรือ Clopidogrel 600 mg) loading","Warfarin","Heparin IV เพียงอย่างเดียว"]'::jsonb, 'B', 'STEMI: dual antiplatelet (DAPT) loading — Aspirin 150-300 mg + Ticagrelor 180 mg หรือ Clopidogrel 600 mg ก่อน PCI', '{"A":"ผิด — 81 mg OD เป็น maintenance dose ไม่ใช่ loading","B":"ถูก — DAPT loading: Aspirin 150-300 mg + Ticagrelor 180 mg (preferred) หรือ Clopidogrel 600 mg ก่อน primary PCI ตาม ACC/AHA/ESC guidelines","C":"ผิด — Warfarin ไม่มีบทบาทใน acute STEMI management","D":"ผิด — Heparin IV ใช้ร่วมใน PCI แต่ไม่ใช่ antiplatelet therapy"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:14') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2b5e45b4-11a3-4271-8a13-a04fe1019927', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี Post-MI (2 สัปดาห์) ปัจจุบัน EF 35% ยาที่ช่วยลด mortality หลัง MI ที่ต้องใช้ทุกราย (ไม่มี contraindication) คือ', NULL, '["Aspirin เพียงอย่างเดียว","Aspirin + Beta-blocker + ACEi/ARB + Statin","CCB + Diuretic","Nitrate ทุกวัน"]'::jsonb, 'B', 'Post-MI with reduced EF: ยา 4 กลุ่ม ลด mortality — Aspirin, Beta-blocker, ACEi/ARB, Statin (ACC/AHA secondary prevention)', '{"A":"ผิด — Aspirin เดี่ยวไม่เพียงพอ","B":"ถูก — Post-MI evidence-based therapies: Aspirin (antiplatelet) + Beta-blocker (reduce arrhythmia/remodeling) + ACEi/ARB (reduce mortality HFrEF) + Statin (LDL reduction, plaque stabilization)","C":"ผิด — CCB ไม่ได้ลด mortality post-MI (ยกเว้น rate control AF)","D":"ผิด — Nitrate ใช้ symptom relief ไม่ได้ลด mortality"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('33c3380a-df22-4ba7-99a6-93f10e1fca17', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี Heart Failure HFrEF (EF 30%) ยา 4 pillars of HFrEF ที่ลด mortality ประกอบด้วย', NULL, '["Furosemide + Spironolactone + Digoxin + ACEi","ACEi/ARB/ARNI + Beta-blocker + MRA + SGLT2i","CCB + Diuretic + Digoxin + Statin","Amiodarone + ACEi + Diuretic + Aspirin"]'::jsonb, 'B', 'HFrEF 4 pillars (2023 AHA/ESC): ARNI (Sacubitril/Valsartan) or ACEi/ARB + Beta-blocker + MRA (Eplerenone/Spironolactone) + SGLT2i', '{"A":"ผิด — Digoxin ไม่ได้ลด mortality เพียงลดการ hospitalization","B":"ถูก — 2022 AHA HF guideline 4 pillars: ARNI/ACEi/ARB + Beta-blocker + MRA + SGLT2i (Dapagliflozin/Empagliflozin) ลด mortality และ hospitalization","C":"ผิด — CCB (non-DHP) อาจแย่ลง HF; Statin ไม่มี mortality benefit ใน HF","D":"ผิด — Amiodarone ใช้เฉพาะ arrhythmia management ไม่ใช่ standard HF pillar"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('9e07f81b-349a-45a9-a07a-350fc9f8f361', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 55 ปี AF (Atrial Fibrillation) สะดุดใจ แพทย์ต้องการ rate control เป้าหมาย resting heart rate ที่ยอมรับได้สำหรับ lenient control คือ', NULL, '["HR < 60 bpm","HR < 80 bpm","HR < 100 bpm","HR < 110 bpm"]'::jsonb, 'D', 'RACE II trial: lenient rate control (HR < 110 bpm) ไม่แย่กว่า strict (< 80 bpm) ใน AF ที่ไม่มีอาการรุนแรง', '{"A":"ผิด — 60 bpm เข้มเกินไป","B":"ผิด — < 80 bpm คือ strict rate control ใช้ได้แต่ lenient ก็ acceptable","C":"ผิด — < 100 bpm เป็น older target","D":"ถูก — Lenient rate control: resting HR < 110 bpm ยอมรับได้ตาม ESC/ACC ในผู้ที่ไม่มี HF หรืออาการรุนแรง (RACE II)"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('4aea576b-4539-4966-a714-1f1d63340a29', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี LDL 180 mg/dL มีประวัติครอบครัว premature CVD แต่ยังไม่มี CVD เอง คำนวณ 10-year ASCVD risk ได้ 12% ควรเริ่มยาชนิดใด', NULL, '["Lifestyle modification อย่างเดียว","Moderate-intensity Statin (Atorvastatin 10-20 mg)","High-intensity Statin (Atorvastatin 40-80 mg)","Ezetimibe เดี่ยว"]'::jsonb, 'C', 'ASCVD risk ≥ 10% + LDL สูง: High-intensity statin เป็น first-line ตาม ACC/AHA 2019 guideline', '{"A":"ผิด — ASCVD risk 12% เกิน threshold ที่ต้องการยา","B":"ผิด — Moderate statin ใช้ใน intermediate risk (7.5-10%)","C":"ถูก — ASCVD risk ≥ 10% (high risk): high-intensity statin เป็น first-line (Atorvastatin 40-80 mg หรือ Rosuvastatin 20-40 mg)","D":"ผิด — Ezetimibe เป็น add-on ไม่ใช่ monotherapy first-line"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b33d80b3-a6f8-4f71-ae34-f9e9b992f1f5', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 35 ปี ตั้งครรภ์ 24 สัปดาห์ ความดันโลหิต 158/104 mmHg วินิจฉัย Gestational Hypertension ยาลดความดันที่ปลอดภัยในตั้งครรภ์คือ', NULL, '["Enalapril (ACE inhibitor)","Methyldopa หรือ Nifedipine หรือ Labetalol","Losartan (ARB)","Hydrochlorothiazide"]'::jsonb, 'B', 'Hypertension ในตั้งครรภ์: Methyldopa, Nifedipine, Labetalol ปลอดภัย; ACEi/ARB ห้ามใช้ (fetotoxic)', '{"A":"ผิด — ACEi (Enalapril) ห้ามใช้ใน pregnancy: ทำให้ fetal renal agenesis, oligohydramnios","B":"ถูก — Methyldopa (category B), Nifedipine extended-release, Labetalol เป็น safe options ตาม ACOG","C":"ผิด — ARB ห้ามใช้ใน pregnancy เช่นเดียวกับ ACEi","D":"ผิด — Thiazide ลด plasma volume อาจส่งผลเสียต่อ fetal perfusion"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2e2c34e6-52d4-41df-b801-dd81793738b1', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี ได้รับ Digoxin 0.25 mg OD สำหรับ AF + HF มาพบแพทย์ด้วยอาการคลื่นไส้อาเจียน ตาพร่า มองเห็นสีเหลือง EKG พบ premature ventricular contractions ค่าใดที่ต้องตรวจ', NULL, '["Serum potassium และ Digoxin level","Serum sodium","INR","Troponin"]'::jsonb, 'A', 'Digoxin toxicity signs: GI, visual (xanthopsia), arrhythmias; Hypokalemia เพิ่ม toxicity — ต้องตรวจ K+ และ Digoxin level', '{"A":"ถูก — Digoxin toxicity: ตรวจ serum digoxin level (therapeutic 0.5-0.9 ng/mL สำหรับ HF) + serum K+ เพราะ hypokalemia เพิ่มความเป็น toxicity อย่างมาก","B":"ผิด — Sodium ไม่เกี่ยวข้องกับ Digoxin toxicity โดยตรง","C":"ผิด — INR สำหรับ Warfarin ไม่เกี่ยวกับ Digoxin","D":"ผิด — Troponin สำหรับ MI ไม่ใช่ Digoxin toxicity"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8d582bf3-dfcc-4a17-9f0b-b2c1254ee6ce', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 50 ปี Stable Angina ใช้ Nitrate (ISDN) ทุกวัน เภสัชกรแนะนำให้มี nitrate-free interval ประมาณ 8-12 ชั่วโมงต่อวัน เหตุใด', NULL, '["ลดโอกาส hypotension","ป้องกัน nitrate tolerance","ลด reflex tachycardia","ป้องกัน methemoglobinemia"]'::jsonb, 'B', 'Nitrate tolerance: การใช้ nitrate ต่อเนื่องทำให้ vascular sensitivity ลดลง → ต้องมี nitrate-free interval', '{"A":"ผิด — Hypotension ป้องกันโดยไม่ใช้ขนาดสูงและหลีกเลี่ยง PDE5 inhibitors","B":"ถูก — Nitrate tolerance เกิดจาก continuous exposure → ลด cGMP generation; nitrate-free interval 8-12 ชม./วัน ป้องกัน tolerance","C":"ผิด — Reflex tachycardia เกิดในช่วงแรก ไม่ใช่สาเหตุของ nitrate-free interval","D":"ผิด — Methemoglobinemia เกิดที่ขนาดสูงมาก ไม่ใช่สาเหตุหลัก"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8fa6f0e0-0c21-4cd5-ba6e-1ac4e0671d6c', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 48 ปี ใช้ Sildenafil (Viagra) สำหรับ Erectile Dysfunction อยู่แล้ว แพทย์อยากให้ใช้ยาใดสำหรับ Angina แต่มี contraindication', NULL, '["Beta-blocker (Metoprolol)","CCB (Amlodipine)","Nitrate (Isosorbide dinitrate)","Ivabradine"]'::jsonb, 'C', 'Nitrate + PDE5 inhibitor (Sildenafil) → severe hypotension อาจถึงแก่ชีวิต — ห้ามใช้ร่วมกัน absolute contraindication', '{"A":"ผิด — Beta-blocker ปลอดภัย ใช้ร่วมกับ Sildenafil ได้","B":"ผิด — CCB ปลอดภัย ไม่มี interaction รุนแรงกับ Sildenafil","C":"ถูก — Nitrate + PDE5i: cGMP ยิ่งเพิ่ม → vasodilation รุนแรง → severe hypotension → absolute contraindication","D":"ผิด — Ivabradine ไม่มี severe interaction กับ Sildenafil"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:48:15') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('2c6d9008-1d16-46e2-b79e-06f0a13319bc', 'dce79912-01f6-4871-96df-94c6cfc853e7', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 65 ปี HTN + Asthma ยาลดความดันกลุ่มใดที่ควรหลีกเลี่ยง', NULL, '["Amlodipine (dihydropyridine CCB)","Losartan (ARB)","Atenolol (selective beta-blocker)","Furosemide"]'::jsonb, 'C', 'Beta-blocker (แม้ selective) ควรหลีกเลี่ยงใน asthma เพราะอาจ exacerbate bronchospasm', '{"A":"ผิด — DHP-CCB (Amlodipine) ปลอดภัยใน asthma","B":"ผิด — ARB ปลอดภัยใน asthma","C":"ถูก — Beta-blockers (แม้ cardioselective เช่น Atenolol, Metoprolol) ควรหลีกเลี่ยงใน asthma เพราะ beta-2 blockade อาจทำให้ bronchospasm แย่ลง","D":"ผิด — Furosemide ปลอดภัยใน asthma"}'::jsonb, 'easy', false, NULL, 'active', '2026-03-29 03:48:16') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('482940c8-3c3b-4179-8e1d-f67c59d55867', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 65 ปี CKD stage 4 (eGFR 22 mL/min) ได้รับยา Metformin 500 mg BID สำหรับ DM type 2 ปัญหาที่อาจเกิดขึ้นคือ', NULL, '["Hypoglycemia","Lactic acidosis","Hepatotoxicity","Pancreatitis"]'::jsonb, 'B', 'Metformin ห้ามใช้ใน eGFR < 30 (บาง guideline < 45) เพราะสะสมใน renal failure → lactic acidosis', '{"A":"ผิด — Metformin ไม่ทำให้ hypoglycemia (ไม่กระตุ้น insulin secretion)","B":"ถูก — Metformin accumulation ใน CKD severe → lactic acidosis ซึ่งอาจถึงแก่ชีวิต; ควรหยุดเมื่อ eGFR < 30 mL/min","C":"ผิด — Metformin ไม่ hepatotoxic","D":"ผิด — Pancreatitis เกี่ยวข้องกับ GLP-1 RA และ DPP-4i ไม่ใช่ Metformin"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:49:59') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8480a156-2100-40b0-9b43-93012d748e1f', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 75 ปี ได้รับ Gentamicin IV สำหรับ gram-negative sepsis เภสัชกรต้องติดตามอะไรบ้าง', NULL, '["Liver function test","Serum creatinine + audiometry (hearing test) + drug level","CBC ทุกวัน","Blood glucose"]'::jsonb, 'B', 'Aminoglycoside monitoring: nephrotoxicity (SCr/BUN), ototoxicity (hearing), drug level (peak/trough) เพื่อ optimize dose และลด toxicity', '{"A":"ผิด — Aminoglycoside ไม่ hepatotoxic","B":"ถูก — Gentamicin/Aminoglycoside: ติดตาม SCr (nephrotoxicity), audiometry (ototoxicity), drug level: trough < 2 mcg/mL, peak 5-10 mcg/mL (conventional dosing)","C":"ผิด — CBC ไม่ใช่ primary monitoring parameter","D":"ผิด — Blood glucose ไม่เกี่ยวข้อง"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:49:59') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('f194ca8a-5e3a-41e4-a22c-540c4732e402', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 50 ปี ใช้ Warfarin สำหรับ AF มาพบเภสัชกรพร้อมใบสั่งยา Fluconazole สำหรับ oral thrush เภสัชกรควรทำอะไร', NULL, '["จ่ายยาได้ปกติ ไม่มี interaction","แจ้งแพทย์ลดขนาด Warfarin ลงก่อนเริ่ม Fluconazole + monitor INR closely","หยุด Warfarin ระหว่างใช้ Fluconazole","เปลี่ยน Fluconazole เป็น Nystatin oral ถ้าเหมาะสม"]'::jsonb, 'B', 'Fluconazole inhibit CYP2C9 → Warfarin (S-warfarin) ลด metabolism → INR เพิ่มขึ้น → เสี่ยงเลือดออก', '{"A":"ผิด — มี significant interaction","B":"ถูก — Fluconazole + Warfarin: INR เพิ่มมาก (อาจเป็น 2-3 เท่า) ควรลดขนาด Warfarin 25-50% และตรวจ INR บ่อยขึ้น","C":"ผิด — หยุด Warfarin ทำให้เกิด thromboembolism เสี่ยงมากกว่า","D":"ผิด — Nystatin ใช้ได้แต่ถ้า Fluconazole จำเป็นต้องจัดการ interaction ไม่ใช่เปลี่ยนยาเสมอไป"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('def0151f-8efc-4f90-91f9-757d96c78b69', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 28 ปี ตั้งครรภ์ 6 สัปดาห์ มีอาการ UTI แบบ uncomplicated ยา antibiotic ใดที่ปลอดภัยในไตรมาสแรก', NULL, '["Ciprofloxacin","Nitrofurantoin","TMP-SMX","Amoxicillin"]'::jsonb, 'D', 'Amoxicillin/Amoxicillin-clavulanate ปลอดภัยในตั้งครรภ์ทุกไตรมาส ใช้รักษา UTI uncomplicated', '{"A":"ผิด — Fluoroquinolone ห้ามใช้ในตั้งครรภ์ (cartilage toxicity, category C)","B":"ผิด — Nitrofurantoin ปลอดภัย ไตรมาส 1-2 แต่ห้ามไตรมาส 3 (hemolytic anemia)","C":"ผิด — TMP-SMX: trimethoprim ต้าน folate → neural tube defects ไตรมาสแรก; SMX ใกล้คลอดทำให้ kernicterus","D":"ถูก — Amoxicillin ปลอดภัยทุกไตรมาส (category B) เป็น preferred antibiotic สำหรับ UTI ในตั้งครรภ์"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('b09eadc1-40c5-425d-a327-6d7121bc130c', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 60 ปี CKD stage 3 (eGFR 40) ปวดข้อ แพทย์สั่ง Colchicine 0.6 mg BID สำหรับ gout เภสัชกรควรแนะนำอะไร', NULL, '["ใช้ได้ปกติไม่ต้องปรับ","ลดขนาดเป็น 0.6 mg OD และ monitor for toxicity","ห้ามใช้ Colchicine ใน CKD ทุก stage","เพิ่มขนาดเป็น 1.2 mg BID"]'::jsonb, 'B', 'Colchicine ถูก eliminate ผ่านไต ใน CKD ต้องลดขนาด: eGFR 30-60 ลดเป็น 0.6 mg OD หรือ reduce frequency', '{"A":"ผิด — CKD stage 3 (eGFR 30-60) ต้องปรับขนาด","B":"ถูก — eGFR 30-60: Colchicine dose reduction เหลือ 0.6 mg OD หรือลด frequency; ติดตาม neuromuscular toxicity","C":"ผิด — Colchicine ใช้ได้ใน CKD แต่ต้องปรับขนาด; ห้ามใช้เฉพาะ eGFR < 10 หรือ dialysis (ตาม some guidelines)","D":"ผิด — เพิ่มขนาดอันตรายมาก"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8148a9fb-9f31-49fd-a0cd-9711dd3251e6', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 45 ปี มีประวัติแพ้ Penicillin (ผื่น maculopapular) แพทย์ต้องการใช้ Cephalosporin รักษา cellulitis ความเสี่ยง cross-reactivity ระหว่าง Penicillin และ Cephalosporin คือ', NULL, '["50% cross-reactivity ห้ามใช้เด็ดขาด","~2% cross-reactivity สามารถใช้ได้ระวัง","ไม่มี cross-reactivity เลย","100% cross-reactivity ห้ามใช้"]'::jsonb, 'B', 'Cross-reactivity Penicillin-Cephalosporin ประมาณ 1-2% (ต่ำกว่าที่เชื่อในอดีต 10%) ขึ้นกับ R1 side chain ที่เหมือนกัน', '{"A":"ผิด — 50% เป็นความเชื่อเก่าที่ผิด","B":"ถูก — Cross-reactivity ประมาณ 1-2% พบใน shared R1 side chains เช่น Amoxicillin-Cefadroxil; ผู้แพ้ penicillin mild (rash) สามารถใช้ cephalosporin ได้ระวัง","C":"ผิด — มี cross-reactivity เล็กน้อยโดยเฉพาะกับ R1 group เหมือนกัน","D":"ผิด — 100% ไม่ถูกต้อง"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('1f396506-29dd-4f9e-b7b0-edbf7f62a2b5', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 70 ปี กำลังรับ Amiodarone สำหรับ persistent AF เภสัชกรต้องติดตามผลข้างเคียงระยะยาวอะไรบ้าง', NULL, '["Liver function, Thyroid function, Pulmonary function, Eye exam","Blood glucose, Uric acid, CBC","INR, APTT","Serum sodium, Potassium"]'::jsonb, 'A', 'Amiodarone toxicity: hepatotoxicity (LFT), thyroid dysfunction (both hypo/hyper), pulmonary toxicity (PFT, CXR), corneal microdeposits + optic neuropathy', '{"A":"ถูก — Amiodarone long-term monitoring: LFT (hepatotoxicity), TFT (thyroid: hypo/hyperthyroidism เพราะมี iodine สูง), CXR/PFT (pulmonary fibrosis), eye exam (corneal deposit, optic neuropathy)","B":"ผิด — glucose/uric acid/CBC ไม่ใช่ primary monitoring","C":"ผิด — INR สำหรับ Warfarin (Amiodarone เพิ่ม INR ถ้าใช้ร่วม Warfarin แต่ไม่ใช่ primary monitoring)","D":"ผิด — Electrolytes ไม่ใช่ primary monitoring parameter ของ Amiodarone"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('72702b92-9ffe-488c-828b-368f30738b7c', '41f903b7-5258-47fa-9ec3-44e756e705d1', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 55 ปี ได้รับ Vancomycin IV สำหรับ MRSA bacteremia เภสัชกรต้องติดตามอะไรเพื่อป้องกัน nephrotoxicity', NULL, '["Peak level เท่านั้น","Trough level (เก้า < 15 mg/L) หรือ AUC/MIC monitoring","ตรวจ urine protein ทุกวัน","INR"]'::jsonb, 'B', 'Vancomycin monitoring: trough level (< 15 mg/L) หรือ AUC24/MIC ≥ 400-600 เพื่อทั้ง efficacy และลด nephrotoxicity', '{"A":"ผิด — Peak level ไม่ใช่ standard monitoring parameter สำหรับ Vancomycin ทั่วไป","B":"ถูก — ASHP/IDSA 2020 guideline: AUC/MIC-guided dosing preferred; trough-only: ≥ 15 mg/L เพิ่มความเสี่ยง nephrotoxicity; ควรใช้ AUC target 400-600 mg·h/L","C":"ผิด — Urine protein ไม่ใช่ standard Vancomycin monitoring","D":"ผิด — INR ไม่เกี่ยวข้อง"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:50:00') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('cd479eb1-a245-4610-9e45-00709a3d1c8e', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 35 ปี วินิจฉัย Typhoid fever (Salmonella typhi) ยา antibiotic first-line ที่แนะนำในปัจจุบันคือ', NULL, '["Chloramphenicol","Fluoroquinolone (Ciprofloxacin) หรือ Azithromycin","Ampicillin","TMP-SMX"]'::jsonb, 'B', 'Fluoroquinolone (uncomplicated) หรือ Azithromycin เป็น first-line ปัจจุบัน เนื่องจาก resistance ต่อ Chloramphenicol และ Ampicillin สูงขึ้น', '{"A":"ผิด — Chloramphenicol เคยเป็น first-line แต่ resistance สูง และมีผลข้างเคียง aplastic anemia","B":"ถูก — Ciprofloxacin 500 mg BID × 7-14 วัน หรือ Azithromycin 1 g OD × 5 วัน เป็น preferred treatment ปัจจุบัน","C":"ผิด — Ampicillin resistance สูงขึ้นมาก","D":"ผิด — TMP-SMX resistance สูงในหลายพื้นที่"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:59:26') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('12e2d71e-f307-49ff-9f57-45cb9c8fcad2', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยหญิงอายุ 40 ปี Sepsis จาก E. coli UTI ได้รับ Ceftriaxone IV อยู่ ผล culture ออกมาเป็น ESBL-producing E. coli ควรเปลี่ยนยาเป็นอะไร', NULL, '["เพิ่มขนาด Ceftriaxone","Meropenem หรือ Ertapenem (Carbapenem)","Cefepime","Azithromycin"]'::jsonb, 'B', 'ESBL-producing organisms ดื้อต่อ cephalosporins ทุกชนิด → Carbapenem เป็น definitive treatment', '{"A":"ผิด — ESBL enzyme ทำลาย beta-lactam ring การเพิ่มขนาดไม่ช่วย","B":"ถูก — Carbapenem (Meropenem, Imipenem, Ertapenem) เป็น drug of choice สำหรับ ESBL-producing Enterobacteriaceae","C":"ผิด — Cefepime ถูก hydrolyzed โดย ESBL ไม่ reliable","D":"ผิด — Azithromycin ไม่มีประสิทธิภาพต่อ gram-negative sepsis"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:59:26') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('658aae2a-dc72-4c61-bd80-68dea04d1b9c', '8bccedb2-3bdb-4f5c-9da9-f589b25672fd', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 28 ปี วินิจฉัย Gonorrhea (Neisseria gonorrhoeae) ยา first-line ที่แนะนำตาม CDC 2021 guideline คือ', NULL, '["Ciprofloxacin 500 mg single dose","Ceftriaxone 500 mg IM single dose","Azithromycin 1 g single dose เดี่ยว","Doxycycline 100 mg BID × 7 วัน"]'::jsonb, 'B', 'CDC 2021: Ceftriaxone 500 mg IM single dose (1 g ถ้า weight > 150 kg) เป็น first-line เนื่องจาก fluoroquinolone resistance สูง', '{"A":"ผิด — Ciprofloxacin resistance สูงมาก ไม่แนะนำ","B":"ถูก — Ceftriaxone 500 mg IM single dose เป็น standard first-line (CDC 2021); ถ้าน้ำหนัก > 150 kg ให้ 1 g","C":"ผิด — Azithromycin เดี่ยวไม่แนะนำแล้วเพราะ resistance เพิ่มขึ้น (เดิมใช้ dual therapy)","D":"ผิด — Doxycycline ใช้ cover Chlamydia ร่วม แต่ไม่ใช่ first-line Gonorrhea เดี่ยว"}'::jsonb, 'hard', false, NULL, 'active', '2026-03-29 03:59:27') ON CONFLICT DO NOTHING;
INSERT INTO mcq_questions ("id", "subject_id", "exam_type", "exam_source", "exam_day", "question_number", "scenario", "image_url", "choices", "correct_answer", "explanation", "detailed_explanation", "difficulty", "is_ai_enhanced", "ai_notes", "status", "created_at") VALUES ('8ca3a417-4b22-45be-817e-19e365099f38', 'fb62e97d-dec1-4b47-b45f-617b2c03fb4d', 'PLE-CC1', NULL, NULL, NULL, 'ผู้ป่วยชายอายุ 45 ปี มีอาการปวดศีรษะเรื้อรัง ไม่ตอบสนองต่อยาแก้ปวดทั่วไป แพทย์วินิจฉัย Chronic Migraine ยาป้องกัน (prophylaxis) ที่แนะนำเป็น first-line คือ', NULL, '["Paracetamol 1 g BID ทุกวัน","Propranolol 40-240 mg/day หรือ Topiramate 25-100 mg/day","Sumatriptan ทุกวัน","Codeine PRN"]'::jsonb, 'B', 'Migraine prophylaxis first-line: Propranolol (beta-blocker) หรือ Topiramate เป็น evidence-based treatment ตาม AHS/AAN guideline', '{"A":"ผิด — Paracetamol ทุกวันทำให้ Medication Overuse Headache","B":"ถูก — Propranolol, Topiramate, Amitriptyline, Valproate เป็น first-line prophylaxis สำหรับ chronic/frequent migraine","C":"ผิด — Sumatriptan ทุกวันทำให้ MOH (Medication Overuse Headache)","D":"ผิด — Opioid ไม่แนะนำใน migraine management"}'::jsonb, 'medium', false, NULL, 'active', '2026-03-29 03:59:27') ON CONFLICT DO NOTHING;
